@dataclass
class NLIntent:
    intent: str
    form_type: Optional[str]
    entities: Dict[str, Any]
    context: Dict[str, Any]


class ArtifactRollbackRequest(BaseModel):
    artifact_name: str
    artifact_id: str
    created_by: str = Field(default="system.rollback")


class NL2Gate:
    def __init__(self, project_context: Dict[str, Any], session_store: Dict[str, Dict[str, Any]]):
        self.project = project_context
        self.session_store = session_store
        self.intent_patterns = {
            "validate": r"(合格|行吗|够不够|可以吗|满足|判定|是否通过|达标)",
            "query_standard": r"(标准|规范|要求|阈值|是多少)",
            "calculate": r"(计算|结果|得多少|怎么算)",
        }
        self.layer_pattern = re.compile(r"(Z96|Z94|Z92|96区|94区|92区|上面层|中面层|下面层|基层|底基层)", re.IGNORECASE)
        self.stake_pattern = re.compile(r"(?:[Kk]?(\d{1,4})[+加](\d{3}))")

    def parse(self, text: str, user_id: str) -> NLIntent:
        clean_text = text.strip()
        intent = self._detect_intent(clean_text)
        entities = self._extract_entities(clean_text)
        entities = self._fill_context(entities, user_id)
        form_type = self._map_to_form(clean_text, entities)
        self._update_context(user_id, entities)
        return NLIntent(
            intent=intent,
            form_type=form_type,
            entities=entities,
            context=self.session_store.get(user_id, {}),
        )

    def _detect_intent(self, text: str) -> str:
        for intent, pattern in self.intent_patterns.items():
            if re.search(pattern, text):
                return intent
        return "validate"

    def _extract_entities(self, text: str) -> Dict[str, Any]:
        entities: Dict[str, Any] = {"raw_text": text}

        stake_match = self.stake_pattern.search(text)
        if stake_match:
            entities["stake"] = f"K{int(stake_match.group(1))}+{stake_match.group(2)}"

        compaction_match = re.search(r"压实度[^\d]*(\d{2,3}(?:\.\d+)?)", text)
        if compaction_match:
            entities["compaction"] = float(compaction_match.group(1))

        thickness_match = re.search(r"厚度[^\d]*(\d{2,4}(?:\.\d+)?)", text)
        if thickness_match:
            entities["thickness"] = float(thickness_match.group(1))

        iri_match = re.search(r"(?:IRI|平整度)[^\d]*(\d+(?:\.\d+)?)", text, re.IGNORECASE)
        if iri_match:
            entities["iri"] = float(iri_match.group(1))

        deflection_match = re.search(r"(?:弯沉|贝克曼)[^\d]*(\d+(?:\.\d+)?)", text)
        if deflection_match:
            entities["deflection"] = float(deflection_match.group(1))

        layer_match = self.layer_pattern.search(text)
        if layer_match:
            layer_raw = layer_match.group(1)
            entities["layer_zone_raw"] = layer_raw
            entities["layer_zone"] = _normalize_layer_zone(layer_raw, fallback="Z96", allow_raw=True)

        road_match = re.search(r"(高速|一级|二级|三级|四级)", text)
        if road_match:
            entities["road_class"] = road_match.group(1)

        return entities

    def _fill_context(self, entities: Dict[str, Any], user_id: str) -> Dict[str, Any]:
        previous = self.session_store.get(user_id, {})

        if "stake" not in entities and previous.get("last_stake"):
            entities["stake"] = previous["last_stake"]

        if "layer_zone" not in entities:
            entities["layer_zone"] = previous.get("last_layer") or self.project.get("default_layer") or "Z96"

        return entities

    def _map_to_form(self, text: str, entities: Dict[str, Any]) -> Optional[str]:
        if "compaction" in entities or "压实度" in text:
            return "T0921-2019"
        if "iri" in entities or "平整度" in text or "IRI" in text.upper():
            return "T0931-2019"
        if "thickness" in entities or "厚度" in text:
            return "T0912-2019"
        if "deflection" in entities or "弯沉" in text or "贝克曼" in text:
            return "T0951-2008"
        return None

    def _update_context(self, user_id: str, entities: Dict[str, Any]) -> None:
        if user_id not in self.session_store:
            self.session_store[user_id] = {}
        if "stake" in entities:
            self.session_store[user_id]["last_stake"] = entities["stake"]
        if "layer_zone" in entities:
            self.session_store[user_id]["last_layer"] = entities["layer_zone"]

    def to_api_params(
        self,
        intent: NLIntent,
        project_id: str,
        normdoc: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        if not intent.form_type:
            raise ValueError("无法识别检测类型，请说明是压实度、平整度、厚度或弯沉。")

        inputs: Dict[str, Any] = {}

        if intent.form_type == "T0921-2019":
            if "compaction" not in intent.entities:
                raise ValueError("压实度数值缺失，请补充如：压实度94.5%。")
            inputs["compaction_degree"] = intent.entities["compaction"]
            inputs["layer_zone"] = _normalize_layer_zone(intent.entities.get("layer_zone"), fallback="Z96", allow_raw=False)
        elif intent.form_type == "T0931-2019":
            if "iri" not in intent.entities:
                raise ValueError("IRI 数值缺失，请补充如：IRI 1.8。")
            inputs["iri"] = intent.entities["iri"]
            inputs["layer_zone"] = intent.entities.get("layer_zone", "上面层")
        elif intent.form_type == "T0912-2019":
            if "thickness" not in intent.entities:
                raise ValueError("厚度数值缺失，请补充如：厚度58。")
            inputs["thickness"] = intent.entities["thickness"]
            inputs["layer_zone"] = intent.entities.get("layer_zone", "面层")
        elif intent.form_type == "T0951-2008":
            if "deflection" not in intent.entities:
                raise ValueError("弯沉数值缺失，请补充如：弯沉180。")
            inputs["deflection"] = intent.entities["deflection"]

        for optional_key in ("road_class", "layer_zone", "filler_type"):
            if optional_key in intent.entities and optional_key not in inputs:
                inputs[optional_key] = intent.entities[optional_key]

        payload: Dict[str, Any] = {
            "form_type": intent.form_type,
            "project_id": project_id,
            "intent": intent.intent,
            "inputs": inputs,
        }

        if intent.entities.get("stake"):
            payload["section"] = intent.entities["stake"]

        if normdoc:
            header = normdoc.get("header", {})
            _, table = resolve_normdoc_table(normdoc, intent.form_type)
            payload["normdoc_ref"] = {
                "standard_id": header.get("standard_id", ""),
                "version": header.get("version", ""),
                "table_id": table.get("table_id", "") if isinstance(table, dict) else "",
                "schema_uri": normdoc.get("schema_uri", ""),
            }

        return payload


