def _derive_default_layer(data: Dict[str, Any]) -> str:
    explicit = data.get("default_layer") or data.get("design_params", {}).get("default_layer")
    if isinstance(explicit, str) and explicit.strip():
        return _normalize_layer_zone(explicit.strip(), fallback="Z96", allow_raw=False) or explicit.strip()

    zones = data.get("design_params", {}).get("subgrade", {}).get("zones", {})
    if isinstance(zones, dict) and zones:
        if "Z96" in zones:
            return "Z96"
        first = next(iter(zones.keys()))
        if isinstance(first, str) and first.strip():
            return _normalize_layer_zone(first.strip(), fallback="Z96", allow_raw=False) or first.strip()

    return "Z96"


def _canonical_layer_zone_key(raw: Any) -> str:
    text = str(raw or "").strip()
    if not text:
        return ""

    upper = re.sub(r"[\s_\-]+", "", text).upper()
    if upper in {"Z96", "96区", "96"} or "96" in upper:
        return "Z96"
    if upper in {"Z94", "94区", "94"} or "94" in upper:
        return "Z94"
    if upper in {"Z92", "92区", "92"} or "92" in upper:
        return "Z92"
    return ""


def _normalize_layer_zone(raw: Any, fallback: str = "Z96", allow_raw: bool = True) -> str:
    canonical = _canonical_layer_zone_key(raw)
    if canonical:
        return canonical
    if allow_raw:
        text = str(raw or "").strip()
        if text:
            return text
    return fallback


def _normalize_override_target(target: Any) -> str:
    text = str(target or "").strip()
    if not text:
        return ""
    hit = re.match(r"^subgrade\.([^\.]+)\.(.+)$", text)
    if not hit:
        return text
    canonical = _canonical_layer_zone_key(hit.group(1))
    if not canonical:
        return text
    return f"subgrade.{canonical}.{hit.group(2)}"


def _resolve_zone_from_layer_depth(layer_depth: str) -> str:
    text = str(layer_depth or "").strip().lower().replace(" ", "")
    if text in {"0-0.8m", "0~0.8m", "0to0.8m", "0.8m"}:
        return "Z96"
    if text in {"0.8-1.5m", "0.8~1.5m", "0.8to1.5m", "1.5m"}:
        return "Z96"
    if text in {">1.5m", "gt1.5m", "1.5m+"}:
        return "Z94"
    return _normalize_layer_zone(layer_depth, fallback="Z96", allow_raw=False)


def _resolve_zone_tolerance(project: Dict[str, Any], zone: str, default_tolerance: float = 2.0) -> float:
    zones = project.get("design_params", {}).get("subgrade", {}).get("zones", {})
    if not isinstance(zones, dict):
        return default_tolerance
    item = zones.get(zone, {})
    if not isinstance(item, dict):
        return default_tolerance
    value = _to_float(item.get("tolerance"))
    if value is None:
        return default_tolerance
    return abs(value)


def _normalize_test_method(raw: Any) -> str:
    text = str(raw or "").strip().upper().replace("_", "").replace("-", "")
    if text == "T0921":
        return "T0921"
    if text == "T0923":
        return "T0923"
    if text == "T0924":
        return "T0924"
    return "T0921"


def _parse_iso_date_or_today(raw: Any) -> date:
    text = str(raw or "").strip()
    if not text:
        return date.today()
    try:
        return datetime.strptime(text[:10], "%Y-%m-%d").date()
    except ValueError:
        return date.today()


def _normalize_instrument_key(raw: Any) -> str:
    return re.sub(r"[^A-Za-z0-9]+", "", str(raw or "").upper())


def _find_sand_bottle(project: Dict[str, Any], instrument_id: str) -> Dict[str, Any]:
    bottles = project.get("instruments", {}).get("sand_bottles", [])
    if not isinstance(bottles, list) or not bottles:
        return {}
    if not instrument_id.strip():
        first = bottles[0]
        return first if isinstance(first, dict) else {}

    ask = _normalize_instrument_key(instrument_id)
    for item in bottles:
        if not isinstance(item, dict):
            continue
        key = _normalize_instrument_key(item.get("id", ""))
        if not key:
            continue
        if key == ask or key.endswith(ask) or ask.endswith(key):
            return item
    return {}


def _validate_compaction_instrument(
    project: Dict[str, Any],
    test_method: str,
    instrument_id: str,
    inspection_date: date,
    sand_density: float,
) -> Dict[str, Any]:
    # T0921 对应灌砂法，要求砂瓶有效；其他方法暂保持接口并放行。
    if test_method != "T0921":
        return {
            "passed": True,
            "code": "INSTRUMENT_SKIPPED",
            "message": f"{test_method} 暂不启用砂瓶校验。",
            "instrument": {},
        }

    bottle = _find_sand_bottle(project, instrument_id)
    if not bottle:
        return {
            "passed": False,
            "code": "INSTRUMENT_NOT_FOUND",
            "message": "未找到砂瓶或未配置仪器台账。",
            "instrument": {},
        }

    valid_until = _parse_iso_date_or_today(bottle.get("valid_until"))
    if inspection_date > valid_until:
        return {
            "passed": False,
            "code": "INSTRUMENT_EXPIRED",
            "message": f"砂瓶 {bottle.get('id', '')} 已过期（有效期至 {valid_until}）。",
            "instrument": bottle,
        }

    calibrated_density = _to_float(bottle.get("calibrated_density"))
    density_diff = None
    if calibrated_density is not None:
        density_diff = abs(calibrated_density - sand_density)
        if density_diff > 0.02:
            return {
                "passed": False,
                "code": "INSTRUMENT_DENSITY_MISMATCH",
                "message": "输入砂密度与仪器标定值偏差过大。",
                "instrument": bottle,
                "density_diff": density_diff,
            }

    return {
        "passed": True,
        "code": "INSTRUMENT_OK",
        "message": f"砂瓶 {bottle.get('id', '')} 在有效期内。",
        "instrument": bottle,
        "density_diff": density_diff,
    }


def _t_distribution_95(df: int) -> float:
    if df <= 0:
        return 0.0
    if df in T_DISTRIBUTION_95_TABLE:
        return T_DISTRIBUTION_95_TABLE[df]
    if df < 40:
        return 2.021
    if df < 60:
        return 2.0
    return 1.96


def _compute_representative_value_95(values: List[float]) -> Dict[str, Any]:
    cleaned = [float(v) for v in values if _to_float(v) is not None]
    if not cleaned:
        return {
            "n": 0,
            "mean": 0.0,
            "std_dev": 0.0,
            "t_value": 0.0,
            "representative": 0.0,
        }
    n = len(cleaned)
    mean = sum(cleaned) / n
    if n == 1:
        return {
            "n": 1,
            "mean": mean,
            "std_dev": 0.0,
            "t_value": 0.0,
            "representative": mean,
        }
    variance = sum((item - mean) ** 2 for item in cleaned) / (n - 1)
    std_dev = variance ** 0.5
    t_value = _t_distribution_95(n - 1)
    representative = mean - t_value * std_dev / (n ** 0.5)
    return {
        "n": n,
        "mean": mean,
        "std_dev": std_dev,
        "t_value": t_value,
        "representative": representative,
    }


def _can_compaction_override(project: Dict[str, Any], actor_did: str, evidence: str) -> bool:
    personnel = project.get("personnel", {})
    if not isinstance(personnel, dict):
        return False
    chief = personnel.get("chief_engineer", {})
    if not isinstance(chief, dict):
        return False
    chief_did = str(chief.get("did", "")).strip()
    needs_evidence = bool(chief.get("requires_photo_evidence", True))
    if actor_did.strip() != chief_did:
        return False
    if needs_evidence and not str(evidence or "").strip():
        return False
    return True


def execute_compaction_component(request: CompactionExecutionRequest, project: Dict[str, Any]) -> Dict[str, Any]:
    test_method = _normalize_test_method(request.test_method)
    inspection_date = _parse_iso_date_or_today(request.inspection_date)
    zone_type = _resolve_zone_from_layer_depth(request.layer_depth)
    standard_value = _lookup_project_standard(project, zone_type, 95.0, section=request.stake)
    tolerance = _resolve_zone_tolerance(project, zone_type, default_tolerance=2.0)

    instrument_check = _validate_compaction_instrument(
        project=project,
        test_method=test_method,
        instrument_id=request.instrument_id,
        inspection_date=inspection_date,
        sand_density=request.raw_data.sand_density,
    )

    state_flow: List[str] = ["DRAFT"]
    path_steps: List[Dict[str, Any]] = []
    gate_results: List[Dict[str, Any]] = []
    actions: List[str] = []

    if not instrument_check.get("passed"):
        state_flow.append("REJECTED")
        gate_results.append(
            {
                "gate": "instrument_check",
                "status": "BLOCKED",
                "severity": "CRITICAL",
                "message": instrument_check.get("message", "仪器校验失败"),
            }
        )
        actions.append("更换或复检仪器后重试")
        compaction_degree = 0.0
        representative_bundle = {
            "n": 0,
            "mean": 0.0,
            "std_dev": 0.0,
            "t_value": 0.0,
            "representative": 0.0,
        }
        single_point_pass = False
        representative_pass = False
    else:
        wet_density = (request.raw_data.mass_hole_sand / request.raw_data.sand_density) / request.raw_data.volume_ring
        dry_density = wet_density / (1 + request.raw_data.moisture_content / 100)
        compaction_degree = dry_density / request.raw_data.max_dry_density * 100

        path_steps.extend(
            [
                {
                    "id": "calc_wet_density",
                    "formula": "(mass_hole_sand / sand_density) / volume_ring",
                    "output": wet_density,
                },
                {
                    "id": "calc_dry_density",
                    "formula": "wet_density / (1 + moisture_content / 100)",
                    "output": dry_density,
                },
                {
                    "id": "calc_compaction",
                    "formula": "dry_density / max_dry_density * 100",
                    "output": compaction_degree,
                },
                {
                    "id": "determine_zone",
                    "formula": "lookup(layer_depth -> zone_type)",
                    "output": zone_type,
                },
                {
                    "id": "determine_standard",
                    "formula": "lookup(zone_type -> standard_value)",
                    "output": standard_value,
                },
            ]
        )
        state_flow.append("COMPUTED")

        single_threshold = standard_value - tolerance
        single_point_pass = compaction_degree >= single_threshold
        gate_results.append(
            {
                "gate": "single_point",
                "condition": "compaction_degree >= standard_value - tolerance",
                "actual": compaction_degree,
                "expected": single_threshold,
                "status": "PASS" if single_point_pass else "BLOCKED",
                "severity": "BLOCKING",
                "message": (
                    "单点压实度满足下限。"
                    if single_point_pass
                    else f"单点压实度 {compaction_degree:.3f} 低于下限 {single_threshold:.3f}。"
                ),
            }
        )
        if single_point_pass:
            state_flow.append("VALIDATED")

        paragraph_values = [float(v) for v in request.paragraph_values if _to_float(v) is not None]
        if not paragraph_values:
            paragraph_values = [compaction_degree]
        representative_bundle = _compute_representative_value_95(paragraph_values)
        representative_value = representative_bundle["representative"]
        representative_pass = representative_value >= standard_value
        gate_results.append(
            {
                "gate": "representative",
                "method": "t_distribution_95",
                "condition": "representative >= standard_value",
                "actual": representative_value,
                "expected": standard_value,
                "status": "PASS" if representative_pass else "BLOCKED",
                "severity": "CRITICAL" if not representative_pass else "INFO",
                "message": (
                    "代表值满足标准。"
                    if representative_pass
                    else f"代表值 {representative_value:.3f} 低于标准 {standard_value:.3f}。"
                ),
            }
        )

    blocked = not instrument_check.get("passed") or (not single_point_pass) or (not representative_pass)
    final_state = "QUALIFIED"
    output_status = "合格"

    if blocked:
        final_state = "REJECTED"
        output_status = "不合格"
        actions.extend(["下发不合格通知", "建议补压或返工", "安排复测并补充影像证据"])

    if blocked and request.override:
        if _can_compaction_override(project, request.actor_did, request.override_evidence):
            final_state = "OVERRIDDEN"
            output_status = "特批"
            actions.append("特批通过，保留复测跟踪")
            gate_results.append(
                {
                    "gate": "override",
                    "status": "PASS",
                    "severity": "WARNING",
                    "message": "已按特批流程通过（总工 + 证据）。",
                }
            )
        else:
            gate_results.append(
                {
                    "gate": "override",
                    "status": "BLOCKED",
                    "severity": "CRITICAL",
                    "message": "特批条件不满足（需总工 DID 与证据）。",
                }
            )

    if final_state not in state_flow:
        state_flow.append(final_state)

    proof_payload = {
        "component_id": "JTG_F80_1_2017.4.2.1.compaction",
        "component_locator": "土方路基.压实度",
        "project_id": project.get("project_id", request.project_id),
        "stake": request.stake,
        "layer_depth": request.layer_depth,
        "zone_type": zone_type,
        "test_method": test_method,
        "input_dto": request.model_dump() if hasattr(request, "model_dump") else request.dict(),
        "path_steps": path_steps,
        "gate_results": gate_results,
        "state_flow": state_flow,
        "actor": {"did": request.actor_did, "name": request.actor_name},
        "computed_at": _utc_now(),
    }
    proof_hash = _stable_json_hash(proof_payload)

    return {
        "component": {
            "component_id": "JTG_F80_1_2017.4.2.1.compaction",
            "name": "压实度",
            "type": "MeasuredItem",
            "critical": True,
            "locator": "土方路基.压实度",
        },
        "input": {
            "stake": request.stake,
            "layer_depth": request.layer_depth,
            "zone_type": zone_type,
            "test_method": test_method,
            "raw_data": request.raw_data.model_dump() if hasattr(request.raw_data, "model_dump") else request.raw_data.dict(),
            "inspection_date": inspection_date.isoformat(),
            "instrument_id": request.instrument_id,
        },
        "path": {
            "steps": path_steps,
            "compaction_degree": compaction_degree,
            "representative_bundle": representative_bundle,
        },
        "gate": {
            "status": "PASS" if final_state in {"QUALIFIED", "OVERRIDDEN"} else "BLOCKED",
            "single_point_pass": single_point_pass,
            "representative_pass": representative_pass,
            "standard_value": standard_value,
            "tolerance": tolerance,
            "results": gate_results,
        },
        "state": {"current": final_state, "flow": state_flow},
        "instrument_check": instrument_check,
        "output": {
            "compaction_degree": round(compaction_degree, 3),
            "status": output_status,
            "representative_value": round(float(representative_bundle.get("representative", 0.0)), 3),
            "proof_hash": proof_hash,
        },
        "proof": {
            "proof_hash": proof_hash,
            "snapshot": proof_payload,
        },
        "actions": actions,
    }


def _normalize_project_layer_profiles(data: Dict[str, Any]) -> None:
    design_params = data.get("design_params", {})
    if not isinstance(design_params, dict):
        return
    subgrade = design_params.get("subgrade", {})
    if not isinstance(subgrade, dict):
        return
    zones = subgrade.get("zones", {})
    if not isinstance(zones, dict):
        return

    normalized_zones: Dict[str, Any] = {}
    alias_map: Dict[str, List[str]] = {}
    for raw_key, raw_value in zones.items():
        zone_key = str(raw_key or "").strip()
        canonical = _canonical_layer_zone_key(zone_key) or zone_key
        if canonical in normalized_zones and isinstance(normalized_zones[canonical], dict) and isinstance(raw_value, dict):
            merged = dict(normalized_zones[canonical])
            for field, val in raw_value.items():
                if field not in merged or merged[field] in ("", None):
                    merged[field] = val
            normalized_zones[canonical] = merged
        else:
            normalized_zones[canonical] = raw_value

        bucket = alias_map.setdefault(canonical, [])
        if zone_key and zone_key not in bucket:
            bucket.append(zone_key)

    for canonical, defaults in CANONICAL_LAYER_ZONE_MAP.items():
        if canonical not in normalized_zones:
            continue
        bucket = alias_map.setdefault(canonical, [])
        for alias in defaults:
            if alias not in bucket:
                bucket.append(alias)

    subgrade["zones"] = normalized_zones
    data["layer_zone_aliases"] = alias_map

    overrides = data.get("project_overrides", [])
    if isinstance(overrides, list):
        for item in overrides:
            if not isinstance(item, dict):
                continue
            rules = item.get("rules", [])
            if not isinstance(rules, list):
                continue
            for rule in rules:
                if not isinstance(rule, dict):
                    continue
                rule["target"] = _normalize_override_target(rule.get("target", ""))


def _normalize_project(data: Dict[str, Any], requested_id: str) -> Dict[str, Any]:
    normalized = dict(data)
    _normalize_project_layer_profiles(normalized)
    normalized["project_id"] = (
        normalized.get("project_id")
        or normalized.get("id")
        or requested_id
    )
    normalized["project_name"] = (
        normalized.get("project_name")
        or normalized.get("name")
        or requested_id
    )
    normalized["default_layer"] = _derive_default_layer(normalized)
    return normalized


def _load_json_file(path: Path) -> Dict[str, Any]:
    with path.open("r", encoding="utf-8") as f:
        return json.load(f)


def _normalize_code(value: str) -> str:
    return re.sub(r"[^A-Za-z0-9]", "", value or "").upper()


def _normalize_std_code_segment(value: str) -> str:
    token = (
        str(value or "")
        .upper()
        .replace("／", "/")
        .replace("－", "-")
        .replace("—", "-")
        .replace("–", "-")
    )
    token = re.sub(r"\s+", "", token).replace("/", "-")
    if not token:
        return ""
    matched_alpha = re.fullmatch(r"([A-Z]+)(\d{2})(\d)", token)
    if matched_alpha:
        return f"{matched_alpha.group(1)}{matched_alpha.group(2)}-{matched_alpha.group(3)}"
    matched_numeric = re.fullmatch(r"(\d{2})(\d)", token)
    if matched_numeric:
        return f"{matched_numeric.group(1)}-{matched_numeric.group(2)}"
    return token


def _normalize_std_prefix(prefix: str) -> str:
    raw = re.sub(r"[^A-Z0-9]", "", str(prefix or "").upper())
    if raw == "JTGT":
        return "JTG/T"
    if raw == "JTGF":
        return "JTG"
    if raw in {"JTG", "JTGF", "JTG/T"}:
        return "JTG/T" if raw == "JTG/T" else "JTG"
    return str(prefix or "").upper()


def _format_std_code_display(std_code: str) -> str:
    text = str(std_code or "").strip().upper()
    if not text:
        return ""
    text = (
        text.replace("／", "/")
        .replace("－", "-")
        .replace("—", "-")
        .replace("–", "-")
    )
    compact = re.sub(r"[^A-Z0-9]", "", text)
    if compact == "JTGT36502020":
        return "JTG/T 3650-2020"
    m_jtgt = re.fullmatch(r"JTG(?:/|-)T[-\s]*(\d{4})-(\d{4})", text)
    if m_jtgt:
        return f"JTG/T {m_jtgt.group(1)}-{m_jtgt.group(2)}"
    m_jtgf = re.fullmatch(r"JTG[-\s]*F(\d{2})[-/](\d)-(\d{4})", text)
    if m_jtgf:
        return f"JTG F{m_jtgf.group(1)}/{m_jtgf.group(2)}-{m_jtgf.group(3)}"
    m_jtg_plain = re.fullmatch(r"JTG[-\s]*(\d{4})-(\d{4})", text)
    if m_jtg_plain:
        return f"JTG {m_jtg_plain.group(1)}-{m_jtg_plain.group(2)}"
    if text.startswith("JTG-T-"):
        return f"JTG/T {text[len('JTG-T-'):]}"
    return text


def _detect_std_identity(text: str) -> Dict[str, str]:
    raw = str(text or "")
    normalized = (
        raw.replace("／", "/")
        .replace("－", "-")
        .replace("—", "-")
        .replace("–", "-")
        .replace("—", "-")
        .replace("_", " ")
    )

    patterns = [
        re.compile(r"\b(?P<prefix>JTG(?:\s*(?:/|-)?\s*T)?|JTGT)\s*(?P<code>[A-Z]?\d+(?:\s*[/-]\s*\d+)?)\s*[-\s]\s*(?P<year>\d{4})\b", re.IGNORECASE),
        re.compile(r"\b(?P<prefix>GB(?:\s*(?:/|-)?\s*T)?)\s*(?P<code>\d+(?:\.\d+)?)\s*[-\s]\s*(?P<year>\d{4})\b", re.IGNORECASE),
        re.compile(r"\b(?P<prefix>DB\d{2})\s*/?\s*(?P<code>[A-Z]?\d+(?:\.\d+)?)\s*[-\s]\s*(?P<year>\d{4})\b", re.IGNORECASE),
        re.compile(r"\b(?P<prefix>Q\s*/\s*[A-Z0-9]+)\s*(?P<code>[A-Z]?\d+(?:\.\d+)?)\s*[-\s]\s*(?P<year>\d{4})\b", re.IGNORECASE),
    ]

    for pattern in patterns:
        hit = pattern.search(normalized)
        if not hit:
            continue
        prefix = re.sub(r"\s+", "", hit.group("prefix").upper()).replace("/", "-")
        prefix = re.sub(r"^JTG-?T$", "JTG-T", prefix)
        prefix = re.sub(r"^GB-?T$", "GB-T", prefix)
        code = _normalize_std_code_segment(hit.group("code"))
        year = hit.group("year")
        canonical_prefix = _normalize_std_prefix(prefix)
        if canonical_prefix == "JTG/T":
            canonical = f"JTG/T {code}-{year}"
        elif canonical_prefix == "JTG":
            if re.fullmatch(r"F\d{2}-\d", code):
                canonical = f"JTG {code.replace('-', '/')}-{year}"
            else:
                canonical = f"JTG {code}-{year}"
        else:
            canonical = f"{canonical_prefix}-{code}-{year}"
        return {"std_code": _format_std_code_display(canonical), "year": year}

    return {"std_code": "", "year": ""}


def _extract_pdf_preview_text(pdf_bytes: bytes, max_pages: int = 6) -> str:
    if not pdf_bytes:
        return ""

    chunks: List[str] = []
    try:
        from pypdf import PdfReader  # type: ignore

        reader = PdfReader(io.BytesIO(pdf_bytes))
        limit = min(max_pages, len(reader.pages))
        for idx in range(limit):
            page_text = reader.pages[idx].extract_text() or ""
            if page_text.strip():
                chunks.append(page_text.strip())
    except Exception:
        pass

    if chunks:
        return "\n".join(chunks)

    try:
        import pdfplumber  # type: ignore

        with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
            limit = min(max_pages, len(pdf.pages))
            for idx in range(limit):
                page = pdf.pages[idx]
                page_text = page.extract_text() or ""
                if page_text.strip():
                    chunks.append(page_text.strip())
    except Exception:
        pass

    return "\n".join(chunks)


def _detect_title_from_preview(preview_text: str) -> str:
    if not preview_text.strip():
        return ""

    lines = [line.strip() for line in preview_text.splitlines() if line.strip()]
    for line in lines[:120]:
        compact = re.sub(r"\s+", "", line)
        if len(compact) < 4 or len(compact) > 48:
            continue
        if re.search(r"(www\.|biao-zhun\.cn|标准出版社)", compact, re.IGNORECASE):
            continue
        if _detect_std_identity(compact).get("std_code"):
            continue
        if re.search(r"(发布|实施|批准|主编|前言|目录|范围|总则)$", compact):
            continue
        if re.search(r"(规范|标准|规程|细则|指南|导则|技术要求|试验方法|施工)", compact):
            return compact
    return ""


def _detect_title_from_filename(filename: str) -> str:
    stem = str(filename or "")
    if "." in stem:
        stem = stem.rsplit(".", 1)[0]
    stem = re.sub(r"^\d{8,14}-[a-f0-9]{6,12}-\d+[_-]*", "", stem, flags=re.IGNORECASE)
    stem = re.sub(r"[_-]+", " ", stem).strip()
    stem = re.sub(
        r"(?i)\b(?:JTG|GB|DB\d{2}|Q\s*/\s*[A-Z0-9]+)(?:\s*(?:/|-)?\s*T)?\s*[A-Z]?\d+(?:\s*/\s*\d+)?\s*[-\s]?\d{4}\b",
        "",
        stem,
    ).strip()
    if re.search(r"(规范|标准|规程|细则|指南|导则|技术要求|试验方法|施工)", stem):
        return stem
    return ""


def _build_prefill_from_file(filename: str, preview_text: str) -> Dict[str, Any]:
    detect_from_pdf = _detect_std_identity(preview_text)
    detect_from_name = _detect_std_identity(filename)
    detected_std_code = _format_std_code_display(detect_from_pdf.get("std_code") or detect_from_name.get("std_code") or "")
    detected_year = detect_from_pdf.get("year") or detect_from_name.get("year") or ""
    detected_level = _infer_level_from_std_code(detected_std_code)
    source = "pdf_preview" if detect_from_pdf.get("std_code") else ("filename" if detect_from_name.get("std_code") else "none")
    detected_title = _detect_title_from_preview(preview_text) or _detect_title_from_filename(filename)

    warnings: List[str] = []
    if not detected_std_code:
        warnings.append("未从文件中识别到标准编号，请手动确认。")
    # 标题缺失不阻断流程；仅在标准号也未识别时再提示，避免无效告警干扰。
    if not detected_title and not detected_std_code:
        warnings.append("未从文件中识别到标题，请手动补充。")

    return {
        "detected": {
            "std_code": detected_std_code,
            "year": detected_year,
            "level": detected_level,
            "title": detected_title,
            "source": source,
        },
        "suggested": {
            "std_code": detected_std_code,
            "level": detected_level or "industry",
            "title": detected_title,
        },
        "warnings": warnings,
    }


def _infer_level_from_std_code(std_code: str) -> str:
    upper = str(std_code or "").upper().replace("_", "-")
    if upper.startswith("GB"):
        return "national"
    if upper.startswith("DB"):
        return "local"
    if upper.startswith("Q-") or upper.startswith("Q/"):
        return "enterprise"
    if upper.startswith("JTG") or upper.startswith("JTG"):
        return "industry"
    return ""



def _infer_spec_type(std_code: str, title: str) -> str:
    code_norm = re.sub(r"[^A-Za-z0-9]", "", str(std_code or "")).upper()
    title_text = str(title or "")
    if code_norm == "JTGT36502020" or "施工技术规范" in title_text:
        return "施工技术规范"
    return "工程规范"


def _resolve_ingest_spec_identity(
    original_filename: str,
    file_bytes: bytes,
    provided_std_code: str,
    provided_level: str,
    provided_title: str,
) -> Dict[str, Any]:
    preview_text = _extract_pdf_preview_text(file_bytes, max_pages=6)
    prefill = _build_prefill_from_file(filename=original_filename, preview_text=preview_text)
    detected = prefill.get("detected", {}) if isinstance(prefill.get("detected"), dict) else {}
    suggested = prefill.get("suggested", {}) if isinstance(prefill.get("suggested"), dict) else {}

    cover_std_code = str(detected.get("std_code", "")).strip()
    filename_std_code = str(_detect_std_identity(original_filename).get("std_code", "")).strip()
    provided_std = str(provided_std_code or "").strip()
    resolved_std_code = _format_std_code_display(cover_std_code or filename_std_code or provided_std)
    if not resolved_std_code:
        resolved_std_code = "UNKNOWN-STD"

    cover_title = str(detected.get("title", "")).strip()
    filename_title = str(_detect_title_from_filename(original_filename)).strip()
    provided_title_text = str(provided_title or "").strip()
    resolved_title = cover_title or filename_title or provided_title_text

    detected_level = str(detected.get("level", "")).strip() or str(suggested.get("level", "")).strip()
    resolved_level = detected_level or str(provided_level or "").strip() or "industry"

    return {
        "preview_text": preview_text,
        "prefill": prefill,
        "resolved_std_code": resolved_std_code,
        "resolved_title": resolved_title,
        "resolved_level": resolved_level,
        "resolved_spec_type": _infer_spec_type(resolved_std_code, resolved_title),
    }


def _build_std_identity_check(
    provided_std_code: str,
    provided_level: str,
    filename: str,
    ingest_payload: Dict[str, Any],
) -> Dict[str, Any]:
    preview_text = ""
    report = ingest_payload.get("report", {})
    if isinstance(report, dict):
        jobs = report.get("jobs", [])
        if isinstance(jobs, list) and jobs:
            first_job = jobs[0]
            if isinstance(first_job, dict):
                job = first_job.get("job", {})
                if isinstance(job, dict):
                    preview_text = str(job.get("source_text_preview", "") or "")

    detect_from_pdf = _detect_std_identity(preview_text)
    detect_from_name = _detect_std_identity(filename)
    detected_std_code = _format_std_code_display(detect_from_pdf.get("std_code") or detect_from_name.get("std_code") or "")
    detected_year = detect_from_pdf.get("year") or detect_from_name.get("year") or ""
    detected_level = _infer_level_from_std_code(detected_std_code)
    source = "pdf_preview" if detect_from_pdf.get("std_code") else ("filename" if detect_from_name.get("std_code") else "none")

    provided_std_norm = _normalize_code(provided_std_code)
    detected_std_norm = _normalize_code(detected_std_code)
    std_code_match: Optional[bool]
    level_match: Optional[bool]
    if detected_std_norm:
        std_code_match = provided_std_norm == detected_std_norm
    else:
        std_code_match = None

    if detected_level:
        level_match = detected_level.lower() == str(provided_level or "").strip().lower()
    else:
        level_match = None

    warnings: List[str] = []
    if not detected_std_code:
        warnings.append("未能从PDF文本识别标准号，请人工确认标准编号和版本。")
    if std_code_match is False:
        warnings.append(f"标准号不一致：检测到 {detected_std_code}，但当前填写为 {provided_std_code}。")
    if level_match is False:
        warnings.append(f"规范层级疑似不一致：检测到 {detected_level}，当前填写为 {provided_level}。")

    return {
        "provided": {
            "std_code": provided_std_code,
            "level": provided_level,
        },
        "detected": {
            "std_code": detected_std_code,
            "year": detected_year,
            "level": detected_level,
            "source": source,
        },
        "matched": {
            "std_code": std_code_match,
            "level": level_match,
        },
        "warnings": warnings,
    }


def validate_normdoc_structure(normdoc: Dict[str, Any]) -> Tuple[bool, str]:
    required = {
        "schema_uri",
        "version",
        "header",
        "body",
        "gate",
        "trailer",
        "incremental_updates",
        "term_cmap",
    }
    missing = [key for key in required if key not in normdoc]
    if missing:
        return False, f"NormDoc缺少关键字段: {', '.join(missing)}"
    if not isinstance(normdoc.get("body"), dict) or not isinstance(normdoc.get("gate"), dict):
        return False, "NormDoc的body/gate结构非法。"
    return True, ""


def _build_layerpeg_from_normdoc_artifacts(
    *,
    normdoc: Dict[str, Any],
    audit: Dict[str, Any],
    job_id: str,
) -> Dict[str, Any]:
    spec_code = str(normdoc.get("spec_code") or normdoc.get("standard_code") or "").strip()
    spec_name = str(normdoc.get("spec_name") or "").strip()
    version = str(normdoc.get("version") or "").strip()
    rules = normdoc.get("rules") if isinstance(normdoc.get("rules"), list) else []
    gates = normdoc.get("gates") if isinstance(normdoc.get("gates"), list) else []
    dto_schemas = normdoc.get("dto_schemas") if isinstance(normdoc.get("dto_schemas"), list) else []
    components = normdoc.get("components") if isinstance(normdoc.get("components"), list) else []
    catalog = normdoc.get("catalog") if isinstance(normdoc.get("catalog"), list) else []
    proof_templates = normdoc.get("proof_templates") if isinstance(normdoc.get("proof_templates"), list) else []
    blockers = audit.get("blockers") if isinstance(audit.get("blockers"), list) else []
    warnings = audit.get("warnings") if isinstance(audit.get("warnings"), list) else []
    errors = audit.get("errors") if isinstance(audit.get("errors"), list) else []
    created_at = _utc_now()
    rule_total = len(rules)
    unresolved = len([r for r in rules if isinstance(r, dict) and bool(r.get("unresolved", False))])
    passed = max(0, rule_total - unresolved)
    decision = "pass" if bool(normdoc.get("publishable", False)) else "block"
    return {
        "header": {
            "usi": f"v://normdoc/{job_id}/{spec_code or 'unknown'}@{version or 'unknown'}",
            "docType": "spec",
            "version": version or "v1",
            "ownerDid": str(normdoc.get("publisher") or "").strip() or None,
            "createdAt": created_at,
            "rootRef": str(normdoc.get("normdoc_id") or "").strip() or None,
            "projectRef": job_id,
            "normRef": {
                "normRefId": str(normdoc.get("spec_id") or "").strip(),
                "norm": spec_code,
                "clause": "",
                "version": version or "",
            },
        },
        "gate": {
            "decision": decision,
            "decisionReason": str(normdoc.get("reason") or "").strip() or ("publishable" if decision == "pass" else "blocked_by_validation"),
            "policyRef": str(normdoc.get("normdoc_id") or "").strip() or None,
            "entryConditions": [
                "components_count > 0",
                "rules_count > 0",
                "gates_count > 0",
                "business_valid = true",
            ],
            "executionPath": [
                {"step": "catalog"},
                {"step": "clause_tree"},
                {"step": "classification"},
                {"step": "components"},
                {"step": "rules"},
                {"step": "gates"},
            ],
            "dependencyGraph": [],
            "evaluation": {"ruleTotal": rule_total, "passed": passed, "failed": max(0, rule_total - passed)},
        },
        "body": {
            "payloadType": str(normdoc.get("spec_type") or "spec_asset_bundle"),
            "inputDto": {"spec_code": spec_code, "spec_name": spec_name},
            "outputDto": {
                "catalog_count": len(catalog),
                "components_count": len(components),
                "dto_count": len(dto_schemas),
                "rules_count": len(rules),
                "gates_count": len(gates),
            },
            "data": {
                "catalog": catalog,
                "clause_tree_ref": normdoc.get("clause_tree_ref", {}),
                "components": components,
                "dto_schemas": dto_schemas,
                "rules": rules,
                "gates": gates,
            },
            "tables": [],
            "formulas": [],
        },
        "proof": {
            "proofHash": str(normdoc.get("bundle_hash") or "").strip() or None,
            "payloadHash": str(normdoc.get("source_pdf_hash") or "").strip() or None,
            "merkleRoot": None,
            "signatures": [],
            "anchors": [],
            "evidence": proof_templates,
        },
        "state": {
            "current": str(normdoc.get("status") or "draft").upper(),
            "stateMachine": "normref_build_lifecycle@v1",
            "pendingActions": [] if bool(normdoc.get("publishable", False)) else ["fix_blockers", "regenerate_assets"],
            "transitionRules": ["DRAFT->READY_TO_PUBLISH", "READY_TO_PUBLISH->PUBLISHED", "DRAFT->DRAFT_INVALID"],
            "history": [
                {"to": str(normdoc.get("status") or "draft").upper(), "at": created_at, "by": "system", "reason": "artifact_pipeline"},
                *[
                    {"to": "BLOCKED", "at": created_at, "by": "system", "reason": str(x)}
                    for x in [*blockers, *errors, *warnings][:10]
                ],
            ],
        },
    }


def _validate_layerpeg_publishable(layerpeg: Dict[str, Any]) -> Tuple[bool, str]:
    if not isinstance(layerpeg, dict):
        return False, "layerpeg 缺失"
    required = ["header", "gate", "body", "proof", "state"]
    if any(k not in layerpeg for k in required):
        return False, "layerpeg 五层不完整"
    gate = layerpeg.get("gate", {}) if isinstance(layerpeg.get("gate"), dict) else {}
    body = layerpeg.get("body", {}) if isinstance(layerpeg.get("body"), dict) else {}
    state = layerpeg.get("state", {}) if isinstance(layerpeg.get("state"), dict) else {}
    out = body.get("outputDto", {}) if isinstance(body.get("outputDto"), dict) else {}
    rules_count = int(out.get("rules_count", 0) or 0)
    gates_count = int(out.get("gates_count", 0) or 0)
    components_count = int(out.get("components_count", 0) or 0)
    if components_count <= 0:
        return False, "layerpeg body 无 components"
    if rules_count <= 0:
        return False, "layerpeg gate 无 rules"
    if gates_count <= 0:
        return False, "layerpeg gate 无 gates"
    if str(state.get("current", "")).strip().upper() != "READY_TO_PUBLISH":
        return False, "layerpeg state 非 READY_TO_PUBLISH"
    decision = str(gate.get("decision", "")).strip().lower()
    if decision not in {"pass", "override"}:
        return False, "layerpeg gate decision 非 pass/override"
    return True, ""


def _load_normdoc_file(path: Path) -> Dict[str, Any]:
    cache_key = str(path.resolve())
    if cache_key in _normdoc_cache:
        return _normdoc_cache[cache_key]

    normdoc = _load_json_file(path)
    ok, reason = validate_normdoc_structure(normdoc)
    if not ok:
        raise HTTPException(status_code=500, detail=f"NormDoc结构不合法: {path.name} ({reason})")

    _normdoc_cache[cache_key] = normdoc
    return normdoc


def _find_normdoc_file(form_type: str, project: Dict[str, Any]) -> Optional[Path]:
    bindings = project.get("normdoc_bindings", {})
    if isinstance(bindings, dict) and bindings.get(form_type):
        candidate = NORMDOCS_DIR / str(bindings[form_type]).replace("\\", "/")
        if candidate.exists():
            return candidate

    mapped = FORM_NORMDOC_PATHS.get(form_type)
    if mapped:
        mapped_candidate = NORMDOCS_DIR / mapped
        if mapped_candidate.exists():
            return mapped_candidate

    direct = NORMDOCS_DIR / f"{form_type}.normdoc.json"
    if direct.exists():
        return direct

    short_code = form_type.split("-")[0]
    short_candidate = NORMDOCS_DIR / f"{short_code}.normdoc.json"
    if short_candidate.exists():
        return short_candidate

    return None


def load_normdoc_for_form(project: Dict[str, Any], form_type: str) -> Dict[str, Any]:
    path = _find_normdoc_file(form_type, project)
    if not path:
        raise HTTPException(
            status_code=422,
            detail=f"表单 {form_type} 尚未完成 NormDoc 化，请先在 normdocs/library/cn/mot 配置。",
        )
    return _load_normdoc_file(path)


def resolve_normdoc_table(normdoc: Dict[str, Any], form_type: Optional[str]) -> Tuple[str, Dict[str, Any]]:
    tables_root = normdoc.get("body", {}).get("tables", {})
    candidates: List[Dict[str, Any]] = []
    for key in ("inspection_record_tables", "evaluation_tables", "summary_tables"):
        tables = tables_root.get(key, [])
        if isinstance(tables, list):
            candidates.extend([t for t in tables if isinstance(t, dict)])

    if not candidates:
        return "", {}

    if not form_type:
        table = candidates[0]
        return str(table.get("table_id", "")), table

    target = _normalize_code(form_type)
    for table in candidates:
        meta = table.get("meta", {})
        external_form_type = str(table.get("external_form_type", ""))
        aliases = table.get("aliases", [])
        if isinstance(meta, dict):
            aliases = list(aliases) + list(meta.get("aliases", []))
            if _normalize_code(str(meta.get("form_type", ""))) == target:
                return str(table.get("table_id", "")), table
        if _normalize_code(external_form_type) == target:
            return str(table.get("table_id", "")), table
        for alias in aliases:
            if _normalize_code(str(alias)) == target:
                return str(table.get("table_id", "")), table
        table_id = str(table.get("table_id", ""))
        if target and target in _normalize_code(table_id):
            return table_id, table

    table = candidates[0]
    return str(table.get("table_id", "")), table


def _build_field_value_map(table: Dict[str, Any], inputs: Dict[str, Any]) -> Dict[str, Any]:
    values: Dict[str, Any] = {}
    fields = table.get("fields", [])
    if not isinstance(fields, list):
        return values

    for field in fields:
        if not isinstance(field, dict):
            continue
        field_id = str(field.get("field_id", "")).strip()
        name = str(field.get("name", "")).strip()
        if field_id and name and name in inputs:
            values[field_id] = inputs[name]
        if field_id and name and name not in inputs:
            alt = name.replace("-", "_")
            if alt in inputs:
                values[field_id] = inputs[alt]
    return values


def _to_float(value: Any) -> Optional[float]:
    try:
        if value is None:
            return None
        return float(value)
    except (TypeError, ValueError):
        return None


def _parse_chainage_to_meter(text: str) -> Optional[float]:
    match = re.search(r"[Kk]?\s*(\d{1,4})\s*[+加]\s*(\d{1,3})", text or "")
    if not match:
        return None
    return float(int(match.group(1)) * 1000 + int(match.group(2)))


def _extract_chainages(text: str) -> List[float]:
    values: List[float] = []
    for match in re.finditer(r"[Kk]?\s*(\d{1,4})\s*[+加]\s*(\d{1,3})", text or ""):
        values.append(float(int(match.group(1)) * 1000 + int(match.group(2))))
    return values


def _is_override_effective(override_item: Dict[str, Any]) -> bool:
    effective = str(override_item.get("effective_date", "")).strip()
    if not effective:
        return True
    try:
        return datetime.strptime(effective, "%Y-%m-%d").date() <= date.today()
    except ValueError:
        return True


def _section_in_scope(section: Optional[str], applies_to: Any) -> bool:
    scope = str(applies_to or "").strip()
    if not scope:
        return True

    if scope.lower() in {"all", "*"} or scope in {"全段", "全段落", "全线"}:
        return True

    section_meter = _parse_chainage_to_meter(section or "")
    if section_meter is None:
        return False

    meters = _extract_chainages(scope)
    if not meters:
        return False
    if len(meters) == 1:
        return abs(section_meter - meters[0]) < 0.5

    low = min(meters[0], meters[1])
    high = max(meters[0], meters[1])
    return low <= section_meter <= high


def _resolve_override_value(project: Dict[str, Any], target: str, section: Optional[str]) -> Any:
    overrides = project.get("project_overrides", [])
    if not isinstance(overrides, list):
        overrides = []

    resolved_value: Any = None
    target = _normalize_override_target(target)
    for item in overrides:
        if not isinstance(item, dict):
            continue
        if not _is_override_effective(item):
            continue
        if not _section_in_scope(section, item.get("applies_to")):
            continue
        rules = item.get("rules", [])
        if not isinstance(rules, list):
            continue
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            if _normalize_override_target(rule.get("target", "")) != target:
                continue
            if "override" in rule:
                resolved_value = rule.get("override")
            else:
                leaf = target.split(".")[-1]
                if leaf in rule:
                    resolved_value = rule.get(leaf)
    hot_override = _resolve_layer2_hot_override(project, target, section)
    if hot_override is not None:
        resolved_value = hot_override
    return resolved_value


def _lookup_project_standard(
    project: Dict[str, Any],
    layer_zone: Optional[str],
    default: float = 95.0,
    section: Optional[str] = None,
) -> float:
    zones = project.get("design_params", {}).get("subgrade", {}).get("zones", {})
    zone = _normalize_layer_zone(layer_zone, fallback="", allow_raw=False)
    if isinstance(zones, dict) and zone in zones:
        standard = _to_float(zones[zone].get("standard_value"))
        if standard is not None:
            override_value = _to_float(_resolve_override_value(project, f"subgrade.{zone}.standard_value", section))
            return override_value if override_value is not None else standard
    return default


def _lookup_iri_limit(
    project: Dict[str, Any],
    layer_zone: Optional[str],
    default: float = 2.0,
    section: Optional[str] = None,
) -> float:
    flatness = project.get("design_params", {}).get("pavement", {}).get("flatness", {})
    upper = _to_float(flatness.get("upper_layer", {}).get("IRI")) if isinstance(flatness, dict) else None
    base = _to_float(flatness.get("base_course", {}).get("IRI")) if isinstance(flatness, dict) else None
    upper_override = _to_float(_resolve_override_value(project, "pavement.upper_layer.IRI", section))
    base_override = _to_float(_resolve_override_value(project, "pavement.base_course.IRI", section))
    upper = upper_override if upper_override is not None else upper
    base = base_override if base_override is not None else base

    if layer_zone in {"基层", "底基层", "base_course"}:
        return base if base is not None else (upper if upper is not None else default)
    if layer_zone in {"上面层", "中面层", "下面层", "面层", "upper_layer"}:
        return upper if upper is not None else (base if base is not None else default)
    return upper if upper is not None else (base if base is not None else default)


def _lookup_design_thickness(project: Dict[str, Any], layer_zone: Optional[str], section: Optional[str] = None) -> Optional[float]:
    structure = project.get("design_params", {}).get("pavement", {}).get("structure", [])
    if not isinstance(structure, list):
        return None
    for layer in structure:
        if not isinstance(layer, dict):
            continue
        if str(layer.get("layer", "")) == str(layer_zone or ""):
            target_1 = f"pavement.structure.{layer_zone}.thickness"
            target_2 = f"pavement.{layer_zone}.thickness"
            override_value = _to_float(_resolve_override_value(project, target_1, section))
            if override_value is None:
                override_value = _to_float(_resolve_override_value(project, target_2, section))
            return override_value if override_value is not None else _to_float(layer.get("thickness"))
    return None


def _lookup_deflection_limit(project: Dict[str, Any], default: float = 180.0, section: Optional[str] = None) -> float:
    override_value = _to_float(_resolve_override_value(project, "pavement.deflection.max", section))
    if override_value is not None:
        return override_value
    value = _to_float(
        project.get("design_params", {})
        .get("pavement", {})
        .get("deflection", {})
        .get("max")
    )
    if value is not None:
        return value
    return default


def _resolve_rule_expected_value(rule: Dict[str, Any], inputs: Dict[str, Any], project: Dict[str, Any]) -> Any:
    expr = str(rule.get("value_expr", "")).strip().lower()
    if not expr:
        return rule.get("value")

    layer_zone = _normalize_layer_zone(inputs.get("layer_zone", ""), fallback="", allow_raw=True)
    default_standard = _to_float(rule.get("default_standard"))
    section = str(inputs.get("section", "") or "")
    standard = _lookup_project_standard(project, layer_zone, default_standard or 95.0, section=section)

    if expr == "standard_minus_2":
        return standard - 2
    if expr == "standard_value":
        return standard
    if expr == "standard_plus_2":
        return standard + 2
    if expr == "iri_limit":
        default_limit = _to_float(rule.get("default_standard")) or 2.0
        return _lookup_iri_limit(project, layer_zone, default_limit, section=section)
    if expr == "deflection_limit":
        default_limit = _to_float(rule.get("default_standard")) or 180.0
        return _lookup_deflection_limit(project, default_limit, section=section)
    if expr == "design_thickness_pm_tol":
        design = _lookup_design_thickness(project, layer_zone, section=section)
        if design is None:
            design = _to_float(rule.get("default_design"))
        tol = _to_float(rule.get("tolerance")) or 0.0
        if design is None:
            return rule.get("value")
        return [design - tol, design + tol]
    return rule.get("value")


def _normalize_condition_value(key: str, value: Any) -> Any:
    if key == "layer_zone":
        normalized = _normalize_layer_zone(value, fallback="", allow_raw=False)
        return normalized or str(value or "").strip()
    return value


def _match_condition(key: str, value: Any, condition: Any) -> bool:
    left = _normalize_condition_value(key, value)
    if isinstance(condition, list):
        right = [_normalize_condition_value(key, item) for item in condition]
        return left in right
    right = _normalize_condition_value(key, condition)
    return left == right


def _select_test_method(test_method: Dict[str, Any], inputs: Dict[str, Any]) -> Tuple[str, str]:
    primary = str(test_method.get("ref", "")).strip()
    rules = test_method.get("selection_rules", [])
    if isinstance(rules, list):
        for rule in rules:
            if not isinstance(rule, dict):
                continue
            when = rule.get("when", {})
            use = str(rule.get("use", "")).strip()
            if not use or not isinstance(when, dict):
                continue
            matched = True
            for key, condition in when.items():
                if not _match_condition(key, inputs.get(key), condition):
                    matched = False
                    break
            if matched:
                return use, f"matched selection_rules by {when}"
    if primary:
        return primary, "fallback to primary ref"
    alternatives = test_method.get("alternatives", [])
    if isinstance(alternatives, list) and alternatives:
        return str(alternatives[0]), "fallback to first alternative"
    return "", "no available test method"


def resolve_cross_spec_links(normdoc: Dict[str, Any], api_params: Dict[str, Any], project: Dict[str, Any]) -> Dict[str, Any]:
    body = normdoc.get("body", {})
    refs = body.get("cross_spec_refs", [])
    if isinstance(refs, dict):
        refs = list(refs.values())
    if not isinstance(refs, list):
        refs = []

    form_type = str(api_params.get("form_type", ""))
    inputs = api_params.get("inputs", {})
    if not isinstance(inputs, dict):
        inputs = {}
    inputs = dict(inputs)
    if api_params.get("section") and "section" not in inputs:
        inputs["section"] = api_params.get("section")

    linked_items: List[Dict[str, Any]] = []
    for item in refs:
        if not isinstance(item, dict):
            continue
        applies = item.get("applies_to_form_types", [])
        if isinstance(applies, list) and applies and form_type not in applies:
            continue

        test_method = item.get("test_method", {}) if isinstance(item.get("test_method"), dict) else {}
        selected_method, reason = _select_test_method(test_method, inputs)
        linked_items.append(
            {
                "clause_id": item.get("clause_id", ""),
                "id": item.get("id", ""),
                "type": item.get("type", ""),
                "test_method": {
                    "ref": test_method.get("ref", ""),
                    "alternatives": test_method.get("alternatives", []),
                    "selected": selected_method,
                    "selection_reason": reason,
                },
                "calculation": item.get("calculation", {}),
                "construction_control": item.get("construction_control", {}),
            }
        )

    return {"form_type": form_type, "items": linked_items}


def evaluate_cross_spec_consistency(
    links: Dict[str, Any],
    api_params: Dict[str, Any],
    project: Dict[str, Any],
) -> List[Dict[str, Any]]:
    issues: List[Dict[str, Any]] = []
    inputs = api_params.get("inputs", {})
    if not isinstance(inputs, dict):
        return issues
    inputs = dict(inputs)
    if api_params.get("section") and "section" not in inputs:
        inputs["section"] = api_params.get("section")

    layer_zone = str(inputs.get("layer_zone", "") or "")
    section = str(inputs.get("section", "") or "")
    single_value = _to_float(inputs.get("compaction_degree"))
    iri_value = _to_float(inputs.get("iri"))
    thickness_value = _to_float(inputs.get("thickness"))
    deflection_value = _to_float(inputs.get("deflection"))
    standard = _lookup_project_standard(project, layer_zone, 95.0, section=section)

    for item in links.get("items", []):
        if not isinstance(item, dict):
            continue
        calc = item.get("calculation", {})
        if not isinstance(calc, dict):
            continue
        pass_criteria = str(calc.get("pass_criteria", ""))
        if "single >= standard - 2" in pass_criteria and single_value is not None:
            expected_min = standard - 2
            if single_value < expected_min:
                issues.append(
                    {
                        "rule_id": "cross_spec.single_min",
                        "field_id": "compaction_degree",
                        "message": f"单点压实度低于跨规范最低阈值: {single_value} < {expected_min}",
                        "severity": "blocking",
                        "actual": single_value,
                        "expected": expected_min,
                        "source": "cross_spec",
                    }
                )
        if ("iri <= standard" in pass_criteria or "iri <= iri_limit" in pass_criteria) and iri_value is not None:
            iri_limit = _lookup_iri_limit(
                project,
                layer_zone,
                _to_float(calc.get("default_limit")) or 2.0,
                section=section,
            )
            if iri_value > iri_limit:
                issues.append(
                    {
                        "rule_id": "cross_spec.iri_limit",
                        "field_id": "iri",
                        "message": f"IRI超过跨规范阈值: {iri_value} > {iri_limit}",
                        "severity": "blocking",
                        "actual": iri_value,
                        "expected": iri_limit,
                        "source": "cross_spec",
                    }
                )
        if "abs(thickness - design) <= tolerance" in pass_criteria and thickness_value is not None:
            design = _lookup_design_thickness(project, layer_zone, section=section)
            tolerance = _to_float(calc.get("tolerance")) or 0.0
            if design is not None and abs(thickness_value - design) > tolerance:
                issues.append(
                    {
                        "rule_id": "cross_spec.thickness_tolerance",
                        "field_id": "thickness",
                        "message": f"厚度偏差超限: |{thickness_value}-{design}| > {tolerance}",
                        "severity": "blocking",
                        "actual": thickness_value,
                        "expected": [design - tolerance, design + tolerance],
                        "source": "cross_spec",
                    }
                )
        if "deflection <= limit" in pass_criteria and deflection_value is not None:
            limit = _to_float(calc.get("limit")) or _lookup_deflection_limit(project, 180.0, section=section)
            if deflection_value > limit:
                issues.append(
                    {
                        "rule_id": "cross_spec.deflection_limit",
                        "field_id": "deflection",
                        "message": f"弯沉超过跨规范限值: {deflection_value} > {limit}",
                        "severity": "blocking",
                        "actual": deflection_value,
                        "expected": limit,
                        "source": "cross_spec",
                    }
                )

    return issues


def _evaluate_operator(operator: str, actual: Any, expected: Any) -> bool:
    if actual is None:
        return False
    op = str(operator).lower()
    if op == "gt":
        return actual > expected
    if op == "gte":
        return actual >= expected
    if op == "lt":
        return actual < expected
    if op == "lte":
        return actual <= expected
    if op == "eq":
        return actual == expected
    if op == "neq":
        return actual != expected
    if op == "in":
        return isinstance(expected, list) and actual in expected
    if op == "range":
        return isinstance(expected, list) and len(expected) == 2 and expected[0] <= actual <= expected[1]
    return False


def evaluate_normdoc_gate(
    api_params: Dict[str, Any],
    normdoc: Dict[str, Any],
    project: Optional[Dict[str, Any]] = None,
    cross_spec_links: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    project = project or {}
    form_type = str(api_params.get("form_type", ""))
    table_id, table = resolve_normdoc_table(normdoc, form_type)
    if not table_id:
        return {"status": "WARNING", "source": "local_normdoc_gate", "results": [{"message": "未找到NormDoc表格定义"}]}

    inputs = api_params.get("inputs", {})
    if not isinstance(inputs, dict):
        inputs = {}

    field_values = _build_field_value_map(table, inputs)
    tree = normdoc.get("gate", {}).get("table_rule_tree", [])
    table_rules = []
    for node in tree if isinstance(tree, list) else []:
        if not isinstance(node, dict):
            continue
        if str(node.get("table_id", "")) == table_id:
            rules = node.get("field_rules", [])
            if isinstance(rules, list):
                table_rules.extend([r for r in rules if isinstance(r, dict)])

    if not table_rules:
        return {
            "status": "WARNING",
            "source": "local_normdoc_gate",
            "table_id": table_id,
            "results": [{"message": "NormDoc中未找到可执行field_rules"}],
        }

    failures: List[Dict[str, Any]] = []
    has_warning = False
    for rule in table_rules:
        field_id = str(rule.get("field_id", ""))
        field_name = field_id.split(".")[-1] if field_id else ""
        actual = field_values.get(field_id)
        if actual is None and field_name:
            actual = inputs.get(field_name)
        expected = _resolve_rule_expected_value(rule, inputs, project)
        if field_name == "layer_zone":
            actual = _normalize_layer_zone(actual, fallback="", allow_raw=False) or str(actual or "")
            if isinstance(expected, list):
                expected = [
                    _normalize_layer_zone(item, fallback="", allow_raw=False) or str(item or "")
                    for item in expected
                ]
            else:
                expected = _normalize_layer_zone(expected, fallback="", allow_raw=False) or str(expected or "")
        operator = str(rule.get("operator", ""))
        passed = _evaluate_operator(operator, actual, expected)

        if passed:
            continue

        severity = str(rule.get("severity", "mandatory")).lower()
        if severity == "warning":
            has_warning = True
        failures.append(
            {
                "rule_id": rule.get("rule_id", ""),
                "field_id": field_id,
                "message": rule.get("error_message") or f"{field_id} 未满足 {operator} {expected}",
                "severity": severity,
                "actual": actual,
                "expected": expected,
                "source": "normdoc_gate",
            }
        )

    cross_spec_failures: List[Dict[str, Any]] = []
    if cross_spec_links:
        cross_spec_failures = evaluate_cross_spec_consistency(cross_spec_links, api_params, project)
        failures.extend(cross_spec_failures)

    if not failures:
        status = "PASS"
    elif any(str(item.get("severity", "")).lower() != "warning" for item in failures):
        status = "BLOCKED"
    elif has_warning:
        status = "WARNING"
    else:
        status = "BLOCKED"

    return {
        "status": status,
        "source": "local_normdoc_gate",
        "table_id": table_id,
        "results": failures,
        "cross_spec_links": cross_spec_links or {"items": []},
    }


def _find_project_file(project_query: str) -> Optional[Path]:
    normalized_query = _normalize_code(project_query)

    for path in PROJECTS_DIR.rglob("*.json"):
        try:
            data = _load_json_file(path)
        except Exception:
            continue
        identifiers = {
            str(data.get("project_id", "")).strip(),
            str(data.get("id", "")).strip(),
            str(data.get("project_name", "")).strip(),
            str(data.get("name", "")).strip(),
            path.stem,
            str(path.parent.name),
        }
        identifiers.discard("")
        if project_query in identifiers:
            return path
        if normalized_query and any(_normalize_code(identifier) == normalized_query for identifier in identifiers):
            return path

    return None


def load_project_config(project_id: str) -> Dict[str, Any]:
    if project_id in _project_cache:
        return _project_cache[project_id]

    file_path = _find_project_file(project_id)
    if not file_path:
        raise HTTPException(
            status_code=404,
            detail=f"未找到项目配置：{project_id}。请先在 projects/<project>/project.profile.json 下创建。",
        )

    data = _normalize_project(_load_json_file(file_path), requested_id=project_id)

    # Cache by requested id and canonical id to reduce repeated file scans.
    _project_cache[project_id] = data
    canonical_id = str(data.get("project_id", "")).strip()
    if canonical_id:
        _project_cache[canonical_id] = data

    return data


def validate_subset_baseline(project: Dict[str, Any]) -> Tuple[bool, str]:
    subset = project.get("normative_subset", {})
    if not isinstance(subset, dict):
        return False, "项目缺少 normative_subset 配置。"

    status = str(subset.get("status", "")).strip().lower()
    if status not in {"confirmed", "completed"}:
        return False, "subset baseline 未完成确认：normative_subset.status 需要是 confirmed/completed。"

    standards = subset.get("standards", [])
    if not isinstance(standards, list):
        return False, "normative_subset.standards 结构非法。"
    codes = {
        str(item.get("code", "")).strip()
        for item in standards
        if isinstance(item, dict)
    }
    missing_codes = sorted(code for code in SUBSET_REQUIRED_STANDARDS if code not in codes)
    if missing_codes:
        return False, f"subset baseline 缺少标准子集：{', '.join(missing_codes)}"

    form_map = subset.get("indicator_form_map", {})
    if not isinstance(form_map, dict):
        return False, "normative_subset.indicator_form_map 结构非法。"
    for indicator, form_type in SUBSET_REQUIRED_INDICATORS.items():
        if str(form_map.get(indicator, "")).strip() != form_type:
            return False, f"subset baseline 指标映射缺失或不一致：{indicator} -> {form_type}"

    bindings = project.get("normdoc_bindings", {})
    if not isinstance(bindings, dict):
        return False, "项目缺少 normdoc_bindings。"
    missing_bindings = [f for f in SUBSET_REQUIRED_INDICATORS.values() if f not in bindings]
    if missing_bindings:
        return False, f"subset baseline 缺少 NormDoc 绑定：{', '.join(missing_bindings)}"

    return True, ""


def validate_day1_2_subset(project: Dict[str, Any]) -> Tuple[bool, str]:
    """Legacy wrapper. Prefer validate_subset_baseline."""
    return validate_subset_baseline(project)


def build_subset_baseline_report(project: Dict[str, Any]) -> Dict[str, Any]:
    ok, reason = validate_subset_baseline(project)
    subset = project.get("normative_subset", {}) if isinstance(project.get("normative_subset", {}), dict) else {}
    return {
        "project_id": str(project.get("project_id", "")),
        "project_name": str(project.get("project_name", "")),
        "ready": ok,
        "reason": reason,
        "subset_ready": ok,
        "subset_reason": reason,
        "normative_subset": subset,
        "required_standards": sorted(SUBSET_REQUIRED_STANDARDS),
        "required_indicator_map": SUBSET_REQUIRED_INDICATORS,
    }


def build_day1_2_report(project: Dict[str, Any]) -> Dict[str, Any]:
    """Legacy wrapper. Prefer build_subset_baseline_report."""
    return build_subset_baseline_report(project)


def validate_digital_standards(project: Dict[str, Any]) -> Tuple[bool, str, List[Dict[str, Any]]]:
    digital = project.get("digital_standards", {})
    if not isinstance(digital, dict):
        return False, "项目缺少 digital_standards 配置。", []

    status = str(digital.get("status", "")).strip().lower()
    if status not in {"completed", "confirmed"}:
        return False, "digital_standards.status 需为 completed/confirmed。", []

    standards = digital.get("standards", [])
    if not isinstance(standards, list):
        return False, "digital_standards.standards 结构非法。", []

    declared_map: Dict[str, str] = {}
    for item in standards:
        if not isinstance(item, dict):
            continue
        code = str(item.get("code", "")).strip()
        file_name = str(item.get("file", "")).strip()
        if code and file_name:
            declared_map[code] = file_name

    details: List[Dict[str, Any]] = []
    missing_codes: List[str] = []
    for code in sorted(SUBSET_REQUIRED_STANDARDS):
        file_name = declared_map.get(code) or DAY57_REQUIRED_STANDARD_FILES.get(code, "")
        path = STANDARDS_DIR / file_name if file_name else STANDARDS_DIR / "__missing__"
        ok = path.exists()
        detail: Dict[str, Any] = {
            "code": code,
            "file": file_name,
            "exists": ok,
            "path": str(path),
        }
        if not ok:
            missing_codes.append(code)
            detail["reason"] = "标准数字化文件不存在。"
        else:
            try:
                data = _load_json_file(path)
                standard_code = str(data.get("standard_code", "")).strip()
                if standard_code and standard_code != code:
                    detail["exists"] = False
                    detail["reason"] = f"standard_code 不匹配: {standard_code}"
                    missing_codes.append(code)
                else:
                    detail["schema_uri"] = data.get("schema_uri", "")
            except Exception as exc:
                detail["exists"] = False
                detail["reason"] = f"文件不可解析: {exc}"
                missing_codes.append(code)
        details.append(detail)

    if missing_codes:
        return False, f"3份标准数字化未完成: {', '.join(sorted(set(missing_codes)))}", details
    return True, "", details


def run_ops_smoke_checks(project: Dict[str, Any]) -> List[Dict[str, Any]]:
    ready, reason = validate_subset_baseline(project)
    checks: List[Dict[str, Any]] = [{"name": "subset_baseline", "ok": ready, "detail": reason or "ok"}]

    required_forms = ["T0921-2019", "T0931-2019", "T0912-2019", "T0951-2008"]
    for form in required_forms:
        try:
            doc = load_normdoc_for_form(project, form)
            ok, msg = validate_normdoc_structure(doc)
            checks.append({"name": f"normdoc_{form}", "ok": ok, "detail": msg or "ok"})
        except Exception as exc:
            checks.append({"name": f"normdoc_{form}", "ok": False, "detail": str(exc)})
    return checks


def _safe_upload_name(filename: str) -> str:
    base = Path(filename or "upload.pdf").name
    base = re.sub(r"[^A-Za-z0-9._-]", "_", base).strip("._")
    if not base:
        base = "upload.pdf"
    return base


def _read_json_report(path: Path) -> Dict[str, Any]:
    return _load_json_file(path)


def _utc_now() -> str:
    return datetime.utcnow().isoformat() + "Z"


def _sha256_text(text: str) -> str:
    return "sha256:" + hashlib.sha256(text.encode("utf-8")).hexdigest()


def _stable_json_hash(payload: Dict[str, Any]) -> str:
    raw = json.dumps(payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    return _sha256_text(raw)


def _normalize_field_key(raw: Any, fallback: str = "measured_value") -> str:
    key = re.sub(r"[^A-Za-z0-9_]+", "_", str(raw or "").strip().lower()).strip("_")
    return key or fallback


def _parse_scalar_or_text(raw: Any) -> Any:
    text = str(raw or "").strip()
    if not text:
        return None
    if re.fullmatch(r"-?\d+(?:\.\d+)?", text):
        if "." in text:
            return float(text)
        return int(text)
    return text


def _parse_threshold_value(operator: str, raw_value: Any) -> Any:
    text = str(raw_value or "").strip()
    if not text:
        return None
    op = str(operator or "").lower()
    if op == "range" and ".." in text:
        left, right = text.split("..", 1)
        left_value = _parse_scalar_or_text(left)
        right_value = _parse_scalar_or_text(right)
        return [left_value, right_value]
    return _parse_scalar_or_text(text)


_CLAUSE_CN_PATTERN = re.compile(r"第\s*(\d+\.\d+\.\d+(?:\.\d+){0,2})\s*条")
_CLAUSE_NO_PATTERN = re.compile(r"(?<!\d)(\d+\.\d+\.\d+(?:\.\d+){0,2})(?!\d)")
_NORMREF_SEG_PATTERN = re.compile(r"^[a-z0-9][a-z0-9._-]*$", re.IGNORECASE)


def _extract_clause_no_from_text(raw: Any) -> str:
    text = str(raw or "").strip()
    if not text:
        return ""
    cn_match = _CLAUSE_CN_PATTERN.search(text)
    if cn_match:
        return str(cn_match.group(1) or "").strip()
    direct_match = _CLAUSE_NO_PATTERN.search(text)
    if direct_match:
        return str(direct_match.group(1) or "").strip()
    return ""


def _infer_candidate_clause_no(candidate: Dict[str, Any]) -> str:
    for key in ("clause_no", "clause_id", "norm_ref", "source_line", "rule_id"):
        clause_no = _extract_clause_no_from_text(candidate.get(key))
        if clause_no:
            return clause_no
    return ""


def _parse_normref_uri(normref: str) -> Dict[str, Any]:
    text = str(normref or "").strip()
    prefix = "v://std/"
    if not text.lower().startswith(prefix):
        raise HTTPException(
            status_code=400,
            detail="normRef 非法。格式必须为 v://std/{spec_id}/{chapter}/{section}/{table}/{field}",
        )
    path = text[len(prefix):].strip("/")
    parts = [p.strip().lower() for p in path.split("/") if p.strip()]
    # must be: spec + (chapter/section/table[/row[/column]]) + field
    # allowed total segments after prefix:
    # - 5: spec/chapter/section/table/field
    # - 6: spec/chapter/section/table/row/field
    # - 7: spec/chapter/section/table/row/column/field
    if len(parts) < 5 or len(parts) > 7:
        raise HTTPException(
            status_code=400,
            detail="normRef 非法。必须为 v://std/{spec_id}/{chapter}/{section}/{table}/{field}，可选 /{row}/{column}。",
        )
    for seg in parts:
        if not _NORMREF_SEG_PATTERN.match(seg):
            raise HTTPException(status_code=400, detail=f"normRef 段非法：{seg}")
    spec = parts[0]
    address_segments = parts[1:-1]
    field = parts[-1]
    level_keys = ["chapter", "section", "table", "row", "column"]
    levels: Dict[str, str] = {k: "" for k in level_keys}
    for idx, seg in enumerate(address_segments[: len(level_keys)]):
        levels[level_keys[idx]] = seg
    # Compatibility aliases for existing callers.
    clause_or_table = (
        levels.get("table")
        or levels.get("section")
        or levels.get("chapter")
        or (address_segments[-1] if address_segments else "")
    )
    return {
        "normRef": text,
        "spec": spec,
        "field": field,
        "clause_or_table": clause_or_table,
        "path_segments": address_segments,
        **levels,
    }


def _canonical_std_code_from_normref_spec(spec: str) -> str:
    token = str(spec or "").strip().lower()
    if not token:
        return ""
    # jtg-f80-1-2017 -> JTG-F80-1-2017
    return re.sub(r"[^A-Za-z0-9]+", "-", token).strip("-").upper()


def _derive_normref_from_package(package: Dict[str, Any]) -> str:
    std_code = _format_std_code_display(str(package.get("std_code", "")).strip())
    spec = re.sub(r"[^a-z0-9]+", "-", std_code.lower()).strip("-") or "unknown-spec"
    clause_tree = (package.get("clause_tree") or {}).get("nodes") if isinstance(package.get("clause_tree"), dict) else []
    clause_or_table = "unknown-clause"
    if isinstance(clause_tree, list):
        for node in clause_tree:
            if not isinstance(node, dict):
                continue
            cid = str(node.get("clause_id", "")).strip().lower()
            if cid:
                clause_or_table = re.sub(r"[^a-z0-9]+", "-", cid).strip("-") or clause_or_table
                break
    field = "measured_value"
    candidates = package.get("candidates", [])
    if isinstance(candidates, list):
        for cand in candidates:
            if not isinstance(cand, dict):
                continue
            key = str(cand.get("field_key", "")).strip().lower()
            if key:
                field = re.sub(r"[^a-z0-9._-]+", "_", key).strip("_") or field
                break
    return f"v://std/{spec}/{clause_or_table}/{field}"


def _normalize_normref_seg(text: Any, fallback: str) -> str:
    token = re.sub(r"[^a-z0-9._-]+", "-", str(text or "").strip().lower()).strip("-")
    return token or fallback


def _normalize_rule_operator(raw: Any) -> str:
    op = str(raw or "").strip().lower()
    alias = {
        "range": "between",
        "between": "between",
        "gte": ">=",
        "ge": ">=",
        "gt": ">",
        "lte": "<=",
        "le": "<=",
        "lt": "<",
        "eq": "=",
        "==": "=",
        "exists": "exists",
        "lookup": "lookup",
        "formula": "formula",
    }
    return alias.get(op, op or "exists")


def _to_rule_min_max(
    operator: str,
    condition: Dict[str, Any],
    threshold: Any,
) -> Tuple[Any, Any]:
    min_v: Any = None
    max_v: Any = None
    op = _normalize_rule_operator(operator)
    if isinstance(threshold, dict):
        if "min" in threshold:
            min_v = threshold.get("min")
        if "max" in threshold:
            max_v = threshold.get("max")
    elif isinstance(threshold, list) and len(threshold) >= 2:
        min_v = threshold[0]
        max_v = threshold[1]
    elif threshold is not None:
        if op in {">=", ">"}:
            min_v = threshold
        elif op in {"<=", "<"}:
            max_v = threshold
        elif op == "=":
            min_v = threshold
            max_v = threshold
    if min_v is None and "min" in condition:
        min_v = condition.get("min")
    if max_v is None and "max" in condition:
        max_v = condition.get("max")
    if min_v is None and max_v is None and "value" in condition:
        val = condition.get("value")
        if op == "between" and isinstance(val, list) and len(val) >= 2:
            min_v, max_v = val[0], val[1]
        elif op in {">=", ">", "="}:
            min_v = val
            if op == "=":
                max_v = val
        elif op in {"<=", "<"}:
            max_v = val
    return min_v, max_v


def _build_norm_ref_index(
    *,
    normref_meta: Dict[str, Any],
    std_code: str,
    clause_tree_nodes: List[Dict[str, Any]],
    catalog_rows: List[Dict[str, Any]],
    clause_classifications: List[Dict[str, Any]],
    components: List[Dict[str, Any]],
    rules: List[Dict[str, Any]],
) -> Dict[str, Any]:
    standard_code = _normalize_normref_seg(
        str(normref_meta.get("spec") or normref_meta.get("spec_id") or normref_meta.get("standard_id") or std_code),
        "unknown-spec",
    )
    version_raw = str(normref_meta.get("version") or normref_meta.get("standard_version") or "").strip()
    if not version_raw:
        year_match = re.search(r"(19|20)\d{2}", str(std_code))
        version_raw = year_match.group(0) if year_match else "v1"
    version = _normalize_normref_seg(version_raw, "v1")

    entries: List[Dict[str, Any]] = []
    uniq: Dict[str, Dict[str, Any]] = {}
    def _is_valid_node_no(ntype: str, no: str) -> bool:
        text = str(no or "").strip()
        if ntype == "chapter":
            return bool(re.fullmatch(r"\d+", text))
        if ntype == "section":
            return bool(re.fullmatch(r"\d+\.\d+", text))
        if ntype == "clause":
            return bool(re.fullmatch(r"\d+\.\d+\.\d+", text))
        if ntype == "table":
            return bool(re.fullmatch(r"\d+(?:\.\d+)*(?:-\d+)?", text))
        return False
    for row in catalog_rows:
        if not isinstance(row, dict):
            continue
        node_type = str(row.get("type", "")).strip().lower()
        if node_type not in {"chapter", "section", "clause", "table"}:
            continue
        node_no = str(row.get("id", "")).strip()
        if not node_no:
            continue
        if not _is_valid_node_no(node_type, node_no):
            continue
        vuri = f"v://std/{standard_code}/{version}/{node_type}/{node_no}"
        item = {
            "normRef": vuri,
            "vuri": vuri,
            "node": {
                "id": node_no,
                "type": node_type,
                "title": str(row.get("title") or row.get("name") or node_no).strip() or node_no,
                "parent_id": str(row.get("parent_id", "")).strip() or None,
                "page": int(row.get("page", row.get("source_page", 0)) or 0),
                "source_text": str(row.get("source_text", "")).strip(),
            },
            "segments": {
                "standard_code": standard_code,
                "version": version,
                "type": node_type,
                "no": node_no,
            },
        }
        if vuri not in uniq:
            uniq[vuri] = item
            entries.append(item)
    return {
        "valid": True,
        "schema_version": "norm_ref_index.v1",
        "address_format": "v://std/{standard_code}/{version}/{chapter|section|clause|table}/{no}",
        "supports": ["chapter", "section", "clause", "table"],
        "standard_code": standard_code,
        "version": version,
        "count": len(entries),
        "entries": entries,
        "note": "Catalog nodes are the canonical addressable normRef entries.",
    }


def _fetch_clause_search_results(
    *,
    clause_no: str,
    standard_code: str,
    version: str,
    cache: Dict[str, List[Dict[str, Any]]],
) -> List[Dict[str, Any]]:
    normalized_clause_no = str(clause_no or "").strip()
    if not normalized_clause_no:
        return []
    key = f"{standard_code}@@{version}@@{normalized_clause_no}"
    if key in cache:
        return cache[key]

    url = f"{CLAUSE_STORE_API_BASE}/api/clauses/search"
    try:
        response = requests.get(
            url,
            params={
                "q": normalized_clause_no,
                "standard_code": standard_code or None,
                "version": version or None,
                "limit": 5,
            },
            timeout=4,
        )
        response.raise_for_status()
        payload = response.json()
    except Exception:
        cache[key] = []
        return []

    rows = payload.get("results", []) if isinstance(payload, dict) else []
    results = [item for item in rows if isinstance(item, dict)]
    cache[key] = results
    return results


def _resolve_clause_search_hit(clause_no: str, results: List[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
    normalized = str(clause_no or "").strip()
    if not normalized:
        return None
    for item in results:
        if str(item.get("clause_no", "")).strip() == normalized:
            return item
        if str(item.get("clause_id", "")).strip() == normalized:
            return item
    return results[0] if results else None


def _proxy_clause_search(
    *,
    query_text: str,
    standard_code: str,
    version: str,
    limit: int,
) -> Dict[str, Any]:
    q = str(query_text or "").strip()
    if not q:
        raise HTTPException(status_code=400, detail="q is required")

    try:
        response = requests.get(
            f"{CLAUSE_STORE_API_BASE}/api/clauses/search",
            params={
                "q": q,
                "standard_code": standard_code or None,
                "version": version or None,
                "limit": max(1, min(int(limit or 20), 100)),
            },
            timeout=6,
        )
        response.raise_for_status()
        payload = response.json()
    except Exception as exc:
        raise HTTPException(status_code=502, detail=f"CLAUSE_STORE_UNAVAILABLE: {exc}") from exc

    rows = payload.get("results", []) if isinstance(payload, dict) else []
    normalized_results: List[Dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        clause_no = str(row.get("clause_no", "")).strip()
        clause_id = str(row.get("clause_id") or clause_no).strip()
        normalized_results.append(
            {
                "clause_id": clause_id,
                "clause_no": clause_no,
                "title": str(row.get("title", "")).strip(),
                "content": str(row.get("content", "")).strip(),
                "standard_code": str(row.get("standard_code", "")).strip(),
                "version": str(row.get("version", "")).strip(),
                "score": row.get("score", 0),
            }
        )

    return {"query": q, "results": normalized_results}


def _refresh_review_candidate_clause_bindings(
    package: Dict[str, Any],
    *,
    target_statuses: Optional[set[str]] = None,
) -> Dict[str, int]:
    candidates = [item for item in package.get("candidates", []) if isinstance(item, dict)]
    standard_code = str(package.get("std_code", "")).strip()
    version = str(package.get("standard_version", "")).strip() or "v1"
    cache: Dict[str, List[Dict[str, Any]]] = {}

    summary = {"total": 0, "bound": 0, "pending": 0, "review_required": 0}
    for candidate in candidates:
        status = str(candidate.get("status", "pending")).strip().lower() or "pending"
        clause_no = _infer_candidate_clause_no(candidate)
        if clause_no:
            candidate["clause_no"] = clause_no
        if target_statuses and status not in target_statuses:
            continue
        summary["total"] += 1
        if not clause_no:
            candidate["binding_status"] = "pending"
            candidate["review_required"] = True
            candidate["clause_id"] = ""
            candidate["clause_title"] = ""
            candidate["clause_content"] = ""
            candidate["clause_preview"] = ""
            summary["pending"] += 1
            summary["review_required"] += 1
            continue

        results = _fetch_clause_search_results(
            clause_no=clause_no,
            standard_code=standard_code,
            version=version,
            cache=cache,
        )
        hit = _resolve_clause_search_hit(clause_no, results)
        if not hit:
            candidate["binding_status"] = "pending"
            candidate["review_required"] = True
            candidate["clause_id"] = ""
            candidate["clause_title"] = ""
            candidate["clause_content"] = ""
            candidate["clause_preview"] = ""
            summary["pending"] += 1
            summary["review_required"] += 1
            continue

        content = str(hit.get("content", "")).strip()
        candidate["binding_status"] = "bound"
        candidate["review_required"] = False
        candidate["clause_id"] = str(hit.get("clause_id") or hit.get("clause_no") or clause_no).strip()
        candidate["clause_no"] = str(hit.get("clause_no") or clause_no).strip()
        candidate["clause_title"] = str(hit.get("title", "")).strip()
        candidate["clause_content"] = content
        candidate["clause_preview"] = (content[:140] + "...") if len(content) > 140 else content
        candidate["clause_score"] = hit.get("score")
        summary["bound"] += 1

    return summary


def _layer2_store_path(name: str) -> Path:
    safe = re.sub(r"[^A-Za-z0-9._-]+", "_", str(name or "").strip().lower())
    if not safe:
        safe = "unknown"
    LAYER2_DIR.mkdir(parents=True, exist_ok=True)
    return LAYER2_DIR / f"{safe}.json"


def _load_layer2_store(name: str) -> List[Dict[str, Any]]:
    path = _layer2_store_path(name)
    if not path.exists():
        return []
    try:
        payload = _load_json_file(path)
    except Exception:
        return []
    if not isinstance(payload, list):
        return []
    return [item for item in payload if isinstance(item, dict)]


def _save_layer2_store(name: str, records: List[Dict[str, Any]]) -> None:
    path = _layer2_store_path(name)
    path.write_text(json.dumps(records, ensure_ascii=False, indent=2), encoding="utf-8")


def _load_specir_store_doc() -> Dict[str, Any]:
    if not SPECIR_STORE_PATH.exists():
        return {"schema_version": "specir_store.v1", "updated_at": "", "records": []}
    try:
        doc = json.loads(SPECIR_STORE_PATH.read_text(encoding="utf-8-sig"))
    except Exception:
        return {"schema_version": "specir_store.v1", "updated_at": "", "records": []}
    if not isinstance(doc, dict):
        return {"schema_version": "specir_store.v1", "updated_at": "", "records": []}
    records = doc.get("records", [])
    if not isinstance(records, list):
        records = []
    return {
        "schema_version": str(doc.get("schema_version") or "specir_store.v1").strip() or "specir_store.v1",
        "updated_at": str(doc.get("updated_at") or "").strip(),
        "records": [x for x in records if isinstance(x, dict)],
    }


def _save_specir_store_doc(doc: Dict[str, Any]) -> None:
    SPECIR_STORE_PATH.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "schema_version": str(doc.get("schema_version") or "specir_store.v1").strip() or "specir_store.v1",
        "updated_at": _utc_now(),
        "records": [x for x in (doc.get("records", []) if isinstance(doc.get("records"), list) else []) if isinstance(x, dict)],
    }
    SPECIR_STORE_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _normalize_specir_store_row(row: Dict[str, Any], *, job_id: str, std_code: str) -> Dict[str, Any]:
    now = _utc_now()
    specir_id = str(row.get("specir_id") or row.get("component_id") or "").strip()
    created_at = str(row.get("created_at") or "").strip() or now
    updated_at = str(row.get("updated_at") or "").strip() or now
    return {
        "job_id": str(job_id or "").strip(),
        "std_code": str(std_code or "").strip(),
        "specir_id": specir_id,
        "normRef": str(row.get("normRef") or row.get("norm_ref") or "").strip(),
        "semantic_type": str(row.get("semantic_type") or "").strip(),
        "slotKey": str(row.get("slotKey") or row.get("slot_key") or "").strip(),
        "constraint": row.get("constraint"),
        "condition": row.get("condition"),
        "evidence": row.get("evidence") if isinstance(row.get("evidence"), dict) else {},
        "confidence": row.get("confidence"),
        "semantic_status": str(row.get("semantic_status") or "").strip(),
        "execution_status": str(row.get("execution_status") or "").strip(),
        "review_status": str(row.get("review_status") or "").strip(),
        "created_at": created_at,
        "updated_at": updated_at,
        "specir_version": str(row.get("specir_version") or "v1").strip() or "v1",
    }


def _upsert_specir_store_rows(job_id: str, std_code: str, rows: List[Dict[str, Any]]) -> None:
    doc = _load_specir_store_doc()
    records = [x for x in doc.get("records", []) if isinstance(x, dict)]
    index: Dict[str, int] = {}
    for i, row in enumerate(records):
        key = f"{str(row.get('job_id') or '').strip()}::{str(row.get('specir_id') or '').strip()}"
        if key:
            index[key] = i
    for raw in rows:
        if not isinstance(raw, dict):
            continue
        norm = _normalize_specir_store_row(raw, job_id=job_id, std_code=std_code)
        sid = str(norm.get("specir_id") or "").strip()
        if not sid:
            continue
        key = f"{job_id}::{sid}"
        pos = index.get(key)
        if pos is None:
            records.append(norm)
            index[key] = len(records) - 1
        else:
            prev = records[pos]
            merged = dict(prev)
            merged.update(norm)
            merged["created_at"] = str(prev.get("created_at") or norm.get("created_at") or _utc_now()).strip()
            merged["updated_at"] = _utc_now()
            records[pos] = merged
    doc["records"] = records
    _save_specir_store_doc(doc)


def _load_slot_registry_doc() -> Dict[str, Any]:
    if not SLOT_REGISTRY_PATH.exists():
        return {"schema_version": "slot_registry.v1", "updated_at": "", "slots": []}
    try:
        doc = json.loads(SLOT_REGISTRY_PATH.read_text(encoding="utf-8-sig"))
    except Exception:
        return {"schema_version": "slot_registry.v1", "updated_at": "", "slots": []}
    if not isinstance(doc, dict):
        return {"schema_version": "slot_registry.v1", "updated_at": "", "slots": []}
    rows = doc.get("slots", [])
    if not isinstance(rows, list):
        rows = []
    return {
        "schema_version": "slot_registry.v1",
        "updated_at": str(doc.get("updated_at") or "").strip(),
        "slots": [x for x in rows if isinstance(x, dict)],
    }


def _save_slot_registry_doc(doc: Dict[str, Any]) -> None:
    SLOT_REGISTRY_PATH.parent.mkdir(parents=True, exist_ok=True)
    out = {
        "schema_version": "slot_registry.v1",
        "updated_at": _utc_now(),
        "slots": [x for x in (doc.get("slots", []) if isinstance(doc.get("slots"), list) else []) if isinstance(x, dict)],
    }
    SLOT_REGISTRY_PATH.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")


def _upsert_slot_registry_rows(rows: List[Dict[str, Any]]) -> None:
    doc = _load_slot_registry_doc()
    slots = [x for x in doc.get("slots", []) if isinstance(x, dict)]
    by_key: Dict[str, int] = {}
    for i, row in enumerate(slots):
        k = str(row.get("slotKey") or "").strip()
        if k:
            by_key[k] = i
    for raw in rows:
        if not isinstance(raw, dict):
            continue
        slot_key = str(raw.get("slotKey") or "").strip()
        if (not slot_key) or slot_key == "measured_value":
            continue
        norm = {
            "slotKey": slot_key,
            "domain": str(raw.get("domain") or "").strip(),
            "object": str(raw.get("object") or "").strip(),
            "property": str(raw.get("property") or "").strip(),
            "measure": str(raw.get("measure") or "").strip(),
            "aliases": [str(x).strip() for x in (raw.get("aliases", []) if isinstance(raw.get("aliases"), list) else []) if str(x).strip()],
            "unit": str(raw.get("unit") or "").strip(),
            "semantic_type": str(raw.get("semantic_type") or "").strip(),
            "supported_forms": [str(x).strip() for x in (raw.get("supported_forms", []) if isinstance(raw.get("supported_forms"), list) else []) if str(x).strip()],
            "updated_at": _utc_now(),
        }
        if slot_key not in by_key:
            norm["created_at"] = _utc_now()
            slots.append(norm)
            by_key[slot_key] = len(slots) - 1
        else:
            prev = slots[by_key[slot_key]]
            merged = dict(prev)
            merged.update(norm)
            merged["created_at"] = str(prev.get("created_at") or _utc_now()).strip()
            merged_forms = set([str(x).strip() for x in (prev.get("supported_forms", []) if isinstance(prev.get("supported_forms"), list) else []) if str(x).strip()])
            merged_forms.update(norm["supported_forms"])
            merged["supported_forms"] = sorted(list(merged_forms))
            slots[by_key[slot_key]] = merged
    doc["slots"] = slots
    _save_slot_registry_doc(doc)


def _new_layer2_id(prefix: str) -> str:
    token = uuid.uuid4().hex[:8]
    return f"{prefix}_{datetime.utcnow().strftime('%Y%m%d%H%M%S')}_{token}"


def _enqueue_unresolved_rules(job_id: str, rules: List[Dict[str, Any]]) -> Dict[str, int]:
    queue = _load_layer2_store("unresolved_rule_queue")
    existing_keys = {
        (str(item.get("job_id", "")).strip(), str(item.get("rule_id", "")).strip())
        for item in queue
        if isinstance(item, dict)
    }
    added = 0
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        if not bool(rule.get("unresolved", False)):
            continue
        rule_id = str(rule.get("rule_id", "")).strip()
        if not rule_id:
            continue
        key = (job_id, rule_id)
        if key in existing_keys:
            continue
        queue.append(
            {
                "queue_id": _new_layer2_id("unresolved_rule"),
                "job_id": job_id,
                "rule_id": rule_id,
                "norm_ref": str(rule.get("norm_ref", "")).strip(),
                "source_clause_id": str(rule.get("source_clause_id", "")).strip(),
                "field": str(rule.get("field", "")).strip(),
                "operator": str(rule.get("operator", "")).strip(),
                "min": rule.get("min"),
                "max": rule.get("max"),
                "unit": str(rule.get("unit", "")).strip(),
                "scope": rule.get("scope", {}),
                "unresolved_reason": str(rule.get("unresolved_reason", "")).strip(),
                "status": "pending_confirmation",
                "created_at": _utc_now(),
                "resolved_at": "",
                "resolved": False,
                "resolution": {},
            }
        )
        existing_keys.add(key)
        added += 1
    _save_layer2_store("unresolved_rule_queue", queue)
    pending = sum(1 for x in queue if str(x.get("job_id", "")).strip() == job_id and str(x.get("status", "")).strip() == "pending_confirmation")
    return {"added": added, "pending": pending}


def _writeback_resolved_rule_to_store(payload: Dict[str, Any]) -> str:
    records = _load_layer2_store("rule_store_writebacks")
    writeback_id = _new_layer2_id("rule_store_wb")
    records.append(
        {
            "writeback_id": writeback_id,
            "status": "ok",
            "created_at": _utc_now(),
            "payload": payload,
        }
    )
    _save_layer2_store("rule_store_writebacks", records)
    return writeback_id


def _patch_rule_in_artifacts(job_id: str, rule_id: str, patch: Dict[str, Any]) -> Dict[str, Any]:
    rules_path = _artifact_dir_for_job(job_id) / "07_rules.json"
    if not rules_path.exists():
        raise HTTPException(status_code=404, detail=f"任务 {job_id} 缺少 07_rules.json。")
    try:
        rules_doc = json.loads(rules_path.read_text(encoding="utf-8-sig"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"任务 {job_id} 07_rules.json 非法。") from exc
    rows = rules_doc.get("rules", [])
    if not isinstance(rows, list):
        raise HTTPException(status_code=400, detail="07_rules.json.rules 非法。")
    hit = None
    for row in rows:
        if isinstance(row, dict) and str(row.get("rule_id", "")).strip() == rule_id:
            hit = row
            break
    if hit is None:
        raise HTTPException(status_code=404, detail=f"未找到 rule_id={rule_id}")
    before = dict(hit)
    hit.update(patch)
    after = dict(hit)
    rules_doc["count"] = len(rows)
    rules_doc["valid"] = True
    rules_path.write_text(json.dumps(rules_doc, ensure_ascii=False, indent=2), encoding="utf-8")

    normdoc_path = _artifact_dir_for_job(job_id) / "11_normdoc.json"
    if normdoc_path.exists():
        try:
            normdoc = json.loads(normdoc_path.read_text(encoding="utf-8-sig"))
            nrows = normdoc.get("rules", [])
            if isinstance(nrows, list):
                for row in nrows:
                    if isinstance(row, dict) and str(row.get("rule_id", "")).strip() == rule_id:
                        row.update(patch)
                normdoc["rules"] = nrows
            normdoc_path.write_text(json.dumps(normdoc, ensure_ascii=False, indent=2), encoding="utf-8")
        except Exception:
            pass
    return {"before": before, "after": after}


