def _assert_pipeline_ready_for_publish(job_id: str, *, require_runtime_derived: bool = False) -> Dict[str, Any]:
    blockers: List[str] = []

    def _add_blocker(message: str) -> None:
        if message and message not in blockers:
            blockers.append(message)

    index_path = _artifact_dir_for_job(job_id) / "00_pipeline_index.json"
    if not index_path.exists():
        raise HTTPException(status_code=400, detail=f"禁止发布（原因）：\n- 任务 {job_id} 未生成 artifacts")
    try:
        index = json.loads(index_path.read_text(encoding="utf-8-sig"))
    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail=f"禁止发布（原因）：\n- 任务 {job_id} artifacts 索引非法") from exc

    validations = index.get("validations")
    if not isinstance(validations, dict) or not validations:
        _add_blocker("缺少 schema 校验结果")

    required_artifacts = [
        "01_spec.json",
        "02_catalog.json",
        "03_clause_tree.json",
        "05_components.json",
        "07_rules.json",
        "08_gates.json",
        "norm_ref_index.json",
        "11_normdoc.json",
        "12_pipeline_audit.json",
    ]
    if require_runtime_derived:
        required_artifacts.extend(["06_dto_schema.json", "10_proof_templates.json"])

    files = index.get("files")
    if not isinstance(files, dict):
        _add_blocker("缺少 artifacts 文件清单")
        files = {}

    missing_artifacts = [name for name in required_artifacts if name not in files]
    for name in missing_artifacts:
        _add_blocker(f"缺少产物：{name}")

    summaries = index.get("artifact_summaries")
    if not isinstance(summaries, dict):
        summaries = {}

    normdoc: Dict[str, Any] = {}
    audit: Dict[str, Any] = {}
    normdoc_path = _artifact_dir_for_job(job_id) / "11_normdoc.json"
    audit_path = _artifact_dir_for_job(job_id) / "12_pipeline_audit.json"
    try:
        normdoc = json.loads(normdoc_path.read_text(encoding="utf-8-sig"))
    except Exception:
        _add_blocker("11_normdoc.json 读取失败")
    try:
        audit = json.loads(audit_path.read_text(encoding="utf-8-sig"))
    except Exception:
        _add_blocker("12_pipeline_audit.json 读取失败")

    spec_node = normdoc.get("spec", {}) if isinstance(normdoc.get("spec"), dict) else {}
    spec_exists = bool(str(spec_node.get("spec_id") or normdoc.get("spec_id") or "").strip())
    catalog_count = int(summaries.get("02_catalog.json", {}).get("count", 0) or 0) if isinstance(summaries.get("02_catalog.json"), dict) else 0
    rules_count = int(summaries.get("07_rules.json", {}).get("count", 0) or 0) if isinstance(summaries.get("07_rules.json"), dict) else 0
    gates_count = int(summaries.get("08_gates.json", {}).get("count", 0) or 0) if isinstance(summaries.get("08_gates.json"), dict) else 0
    normdoc_status = str(normdoc.get("status", "")).strip()
    normdoc_valid = bool(normdoc.get("valid", False))

    if not spec_exists:
        _add_blocker("未生成规范标识（spec_id）")
    if catalog_count <= 0:
        _add_blocker("未生成 normRef（Catalog 结构为空）")
    if rules_count <= 0:
        _add_blocker("无规则")
    if gates_count <= 0:
        _add_blocker("无判定逻辑")
    if normdoc_status != "ready_to_publish":
        _add_blocker(f"NormDoc 状态非法：{normdoc_status or '-'}")
    if not normdoc_valid:
        _add_blocker("NormDoc 无效")

    audit_blockers = audit.get("blockers", []) if isinstance(audit, dict) and isinstance(audit.get("blockers"), list) else []
    for item in audit_blockers:
        text = str(item).strip()
        if text:
            _add_blocker(f"audit blocker: {text}")

    unresolved_queue = _load_layer2_store("unresolved_rule_queue")
    pending_unresolved = [
        item for item in unresolved_queue
        if isinstance(item, dict)
        and str(item.get("job_id", "")).strip() == job_id
        and str(item.get("status", "")).strip() == "pending_confirmation"
    ]
    # Pending unresolved items are warnings unless they dominate all rules.
    pending_unresolved_count = len(pending_unresolved)

    rules_path = Path(str(files.get("07_rules.json", "")))
    gates_path = Path(str(files.get("08_gates.json", "")))
    normref_index_path = Path(str(files.get("norm_ref_index.json", "")))
    rules_doc: Dict[str, Any] = {}
    gates_doc: Dict[str, Any] = {}
    normref_index_doc: Dict[str, Any] = {}
    if not rules_path.exists():
        _add_blocker("缺少 Rule 产物文件")
    if not gates_path.exists():
        _add_blocker("缺少 Gate 产物文件")
    if not normref_index_path.exists():
        _add_blocker("缺少 norm_ref_index 产物文件")

    if rules_path.exists():
        try:
            rules_doc = json.loads(rules_path.read_text(encoding="utf-8-sig"))
        except Exception:
            _add_blocker("Rule 产物读取失败")
    if gates_path.exists():
        try:
            gates_doc = json.loads(gates_path.read_text(encoding="utf-8-sig"))
        except Exception:
            _add_blocker("Gate 产物读取失败")
    if normref_index_path.exists():
        try:
            normref_index_doc = json.loads(normref_index_path.read_text(encoding="utf-8-sig"))
        except Exception:
            _add_blocker("norm_ref_index 读取失败")

    rules_rows = rules_doc.get("rules", []) if isinstance(rules_doc, dict) else []
    gates_rows = gates_doc.get("gates", []) if isinstance(gates_doc, dict) else []
    normref_entries = normref_index_doc.get("entries", []) if isinstance(normref_index_doc, dict) else []
    if not isinstance(rules_rows, list):
        _add_blocker("Rule 结构非法")
        rules_rows = []
    if not isinstance(gates_rows, list):
        _add_blocker("Gate 结构非法")
        gates_rows = []
    if not isinstance(normref_entries, list):
        _add_blocker("norm_ref_index 结构非法")
        normref_entries = []

    ref_to_entry: Dict[str, Dict[str, Any]] = {}
    for entry in normref_entries:
        if not isinstance(entry, dict):
            continue
        ref = str(entry.get("normRef", "")).strip()
        if ref:
            ref_to_entry[ref] = entry

    # Build fallback map: source clause id -> normRef entry (for clause-level traceability).
    clause_ref_map: Dict[str, str] = {}
    for ref in ref_to_entry.keys():
        m = re.search(r"/clause/(\d+(?:\.\d+)*)$", ref)
        if m:
            clause_ref_map[m.group(1)] = ref

    rule_ref_map: Dict[str, str] = {}
    rule_specir_map: Dict[str, str] = {}
    unresolved_rules_count = 0
    anchor_missing_count = 0
    specir_ref_missing_count = 0
    for idx, row in enumerate(rules_rows, start=1):
        if not isinstance(row, dict):
            _add_blocker(f"Rule#{idx} 非对象")
            continue
        rule_id = str(row.get("rule_id", "")).strip() or f"rule#{idx}"
        norm_ref = str(row.get("norm_ref", "")).strip()
        source_specir_id = str(row.get("source_specir_id") or row.get("specir_id") or "").strip()
        specir_version = str(row.get("specir_version") or "").strip()
        if not source_specir_id:
            specir_ref_missing_count += 1
            _add_blocker(f"Rule {rule_id} 缺少 source_specir_id/specir_id")
        if not specir_version:
            specir_ref_missing_count += 1
            _add_blocker(f"Rule {rule_id} 缺少 specir_version")
        anchor = _extract_rule_anchor_fields(row, ref_to_entry.get(norm_ref))
        anchor_errs = _validate_rule_anchor_fields(anchor)
        if anchor_errs:
            anchor_missing_count += 1
            _add_blocker(f"Rule {rule_id} 缺少原文锚点字段: {', '.join(anchor_errs)}")
        if norm_ref:
            rule_ref_map[rule_id] = norm_ref
        if source_specir_id:
            rule_specir_map[rule_id] = source_specir_id
        entry = ref_to_entry.get(norm_ref)
        if not entry:
            source_clause_id = str(row.get("source_clause_id", "")).strip()
            fallback_ref = clause_ref_map.get(source_clause_id, "")
            if fallback_ref:
                entry = ref_to_entry.get(fallback_ref)
        if not entry:
            # Allow publish with partial normRef index mapping; keep traceability via source_clause_id/source_ref.
            continue
        locator = entry.get("locator", {}) if isinstance(entry.get("locator", {}), dict) else {}
        source = locator.get("source", {}) if isinstance(locator.get("source", {}), dict) else {}
        page_start = source.get("page_start")
        page_end = source.get("page_end")
        # page_start/page_end are best-effort trace fields and may be absent in historical index shape.
        # Keep publish gate non-blocking for this case.
        if bool(row.get("unresolved")) and not bool(row.get("resolved")):
            unresolved_rules_count += 1
    # Keep strict blocker only when unresolved dominates all generated rules.
    if rules_rows and unresolved_rules_count >= len(rules_rows):
        _add_blocker(f"存在 unresolved Rule（未确认 {unresolved_rules_count} 条）")
    if rules_rows and pending_unresolved_count >= len(rules_rows):
        _add_blocker(f"存在 unresolved 项（待人工确认 {pending_unresolved_count} 条）")
    if anchor_missing_count > 0:
        _add_blocker(f"存在缺少原文锚点的 Rule（{anchor_missing_count} 条）")
    if specir_ref_missing_count > 0:
        _add_blocker(f"存在缺少 SpecIR 引用链的 Rule（{specir_ref_missing_count} 处）")

    for idx, gate in enumerate(gates_rows, start=1):
        if not isinstance(gate, dict):
            _add_blocker(f"Gate#{idx} 非对象")
            continue
        gate_id = str(gate.get("gate_id", "")).strip() or f"gate#{idx}"
        gate_rules = gate.get("rules", gate.get("rule_ids", []))
        if not isinstance(gate_rules, list) or len(gate_rules) <= 0:
            _add_blocker(f"Gate {gate_id} 未引用 Rule")
            continue
        gate_rule_refs = gate.get("ruleRefs", gate.get("rule_refs", []))
        if gate_rule_refs and (not isinstance(gate_rule_refs, list)):
            _add_blocker(f"Gate {gate_id} 的 ruleRefs 结构非法")
            continue
        referenced_specir_ids: List[str] = []
        for rid_raw in gate_rules:
            rid = str(rid_raw).strip()
            if not rid:
                continue
            specir_id = rule_specir_map.get(rid, "")
            if not specir_id:
                _add_blocker(f"Gate {gate_id} 引用了不存在或缺少 SpecIR 引用链的 Rule：{rid}")
                continue
            referenced_specir_ids.append(specir_id)
        if len(referenced_specir_ids) == 0:
            _add_blocker(f"Gate {gate_id} 缺少可追溯的 Rule→SpecIR 链路")

    if require_runtime_derived:
        dto_count = int(summaries.get("06_dto_schema.json", {}).get("count", 0) or 0) if isinstance(summaries.get("06_dto_schema.json"), dict) else 0
        proof_count = int(summaries.get("10_proof_templates.json", {}).get("count", 0) or 0) if isinstance(summaries.get("10_proof_templates.json"), dict) else 0
        runtime_derived = ((normdoc.get("asset_layers") or {}).get("runtime_derived") if isinstance(normdoc.get("asset_layers"), dict) else {}) or {}
        executor_spec_count = int((runtime_derived.get("executor_spec_count", 0) if isinstance(runtime_derived, dict) else 0) or 0)
        if dto_count <= 0:
            _add_blocker("发布可执行包失败：DTO count <= 0")
        if executor_spec_count <= 0:
            _add_blocker("发布可执行包失败：ExecutorSpec count <= 0")
        if proof_count <= 0:
            _add_blocker("发布可执行包失败：ProofTemplate count <= 0")

    specir_refs = normdoc.get("specir_refs", []) if isinstance(normdoc, dict) else []
    if not isinstance(specir_refs, list) or len([x for x in specir_refs if str(x).strip()]) <= 0:
        _add_blocker("发布资产缺少 specir_refs")

    if blockers:
        detail = "禁止发布（原因）：\n" + "\n".join(f"- {item}" for item in blockers)
        raise HTTPException(status_code=400, detail=detail)
    return index


def _refresh_artifact_business_valid(job_id: str) -> Dict[str, Any]:
    index_path = _artifact_dir_for_job(job_id) / "00_pipeline_index.json"
    if not index_path.exists():
        raise HTTPException(status_code=404, detail=f"未找到任务 {job_id} 的 artifacts 索引。")
    index = json.loads(index_path.read_text(encoding="utf-8-sig"))
    validations = index.get("validations", {})
    if not isinstance(validations, dict):
        validations = {}
    artifact_summaries = index.get("artifact_summaries", {})
    if not isinstance(artifact_summaries, dict):
        artifact_summaries = {}
    files = index.get("files", {})
    if not isinstance(files, dict):
        files = {}

    # Backfill missing norm_ref_index for historical jobs.
    normref_index_name = "norm_ref_index.json"
    normref_index_path = _artifact_dir_for_job(job_id) / normref_index_name
    if not normref_index_path.exists():
        std_code = str(index.get("std_code", "")).strip()
        catalog_doc: Dict[str, Any] = {}
        clause_tree_doc: Dict[str, Any] = {}
        cls_doc: Dict[str, Any] = {}
        comp_doc: Dict[str, Any] = {}
        rules_doc: Dict[str, Any] = {}
        review_pkg: Dict[str, Any] = {}
        try:
            review_pkg = _load_review_package(job_id)
        except Exception:
            review_pkg = {}

        def _read_artifact_obj(name: str) -> Dict[str, Any]:
            p = _artifact_dir_for_job(job_id) / name
            if not p.exists():
                return {}
            try:
                payload = json.loads(p.read_text(encoding="utf-8-sig"))
                return payload if isinstance(payload, dict) else {}
            except Exception:
                return {}

        catalog_doc = _read_artifact_obj("02_catalog.json")
        clause_tree_doc = _read_artifact_obj("03_clause_tree.json")
        cls_doc = _read_artifact_obj("04_clause_classification.json")
        comp_doc = _read_artifact_obj("05_components.json")
        rules_doc = _read_artifact_obj("07_rules.json")

        clause_tree_nodes = []
        if isinstance(clause_tree_doc.get("nodes"), list):
            clause_tree_nodes = [x for x in clause_tree_doc.get("nodes", []) if isinstance(x, dict)]
        elif isinstance(clause_tree_doc.get("clause_tree"), list):
            clause_tree_nodes = [x for x in clause_tree_doc.get("clause_tree", []) if isinstance(x, dict)]
        elif isinstance(clause_tree_doc.get("clause_tree"), dict):
            raw_nodes = (clause_tree_doc.get("clause_tree") or {}).get("nodes", [])
            clause_tree_nodes = [x for x in raw_nodes if isinstance(x, dict)] if isinstance(raw_nodes, list) else []

        catalog_rows = [x for x in catalog_doc.get("catalog", []) if isinstance(x, dict)] if isinstance(catalog_doc.get("catalog"), list) else []
        clause_classifications = [x for x in cls_doc.get("classifications", []) if isinstance(x, dict)] if isinstance(cls_doc.get("classifications"), list) else []
        components = [x for x in comp_doc.get("components", []) if isinstance(x, dict)] if isinstance(comp_doc.get("components"), list) else []
        rules = [x for x in rules_doc.get("rules", []) if isinstance(x, dict)] if isinstance(rules_doc.get("rules"), list) else []

        backfill_normref_meta = {
            "spec_id": std_code,
            "standard_id": std_code,
            "version": str(index.get("version", "") or "").strip(),
            "title": str(index.get("title", "") or "").strip(),
            "source_model": "normref_only",
            "created_at": _utc_now(),
            "updated_at": _utc_now(),
            "job_id": job_id,
        }
        if isinstance(review_pkg, dict):
            backfill_normref_meta["level"] = str(review_pkg.get("level", "") or "").strip()
            if not backfill_normref_meta["title"]:
                backfill_normref_meta["title"] = str(review_pkg.get("title", "") or "").strip()

        rebuilt_normref_index = _build_norm_ref_index(
            normref_meta=backfill_normref_meta,
            std_code=std_code,
            clause_tree_nodes=clause_tree_nodes,
            catalog_rows=catalog_rows,
            clause_classifications=clause_classifications,
            components=components,
            rules=rules,
        )
        _write_artifact_json(job_id, normref_index_name, rebuilt_normref_index)
        files[normref_index_name] = str(normref_index_path)
        schema_map = _schema_map()
        errs = _simple_json_schema_validate(rebuilt_normref_index, schema_map.get(normref_index_name, {"type": "object"}))
        validations[normref_index_name] = {
            "schema_valid": len(errs) == 0,
            "business_valid": bool(int(rebuilt_normref_index.get("count", 0) or 0) > 0),
            "valid": bool(len(errs) == 0 and int(rebuilt_normref_index.get("count", 0) or 0) > 0),
            "errors": errs,
        }
        artifact_summaries[normref_index_name] = {
            "generated": True,
            "valid": bool(validations[normref_index_name]["valid"]),
            "count": int(rebuilt_normref_index.get("count", 0) or 0),
            "status": "ok" if bool(validations[normref_index_name]["valid"]) else "invalid",
        }
    audit_path = _artifact_dir_for_job(job_id) / "12_pipeline_audit.json"
    audit: Dict[str, Any] = {}
    if audit_path.exists():
        loaded_audit = json.loads(audit_path.read_text(encoding="utf-8-sig"))
        audit = loaded_audit if isinstance(loaded_audit, dict) else {}
    normdoc_path = _artifact_dir_for_job(job_id) / "11_normdoc.json"
    normdoc = {}
    if normdoc_path.exists():
        try:
            normdoc = json.loads(normdoc_path.read_text(encoding="utf-8-sig"))
        except json.JSONDecodeError:
            normdoc = {}
    normdoc_status = str((normdoc or {}).get("status", "")).strip().lower()

    def _count_of(name: str) -> int:
        row = artifact_summaries.get(name, {})
        if isinstance(row, dict):
            val = row.get("count")
            if isinstance(val, (int, float)):
                return int(val)
        path = files.get(name)
        if isinstance(path, str) and path:
            p = Path(path)
            if p.exists():
                try:
                    payload = json.loads(p.read_text(encoding="utf-8-sig"))
                    if isinstance(payload, dict):
                        count = payload.get("count")
                        if isinstance(count, (int, float)):
                            return int(count)
                except json.JSONDecodeError:
                    return 0
        return 0

    blockers = audit.get("blockers", [])
    if not isinstance(blockers, list):
        blockers = [str(blockers)] if str(blockers).strip() else []
        audit["blockers"] = blockers
    errors = audit.get("errors", [])
    if not isinstance(errors, list):
        errors = [str(errors)] if str(errors).strip() else []
        audit["errors"] = errors
    publishable = bool(audit.get("publishable"))
    global_business_valid = len(blockers) == 0 and len(errors) == 0 and publishable
    base_non_empty = {
        "01_spec.json": _count_of("01_spec.json") > 0,
        "02_catalog.json": _count_of("02_catalog.json") > 0,
        "03_clause_tree.json": _count_of("03_clause_tree.json") > 0,
        "04_clause_classification.json": _count_of("04_clause_classification.json") > 0,
        "05_components.json": _count_of("05_components.json") > 0,
    }
    executable_core_non_empty = {
        "07_rules.json": _count_of("07_rules.json") > 0,
        "08_gates.json": _count_of("08_gates.json") > 0,
    }
    for name, row in validations.items():
        if not isinstance(row, dict):
            continue
        schema_valid = bool(row.get("schema_valid", row.get("valid", False)))
        if name in base_non_empty:
            row["business_valid"] = bool(base_non_empty[name])
        elif name in executable_core_non_empty:
            row["business_valid"] = bool(executable_core_non_empty[name])
        elif name == "11_normdoc.json":
            row["business_valid"] = bool(normdoc_status == "ready_to_publish")
        elif name == "12_pipeline_audit.json":
            row["business_valid"] = global_business_valid
        else:
            # Preserve per-artifact business validation computed in pipeline generation.
            row["business_valid"] = bool(row.get("business_valid", row.get("valid", False)))
        row["valid"] = bool(schema_valid and bool(row.get("business_valid", False)))
        validations[name] = row
    if any(not x for x in base_non_empty.values()):
        audit["publishable"] = False
    if any(not x for x in executable_core_non_empty.values()):
        audit["publishable"] = False
    if normdoc_status != "ready_to_publish":
        audit["publishable"] = False
    audit_path.write_text(json.dumps(audit, ensure_ascii=False, indent=2), encoding="utf-8")
    _upsert_pipeline_audit_pg(job_id, audit)
    index["validations"] = validations
    index["files"] = files
    index["artifact_summaries"] = artifact_summaries
    index["valid"] = all(bool((v or {}).get("valid")) for v in validations.values()) if validations else False
    index_path.write_text(json.dumps(index, ensure_ascii=False, indent=2), encoding="utf-8")
    _upsert_ingest_artifacts_pg(job_id, index)
    return index


def _append_pipeline_asset_review(request: AssetReviewRequest) -> Dict[str, Any]:
    if str(request.object_type or "").strip().lower() != "specir":
        raise HTTPException(status_code=400, detail="人工校验对象已统一为 SpecIR：object_type 仅允许 specir")
    required_checks = [
        "semantic_correct",
        "slot_correct",
        "operator_correct",
        "threshold_correct",
        "formula_correct",
        "runtime_ready",
        "publishable",
    ]
    checklist = request.review_checklist if isinstance(request.review_checklist, dict) else {}
    missing_checks = [k for k in required_checks if k not in checklist]
    if missing_checks:
        raise HTTPException(status_code=400, detail=f"缺少 review_checklist 字段：{', '.join(missing_checks)}")
    job_id = str(request.job_id).strip()
    audit_path = _artifact_dir_for_job(job_id) / "12_pipeline_audit.json"
    if not audit_path.exists():
        raise HTTPException(status_code=404, detail=f"任务 {job_id} 缺少 12_pipeline_audit.json。")
    loaded_audit = json.loads(audit_path.read_text(encoding="utf-8-sig"))
    audit: Dict[str, Any] = loaded_audit if isinstance(loaded_audit, dict) else {}
    reviews = audit.get("manual_reviews", [])
    if not isinstance(reviews, list):
        reviews = []
    reviewed_at = _utc_now()
    decision_review_status = str(request.review_status or "").strip() or {
        "approve": "approved",
        "needs_edit": "needs_edit",
        "reject": "rejected",
    }.get(str(request.decision or "").strip().lower(), "pending_review")
    sign_seed = {
        "job_id": job_id,
        "object_type": request.object_type,
        "object_id": request.object_id,
        "reviewer_id": request.reviewer_id,
        "reviewer_name": request.reviewer_name,
        "decision": request.decision,
        "review_status": decision_review_status,
        "changed_fields": [str(x) for x in request.changed_fields if str(x).strip()],
        "comment": request.comment,
        "reviewed_at": reviewed_at,
    }
    signature_hash = str(request.signature_hash or "").strip() or _stable_json_hash({**sign_seed, "review_checklist": checklist})
    signed_at = str(request.signed_at or "").strip() or reviewed_at
    reviews.append(
        {
            "object_type": request.object_type,
            "object_id": request.object_id,
            "reviewer_id": request.reviewer_id,
            "reviewer_name": request.reviewer_name,
            "reviewed_at": reviewed_at,
            "decision": request.decision,
            "review_status": decision_review_status,
            "changed_fields": [str(x) for x in request.changed_fields if str(x).strip()],
            "comment": request.comment,
            "signed_at": signed_at,
            "signature_hash": signature_hash,
            "review_hash": signature_hash,
            "review_checklist": checklist,
        }
    )
    audit["manual_reviews"] = reviews
    if request.decision in {"reject", "needs_edit"}:
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = [str(blockers)] if str(blockers).strip() else []
        blockers.append(f"manual_review_{request.decision}:{request.object_type}:{request.object_id}")
        audit["blockers"] = blockers
        audit["publishable"] = False
        audit["valid"] = False
        audit["audit_status"] = "FAIL"
    audit_path.write_text(json.dumps(audit, ensure_ascii=False, indent=2), encoding="utf-8")
    _upsert_asset_review_pg(request)
    index = _refresh_artifact_business_valid(job_id)
    return {"status": "ok", "job_id": job_id, "audit": audit, "index": index}


def _pg_enabled() -> bool:
    return NORMREF_DB_BACKEND == "postgres" and bool(NORMREF_PG_DSN)


def _ensure_psycopg_available() -> None:
    if psycopg is None:
        detail = "psycopg 未安装，无法写入 PostgreSQL。请安装 psycopg[binary] 并重启服务。"
        if _psycopg_error is not None:
            detail = f"{detail} 原始错误：{_psycopg_error}"
        raise HTTPException(status_code=500, detail=detail)


def _upsert_asset_review_pg(request: AssetReviewRequest) -> None:
    if not _pg_enabled():
        return
    _ensure_psycopg_available()
    assert psycopg is not None
    try:
        with psycopg.connect(NORMREF_PG_DSN) as conn:  # type: ignore[call-arg]
            with conn.cursor() as cur:
                cur.execute(
                    """
                    INSERT INTO ingest_jobs(job_id, status, updated_at)
                    VALUES (%s, %s, NOW())
                    ON CONFLICT (job_id) DO UPDATE
                      SET updated_at = NOW()
                    """,
                    (request.job_id, "review_in_progress"),
                )
                cur.execute(
                    """
                    INSERT INTO asset_reviews(
                      job_id, object_type, object_id, decision, reviewer_id, reviewer_name,
                      changed_fields, comment, reviewed_at
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s::jsonb, %s, NOW())
                    """,
                    (
                        request.job_id,
                        request.object_type,
                        request.object_id,
                        request.decision,
                        request.reviewer_id,
                        request.reviewer_name,
                        json.dumps([str(x) for x in request.changed_fields if str(x).strip()], ensure_ascii=False),
                        request.comment,
                    ),
                )
                # Refresh latest decision snapshot for UI query readiness.
                cur.execute("REFRESH MATERIALIZED VIEW asset_review_latest")
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"写入 PostgreSQL 失败：{exc}") from exc


def _upsert_pipeline_audit_pg(job_id: str, audit: Dict[str, Any]) -> None:
    if not _pg_enabled():
        return
    _ensure_psycopg_available()
    assert psycopg is not None
    try:
        with psycopg.connect(NORMREF_PG_DSN) as conn:  # type: ignore[call-arg]
            with conn.cursor() as cur:
                cur.execute(
                    """
                    INSERT INTO ingest_jobs(job_id, status, updated_at)
                    VALUES (%s, %s, NOW())
                    ON CONFLICT (job_id) DO UPDATE
                      SET updated_at = NOW()
                    """,
                    (job_id, "review_in_progress"),
                )
                blockers = audit.get("blockers", [])
                errors = audit.get("errors", [])
                audit_status = str(audit.get("audit_status", "PENDING") or "PENDING")
                publishable = bool(audit.get("publishable", False))
                cur.execute(
                    """
                    INSERT INTO pipeline_audits(
                      job_id, audit_status, publishable, blockers, errors, summary, updated_at
                    )
                    VALUES (%s, %s, %s, %s::jsonb, %s::jsonb, %s::jsonb, NOW())
                    ON CONFLICT (job_id) DO UPDATE SET
                      audit_status = EXCLUDED.audit_status,
                      publishable = EXCLUDED.publishable,
                      blockers = EXCLUDED.blockers,
                      errors = EXCLUDED.errors,
                      summary = EXCLUDED.summary,
                      updated_at = NOW()
                    """,
                    (
                        job_id,
                        audit_status,
                        publishable,
                        json.dumps(blockers if isinstance(blockers, list) else [], ensure_ascii=False),
                        json.dumps(errors if isinstance(errors, list) else [], ensure_ascii=False),
                        json.dumps(audit, ensure_ascii=False),
                    ),
                )
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"写入 PostgreSQL pipeline_audit 失败：{exc}") from exc


def _get_asset_review_latest_pg(job_id: str) -> List[Dict[str, Any]]:
    if not _pg_enabled():
        return []
    _ensure_psycopg_available()
    assert psycopg is not None
    try:
        with psycopg.connect(NORMREF_PG_DSN) as conn:  # type: ignore[call-arg]
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT job_id, object_type, object_id, decision, reviewer_id, reviewer_name, comment, reviewed_at
                    FROM asset_review_latest
                    WHERE job_id = %s
                    ORDER BY object_type, object_id
                    """,
                    (job_id,),
                )
                rows = cur.fetchall()
        result: List[Dict[str, Any]] = []
        for row in rows:
            result.append(
                {
                    "job_id": row[0],
                    "object_type": row[1],
                    "object_id": row[2],
                    "decision": row[3],
                    "reviewer_id": row[4],
                    "reviewer_name": row[5],
                    "comment": row[6],
                    "reviewed_at": row[7].isoformat() if row[7] else None,
                }
            )
        return result
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"读取 PostgreSQL 资产校验结论失败：{exc}") from exc


def _get_asset_review_summary_pg(job_id: str) -> Dict[str, int]:
    if not _pg_enabled():
        return {"total": 0, "approved": 0, "needs_edit": 0, "rejected": 0}
    _ensure_psycopg_available()
    assert psycopg is not None
    try:
        with psycopg.connect(NORMREF_PG_DSN) as conn:  # type: ignore[call-arg]
            with conn.cursor() as cur:
                cur.execute(
                    """
                    SELECT
                      COUNT(*)::int AS total,
                      COUNT(*) FILTER (WHERE decision IN ('approve', 'approved'))::int AS approved,
                      COUNT(*) FILTER (WHERE decision = 'needs_edit')::int AS needs_edit,
                      COUNT(*) FILTER (WHERE decision IN ('reject', 'rejected'))::int AS rejected
                    FROM asset_review_latest
                    WHERE job_id = %s
                    """,
                    (job_id,),
                )
                row = cur.fetchone() or (0, 0, 0, 0)
        return {
            "total": int(row[0] or 0),
            "approved": int(row[1] or 0),
            "needs_edit": int(row[2] or 0),
            "rejected": int(row[3] or 0),
        }
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"读取 PostgreSQL 人工校验汇总失败：{exc}") from exc


def _upsert_ingest_artifacts_pg(job_id: str, index: Dict[str, Any]) -> None:
    if not _pg_enabled():
        return
    _ensure_psycopg_available()
    assert psycopg is not None
    files = index.get("files", {})
    validations = index.get("validations", {})
    summaries = index.get("artifact_summaries", {})
    if not isinstance(files, dict):
        files = {}
    if not isinstance(validations, dict):
        validations = {}
    if not isinstance(summaries, dict):
        summaries = {}

    try:
        with psycopg.connect(NORMREF_PG_DSN) as conn:  # type: ignore[call-arg]
            with conn.cursor() as cur:
                cur.execute(
                    """
                    INSERT INTO ingest_jobs(job_id, std_code, spec_type, title, source_file, status, updated_at)
                    VALUES (%s, %s, %s, %s, %s, %s, NOW())
                    ON CONFLICT (job_id) DO UPDATE SET
                      std_code = COALESCE(EXCLUDED.std_code, ingest_jobs.std_code),
                      spec_type = COALESCE(EXCLUDED.spec_type, ingest_jobs.spec_type),
                      title = COALESCE(EXCLUDED.title, ingest_jobs.title),
                      source_file = COALESCE(EXCLUDED.source_file, ingest_jobs.source_file),
                      status = EXCLUDED.status,
                      updated_at = NOW()
                    """,
                    (
                        job_id,
                        str(index.get("std_code", "") or "").strip() or None,
                        str(index.get("spec_type", "") or "").strip() or None,
                        str(index.get("title", "") or "").strip() or None,
                        str(index.get("source_file", "") or "").strip() or None,
                        "artifacts_ready",
                    ),
                )

                for artifact_name, artifact_path in files.items():
                    name = str(artifact_name or "").strip()
                    if not name:
                        continue
                    path_text = str(artifact_path or "").strip()
                    payload_obj: Dict[str, Any] = {}
                    if path_text:
                        try:
                            p = Path(path_text)
                            if p.exists():
                                loaded = json.loads(p.read_text(encoding="utf-8-sig"))
                                if isinstance(loaded, dict):
                                    payload_obj = loaded
                        except Exception:
                            payload_obj = {}
                    validation_row = validations.get(name, {}) if isinstance(validations.get(name, {}), dict) else {}
                    summary_row = summaries.get(name, {}) if isinstance(summaries.get(name, {}), dict) else {}
                    schema_valid = bool(validation_row.get("schema_valid", validation_row.get("valid", False)))
                    business_valid = bool(validation_row.get("business_valid", validation_row.get("valid", False)))
                    valid = bool(validation_row.get("valid", False))
                    item_count = int(summary_row.get("count", payload_obj.get("count", 0)) or 0)
                    status = str(summary_row.get("status", "pending") or "pending")
                    cur.execute(
                        """
                        INSERT INTO ingest_artifacts(
                          job_id, artifact_name, artifact_path, payload, schema_valid, business_valid, valid, item_count, status, updated_at
                        )
                        VALUES (%s, %s, %s, %s::jsonb, %s, %s, %s, %s, %s, NOW())
                        ON CONFLICT (job_id, artifact_name) DO UPDATE SET
                          artifact_path = EXCLUDED.artifact_path,
                          payload = EXCLUDED.payload,
                          schema_valid = EXCLUDED.schema_valid,
                          business_valid = EXCLUDED.business_valid,
                          valid = EXCLUDED.valid,
                          item_count = EXCLUDED.item_count,
                          status = EXCLUDED.status,
                          updated_at = NOW()
                        """,
                        (
                            job_id,
                            name,
                            path_text or None,
                            json.dumps(payload_obj, ensure_ascii=False),
                            schema_valid,
                            business_valid,
                            valid,
                            item_count,
                            status,
                        ),
                    )
    except HTTPException:
        raise
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"写入 PostgreSQL artifacts 失败：{exc}") from exc


