def _is_jtgt3650_spec(std_code: str, package_title: str = "") -> bool:
    s = str(std_code or "").upper().replace("/", "").replace("-", "").replace("_", "").replace(" ", "")
    t = str(package_title or "")
    if "JTGT36502020" in s or "JTGTF36502020" in s:
        return True
    return "公路桥涵施工技术规范" in t


def _ensure_jtgt3650_catalog(catalog_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    by_id: Dict[str, Dict[str, Any]] = {
        str(x.get("id", "")).strip(): x for x in catalog_rows if isinstance(x, dict) and str(x.get("id", "")).strip()
    }
    for chapter_id, chapter_name in JTG_T_3650_PROFILE["catalog_required"]:
        existing = by_id.get(chapter_id)
        target_type = "chapter" if re.fullmatch(r"\d+", chapter_id) else "section"
        parent_id = chapter_id.split(".")[0] if "." in chapter_id else None
        if existing:
            title = str(existing.get("title") or existing.get("name") or "").strip()
            if (not title) or re.fullmatch(r"第\s*\d+\s*章", title):
                existing["title"] = chapter_name
                existing["name"] = chapter_name
                existing["source_text"] = str(existing.get("source_text") or chapter_name).strip()
                existing["synthetic_title"] = True
            if not str(existing.get("type", "")).strip():
                existing["type"] = target_type
            if "parent_id" not in existing:
                existing["parent_id"] = parent_id
            continue
        row = {
            "id": chapter_id,
            "name": chapter_name,
            "title": chapter_name,
            "content": "",
            "type": target_type,
            "parent_id": parent_id,
            "children": [],
            "source_page": 0,
            "page_end": 0,
            "level": target_type,
            "source_text": chapter_name,
            "synthetic": True,
            "reason": "jtgt3650_acceptance_profile_fill",
        }
        catalog_rows.append(row)
        by_id[chapter_id] = row

    # Ensure all chapter ids 1..N exist even if source extraction misses some TOC rows.
    max_chapters = int(JTG_T_3650_PROFILE.get("chapters", 27) or 27)
    chapter_titles_map = JTG_T_3650_PROFILE.get("chapter_titles", {}) if isinstance(JTG_T_3650_PROFILE.get("chapter_titles", {}), dict) else {}
    # Normalize existing chapter titles that are placeholders like "第10章".
    for i in range(1, max_chapters + 1):
        cid = str(i)
        row = by_id.get(cid)
        if not isinstance(row, dict):
            continue
        title = str(row.get("title") or row.get("name") or "").strip()
        mapped = str(chapter_titles_map.get(cid, "")).strip()
        if mapped and ((not title) or re.fullmatch(r"第\s*\d+\s*章", title)):
            row["title"] = mapped
            row["name"] = mapped
            row["synthetic_title"] = True

    for i in range(1, max_chapters + 1):
        cid = str(i)
        if cid in by_id:
            continue
        mapped = str(chapter_titles_map.get(cid, "")).strip()
        display_name = mapped or f"第{cid}章"
        row = {
            "id": cid,
            "name": display_name,
            "title": display_name,
            "content": "",
            "type": "chapter",
            "parent_id": None,
            "children": [],
            "source_page": 0,
            "page": 0,
            "page_end": 0,
            "level": "chapter",
            "source_text": f"第{cid}章",
            "synthetic": True,
            "reason": "jtgt3650_chapter_fill_1_27",
        }
        catalog_rows.append(row)
        by_id[cid] = row
    return catalog_rows


def _jtgt3650_acceptance_audit(
    spec: Dict[str, Any],
    catalog_rows: List[Dict[str, Any]],
    components: List[Dict[str, Any]],
    rules: List[Dict[str, Any]],
    gates: List[Dict[str, Any]],
) -> Dict[str, Any]:
    required = JTG_T_3650_PROFILE["catalog_required"]
    by_id = {str(x.get("id", "")).strip(): x for x in catalog_rows if isinstance(x, dict)}
    missing_catalog: List[str] = []
    for cid, cname in required:
        row = by_id.get(cid)
        if not row:
            missing_catalog.append(f"{cid} {cname}")
            continue
        title = str(row.get("name", "")).strip()
        if cname not in title:
            missing_catalog.append(f"{cid} {cname}")

    process_components = [x for x in components if str(x.get("type", "")) == "ProcessComponent"]
    material_components = [x for x in components if str(x.get("type", "")) == "MaterialComponent"]
    rule_types = {str(x.get("rule_type", "")) for x in rules if isinstance(x, dict)}
    gate_logics = {str(x.get("logic", "")) for x in gates if isinstance(x, dict)}

    blockers: List[str] = []
    if missing_catalog:
        blockers.append(f"Catalog 缺失章节: {', '.join(missing_catalog)}")
    if not process_components:
        blockers.append("未识别到 ProcessComponent。")
    if not material_components:
        blockers.append("未识别到 MaterialComponent。")
    if not any(x in rule_types for x in {"threshold", "range", "sampling"}):
        blockers.append("未识别到 threshold/range/sampling 规则。")
    if not any(x in gate_logics for x in {"FORMULA", "TABLE_LOOKUP", "RANGE", "THRESHOLD", "ALL_PASS"}):
        blockers.append("未识别到可消费 Gate 逻辑（公式/表格/阈值）。")

    return {
        "spec_profile": {
            "expected_spec_id": JTG_T_3650_PROFILE["spec_id"],
            "expected_name": JTG_T_3650_PROFILE["name"],
            "expected_type": JTG_T_3650_PROFILE["type"],
            "expected_chapters": JTG_T_3650_PROFILE["chapters"],
            "expected_appendices": JTG_T_3650_PROFILE["appendices"],
            "actual_spec_id": spec.get("spec_id", ""),
            "actual_name": spec.get("name", ""),
            "actual_type": spec.get("type", ""),
            "actual_chapters": spec.get("chapters", 0),
            "actual_appendices": spec.get("appendices", []),
        },
        "catalog_check": {
            "required_count": len(required),
            "missing": missing_catalog,
            "passed": len(missing_catalog) == 0,
        },
        "component_check": {
            "process_component_count": len(process_components),
            "material_component_count": len(material_components),
        },
        "rule_gate_check": {
            "rule_types": sorted(rule_types),
            "gate_logics": sorted(gate_logics),
        },
        "blockers": blockers,
        "passed": len(blockers) == 0,
    }


def _normalize_clause_tree_input(package: Dict[str, Any]) -> List[Dict[str, Any]]:
    raw = package.get("clause_tree")
    if isinstance(raw, list):
        return [x for x in raw if isinstance(x, dict)]
    if isinstance(raw, dict):
        roots = raw.get("roots")
        if isinstance(roots, list):
            return [x for x in roots if isinstance(x, dict)]
        nodes = raw.get("nodes")
        if isinstance(nodes, list):
            # fallback: treat as flat roots if no hierarchy payload
            return [x for x in nodes if isinstance(x, dict)]
    return []


def _clause_level_and_type(clause_id: str, title: str, content: str) -> Tuple[str, str]:
    text = f"{title} {content}".strip()
    lower = text.lower()
    metadata_patterns = [
        r"前言",
        r"起草单位",
        r"起草人",
        r"条文说明",
        r"修订说明",
        r"发布公告",
        r"负责起草",
        r"\.{3,}\s*\d+\s*$",
        r"…{3,}\s*\d+\s*$",
    ]
    if any(re.search(pattern, text, re.IGNORECASE) for pattern in metadata_patterns):
        return "metadata", "metadata"
    # 条文说明不应作为主条款，归为 explanation。
    if "条文说明" in text or "说明：" in text or "说明" == title.strip():
        return "explanation", "explanation"

    # 主条款编号识别（强规则）
    line = str(title or "").strip() or str(text).strip()
    if re.match(r"^\d+\s+.+", line):
        return "chapter", "chapter"
    if re.match(r"^\d+\.\d+\s+.+", line):
        return "section", "section"
    if re.match(r"^\d+\.\d+\.\d+\s+.+", line):
        return "article", "clause"
    if re.match(r"^表\s*\d+(?:\.\d+)*(?:-\d+)?\s+.+", line):
        return "table", "table"
    if title.strip().startswith("附录") or lower.startswith("appendix"):
        return "appendix", "appendix"
    if title.strip().startswith("表") or "表" in title:
        return "table", "table"
    parts = [p for p in clause_id.split(".") if p]
    if len(parts) <= 1:
        return "chapter", "chapter"
    if len(parts) == 2:
        return "section", "section"
    if len(parts) == 3:
        return "article", "clause"
    return "paragraph", "paragraph"


def _classify_clause_node(node: Dict[str, Any]) -> str:
    node_type = str(node.get("type", "")).strip()
    level = str(node.get("level", "")).strip()
    title = str(node.get("name", "")).strip()
    content = str(node.get("content", "")).strip()
    text = f"{title} {content}".strip()
    lower = text.lower()
    if node_type == "metadata" or level == "metadata":
        return "metadata"

    if node_type in {"chapter", "section"} or level in {"chapter", "section"}:
        return "catalog_node"
    if node_type == "appendix" or level == "appendix":
        return "non_executable"
    if node_type == "explanation" or level == "explanation":
        return "explanation"
    if node_type == "table" or level == "table":
        return "table_rule"

    if any(k in text for k in ["术语", "定义", "名词解释"]):
        return "definition"
    if any(k in text for k in ["参见", "引用", "按《", "按《", "依照"]):
        return "reference_rule"
    if any(k in text for k in ["每", "每次", "每层", "频率", "抽检", "抽查", "每..."]):
        return "sampling_requirement"
    if any(k in text for k in ["试验", "检测方法", "方法", "法"]):
        return "method_requirement"
    if any(k in text for k in ["材料", "材质", "级配", "配合比"]):
        return "material_requirement"
    if any(k in text for k in ["公式", "计算", "取值", "sqrt", "∑", "Σ", "÷", "×", "*", "/"]):
        return "formula_rule"
    if any(op in text for op in [">=", "<=", "＞=", "≤", "≥"]) or re.search(r"\d+(\.\d+)?\s*[-~～]\s*\d+(\.\d+)?", text):
        if re.search(r"\d+(\.\d+)?\s*[-~～]\s*\d+(\.\d+)?", text):
            return "range_rule"
        return "threshold_rule"
    if re.search(r"\d+(\.\d+)?\s*(mm|cm|m|MPa|kN|%|℃|kg|g)", text, re.IGNORECASE):
        return "threshold_rule"
    if any(k in text for k in ["应", "必须", "不得", "严禁", "宜"]):
        return "process_requirement"
    return "non_executable"


def _component_type_from_clause(
    clause_class: str,
    node_level: str,
    node_type: str,
) -> str:
    if node_level == "chapter":
        return "ChapterComponent"
    if node_level == "appendix" or node_type == "appendix":
        return "AppendixComponent"
    if clause_class == "process_requirement":
        return "ProcessComponent"
    if clause_class == "material_requirement":
        return "MaterialComponent"
    if clause_class == "method_requirement":
        return "MethodComponent"
    if clause_class in {"threshold_rule", "range_rule", "formula_rule"}:
        return "MeasuredItemComponent"
    if clause_class == "table_rule":
        return "TableComponent"
    if node_level == "section":
        return "WorkItemComponent"
    return "WorkItemComponent"


def _has_explicit_execution_signal(clause_class: str, source_text: str) -> bool:
    text = str(source_text or "").strip()
    if clause_class in {"threshold_rule", "range_rule", "formula_rule", "sampling_requirement"}:
        return True
    if clause_class in {"process_requirement", "material_requirement", "method_requirement"}:
        has_action = any(k in text for k in ["应", "必须", "不得", "核对", "检查", "编制", "检测", "试验"])
        has_judgement = bool(re.search(r"(>=|<=|≥|≤|>|<|\d+(\.\d+)?)", text))
        return bool(has_action and (has_judgement or any(k in text for k in ["完成", "合格", "不合格"])))
    return False


def _field_schema(
    name: str,
    label: str,
    ftype: str,
    unit: Optional[str],
    required: bool,
    source: str,
    validation: Dict[str, Any],
) -> Dict[str, Any]:
    return {
        "name": name,
        "label": label,
        "type": ftype,
        "unit": unit,
        "required": required,
        "source": source,
        "validation": validation,
        "input_enabled": source not in {"derived", "lookup"},
    }


def _build_dto_fields_for_component(component: Dict[str, Any], component_rules: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    # DTO is execution-only and must be derived from Rule + normRef.
    fields: List[Dict[str, Any]] = []
    seen: set[str] = set()
    for rule in component_rules:
        if not isinstance(rule, dict):
            continue
        field_name = str(rule.get("field", "")).strip()
        norm_ref = str(rule.get("norm_ref", "")).strip()
        if not field_name or not norm_ref:
            continue
        if field_name in seen:
            continue
        seen.add(field_name)
        unit = str(rule.get("unit", "")).strip() or None
        fields.append(
            {
                "name": field_name,
                "label": field_name,
                "type": "number",
                "unit": unit,
                "required": True,
                "source": "instrument",
                "norm_ref": norm_ref,
                "derived_from_rule_id": str(rule.get("rule_id", "")).strip(),
                "validation": {
                    "operator": str(rule.get("operator", "")).strip(),
                    "min": rule.get("min"),
                    "max": rule.get("max"),
                },
                "input_enabled": True,
            }
        )
    fields.extend(
        [
            _field_schema("measured_at", "检测时间", "datetime", None, True, "user_input", {}),
            _field_schema("instrument_id", "仪器编号", "string", None, False, "instrument", {"minLength": 1}),
        ]
    )
    return fields


def _rule_type_from_clause_class(clause_class: str) -> str:
    mapping = {
        "threshold_rule": "threshold",
        "range_rule": "range",
        "formula_rule": "formula",
        "sampling_requirement": "sampling",
        "process_requirement": "process_check",
        "method_requirement": "method_check",
        "material_requirement": "material_check",
        "table_rule": "table_lookup",
    }
    return mapping.get(clause_class, "process_check")


def _build_clause_tree_and_catalog(package: Dict[str, Any]) -> Dict[str, Any]:
    roots = _normalize_clause_tree_input(package)
    flat_catalog: List[Dict[str, Any]] = []
    all_nodes: List[Dict[str, Any]] = []
    source_metadata: List[Dict[str, Any]] = []
    section_clause_text_index: Dict[str, str] = {}

    def _cleanup_catalog_title(text: str) -> str:
        s = str(text or "").strip()
        if not s:
            return s
        s = re.sub(r"[·•\.。…\s]{3,}\d+\s*$", "", s)
        s = re.sub(r"\s+\d+\s*$", "", s)
        return s.strip() or str(text or "").strip()

    def _has_cjk(text: str) -> bool:
        return bool(re.search(r"[\u4e00-\u9fff]", str(text or "")))

    def _is_numeric_heavy(text: str) -> bool:
        s = str(text or "")
        if not s:
            return False
        digits = len(re.findall(r"\d", s))
        return digits >= 6 and (digits / max(1, len(s))) >= 0.28

    def _looks_like_table_metric_line(text: str) -> bool:
        s = str(text or "").strip()
        if not s:
            return False
        # Typical table metric rows: ranges and dense numeric tokens.
        if re.search(r"[~～]\s*\d", s):
            return True
        if len(re.findall(r"\d+(?:\.\d+)?", s)) >= 4 and not _has_cjk(s):
            return True
        if _is_numeric_heavy(s) and len(re.findall(r"\d+(?:\.\d+)?", s)) >= 4:
            return True
        return False

    def _is_valid_catalog_id(no: str, ctype: str) -> bool:
        nid = str(no or "").strip()
        if not nid:
            return False
        if ctype == "chapter":
            return bool(re.fullmatch(r"[1-9]\d?", nid))
        if ctype == "section":
            return bool(re.fullmatch(r"[1-9]\d?\.[1-9]\d?", nid))
        if ctype == "clause":
            return bool(re.fullmatch(r"[1-9]\d?\.[1-9]\d?\.[1-9]\d?", nid))
        if ctype == "table":
            return bool(re.fullmatch(r"[1-9]\d?(?:\.[1-9]\d?)*(?:-[1-9]\d?)?", nid))
        return False

    def _is_probable_heading(no: str, ctype: str, title: str, line: str) -> bool:
        ttl = str(title or "").strip()
        src = str(line or "").strip()
        if not ttl and not src:
            return False
        if _looks_like_table_metric_line(src) or _looks_like_table_metric_line(ttl):
            return False
        if ctype in {"chapter", "section", "clause"} and not _has_cjk(ttl or src):
            return False
        if ctype == "chapter":
            if re.search(r"[~～]", ttl) or re.search(r"\d+\.\d+", ttl):
                return False
            if _is_numeric_heavy(ttl):
                return False
        if ctype in {"chapter", "section"}:
            # Headings are usually noun phrases, not long requirement sentences.
            if len(ttl) >= 26 and re.search(r"[，。；：:]", ttl):
                return False
            if len(ttl) >= 22 and ("应" in ttl or "不得" in ttl or "宜" in ttl):
                return False
        return _is_valid_catalog_id(no, ctype)

    def _catalog_sort_key(row: Dict[str, Any]) -> Tuple[int, Tuple[int, ...], str]:
        t = str((row or {}).get("type", "")).strip().lower()
        rid = str((row or {}).get("id", "")).strip()
        type_rank = {"chapter": 1, "section": 2, "clause": 3, "table": 4}.get(t, 9)
        nums = tuple(int(x) for x in re.findall(r"\d+", rid)) if rid else tuple()
        return (type_rank, nums, rid)

    def _is_likely_truncated_text(text: str) -> bool:
        s = str(text or "").strip()
        if not s:
            return True
        # Ends with connective / function word and lacks terminal punctuation.
        if (not re.search(r"[。！？；：:]$", s)) and re.search(r"[并及与或运按由应将为在对从向至于其该等时后前内外上下一二三四五六七八九十]$", s):
            return True
        # Long single line clause text without terminal punctuation is often cut.
        if len(s) >= 20 and ("\n" not in s) and (not re.search(r"[。！？；：:]$", s)):
            return True
        return False

    def _build_section_clause_text_index() -> Dict[str, str]:
        out: Dict[str, str] = {}
        grouped: Dict[str, List[str]] = {}
        sections = package.get("sections", [])
        if not isinstance(sections, list):
            return out
        for sec in sections:
            if not isinstance(sec, dict):
                continue
            no_raw = str(sec.get("section_no", "") or "").strip()
            title_raw = str(sec.get("section_title", "") or "").strip()
            line = f"{no_raw} {title_raw}".strip()
            clause_no = ""
            if re.fullmatch(r"\d+\.\d+\.\d+", no_raw):
                clause_no = no_raw
            else:
                m = re.match(r"^\s*(\d+\.\d+\.\d+)\s*(.*)$", line)
                if m:
                    clause_no = str(m.group(1) or "").strip()
                    if not title_raw:
                        title_raw = str(m.group(2) or "").strip()
            if not clause_no:
                continue
            if title_raw:
                grouped.setdefault(clause_no, [])
                grouped[clause_no].append(title_raw)
        for cid, chunks in grouped.items():
            deduped: List[str] = []
            seen: set[str] = set()
            for c in chunks:
                norm = re.sub(r"\s+", "", str(c or ""))
                if not norm or norm in seen:
                    continue
                seen.add(norm)
                deduped.append(str(c).strip())
            merged = "".join(deduped).strip()
            if merged:
                out[cid] = merged
        return out

    def _extract_catalog_candidates(raw_id: str, raw_title: str, raw_text: str) -> List[Tuple[str, str, str]]:
        candidates: List[Tuple[str, str, str]] = []
        rid = str(raw_id or "").strip()
        title = str(raw_title or "").strip()
        text = str(raw_text or "").strip()
        line = title or text
        if "条文说明" in line:
            return candidates

        m_ch = re.match(r"^\s*第?\s*(\d+)\s*章[：:、，.\s]*(.*)$", line)
        if m_ch:
            no = m_ch.group(1).strip()
            ttl = _cleanup_catalog_title(m_ch.group(2).strip() or line)
            if _is_probable_heading(no, "chapter", ttl, line):
                candidates.append((no, "chapter", ttl or no))
        m_ch2 = re.match(r"^\s*(\d+)(?:\s+|[：:、，,.。])(.+)$", line)
        if m_ch2:
            no = m_ch2.group(1).strip()
            ttl = _cleanup_catalog_title(m_ch2.group(2).strip())
            if _is_probable_heading(no, "chapter", ttl, line):
                candidates.append((no, "chapter", ttl or no))

        m_sec = re.match(r"^\s*(\d+\.\d+)(?:\s+|[：:、，,.。])?(.*)$", line)
        if m_sec:
            no = m_sec.group(1).strip()
            ttl = _cleanup_catalog_title(m_sec.group(2).strip() or line)
            if _is_probable_heading(no, "section", ttl, line):
                candidates.append((no, "section", ttl or no))

        m_clause = re.match(r"^\s*(\d+\.\d+\.\d+)(?:\s+|[：:、，,.。])?(.*)$", line)
        if m_clause:
            no = m_clause.group(1).strip()
            ttl = _cleanup_catalog_title(m_clause.group(2).strip() or line)
            if _is_probable_heading(no, "clause", ttl, line):
                candidates.append((no, "clause", ttl or no))

        m_table = re.match(r"^\s*表\s*(\d+(?:\.\d+)*(?:-\d+)?)(?:\s+|[：:、，,.。])?(.*)$", line)
        if m_table:
            no = m_table.group(1).strip()
            ttl = _cleanup_catalog_title(m_table.group(2).strip() or f"表 {no}")
            if _is_probable_heading(no, "table", ttl, line):
                candidates.append((no, "table", ttl or f"表 {no}"))

        if rid:
            if re.fullmatch(r"\d+\.\d+\.\d+", rid):
                ttl = _cleanup_catalog_title(title or rid)
                if _is_probable_heading(rid, "clause", ttl, line):
                    candidates.append((rid, "clause", ttl))
            elif re.fullmatch(r"\d+\.\d+", rid):
                ttl = _cleanup_catalog_title(title or rid)
                if _is_probable_heading(rid, "section", ttl, line):
                    candidates.append((rid, "section", ttl))
            elif re.fullmatch(r"\d+", rid):
                ttl = _cleanup_catalog_title(title or rid)
                if _is_probable_heading(rid, "chapter", ttl, line):
                    candidates.append((rid, "chapter", ttl))
            elif re.fullmatch(r"\d+(?:\.\d+)*(?:-\d+)?", rid):
                ttl = _cleanup_catalog_title(title or rid)
                if _is_probable_heading(rid, "table", ttl, line):
                    candidates.append((rid, "table", ttl))

        seen: set[Tuple[str, str]] = set()
        out: List[Tuple[str, str, str]] = []
        for no, ctype, ttl in candidates:
            k = (no, ctype)
            if not no or k in seen:
                continue
            seen.add(k)
            out.append((no, ctype, ttl))
        return out

    def is_catalog_node(node_type: str) -> bool:
        normalized = str(node_type or "").strip().lower()
        return normalized in {"chapter", "section", "clause", "table"}

    def _catalog_type_from_id_or_text(raw_id: str, raw_title: str, raw_text: str) -> str:
        rid = str(raw_id or "").strip()
        text = f"{raw_title} {raw_text}".strip()
        if "条文说明" in text:
            return ""
        line = str(raw_title or "").strip() or str(text).strip()
        # Support patterns with/without spaces:
        # 1 总则 / 1.1 一般规定 / 1.1.1 桥涵工程... / 表4.2.6 ...
        if re.match(r"^表\s*\d+(?:\.\d+)*(?:-\d+)?(?:\s+.+)?$", line):
            return "table"
        if re.match(r"^\d+\.\d+\.\d+(?:\s+|[：:、，,.。])?.+", line):
            return "clause"
        if re.match(r"^\d+\.\d+(?:\s+|[：:、，,.。])?.+", line):
            return "section"
        if re.match(r"^\d+(?:\s+|[：:、，,.。])?.+", line) and not _looks_like_table_metric_line(line):
            return "chapter"
        if re.search(r"表\s*\d+(?:\.\d+){1,3}(?:-\d+)?", text):
            return "table"
        if re.search(r"^第\s*\d+\s*章", text):
            return "chapter"
        if re.fullmatch(r"[1-9]\d?", rid):
            return "chapter"
        if re.fullmatch(r"\d+\.\d+\.\d+", rid):
            return "clause"
        if re.fullmatch(r"\d+\.\d+", rid):
            return "section"
        if re.fullmatch(r"[1-9]\d?(?:\.[1-9]\d?)*(?:-[1-9]\d?)?", rid):
            return "table"
        return ""

    def _extract_catalog_id_from_text(raw_id: str, raw_title: str, raw_text: str, ctype: str) -> str:
        rid = str(raw_id or "").strip()
        if rid:
            return rid
        line = str(raw_title or "").strip() or str(raw_text or "").strip()
        if ctype == "table":
            m_table = re.search(r"表\s*(\d+(?:\.\d+)*(?:-\d+)?)", line)
            if m_table:
                return m_table.group(1)
        if ctype == "clause":
            m_clause = re.match(r"^\s*(\d+\.\d+\.\d+)", line)
            if m_clause:
                return m_clause.group(1)
        if ctype == "section":
            m_section = re.match(r"^\s*(\d+\.\d+)", line)
            if m_section:
                return m_section.group(1)
        if ctype == "chapter":
            m_chapter = re.match(r"^\s*(\d+)", line)
            if m_chapter:
                return m_chapter.group(1)
        return rid

    def _parent_id_for_catalog(raw_id: str, ctype: str) -> Optional[str]:
        rid = str(raw_id or "").strip()
        nums = [x for x in rid.split(".") if x]
        if ctype == "chapter":
            return None
        if ctype == "section" and len(nums) >= 2:
            return nums[0]
        if ctype == "clause" and len(nums) >= 3:
            return f"{nums[0]}.{nums[1]}"
        if ctype == "table":
            if len(nums) >= 3:
                return f"{nums[0]}.{nums[1]}.{nums[2]}"
            if len(nums) >= 2:
                return f"{nums[0]}.{nums[1]}"
        return None

    catalog_index: Dict[Tuple[str, str], Dict[str, Any]] = {}

    def _add_catalog_node(
        *,
        cid: str,
        ctype: str,
        title: str,
        parent_id: Optional[str],
        page: int,
        source_text: str,
    ) -> None:
        norm_id = str(cid or "").strip()
        norm_type = str(ctype or "").strip().lower()
        if not norm_id or norm_type not in {"chapter", "section", "clause", "table"}:
            return
        if not _is_valid_catalog_id(norm_id, norm_type):
            return
        if not _is_probable_heading(norm_id, norm_type, title, source_text):
            return
        key = (norm_type, norm_id)
        row = {
            "id": norm_id,
            "type": norm_type,
            "title": str(title or norm_id).strip() or norm_id,
            "parent_id": str(parent_id).strip() if parent_id else None,
            "page": int(page or 0),
            "source_text": str(source_text or title or norm_id).strip() or norm_id,
            # backward compatibility
            "name": str(title or norm_id).strip() or norm_id,
            "source_page": int(page or 0),
        }
        if key not in catalog_index:
            catalog_index[key] = row
        else:
            existing = catalog_index[key]
            if not existing.get("page") and row.get("page"):
                existing["page"] = row["page"]
                existing["source_page"] = row["source_page"]
            if len(str(existing.get("source_text", "")).strip()) < len(str(row.get("source_text", "")).strip()):
                existing["source_text"] = row["source_text"]
            if len(str(existing.get("title", "")).strip()) < len(str(row.get("title", "")).strip()):
                existing["title"] = row["title"]
                existing["name"] = row["name"]

    section_clause_text_index = _build_section_clause_text_index()

    def walk(items: List[Dict[str, Any]], parent_id: str = "") -> List[Dict[str, Any]]:
        result: List[Dict[str, Any]] = []
        for item in items:
            if not isinstance(item, dict):
                continue
            cid = str(item.get("clause_id") or item.get("id") or "").strip()
            if not cid:
                continue
            title = str(item.get("title") or item.get("name") or cid).strip()
            content = str(item.get("content") or item.get("text") or "").strip()
            source_text = str(item.get("source_text") or content or title).strip()
            # Prefer richer section-derived text for clause nodes (fix cross-page truncation from upstream parser).
            source_from_sections = str(section_clause_text_index.get(cid, "")).strip()
            if source_from_sections:
                source_full_candidate = source_from_sections
                if (
                    len(source_full_candidate) > len(source_text)
                    or _is_likely_truncated_text(source_text)
                ):
                    source_text = source_full_candidate
                    if (not str(content or "").strip()) or (len(source_full_candidate) > len(str(content or "").strip())):
                        content = source_full_candidate
                    if re.fullmatch(r"\d+\.\d+\.\d+", cid):
                        # Keep title as clause headline (without repeated id prefix)
                        title = re.sub(rf"^\s*{re.escape(cid)}\s*", "", source_full_candidate).strip() or title
            page_no = item.get("page_no", item.get("page"))
            page_start = int(page_no) if isinstance(page_no, int) else 0
            page_end = int(item.get("page_end")) if isinstance(item.get("page_end"), int) else page_start
            level, node_type = _clause_level_and_type(cid, title, content)
            catalog_node_type = _catalog_type_from_id_or_text(cid, title, source_text)
            children_raw = item.get("children")
            children_input = [c for c in children_raw if isinstance(c, dict)] if isinstance(children_raw, list) else []
            node = {
                "clause_id": cid,
                "title": title,
                "content": content,
                "parent_id": parent_id or None,
                "level": level,
                "node_type": node_type,
                "page_start": page_start,
                "page_end": page_end,
                "source_text": source_text,
                "executable": False if node_type in {"metadata", "explanation"} else True,
                "children": [],
            }
            node["children"] = walk(children_input, cid)
            result.append(node)
            node_row = {
                "id": cid,
                "title": title,
                "name": title,
                "content": content,
                "type": node_type,
                "parent_id": parent_id or None,
                "children": [str(ch.get("clause_id", "")) for ch in node["children"]],
                "page": page_start,
                "source_page": page_start,
                "page_end": page_end,
                "level": level,
                "source_text": source_text,
            }
            all_nodes.append(node_row)
            # primary path
            if is_catalog_node(catalog_node_type):
                catalog_id = _extract_catalog_id_from_text(cid, title, source_text, catalog_node_type)
                _add_catalog_node(
                    cid=catalog_id,
                    ctype=catalog_node_type,
                    title=_cleanup_catalog_title(title),
                    parent_id=_parent_id_for_catalog(catalog_id, catalog_node_type),
                    page=page_start,
                    source_text=source_text,
                )
            # generic extraction path for messy PDFs
            for no, ctype, ttl in _extract_catalog_candidates(cid, title, source_text):
                _add_catalog_node(
                    cid=no,
                    ctype=ctype,
                    title=ttl,
                    parent_id=_parent_id_for_catalog(no, ctype),
                    page=page_start,
                    source_text=source_text,
                )
            if node_type == "metadata":
                source_metadata.append(
                    {
                        "clause_id": cid,
                        "title": title,
                        "content": content,
                        "parent_id": parent_id or None,
                        "source_page": page_start,
                        "page_end": page_end,
                        "source_text": source_text,
                        "node_type": "metadata",
                        "executable": False,
                    }
                )
        return result

    tree = walk(roots, "")
    sections = package.get("sections", [])
    if isinstance(sections, list):
        for section in sections:
            if not isinstance(section, dict):
                continue
            sec_no = str(section.get("section_no", "")).strip()
            sec_title = str(section.get("section_title", "")).strip() or sec_no
            sec_text = f"{sec_no} {sec_title}".strip()
            page_no = int(section.get("page_no", 0) or 0)
            ctype = _catalog_type_from_id_or_text(sec_no, sec_title, sec_text)
            if is_catalog_node(ctype):
                catalog_id = _extract_catalog_id_from_text(sec_no, sec_title, sec_text, ctype)
                _add_catalog_node(
                    cid=catalog_id,
                    ctype=ctype,
                    title=_cleanup_catalog_title(sec_title),
                    parent_id=_parent_id_for_catalog(catalog_id, ctype),
                    page=page_no,
                    source_text=sec_text,
                )
            for no, ctype2, ttl in _extract_catalog_candidates(sec_no, sec_title, sec_text):
                _add_catalog_node(
                    cid=no,
                    ctype=ctype2,
                    title=ttl,
                    parent_id=_parent_id_for_catalog(no, ctype2),
                    page=page_no,
                    source_text=sec_text,
                )
            table_hits = re.findall(r"表\s*(\d+(?:\.\d+){1,3}(?:-\d+)?)", sec_text)
            for table_id in table_hits:
                _add_catalog_node(
                    cid=table_id,
                    ctype="table",
                    title=f"表 {table_id}",
                    parent_id=_parent_id_for_catalog(table_id, "table"),
                    page=page_no,
                    source_text=sec_text,
                )

    # Do not build Catalog from candidate source lines.
    # Candidate lines may include table metric rows and body fragments that cause
    # heavy false positives (e.g. "0~25 ..."), polluting chapter/section nodes.

    # Ensure chapter nodes exist when only section/clause/table are detected.
    inferred_chapters: Dict[str, int] = {}
    for row in list(catalog_index.values()):
        rid = str(row.get("id", "")).strip()
        rtype = str(row.get("type", "")).strip().lower()
        if rtype in {"section", "clause", "table"} and rid:
            chapter_id = rid.split(".")[0]
            if chapter_id.isdigit():
                page = int(row.get("page", 0) or 0)
                prev = inferred_chapters.get(chapter_id, 0)
                inferred_chapters[chapter_id] = page if prev == 0 else min(prev, page)
    for chapter_id, page in inferred_chapters.items():
        _add_catalog_node(
            cid=chapter_id,
            ctype="chapter",
            title=f"第{chapter_id}章",
            parent_id=None,
            page=page,
            source_text=f"第{chapter_id}章",
        )

    flat_catalog = sorted(catalog_index.values(), key=_catalog_sort_key)

    std_code = str(package.get("std_code", "") or "")
    pkg_title = str(package.get("title", "") or "")
    if _is_jtgt3650_spec(std_code, pkg_title):
        max_ch = int(JTG_T_3650_PROFILE.get("chapters", 27) or 27)
        cleaned: List[Dict[str, Any]] = []
        for row in flat_catalog:
            if not isinstance(row, dict):
                continue
            rid = str(row.get("id", "")).strip()
            rtype = str(row.get("type", "")).strip().lower()
            title = str(row.get("title") or row.get("name") or "").strip()
            if not rid or rtype not in {"chapter", "section", "clause", "table"}:
                continue
            nums = [int(x) for x in re.findall(r"\d+", rid)]
            if nums:
                if nums[0] <= 0 or nums[0] > max_ch:
                    continue
            if rtype in {"chapter", "section"}:
                # Extra cleanup: remove sentence-like rows from catalog hierarchy.
                if len(title) >= 24 and re.search(r"[，。；：:]", title):
                    continue
                if len(title) >= 20 and ("应" in title or "不得" in title or "宜" in title):
                    continue
            cleaned.append(row)
        flat_catalog = sorted(cleaned, key=_catalog_sort_key)
    return {"clause_tree": tree, "catalog": flat_catalog, "all_nodes": all_nodes, "source_metadata": source_metadata}


def _layout_semantic_type_for_clause_node(node: Dict[str, Any]) -> Tuple[str, str]:
    ntype = str(node.get("type", "")).strip().lower()
    title = str(node.get("name") or node.get("title") or "").strip().lower()
    content = str(node.get("content") or "").strip().lower()
    text = f"{title} {content}"
    if ntype in {"chapter", "section"}:
        return "title", "heading"
    if ntype == "table":
        if any(k in text for k in ["允许偏差", "偏差", "公差", "tolerance"]):
            return "tolerance_table", "constraint_table"
        return "tolerance_table", "table"
    if any(k in text for k in ["注：", "备注", "note"]):
        return "note", "annotation"
    if any(k in text for k in ["应", "不得", "必须", "shall", "should"]):
        return "constraint", "requirement"
    return "clause", "body_clause"


def _extract_formula_variables_and_operators(expr: str) -> Tuple[List[str], List[str]]:
    raw = str(expr or "").strip()
    if not raw:
        return [], []
    vars_found = sorted(list(set(re.findall(r"[A-Za-z_][A-Za-z0-9_]*", raw))))
    # filter trivial function-like tokens that are not variables in this context
    blacklist = {"min", "max", "abs", "pow", "sqrt", "sin", "cos", "tan", "log", "ln", "exp", "lookup"}
    vars_found = [v for v in vars_found if v.lower() not in blacklist]
    ops: List[str] = []
    for op in [">=", "<=", "==", "!=", "&&", "||", "+", "-", "*", "/", ">", "<", "=", "(", ")"]:
        if op in raw:
            ops.append(op)
    return vars_found, ops


def _analyze_table_semantics(table_obj: Dict[str, Any], idx: int) -> Dict[str, Any]:
    title = str(table_obj.get("title") or table_obj.get("name") or table_obj.get("table_name") or f"table_{idx+1}").strip()
    table_id = str(table_obj.get("table_id") or table_obj.get("id") or f"table_{idx+1}").strip()
    rows = table_obj.get("rows", [])
    if not isinstance(rows, list):
        rows = []
    header_rows: List[int] = []
    unit_columns: List[int] = []
    tolerance_columns: List[int] = []
    # lightweight heuristics for semi-structured extraction
    for r_idx, row in enumerate(rows):
        if not isinstance(row, list):
            continue
        row_text = " ".join([str(x or "") for x in row]).lower()
        if r_idx == 0 or any(k in row_text for k in ["指标", "项目", "单位", "允许偏差", "偏差", "公差", "unit", "tolerance"]):
            header_rows.append(r_idx)
        for c_idx, cell in enumerate(row):
            cell_s = str(cell or "").strip().lower()
            if any(u in cell_s for u in ["mm", "cm", "m", "%", "℃", "mpa", "kn", "kg", "单位", "unit"]):
                if c_idx not in unit_columns:
                    unit_columns.append(c_idx)
            if any(t in cell_s for t in ["允许偏差", "偏差", "公差", "±", "<=", ">=", "lt", "lte", "gte", "tolerance"]):
                if c_idx not in tolerance_columns:
                    tolerance_columns.append(c_idx)
    return {
        "table_id": table_id,
        "title": title,
        "semantic_type": "tolerance_table",
        "semantic_role": "constraint_table",
        "header_rows": sorted(list(set(header_rows))),
        "unit_columns": sorted(unit_columns),
        "tolerance_columns": sorted(tolerance_columns),
        "row_count": len(rows),
    }


def _build_layout_semantic_ir(
    *,
    spec: Dict[str, Any],
    clause_tree_nodes: List[Dict[str, Any]],
    table_structured: List[Dict[str, Any]],
    formulas: List[Dict[str, Any]],
) -> Dict[str, Any]:
    blocks: List[Dict[str, Any]] = []
    for node in clause_tree_nodes:
        if not isinstance(node, dict):
            continue
        semantic_type, semantic_role = _layout_semantic_type_for_clause_node(node)
        blocks.append(
            {
                "block_id": str(node.get("id") or node.get("clause_id") or f"block_{len(blocks)+1}").strip(),
                "title": str(node.get("name") or node.get("title") or "").strip(),
                "content": str(node.get("content") or "").strip(),
                "node_type": str(node.get("type") or "").strip(),
                "parent_id": node.get("parent_id"),
                "semantic_type": semantic_type,
                "semantic_role": semantic_role,
            }
        )
    table_items = [_analyze_table_semantics(t, i) for i, t in enumerate(table_structured) if isinstance(t, dict)]
    formula_items: List[Dict[str, Any]] = []
    for i, f in enumerate(formulas):
        if not isinstance(f, dict):
            continue
        latex = str(f.get("latex") or f.get("formula") or f.get("expr") or "").strip()
        variables, operators = _extract_formula_variables_and_operators(latex)
        formula_items.append(
            {
                "formula_id": str(f.get("formula_id") or f.get("id") or f"formula_{i+1}").strip(),
                "semantic_type": "formula",
                "semantic_role": "calculation_constraint",
                "latex": latex,
                "variables": variables,
                "operators": operators,
            }
        )
        blocks.append(
            {
                "block_id": str(f.get("formula_id") or f.get("id") or f"formula_{i+1}").strip(),
                "title": str(f.get("name") or "formula").strip(),
                "content": latex,
                "semantic_type": "formula",
                "semantic_role": "calculation_constraint",
            }
        )
    for i, t in enumerate(table_items):
        blocks.append(
            {
                "block_id": str(t.get("table_id") or f"table_{i+1}"),
                "title": str(t.get("title") or ""),
                "content": "",
                "semantic_type": str(t.get("semantic_type") or "tolerance_table"),
                "semantic_role": str(t.get("semantic_role") or "constraint_table"),
            }
        )
    return {
        "valid": True,
        "schema_version": "layout_semantic_ir.v1",
        "spec_code": str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        "generated_at": _utc_now(),
        "count": len(blocks),
        "blocks": blocks,
        "tables": table_items,
        "formulas": formula_items,
    }


def _build_cross_page_context(
    *,
    spec: Dict[str, Any],
    clause_tree_nodes: List[Dict[str, Any]],
    table_structured: List[Dict[str, Any]],
) -> Dict[str, Any]:
    id_map: Dict[str, Dict[str, Any]] = {}
    clause_rows: List[Dict[str, Any]] = []
    for n in clause_tree_nodes:
        if not isinstance(n, dict):
            continue
        nid = str(n.get("id") or n.get("clause_id") or "").strip()
        if nid:
            id_map[nid] = n
        ntype = str(n.get("type") or n.get("node_type") or "").strip().lower()
        if ntype not in {"clause", "paragraph"}:
            continue
        page_start = int(n.get("source_page", n.get("page", 0)) or 0)
        page_end = int(n.get("page_end", page_start) or page_start)
        clause_rows.append(
            {
                "clause_id": nid or f"clause_{len(clause_rows)+1}",
                "title": str(n.get("title") or n.get("name") or "").strip(),
                "content": str(n.get("content") or "").strip(),
                "parent_id": str(n.get("parent_id") or "").strip(),
                "page_start": page_start,
                "page_end": page_end,
            }
        )
    clause_rows.sort(key=lambda x: (int(x.get("page_start", 0) or 0), str(x.get("clause_id", ""))))
    clause_out: List[Dict[str, Any]] = []
    for i, row in enumerate(clause_rows):
        parent_id = str(row.get("parent_id") or "").strip()
        parent_section = ""
        probe = parent_id
        while probe:
            p = id_map.get(probe, {})
            ptype = str((p or {}).get("type") or (p or {}).get("node_type") or "").strip().lower()
            if ptype in {"section", "chapter"}:
                parent_section = probe
                break
            probe = str((p or {}).get("parent_id") or "").strip()
        clause_out.append(
            {
                "clause_id": str(row.get("clause_id") or ""),
                "page_start": int(row.get("page_start", 0) or 0),
                "page_end": int(row.get("page_end", 0) or 0),
                "previous_clause": str((clause_rows[i - 1].get("clause_id") if i > 0 else "") or ""),
                "next_clause": str((clause_rows[i + 1].get("clause_id") if i + 1 < len(clause_rows) else "") or ""),
                "parent_section": parent_section,
            }
        )

    # Long clause auto-merge (cross-page fragments)
    merged_clauses: List[Dict[str, Any]] = []
    i = 0
    while i < len(clause_rows):
        cur = clause_rows[i]
        merged_ids = [str(cur.get("clause_id") or "")]
        merged_content = str(cur.get("content") or "")
        page_start = int(cur.get("page_start", 0) or 0)
        page_end = int(cur.get("page_end", page_start) or page_start)
        j = i + 1
        while j < len(clause_rows):
            nxt = clause_rows[j]
            same_parent = str(nxt.get("parent_id") or "") == str(cur.get("parent_id") or "")
            title_a = str(cur.get("title") or "").strip()
            title_b = str(nxt.get("title") or "").strip()
            similar_title = bool(title_a and title_b and (title_a == title_b or title_a in title_b or title_b in title_a))
            contiguous_pages = int(nxt.get("page_start", 0) or 0) <= (page_end + 1)
            short_fragment = len(str(nxt.get("content") or "").strip()) < 220
            if same_parent and contiguous_pages and (similar_title or short_fragment):
                merged_ids.append(str(nxt.get("clause_id") or ""))
                part = str(nxt.get("content") or "")
                if part:
                    merged_content = (merged_content + "\n" + part).strip() if merged_content else part
                page_end = max(page_end, int(nxt.get("page_end", nxt.get("page_start", 0)) or 0))
                j += 1
                continue
            break
        merged_clauses.append(
            {
                "clause_id": str(cur.get("clause_id") or ""),
                "merged_clause_ids": [x for x in merged_ids if x],
                "merged": len(merged_ids) > 1,
                "page_start": page_start,
                "page_end": page_end,
                "content": merged_content,
            }
        )
        i = j

    # Table continuation + inherited header
    table_rows: List[Dict[str, Any]] = []
    sorted_tables = [t for t in table_structured if isinstance(t, dict)]
    sorted_tables.sort(key=lambda x: int(x.get("page_start", x.get("page_no", x.get("page", 0))) or 0))
    prev_by_key: Dict[str, Dict[str, Any]] = {}
    for idx, t in enumerate(sorted_tables):
        table_id = str(t.get("table_id") or t.get("id") or f"table_{idx+1}").strip()
        title = str(t.get("title") or t.get("name") or "").strip()
        key = table_id or title
        page_start = int(t.get("page_start", t.get("page_no", t.get("page", 0))) or 0)
        rows = t.get("rows", [])
        if not isinstance(rows, list):
            rows = []
        first_row = rows[0] if rows and isinstance(rows[0], list) else []
        prev = prev_by_key.get(key)
        continued_table = False
        inherited_header = False
        inherited_header_rows: List[Any] = []
        if prev:
            prev_page = int(prev.get("page_start", 0) or 0)
            if page_start >= prev_page and (page_start - prev_page) <= 1:
                continued_table = True
                prev_header = prev.get("header_rows", []) if isinstance(prev.get("header_rows"), list) else []
                prev_first = prev_header[0] if prev_header and isinstance(prev_header[0], list) else []
                if prev_first and first_row and prev_first != first_row:
                    inherited_header = True
                    inherited_header_rows = prev_header
        row = {
            "table_id": table_id,
            "title": title,
            "page_start": page_start,
            "continued_table": continued_table,
            "inherited_header": inherited_header,
            "inherited_header_rows": inherited_header_rows,
        }
        table_rows.append(row)
        prev_by_key[key] = {"page_start": page_start, "header_rows": [first_row] if first_row else []}

    return {
        "valid": True,
        "schema_version": "cross_page_context.v1",
        "spec_code": str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        "generated_at": _utc_now(),
        "count": len(clause_out) + len(table_rows),
        "clauses": clause_out,
        "tables": table_rows,
        "merged_clauses": merged_clauses,
    }


def _extract_semantic_triples_from_text(text: str, clause_id: str) -> List[Dict[str, Any]]:
    s = str(text or "").strip()
    if not s:
        return []
    out: List[Dict[str, Any]] = []
    condition = ""
    m_cond = re.search(r"(?:当|在)(.+?)(?:时|情况下)[，,]", s)
    if m_cond:
        condition = str(m_cond.group(1) or "").strip()

    # between: 压浆压力应为0.5~0.7MPa
    for m in re.finditer(
        r"(?P<subject>[\u4e00-\u9fffA-Za-z0-9_（）()/%·\-\s]{1,40}?)\s*(?:应|应当|须|必须)?(?:为|在)?\s*"
        r"(?P<min>-?\d+(?:\.\d+)?)\s*(?:~|～|至|到|-)\s*(?P<max>-?\d+(?:\.\d+)?)\s*"
        r"(?P<unit>MPa|kPa|Pa|mm|cm|m|%|℃|°C|kg|kN|N)?",
        s,
        re.IGNORECASE,
    ):
        subject = str(m.group("subject") or "").strip(" ：:，,。;；")
        if not subject:
            continue
        out.append(
            {
                "clause_id": clause_id,
                "subject": subject,
                "condition": condition,
                "operator": "between",
                "min": float(m.group("min")),
                "max": float(m.group("max")),
                "unit": str(m.group("unit") or "").strip(),
                "raw_text": s,
            }
        )

    # >=
    for m in re.finditer(
        r"(?P<subject>[\u4e00-\u9fffA-Za-z0-9_（）()/%·\-\s]{1,40}?)\s*(?:应|应当|须|必须)?(?:不小于|不少于|≥|>=)\s*(?P<val>-?\d+(?:\.\d+)?)\s*(?P<unit>MPa|kPa|Pa|mm|cm|m|%|℃|°C|kg|kN|N)?",
        s,
        re.IGNORECASE,
    ):
        subject = str(m.group("subject") or "").strip(" ：:，,。;；")
        if not subject:
            continue
        out.append(
            {
                "clause_id": clause_id,
                "subject": subject,
                "condition": condition,
                "operator": ">=",
                "min": float(m.group("val")),
                "max": None,
                "unit": str(m.group("unit") or "").strip(),
                "raw_text": s,
            }
        )

    # <=
    for m in re.finditer(
        r"(?P<subject>[\u4e00-\u9fffA-Za-z0-9_（）()/%·\-\s]{1,40}?)\s*(?:应|应当|须|必须)?(?:不大于|不超过|≤|<=)\s*(?P<val>-?\d+(?:\.\d+)?)\s*(?P<unit>MPa|kPa|Pa|mm|cm|m|%|℃|°C|kg|kN|N)?",
        s,
        re.IGNORECASE,
    ):
        subject = str(m.group("subject") or "").strip(" ：:，,。;；")
        if not subject:
            continue
        out.append(
            {
                "clause_id": clause_id,
                "subject": subject,
                "condition": condition,
                "operator": "<=",
                "min": None,
                "max": float(m.group("val")),
                "unit": str(m.group("unit") or "").strip(),
                "raw_text": s,
            }
        )

    # enum: 应为A/B/C...
    m_enum = re.search(r"(?P<subject>[\u4e00-\u9fffA-Za-z0-9_（）()/%·\-\s]{1,40}?)\s*(?:应|应当|须|必须)?(?:为|采用)\s*(?P<vals>[^。；;]{2,80})", s)
    if m_enum:
        subject = str(m_enum.group("subject") or "").strip(" ：:，,。;；")
        vals_raw = str(m_enum.group("vals") or "").strip()
        enum_vals = [x.strip() for x in re.split(r"[、,，/或及和]", vals_raw) if str(x).strip()]
        if subject and len(enum_vals) >= 2 and all(len(x) <= 20 for x in enum_vals[:8]):
            out.append(
                {
                    "clause_id": clause_id,
                    "subject": subject,
                    "condition": condition,
                    "operator": "enum",
                    "enum_values": enum_vals[:12],
                    "raw_text": s,
                }
            )

    # exists: 应有/应设置/应配备/应包括...
    m_exists = re.search(r"(?P<subject>[\u4e00-\u9fffA-Za-z0-9_（）()/%·\-\s]{1,40}?)(?:应|应当|须|必须)(?:有|设置|配备|包括|具备)", s)
    if m_exists:
        subject = str(m_exists.group("subject") or "").strip(" ：:，,。;；")
        if subject:
            out.append(
                {
                    "clause_id": clause_id,
                    "subject": subject,
                    "condition": condition,
                    "operator": "exists",
                    "raw_text": s,
                }
            )

    # de-dup
    uniq: Dict[str, Dict[str, Any]] = {}
    for item in out:
        key = _stable_json_hash(
            {
                "clause_id": str(item.get("clause_id") or ""),
                "subject": str(item.get("subject") or ""),
                "condition": str(item.get("condition") or ""),
                "operator": str(item.get("operator") or ""),
                "min": item.get("min"),
                "max": item.get("max"),
                "unit": str(item.get("unit") or ""),
                "enum_values": item.get("enum_values", []),
            }
        )
        uniq[key] = item
    return list(uniq.values())


def _build_semantic_triples_artifact(*, spec: Dict[str, Any], clause_tree_nodes: List[Dict[str, Any]]) -> Dict[str, Any]:
    triples: List[Dict[str, Any]] = []
    for n in clause_tree_nodes:
        if not isinstance(n, dict):
            continue
        ntype = str(n.get("type") or n.get("node_type") or "").strip().lower()
        if ntype not in {"clause", "paragraph", "table"}:
            continue
        cid = str(n.get("id") or n.get("clause_id") or "").strip() or f"clause_{len(triples)+1}"
        txt = str(n.get("content") or n.get("source_text") or n.get("title") or "").strip()
        if not txt:
            continue
        triples.extend(_extract_semantic_triples_from_text(txt, cid))
    return {
        "valid": True,
        "schema_version": "semantic_triples.v1",
        "spec_code": str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        "generated_at": _utc_now(),
        "count": len(triples),
        "triples": triples,
    }


def _norm_slot_text(value: str) -> str:
    s = str(value or "").strip().lower()
    s = re.sub(r"[\s_\-./（）()【】\[\]，,。:：;；]+", "", s)
    return s


def _text_ngrams(text: str, n: int = 2) -> set[str]:
    s = _norm_slot_text(text)
    if not s:
        return set()
    if len(s) <= n:
        return {s}
    return {s[i : i + n] for i in range(0, max(len(s) - n + 1, 1))}


def _jaccard_similarity(a: str, b: str) -> float:
    sa = _text_ngrams(a, 2)
    sb = _text_ngrams(b, 2)
    if not sa and not sb:
        return 0.0
    inter = len(sa.intersection(sb))
    uni = len(sa.union(sb))
    return float(inter) / float(uni) if uni > 0 else 0.0


def _clamp01(v: Any) -> float:
    try:
        x = float(v)
    except Exception:
        x = 0.0
    if x < 0.0:
        return 0.0
    if x > 1.0:
        return 1.0
    return x


def _compute_ai_confidence(
    *,
    semantic_match: Optional[float] = None,
    slot_similarity: Optional[float] = None,
    historical_mapping: Optional[float] = None,
    formula_parsing: Optional[float] = None,
    ocr_quality: Optional[float] = None,
) -> Dict[str, Any]:
    # Weighted by requested signal sources; normalize by available signals only.
    weights: Dict[str, float] = {
        "semantic_match": 0.28,
        "slot_similarity": 0.24,
        "historical_mapping": 0.18,
        "formula_parsing": 0.18,
        "ocr_quality": 0.12,
    }
    values: Dict[str, Optional[float]] = {
        "semantic_match": semantic_match,
        "slot_similarity": slot_similarity,
        "historical_mapping": historical_mapping,
        "formula_parsing": formula_parsing,
        "ocr_quality": ocr_quality,
    }
    used_weight = 0.0
    score_sum = 0.0
    breakdown: Dict[str, float] = {}
    for k, w in weights.items():
        vv = values.get(k)
        if vv is None:
            continue
        cv = _clamp01(vv)
        breakdown[k] = round(cv, 4)
        used_weight += float(w)
        score_sum += float(w) * cv
    confidence = (score_sum / used_weight) if used_weight > 0 else 0.0
    confidence = _clamp01(confidence)
    return {
        "confidence": round(confidence, 4),
        "review_required": bool(confidence < 0.92),
        "confidence_inputs": breakdown,
    }


def _load_mapping_memory_store() -> Dict[str, Any]:
    if not MAPPING_MEMORY_STORE_PATH.exists():
        return {"schema_version": "mapping_memory_store.v1", "items": []}
    try:
        doc = json.loads(MAPPING_MEMORY_STORE_PATH.read_text(encoding="utf-8-sig"))
    except Exception:
        return {"schema_version": "mapping_memory_store.v1", "items": []}
    if not isinstance(doc, dict):
        return {"schema_version": "mapping_memory_store.v1", "items": []}
    items = doc.get("items", [])
    if not isinstance(items, list):
        doc["items"] = []
    return doc


def _save_mapping_memory_store(doc: Dict[str, Any]) -> None:
    MAPPING_MEMORY_STORE_PATH.parent.mkdir(parents=True, exist_ok=True)
    MAPPING_MEMORY_STORE_PATH.write_text(json.dumps(doc, ensure_ascii=False, indent=2), encoding="utf-8")


def _append_mapping_memory_item(
    *,
    clause_text: str,
    mapped_slot_key: str,
    reviewer: str,
    confidence: float,
    job_id: str = "",
    candidate_id: str = "",
) -> Optional[Dict[str, Any]]:
    ct = str(clause_text or "").strip()
    sk = str(mapped_slot_key or "").strip()
    rv = str(reviewer or "").strip()
    if not ct or not sk:
        return None
    conf = max(0.0, min(1.0, float(confidence)))
    doc = _load_mapping_memory_store()
    items = doc.get("items", []) if isinstance(doc.get("items"), list) else []
    sig = _stable_json_hash({"clause_text": ct, "mapped_slotKey": sk, "reviewer": rv, "confidence": round(conf, 4)})
    for row in items:
        if isinstance(row, dict) and str(row.get("signature") or "").strip() == sig:
            return row
    rec = {
        "memory_id": str(uuid.uuid4()),
        "created_at": _utc_now(),
        "clause_text": ct,
        "mapped_slotKey": sk,
        "reviewer": rv or "unknown",
        "confidence": round(conf, 4),
        "job_id": str(job_id or "").strip(),
        "candidate_id": str(candidate_id or "").strip(),
        "signature": sig,
    }
    items.append(rec)
    doc["items"] = items
    doc["updated_at"] = _utc_now()
    _save_mapping_memory_store(doc)
    return rec


def _load_reviewer_learning_store() -> Dict[str, Any]:
    if not REVIEWER_LEARNING_STORE_PATH.exists():
        return {"schema_version": "reviewer_learning_store.v1", "items": []}
    try:
        obj = json.loads(REVIEWER_LEARNING_STORE_PATH.read_text(encoding="utf-8-sig"))
    except Exception:
        return {"schema_version": "reviewer_learning_store.v1", "items": []}
    if not isinstance(obj, dict):
        return {"schema_version": "reviewer_learning_store.v1", "items": []}
    items = obj.get("items", [])
    if not isinstance(items, list):
        obj["items"] = []
    return obj


def _save_reviewer_learning_store(doc: Dict[str, Any]) -> None:
    REVIEWER_LEARNING_STORE_PATH.parent.mkdir(parents=True, exist_ok=True)
    REVIEWER_LEARNING_STORE_PATH.write_text(json.dumps(doc, ensure_ascii=False, indent=2), encoding="utf-8")


def _append_reviewer_learning_item(
    *,
    clause_text: str,
    slot_key: str,
    action: str,
    reviewer: str,
    confidence_before: float,
    corrected_slot_key: str = "",
    candidate_id: str = "",
    job_id: str = "",
) -> Dict[str, Any]:
    ct = str(clause_text or "").strip()
    sk = str(slot_key or "").strip()
    if not ct:
        return {}
    act = str(action or "").strip().lower()
    if act not in {"accepted_mapping", "rejected_mapping", "corrected_mapping"}:
        return {}
    doc = _load_reviewer_learning_store()
    rows = doc.get("items", []) if isinstance(doc.get("items"), list) else []
    rec = {
        "learning_id": f"learn_{uuid.uuid4().hex[:14]}",
        "created_at": _utc_now(),
        "clause_text": ct,
        "slot_key": sk,
        "action": act,
        "corrected_slot_key": str(corrected_slot_key or "").strip(),
        "reviewer": str(reviewer or "").strip() or "unknown",
        "confidence_before": max(0.0, min(1.0, float(confidence_before))),
        "candidate_id": str(candidate_id or "").strip(),
        "job_id": str(job_id or "").strip(),
    }
    rows.append(rec)
    doc["items"] = rows[-8000:]
    doc["updated_at"] = _utc_now()
    _save_reviewer_learning_store(doc)
    return rec


def _reviewer_learning_signal(clause_text: str, slot_key: str) -> Dict[str, Any]:
    ct = str(clause_text or "").strip()
    sk = str(slot_key or "").strip()
    if not ct:
        return {"confidence_delta": 0.0, "accepted": 0, "rejected": 0, "corrected": 0}
    doc = _load_reviewer_learning_store()
    rows = doc.get("items", []) if isinstance(doc.get("items"), list) else []
    accepted = 0
    rejected = 0
    corrected = 0
    for row in rows:
        if not isinstance(row, dict):
            continue
        clause = str(row.get("clause_text") or "").strip()
        if not clause:
            continue
        sim = _jaccard_similarity(ct, clause)
        if sim < 0.25:
            continue
        action = str(row.get("action") or "").strip().lower()
        row_slot = str(row.get("slot_key") or "").strip()
        corr_slot = str(row.get("corrected_slot_key") or "").strip()
        if action == "accepted_mapping" and (not sk or row_slot == sk):
            accepted += 1
        elif action == "rejected_mapping" and (not sk or row_slot == sk):
            rejected += 1
        elif action == "corrected_mapping":
            if sk and corr_slot == sk:
                corrected += 1
            elif sk and row_slot == sk:
                rejected += 1
    delta = max(-0.25, min(0.25, accepted * 0.03 + corrected * 0.04 - rejected * 0.05))
    return {
        "confidence_delta": round(delta, 4),
        "accepted": accepted,
        "rejected": rejected,
        "corrected": corrected,
    }


def _semantic_mapping_memory_search(query_text: str, top_k: int = 8) -> List[Dict[str, Any]]:
    q = str(query_text or "").strip()
    if not q:
        return []
    doc = _load_mapping_memory_store()
    items = doc.get("items", []) if isinstance(doc.get("items"), list) else []
    scored: List[Tuple[float, Dict[str, Any]]] = []
    for row in items:
        if not isinstance(row, dict):
            continue
        clause_text = str(row.get("clause_text") or "").strip()
        if not clause_text:
            continue
        sim = _jaccard_similarity(q, clause_text)
        if sim <= 0:
            continue
        out = {
            "memory_id": str(row.get("memory_id") or "").strip(),
            "clause_text": clause_text,
            "mapped_slotKey": str(row.get("mapped_slotKey") or "").strip(),
            "reviewer": str(row.get("reviewer") or "").strip(),
            "confidence": float(row.get("confidence") or 0.0),
            "similarity": round(sim, 4),
            "created_at": str(row.get("created_at") or "").strip(),
        }
        scored.append((sim, out))
    scored.sort(key=lambda x: x[0], reverse=True)
    return [row for _, row in scored[: max(1, int(top_k))]]


def _collect_historical_slot_mapping_hints(limit_jobs: int = 80) -> Dict[str, Dict[str, int]]:
    out: Dict[str, Dict[str, int]] = {}
    if not NORMREF_ARTIFACTS_DIR.exists():
        return out
    dirs: List[Tuple[float, Path]] = []
    for p in NORMREF_ARTIFACTS_DIR.iterdir():
        if p.is_dir():
            try:
                dirs.append((p.stat().st_mtime, p))
            except Exception:
                continue
    dirs.sort(key=lambda x: x[0], reverse=True)
    for _, d in dirs[: max(1, int(limit_jobs))]:
        fp = d / "slot_mapping_recommendations.json"
        if not fp.exists():
            continue
        try:
            doc = json.loads(fp.read_text(encoding="utf-8-sig"))
        except Exception:
            continue
        rows = doc.get("recommended_slot_keys", []) if isinstance(doc.get("recommended_slot_keys"), list) else []
        for row in rows:
            if not isinstance(row, dict):
                continue
            subject = _norm_slot_text(str(row.get("subject") or "").strip())
            auto_slot = str(row.get("auto_bind_slotKey") or "").strip()
            if not subject or not auto_slot:
                continue
            by_slot = out.setdefault(subject, {})
            by_slot[auto_slot] = int(by_slot.get(auto_slot, 0) or 0) + 1
    return out


def _build_slot_mapping_recommendations_artifact(
    *,
    job_id: str,
    spec: Dict[str, Any],
    clause_tree_nodes: List[Dict[str, Any]],
    semantic_triples: Dict[str, Any],
    components: List[Dict[str, Any]],
    blueprint_metadata: Dict[str, Any],
) -> Dict[str, Any]:
    triples = semantic_triples.get("triples", []) if isinstance(semantic_triples.get("triples"), list) else []
    clause_text_map: Dict[str, str] = {}
    for node in clause_tree_nodes:
        if not isinstance(node, dict):
            continue
        cid = str(node.get("id") or node.get("clause_id") or "").strip()
        txt = str(node.get("content") or node.get("source_text") or node.get("title") or "").strip()
        if cid and txt:
            clause_text_map[cid] = txt
    slot_candidates: List[Dict[str, Any]] = []
    seen_slot: set[str] = set()
    for comp in components:
        if not isinstance(comp, dict):
            continue
        slot_key = str(comp.get("component_id") or comp.get("slotKey") or comp.get("slot") or comp.get("id") or "").strip()
        if not slot_key or slot_key in seen_slot:
            continue
        seen_slot.add(slot_key)
        slot_candidates.append(
            {
                "slotKey": slot_key,
                "label": str(comp.get("component_name") or comp.get("name") or comp.get("title") or slot_key).strip(),
                "unit": str(comp.get("unit") or "").strip(),
            }
        )
    historical = _collect_historical_slot_mapping_hints()
    memory_hits_total = 0
    memory_doc = _load_mapping_memory_store()
    memory_rows = memory_doc.get("items", []) if isinstance(memory_doc.get("items"), list) else []
    results: List[Dict[str, Any]] = []
    for t in triples:
        if not isinstance(t, dict):
            continue
        clause_id = str(t.get("clause_id") or "").strip()
        subject = str(t.get("subject") or "").strip()
        if not subject:
            continue
        subject_norm = _norm_slot_text(subject)
        unit = str(t.get("unit") or "").strip()
        clause_text = clause_text_map.get(clause_id, "")
        semantic_query = f"{subject} {unit} {str(t.get('operator') or '').strip()} {clause_text}".strip()
        memory_hits = _semantic_mapping_memory_search(semantic_query, top_k=5)
        memory_hits_total += len(memory_hits)
        scored: List[Tuple[float, Dict[str, Any]]] = []
        for slot in slot_candidates:
            slot_key = str(slot.get("slotKey") or "").strip()
            if not slot_key:
                continue
            label = str(slot.get("label") or slot_key).strip()
            slot_norm = _norm_slot_text(slot_key)
            label_norm = _norm_slot_text(label)
            sem_sig = max(_jaccard_similarity(subject, label), _jaccard_similarity(subject, slot_key))
            slot_sig = _jaccard_similarity(subject, slot_key)
            score = 0.30
            evidence: List[str] = []
            if subject_norm and subject_norm == slot_norm:
                score += 0.50
                evidence.append("subject=slotKey exact")
            elif subject_norm and subject_norm == label_norm:
                score += 0.46
                evidence.append("subject=slot label exact")
            elif subject_norm and (subject_norm in slot_norm or slot_norm in subject_norm):
                score += 0.28
                evidence.append("subject~slotKey contains")
            elif subject_norm and (subject_norm in label_norm or label_norm in subject_norm):
                score += 0.24
                evidence.append("subject~slot label contains")
            slot_unit = str(slot.get("unit") or "").strip()
            if unit and slot_unit and unit.lower() == slot_unit.lower():
                score += 0.10
                evidence.append("unit match")
            hist_votes = int((historical.get(subject_norm, {}) or {}).get(slot_key, 0) or 0)
            if hist_votes > 0:
                score += min(0.12, 0.03 * float(hist_votes))
                evidence.append(f"historical votes={hist_votes}")
            mem_hit = next((x for x in memory_hits if isinstance(x, dict) and str(x.get("mapped_slotKey") or "").strip() == slot_key), None)
            if isinstance(mem_hit, dict):
                sim = float(mem_hit.get("similarity") or 0.0)
                mc = float(mem_hit.get("confidence") or 0.0)
                score += min(0.25, 0.18 * sim + 0.07 * mc)
                evidence.append(f"memory semantic match(sim={sim:.3f}, conf={mc:.3f})")
            blueprint_forms = blueprint_metadata.get("form_api_mapping", {})
            if isinstance(blueprint_forms, dict) and any(slot_key in str(v or "") for v in blueprint_forms.values()):
                score += 0.03
                evidence.append("blueprint metadata hit")
            score = max(0.0, min(0.999, round(score, 4)))
            hist_sig = min(1.0, 0.25 * float(hist_votes)) if hist_votes > 0 else 0.0
            op = str(t.get("operator") or "").strip().lower()
            formula_sig = 1.0 if op in {"between", "<=", "<", ">=", ">", "enum", "exists"} else 0.6
            ai_conf = _compute_ai_confidence(
                semantic_match=sem_sig,
                slot_similarity=slot_sig,
                historical_mapping=hist_sig,
                formula_parsing=formula_sig,
                ocr_quality=None,
            )
            learning = _reviewer_learning_signal(clause_text=semantic_query, slot_key=slot_key)
            ai_conf_adjusted = max(
                0.0,
                min(1.0, float(ai_conf.get("confidence", 0.0) or 0.0) + float(learning.get("confidence_delta", 0.0) or 0.0)),
            )
            scored.append(
                (
                    score,
                    {
                        "slotKey": slot_key,
                        "confidence": score,
                        "evidence": " | ".join(evidence) or "weak lexical similarity",
                        "ai_confidence": round(ai_conf_adjusted, 4),
                        "ai_review_required": bool(ai_conf_adjusted < 0.92),
                        "ai_confidence_inputs": ai_conf.get("confidence_inputs", {}),
                        "learning_signal": learning,
                    },
                )
            )
        scored.sort(key=lambda x: x[0], reverse=True)
        top3 = [row for _, row in scored[:3]]
        top = top3[0] if top3 else {}
        top_conf = float(top.get("confidence", 0.0) or 0.0) if isinstance(top, dict) else 0.0
        top_ai_conf = float(top.get("ai_confidence", 0.0) or 0.0) if isinstance(top, dict) else 0.0
        auto_bind = top_conf >= 0.92 and top_ai_conf >= 0.92
        results.append(
            {
                "clause_id": clause_id,
                "clause_text": clause_text,
                "subject": subject,
                "operator": str(t.get("operator") or "").strip(),
                "min": t.get("min"),
                "max": t.get("max"),
                "unit": unit,
                "memory_hits": memory_hits,
                "recommended_slot_keys": top3,
                "decision": "auto_bind" if auto_bind else "human_review",
                "auto_bind_slotKey": str(top.get("slotKey") or "").strip() if auto_bind else "",
                "confidence": round(top_ai_conf, 4),
                "review_required": bool(top_ai_conf < 0.92),
            }
        )
    auto_bind_count = len([x for x in results if isinstance(x, dict) and str(x.get("decision") or "") == "auto_bind"])
    return {
        "valid": True,
        "schema_version": "slot_mapping_recommendations.v1",
        "job_id": job_id,
        "spec_code": str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        "generated_at": _utc_now(),
        "input_summary": {
            "clause_count": len(clause_text_map),
            "semantic_triple_count": len([x for x in triples if isinstance(x, dict)]),
            "component_slot_count": len(slot_candidates),
            "historical_subject_count": len(historical),
            "mapping_memory_count": len([x for x in memory_rows if isinstance(x, dict)]),
            "mapping_memory_hit_count": memory_hits_total,
            "blueprint_metadata_keys": sorted([str(k) for k in blueprint_metadata.keys()]),
        },
        "count": len(results),
        "auto_bind_count": auto_bind_count,
        "human_review_count": max(len(results) - auto_bind_count, 0),
        "recommended_slot_keys": results,
    }


def _build_slot_conflict_report(
    *,
    job_id: str,
    spec_code: str,
    recommendations: Dict[str, Any],
) -> Dict[str, Any]:
    rows = recommendations.get("recommended_slot_keys", []) if isinstance(recommendations.get("recommended_slot_keys"), list) else []
    by_slot: Dict[str, List[Dict[str, Any]]] = {}
    for row in rows:
        if not isinstance(row, dict):
            continue
        slot = str(row.get("auto_bind_slotKey") or "").strip()
        if not slot:
            continue
        if str(row.get("decision") or "").strip() != "auto_bind":
            continue
        by_slot.setdefault(slot, []).append(row)

    conflicts: List[Dict[str, Any]] = []
    critical_slots: set[str] = set()
    for slot, items in by_slot.items():
        if len(items) <= 1:
            continue
        op_set = {str(x.get("operator") or "").strip() for x in items if str(x.get("operator") or "").strip()}
        unit_set = {str(x.get("unit") or "").strip().lower() for x in items if str(x.get("unit") or "").strip()}
        threshold_set = {
            _stable_json_hash(
                {
                    "operator": str(x.get("operator") or "").strip(),
                    "min": x.get("min"),
                    "max": x.get("max"),
                    "unit": str(x.get("unit") or "").strip().lower(),
                    "subject": str(x.get("subject") or "").strip(),
                }
            )
            for x in items
            if isinstance(x, dict)
        }
        threshold_conflict = len(threshold_set) > 1
        unit_conflict = len(unit_set) > 1
        operator_conflict = len(op_set) > 1
        if not (threshold_conflict or unit_conflict or operator_conflict):
            continue
        severity = "critical" if operator_conflict or unit_conflict else "high"
        if severity == "critical":
            critical_slots.add(slot)
        conflicts.append(
            {
                "slotKey": slot,
                "severity": severity,
                "conflict_types": [
                    *(["threshold conflict"] if threshold_conflict else []),
                    *(["unit conflict"] if unit_conflict else []),
                    *(["operator conflict"] if operator_conflict else []),
                ],
                "clauses": [
                    {
                        "clause_id": str(x.get("clause_id") or "").strip(),
                        "subject": str(x.get("subject") or "").strip(),
                        "operator": str(x.get("operator") or "").strip(),
                        "min": x.get("min"),
                        "max": x.get("max"),
                        "unit": str(x.get("unit") or "").strip(),
                    }
                    for x in items
                    if isinstance(x, dict)
                ],
            }
        )
    return {
        "valid": True,
        "schema_version": "slot_conflict_report.v1",
        "job_id": str(job_id or "").strip(),
        "spec_code": str(spec_code or "").strip(),
        "generated_at": _utc_now(),
        "count": len(conflicts),
        "critical_conflict_count": len([x for x in conflicts if isinstance(x, dict) and str(x.get("severity") or "") == "critical"]),
        "critical_slots": sorted(list(critical_slots)),
        "conflicts": conflicts,
    }


def _build_mapping_memory_artifact(job_id: str) -> Dict[str, Any]:
    doc = _load_mapping_memory_store()
    items = doc.get("items", []) if isinstance(doc.get("items"), list) else []
    rows: List[Dict[str, Any]] = []
    for row in items:
        if not isinstance(row, dict):
            continue
        rows.append(
            {
                "memory_id": str(row.get("memory_id") or "").strip(),
                "created_at": str(row.get("created_at") or "").strip(),
                "clause_text": str(row.get("clause_text") or "").strip(),
                "mapped_slotKey": str(row.get("mapped_slotKey") or "").strip(),
                "reviewer": str(row.get("reviewer") or "").strip(),
                "confidence": float(row.get("confidence") or 0.0),
                "job_id": str(row.get("job_id") or "").strip(),
                "candidate_id": str(row.get("candidate_id") or "").strip(),
            }
        )
    rows.sort(key=lambda x: str(x.get("created_at") or ""), reverse=True)
    return {
        "valid": True,
        "schema_version": "mapping_memory.v1",
        "job_id": str(job_id or "").strip(),
        "generated_at": _utc_now(),
        "count": len(rows),
        "items": rows,
    }


def _normalize_tolerance_unit(unit: str) -> str:
    u = str(unit or "").strip().lower()
    mp = {
        "毫米": "mm",
        "mm": "mm",
        "厘米": "cm",
        "cm": "cm",
        "米": "m",
        "m": "m",
        "百分比": "%",
        "％": "%",
        "%": "%",
    }
    return mp.get(u, str(unit or "").strip())


def _extract_tolerance_items_from_text(text: str, clause_id: str) -> List[Dict[str, Any]]:
    s = str(text or "").strip()
    if not s:
        return []
    items: List[Dict[str, Any]] = []

    # ±20mm
    for m in re.finditer(r"±\s*(?P<v>-?\d+(?:\.\d+)?)\s*(?P<u>mm|厘米|cm|米|m|%|％)?", s, re.IGNORECASE):
        val = float(m.group("v"))
        unit = _normalize_tolerance_unit(m.group("u"))
        items.append(
            {
                "clause_id": clause_id,
                "threshold": val,
                "unit": unit,
                "operator": "between",
                "min": -val,
                "max": val,
                "tolerance_type": "symmetric",
                "unresolved": False,
                "raw_text": s,
            }
        )

    # 不大于5%
    for m in re.finditer(r"(?:不大于|不超过|≤|<=)\s*(?P<v>-?\d+(?:\.\d+)?)\s*(?P<u>mm|厘米|cm|米|m|%|％)?", s, re.IGNORECASE):
        val = float(m.group("v"))
        unit = _normalize_tolerance_unit(m.group("u"))
        items.append(
            {
                "clause_id": clause_id,
                "threshold": val,
                "unit": unit,
                "operator": "<=",
                "min": None,
                "max": val,
                "tolerance_type": "upper_bound",
                "unresolved": False,
                "raw_text": s,
            }
        )

    # 不小于0.8
    for m in re.finditer(r"(?:不小于|不少于|≥|>=)\s*(?P<v>-?\d+(?:\.\d+)?)\s*(?P<u>mm|厘米|cm|米|m|%|％)?", s, re.IGNORECASE):
        val = float(m.group("v"))
        unit = _normalize_tolerance_unit(m.group("u"))
        items.append(
            {
                "clause_id": clause_id,
                "threshold": val,
                "unit": unit,
                "operator": ">=",
                "min": val,
                "max": None,
                "tolerance_type": "lower_bound",
                "unresolved": False,
                "raw_text": s,
            }
        )

    # 高差控制（可能缺阈值，标 unresolved）
    if re.search(r"高差控制|高程控制|标高控制", s):
        unresolved = not bool(re.search(r"-?\d+(?:\.\d+)?", s))
        threshold = None
        unit = ""
        operator = "exists"
        min_v = None
        max_v = None
        m_num = re.search(r"(-?\d+(?:\.\d+)?)\s*(mm|厘米|cm|米|m|%|％)?", s, re.IGNORECASE)
        if m_num:
            threshold = float(m_num.group(1))
            unit = _normalize_tolerance_unit(m_num.group(2))
            operator = "<="
            max_v = threshold
            unresolved = False
        items.append(
            {
                "clause_id": clause_id,
                "threshold": threshold,
                "unit": unit,
                "operator": operator,
                "min": min_v,
                "max": max_v,
                "tolerance_type": "height_diff_control",
                "unresolved": unresolved,
                "raw_text": s,
            }
        )
    return items


def _build_tolerance_extraction_artifact(*, spec: Dict[str, Any], clause_tree_nodes: List[Dict[str, Any]]) -> Dict[str, Any]:
    items: List[Dict[str, Any]] = []
    for n in clause_tree_nodes:
        if not isinstance(n, dict):
            continue
        ntype = str(n.get("type") or n.get("node_type") or "").strip().lower()
        if ntype not in {"clause", "paragraph", "table"}:
            continue
        cid = str(n.get("id") or n.get("clause_id") or "").strip() or f"clause_{len(items)+1}"
        txt = str(n.get("content") or n.get("source_text") or n.get("title") or "").strip()
        if not txt:
            continue
        items.extend(_extract_tolerance_items_from_text(txt, cid))
    return {
        "valid": True,
        "schema_version": "tolerance_extraction.v1",
        "spec_code": str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        "generated_at": _utc_now(),
        "count": len(items),
        "items": items,
    }


def _tokenize_formula_expr(expr: str) -> List[str]:
    s = str(expr or "").strip()
    if not s:
        return []
    s = s.replace("（", "(").replace("）", ")")
    s = s.replace("＋", "+").replace("－", "-").replace("×", "*").replace("÷", "/")
    pattern = r"[A-Za-z_][A-Za-z0-9_]*|-?\d+(?:\.\d+)?|[()+\-*/]"
    return re.findall(pattern, s)


def _formula_to_rpn(tokens: List[str]) -> List[str]:
    prec = {"+": 1, "-": 1, "*": 2, "/": 2}
    out: List[str] = []
    st: List[str] = []
    for t in tokens:
        if re.fullmatch(r"-?\d+(?:\.\d+)?", t) or re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", t):
            out.append(t)
        elif t in {"+", "-", "*", "/"}:
            while st and st[-1] in prec and prec[st[-1]] >= prec[t]:
                out.append(st.pop())
            st.append(t)
        elif t == "(":
            st.append(t)
        elif t == ")":
            while st and st[-1] != "(":
                out.append(st.pop())
            if st and st[-1] == "(":
                st.pop()
    while st:
        out.append(st.pop())
    return out


def _rpn_to_formula_ast(rpn: List[str]) -> Dict[str, Any]:
    st: List[Dict[str, Any]] = []
    for t in rpn:
        if re.fullmatch(r"-?\d+(?:\.\d+)?", t):
            st.append({"type": "NumberLiteral", "value": float(t)})
        elif re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", t):
            st.append({"type": "Identifier", "name": t})
        elif t in {"+", "-", "*", "/"}:
            if len(st) < 2:
                return {"type": "InvalidFormulaAst", "reason": "stack_underflow", "token": t}
            right = st.pop()
            left = st.pop()
            st.append({"type": "BinaryExpression", "operator": t, "left": left, "right": right})
    if len(st) != 1:
        return {"type": "InvalidFormulaAst", "reason": "stack_not_single"}
    return st[0]


def _to_js_ast(node: Dict[str, Any]) -> Dict[str, Any]:
    ntype = str(node.get("type") or "").strip()
    if ntype == "NumberLiteral":
        return {"type": "Literal", "value": node.get("value")}
    if ntype == "Identifier":
        return {"type": "Identifier", "name": node.get("name")}
    if ntype == "BinaryExpression":
        return {
            "type": "BinaryExpression",
            "operator": node.get("operator"),
            "left": _to_js_ast(node.get("left", {}) if isinstance(node.get("left"), dict) else {}),
            "right": _to_js_ast(node.get("right", {}) if isinstance(node.get("right"), dict) else {}),
        }
    return {"type": "Unknown"}


def _build_formula_ir_artifact(
    *,
    spec: Dict[str, Any],
    formulas: List[Dict[str, Any]],
    rules: List[Dict[str, Any]],
) -> Dict[str, Any]:
    # Build semantic slot lookup from rules.
    slot_map: Dict[str, str] = {}
    for r in rules:
        if not isinstance(r, dict):
            continue
        field = str(r.get("field") or "").strip()
        metric = str((r.get("input_fields") or [""])[0] if isinstance(r.get("input_fields"), list) and r.get("input_fields") else "").strip()
        if field:
            slot_map[field] = field
        if metric:
            slot_map[metric] = field or metric

    rows: List[Dict[str, Any]] = []
    for i, f in enumerate(formulas):
        if not isinstance(f, dict):
            continue
        formula_id = str(f.get("formula_id") or f.get("id") or f"formula_{i+1}").strip()
        latex = str(f.get("latex") or f.get("formula") or f.get("expr") or "").strip()
        if not latex:
            continue
        tokens = _tokenize_formula_expr(latex)
        rpn = _formula_to_rpn(tokens)
        ast = _rpn_to_formula_ast(rpn)
        vars_, _ops = _extract_formula_variables_and_operators(latex)
        bindings: List[Dict[str, Any]] = []
        unresolved = False
        for v in vars_:
            slot = slot_map.get(v, "")
            if not slot:
                unresolved = True
            bindings.append({"variable": v, "semantic_slot": slot, "bound": bool(slot)})
        bound_ratio = (float(len([x for x in bindings if bool(x.get("bound"))])) / float(len(bindings))) if bindings else 1.0
        formula_parse_ok = not (isinstance(ast, dict) and str(ast.get("type") or "").startswith("Invalid"))
        ai_conf = _compute_ai_confidence(
            semantic_match=0.8 if vars_ else 0.6,
            slot_similarity=bound_ratio,
            historical_mapping=None,
            formula_parsing=1.0 if formula_parse_ok else 0.2,
            ocr_quality=None,
        )
        rows.append(
            {
                "formula_id": formula_id,
                "variables": vars_,
                "variable_bindings": bindings,
                "formula_ast": ast,
                "formula_latex": latex,
                "formula_runtime": {
                    "python": {"engine": "python", "expr": latex},
                    "js_ast": {"engine": "js_ast", "ast": _to_js_ast(ast if isinstance(ast, dict) else {})},
                },
                "unresolved": unresolved or (isinstance(ast, dict) and str(ast.get("type") or "").startswith("Invalid")),
                "confidence": float(ai_conf.get("confidence", 0.0) or 0.0),
                "review_required": bool(ai_conf.get("review_required", True)),
                "confidence_inputs": ai_conf.get("confidence_inputs", {}),
            }
        )
    agg = _compute_ai_confidence(
        semantic_match=0.8 if rows else 0.0,
        slot_similarity=(sum([float(x.get("confidence", 0.0) or 0.0) for x in rows]) / float(len(rows))) if rows else 0.0,
        formula_parsing=(sum([1.0 if not bool(x.get("unresolved", False)) else 0.2 for x in rows]) / float(len(rows))) if rows else 0.0,
    )
    return {
        "valid": True,
        "schema_version": "formula_ir.v1",
        "spec_code": str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        "generated_at": _utc_now(),
        "count": len(rows),
        "formulas": rows,
        "confidence": float(agg.get("confidence", 0.0) or 0.0),
        "review_required": bool(agg.get("review_required", True)),
        "confidence_inputs": agg.get("confidence_inputs", {}),
    }


def _synthesize_gate_from_rules(comp_rules: List[Dict[str, Any]]) -> Dict[str, Any]:
    operators = [
        str(r.get("operator") or "").strip()
        for r in comp_rules
        if isinstance(r, dict) and str(r.get("operator") or "").strip()
    ]
    if not operators:
        return {"gate_type": "unresolved_gate", "decision_logic": "REVIEW_REQUIRED"}
    gate_type = "threshold_check"
    decision_logic = "FAIL_IF_MISMATCH"
    if all(op in {"<=", "<", ">=", ">", "between"} for op in operators):
        gate_type = "threshold_check"
        decision_logic = "FAIL_IF_EXCEED"
    elif any(op == "exists" for op in operators):
        gate_type = "presence_check"
        decision_logic = "FAIL_IF_MISSING"
    elif any(op in {"==", "!=", "enum"} for op in operators):
        gate_type = "enum_check"
        decision_logic = "FAIL_IF_NOT_ALLOWED"
    return {"gate_type": gate_type, "decision_logic": decision_logic}


def _run_normref_artifact_pipeline(
    job_id: str,
    version_tag: str,
    source_file: str,
    *,
    normref_input: str = "",
) -> Dict[str, Any]:
    package = _load_review_package(job_id)
    # Ensure latest clause bindings are present before artifact generation.
    # Some jobs can carry approved candidates with empty clause_id when binding
    # was not refreshed yet, which would incorrectly result in zero approved
    # executable candidates in downstream pipeline steps.
    package["clause_binding_summary"] = _refresh_review_candidate_clause_bindings(
        package,
        target_statuses={"approved"},
    )
    package["review_summary"] = _rebuild_review_summary(
        [item for item in package.get("candidates", []) if isinstance(item, dict)]
    )
    package["updated_at"] = _utc_now()
    _save_review_package(package)
    resolved_normref = str(normref_input or package.get("normRef") or "").strip()
    if not resolved_normref:
        raise HTTPException(status_code=400, detail="缺少 normRef。禁止使用无 normRef 输入生成规范资产。")
    normref_meta = _parse_normref_uri(resolved_normref)
    if str(package.get("normRef", "")).strip() != resolved_normref:
        package["normRef"] = resolved_normref
        _save_review_package(package)
    std_code = _format_std_code_display(str(package.get("std_code", "")).strip())
    if not std_code:
        raise HTTPException(status_code=400, detail=f"任务 {job_id} 缺少标准编号，无法生成 artifacts。")
    canonical_from_normref = _canonical_std_code_from_normref_spec(normref_meta["spec"])
    if canonical_from_normref and _normalize_code(canonical_from_normref) != _normalize_code(std_code):
        raise HTTPException(
            status_code=400,
            detail=f"normRef 与任务标准不一致：normRef.spec={canonical_from_normref}，job.std_code={std_code}",
        )
    package_title = str(package.get("title", "")).strip()
    package_spec_type = str(package.get("spec_type", "")).strip() or _infer_spec_type(std_code, package_title)
    candidates = [c for c in package.get("candidates", []) if isinstance(c, dict)]
    approved = [
        c for c in candidates
        if str(c.get("decision", c.get("status", ""))).lower() == "approved"
    ]
    clause_assets = _build_clause_tree_and_catalog(package)
    clause_class_map: Dict[str, str] = {}
    for x in clause_assets.get("all_nodes", []):
        if not isinstance(x, dict):
            continue
        cid = str(x.get("id", "")).strip()
        if not cid:
            continue
        clause_class_map[cid] = _classify_clause_node(x)
    executable_clause_classes = {
        "threshold_rule",
        "range_rule",
        "formula_rule",
        "table_rule",
        "sampling_requirement",
        "process_requirement",
        "method_requirement",
        "material_requirement",
    }
    approved = [
        c for c in approved
        if str(c.get("clause_id") or "").strip() in clause_class_map
        and clause_class_map.get(str(c.get("clause_id") or "").strip(), "non_executable") in executable_clause_classes
    ]
    # Unified source model enforcement:
    # only keep approved candidates already bound to clause ids (normRef lineage).
    approved = [c for c in approved if str(c.get("clause_id") or "").strip()]
    source_pdf_hash = ""
    source_doc_hash = ""
    source_path = Path(str(source_file)).expanduser()
    if source_path.exists() and source_path.is_file():
        source_pdf_hash = hashlib.sha256(source_path.read_bytes()).hexdigest()
        source_doc_hash = _sha256_file(source_path)
    source_file_name = source_path.name if source_path.name else Path(str(source_file)).name
    version_year = ""
    year_match = re.search(r"(\d{4})\s*$", std_code)
    if year_match:
        version_year = year_match.group(1)

    is_jtgt3650 = _is_jtgt3650_spec(std_code, package_title)
    spec = {
        "valid": True,
        "spec_id": std_code,
        "spec_code": std_code,
        "spec_name": JTG_T_3650_PROFILE["name"] if is_jtgt3650 else (package_title or std_code),
        "spec_type": JTG_T_3650_PROFILE["type"] if is_jtgt3650 else package_spec_type,
        "version_year": version_year,
        "source_file_name": source_file_name,
        "source_pdf_hash": source_pdf_hash,
        "source_doc_hash": source_doc_hash,
        "standard_code": std_code,
        "name": JTG_T_3650_PROFILE["name"] if is_jtgt3650 else (package_title or std_code),
        "type": JTG_T_3650_PROFILE["type"] if is_jtgt3650 else package_spec_type,
        "version": version_tag or "v1",
        "status": "active",
        "scope": [str(x) for x in package.get("scope", []) if str(x).strip()] if isinstance(package.get("scope"), list) else [],
        "source_file": source_file,
        "parsed_at": _utc_now(),
    }
    if is_jtgt3650:
        spec["type"] = JTG_T_3650_PROFILE["type"]
        spec["chapters"] = JTG_T_3650_PROFILE["chapters"]
        spec["appendices"] = JTG_T_3650_PROFILE["appendices"]

    catalog_raw = clause_assets
    clause_tree = clause_assets.get("clause_tree", [])
    clause_tree_nodes = clause_assets.get("all_nodes", []) if isinstance(clause_assets.get("all_nodes", []), list) else []
    has_chapter_or_section = any(
        str((node or {}).get("type", "")).strip().lower() in {"chapter", "section"}
        for node in clause_tree_nodes
        if isinstance(node, dict)
    )
    clause_tree_generation_error: Dict[str, Any] | None = None
    if len(clause_tree_nodes) <= 0 or not has_chapter_or_section:
        raw_reason = str(
            package.get("report_error")
            or package.get("error")
            or package.get("parse_error")
            or package.get("parser_error")
            or ""
        ).strip().lower()
        reason = "解析失败"
        if ("ocr" in raw_reason) or ("识别" in raw_reason):
            reason = "OCR失败"
        elif ("regex" in raw_reason) or ("正则" in raw_reason):
            reason = "正则失败"
        elif ("pdf" in raw_reason) or ("pypdf" in raw_reason) or ("pdfplumber" in raw_reason):
            reason = "PDF解析失败"
        clause_tree_generation_error = {
            "artifact": "03_clause_tree.json",
            "reason": reason,
            "detail": raw_reason or "clause_tree 节点为空或缺少 chapter/section",
            "node_count": len(clause_tree_nodes),
            "has_chapter_or_section": has_chapter_or_section,
        }
    source_metadata_nodes = clause_assets.get("source_metadata", []) if isinstance(clause_assets.get("source_metadata", []), list) else []
    catalog_rows = catalog_raw.get("catalog", []) if isinstance(catalog_raw.get("catalog", []), list) else []
    if is_jtgt3650:
        catalog_rows = _ensure_jtgt3650_catalog(catalog_rows)
        def _catalog_sort_key_for_pipeline(row: Dict[str, Any]) -> Tuple[int, Tuple[int, ...], str]:
            t = str((row or {}).get("type", "")).strip().lower()
            rid = str((row or {}).get("id", "")).strip()
            type_rank = {"chapter": 1, "section": 2, "clause": 3, "table": 4}.get(t, 9)
            nums = tuple(int(x) for x in re.findall(r"\d+", rid)) if rid else tuple()
            return (type_rank, nums, rid)
        catalog_rows = sorted([x for x in catalog_rows if isinstance(x, dict)], key=_catalog_sort_key_for_pipeline)
    catalog = {
        "valid": True,
        "count": len(catalog_rows),
        "catalog": catalog_rows,
    }
    components: List[Dict[str, Any]] = []
    measured_items: List[Dict[str, Any]] = []
    rules: List[Dict[str, Any]] = []
    gates: List[Dict[str, Any]] = []
    states: List[Dict[str, Any]] = []
    dtos: List[Dict[str, Any]] = []
    execspecs: List[Dict[str, Any]] = []

    clause_tree_ready = len(clause_tree_nodes) > 0 and has_chapter_or_section
    clause_classifications: List[Dict[str, Any]] = []
    classification_generation_failed = False
    if not clause_tree_ready:
        classification_generation_failed = True
    else:
        for node in clause_tree_nodes:
            node_type = str(node.get("type", "clause"))
            rule_type = _classify_clause_node(node)
            clause_classifications.append(
                {
                    "clause_id": str(node.get("id", "")),
                    "clause_no": str(node.get("id", "")),
                    "rule_type": rule_type,
                    "node_type": node_type,
                    "is_executor_candidate": bool(rule_type in executable_clause_classes),
                    "source_clause": {
                        "clause_id": str(node.get("id", "")),
                        "title": str(node.get("name", "")),
                        "content": str(node.get("content", "")),
                        "parent_id": node.get("parent_id"),
                        "level": str(node.get("level", "")),
                        "page_start": node.get("source_page"),
                        "page_end": node.get("page_end", node.get("source_page")),
                        "source_text": str(node.get("source_text", "")),
                    },
                    "source_page": node.get("source_page"),
                }
            )

    approved_by_clause: Dict[str, Dict[str, Any]] = {}
    for cand in approved:
        if not isinstance(cand, dict):
            continue
        cid = str(cand.get("clause_id") or "").strip()
        if cid and cid not in approved_by_clause:
            approved_by_clause[cid] = cand

    # Component generation from clause classification
    root_component_id = f"{std_code}.specroot"
    components.append(
        {
            "component_id": root_component_id,
            "name": package_title or std_code,
            "type": "ChapterComponent",
            "spec_id": std_code,
            "catalog_path": std_code,
            "source_clause_ids": [],
            "original_text": package_title or std_code,
            "parent_component_id": None,
            "children": [],
            "executable": False,
            "reason": "规范根节点用于组织结构，不直接执行。",
            "rules": [],
            "gates": [],
            "status": "core_only",
            "norm_ref": resolved_normref,
        }
    )
    clause_to_component: Dict[str, str] = {}
    for cls in clause_classifications:
        clause_id = str(cls.get("clause_id", "")).strip()
        if not clause_id:
            continue
        source_clause = cls.get("source_clause", {}) if isinstance(cls.get("source_clause", {}), dict) else {}
        title = str(source_clause.get("title", clause_id))
        clause_class = str(cls.get("rule_type", "non_executable"))
        node_level = str(source_clause.get("level", "item"))
        node_type = str(cls.get("node_type", "clause"))
        comp_type = _component_type_from_clause(clause_class, node_level, node_type)
        executable = False
        reason = "目录/结构节点默认不直接执行。"
        if comp_type in {"ChapterComponent", "WorkItemComponent", "AppendixComponent", "TableComponent"}:
            executable = False
            if comp_type == "AppendixComponent":
                reason = "附录默认仅入 catalog，不直接进入 executor。"
            elif comp_type == "TableComponent":
                reason = "表格节点用于承载行项，默认不直接执行。"
        else:
            executable = _has_explicit_execution_signal(clause_class, str(source_clause.get("source_text", "")))
            reason = "具备明确输入/判定条件，可执行。" if executable else "缺少明确输入或判定条件，暂不设为可执行。"
        comp_id = f"{std_code}.component.{clause_id.replace('.', '_')}"
        clause_to_component[clause_id] = comp_id
        components.append(
            {
                "component_id": comp_id,
                "name": title,
                "type": comp_type,
                "spec_id": std_code,
                "catalog_path": clause_id,
                "source_clause_ids": [clause_id],
                "original_text": str(source_clause.get("source_text", "") or source_clause.get("content", "") or title),
                "parent_component_id": None,
                "children": [],
                "executable": executable,
                "reason": reason,
                "rules": [],
                "gates": [],
                "status": "candidate" if executable else "core_only",
                "norm_ref": resolved_normref,
            }
        )

    # Rule generation: every executable clause classification must produce one rule.
    executable_class_to_rule = {
        "process_requirement": "process_check",
        "material_requirement": "material_check",
        "method_requirement": "method_check",
        "sampling_requirement": "sampling",
        "threshold_rule": "threshold",
        "range_rule": "range",
        "formula_rule": "formula",
        "table_rule": "table_lookup",
        "reference_rule": "reference",
    }
    def _is_mainline_clause_id(clause_id: str) -> bool:
        cid = str(clause_id or "").strip()
        # 主线只接受数字编号体系：章/节/条（如 4 / 4.2 / 4.2.6）
        return bool(re.fullmatch(r"\d+(?:\.\d+){0,2}", cid))

    attempted_rule_count = 0
    skipped_rule_reasons: List[str] = []
    for idx, cls in enumerate(clause_classifications, start=1):
        clause_class = str(cls.get("rule_type", "")).strip()
        if clause_class not in executable_class_to_rule:
            continue
        attempted_rule_count += 1
        clause_id = str(cls.get("clause_id", "")).strip()
        if not clause_id:
            skipped_rule_reasons.append("missing_clause_id")
            continue
        source_clause = cls.get("source_clause", {}) if isinstance(cls.get("source_clause", {}), dict) else {}
        source_text = str(source_clause.get("source_text", "") or source_clause.get("content", "")).strip()
        title_text = str(source_clause.get("title", "")).strip()
        # 附录/非主线编号不进入可执行 Rule（避免 chapter/k/table/measured_value 占位规则）
        if ("附录" in clause_id) or ("附录" in title_text) or ("附录" in source_text):
            skipped_rule_reasons.append("appendix_excluded")
            continue
        if not _is_mainline_clause_id(clause_id):
            skipped_rule_reasons.append("non_mainline_clause_id")
            continue
        cand = approved_by_clause.get(clause_id, {})
        rule_id = f"{std_code}.{clause_id.replace('.', '_')}.rule"
        component_id = clause_to_component.get(clause_id, "")
        metric = str(cand.get("metric_key") or cand.get("field_key") or "measured_value")
        slot_key_raw = str(
            cand.get("slotKey")
            or cand.get("slot_key")
            or cand.get("field_key")
            or cand.get("metric_key")
            or ""
        ).strip()
        field_name = _normalize_normref_seg(slot_key_raw, "")
        condition = cand.get("condition")
        if not isinstance(condition, dict):
            condition = {
                "type": clause_class,
                "operator": None,
                "value": None,
                "unit": None,
            }
        rule_type = executable_class_to_rule[clause_class]
        operator_raw = str(
            condition.get("operator")
            or cand.get("operator")
            or ("between" if rule_type == "range" else ("lookup" if rule_type == "table_lookup" else "exists"))
        ).strip()
        operator = _normalize_rule_operator(operator_raw)
        threshold: Any = None
        if "value" in condition:
            threshold = condition.get("value")
        elif "min" in condition or "max" in condition:
            threshold = {"min": condition.get("min"), "max": condition.get("max")}
        elif "formula" in condition:
            threshold = condition.get("formula")
        unit = (
            str(condition.get("unit") or cand.get("unit") or "").strip()
            or (re.search(r"(mm|cm|m|MPa|kN|%|℃|kg|g)", source_text, re.IGNORECASE).group(1) if re.search(r"(mm|cm|m|MPa|kN|%|℃|kg|g)", source_text, re.IGNORECASE) else "")
        )
        scope = {
            "spec_id": std_code,
            "clause_id": clause_id,
            "level": str(source_clause.get("level", "")).strip(),
            "parent_id": str(source_clause.get("parent_id", "")).strip(),
        }
        min_value, max_value = _to_rule_min_max(operator, condition, threshold)
        chapter_seg = str(normref_meta.get("chapter") or "chapter")
        section_seg = _normalize_normref_seg(clause_id, str(normref_meta.get("section") or "section"))
        table_seg = str(normref_meta.get("table") or "table")
        rule_norm_ref = f"v://std/{normref_meta['spec']}/{chapter_seg}/{section_seg}/{table_seg}/{field_name or 'unbound_slot'}"
        unresolved = False
        unresolved_reason = ""
        if not component_id:
            unresolved = True
            unresolved_reason = "component_missing"
        if not clause_id:
            unresolved = True
            unresolved_reason = "missing_source_ref"
        if rule_type in {"threshold", "range", "formula"}:
            has_numeric = bool(re.search(r"\d+(\.\d+)?", source_text)) or any(k in condition for k in ["value", "min", "max"])
            if not has_numeric:
                unresolved = True
                unresolved_reason = "missing_numeric_or_formula_condition"
        if rule_type in {"process_check", "material_check", "method_check", "sampling"}:
            if not source_text:
                unresolved = True
                unresolved_reason = "missing_source_text"
        if rule_type == "table_lookup" and "表" not in source_text and "table" not in source_text.lower():
            unresolved = True
            unresolved_reason = "missing_table_reference"
        if rule_type == "reference":
            unresolved = True
            unresolved_reason = "reference_only_not_structured"
        if operator == "between" and (min_value is None or max_value is None):
            unresolved = True
            unresolved_reason = "missing_min_max"
        if not field_name:
            unresolved = True
            unresolved_reason = unresolved_reason or "missing_slot_mapping"
        elif field_name == "measured_value":
            unresolved = True
            unresolved_reason = unresolved_reason or "missing_slot_mapping"
        if operator in {">=", "<=", "between"} and not unit:
            unresolved = True
            unresolved_reason = unresolved_reason or "missing_unit"
        enabled = not unresolved
        if not enabled and not unresolved_reason:
            unresolved_reason = "unresolved_condition"
        rules.append(
            {
                "rule_id": rule_id,
                "norm_ref": rule_norm_ref,
                "field": field_name if field_name and field_name != "measured_value" else "",
                "slotKey": field_name if field_name and field_name != "measured_value" else "",
                "debug_field": metric,
                "operator": operator,
                "min": min_value,
                "max": max_value,
                "unit": unit,
                "scope": scope,
                "source_clause_id": clause_id,
                "source_ref": rule_norm_ref,
                "component_id": component_id,
                "rule_type": rule_type,
                "input_fields": [metric] if metric else [],
                "output_fields": [f"{metric}_result"] if metric else ["rule_result"],
                "severity": str(cand.get("severity") or "blocking"),
                "pass_message": str(cand.get("pass_message") or f"{metric} 满足规范要求").strip(),
                "fail_message": str(cand.get("fail_message") or f"{metric} 不满足规范要求").strip(),
                "unresolved": unresolved,
                "unresolved_reason": unresolved_reason,
                "execution_status": ("needs_slot" if (not field_name or field_name == "measured_value") else ("executable" if enabled else "not_executable")),
                "enabled": enabled,
                "source": {"spec": std_code, "clause": clause_id},
                "resolved": False if unresolved else True,
            }
        )
        states.append(
            {
                "state_machine_id": f"{std_code}.{clause_id.replace('.', '_')}.state",
                "work_item_id": f"{std_code}.{clause_id.replace('.', '_')}.work",
                "states": ["draft", "submitted", "inspected", "approved", "rejected", "archived"],
                "transitions": [{"from": "draft", "to": "submitted", "trigger": "submit_inspection"}],
            }
        )
    executable_rule_input_types = set(executable_class_to_rule.keys())
    rule_generation_input_count = sum(
        1 for item in clause_classifications
        if str(item.get("rule_type", "")).strip() in executable_rule_input_types
    )

    # fill parent/children relationship
    component_map: Dict[str, Dict[str, Any]] = {str(c.get("component_id", "")): c for c in components if isinstance(c, dict)}
    for cls in clause_classifications:
        clause_id = str(cls.get("clause_id", "")).strip()
        if not clause_id or clause_id not in clause_to_component:
            continue
        current_id = clause_to_component[clause_id]
        current = component_map.get(current_id)
        if not current:
            continue
        source_clause = cls.get("source_clause", {}) if isinstance(cls.get("source_clause", {}), dict) else {}
        parent_clause = source_clause.get("parent_id")
        parent_id = clause_to_component.get(str(parent_clause), root_component_id) if parent_clause else root_component_id
        current["parent_component_id"] = parent_id
        parent = component_map.get(parent_id)
        if parent is not None:
            children = parent.get("children")
            if not isinstance(children, list):
                parent["children"] = []
                children = parent["children"]
            if current_id not in children:
                children.append(current_id)

    # Bind rules to generated components and enforce clause traceability.
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        source_clause_id = str(rule.get("source_clause_id", "")).strip()
        comp_id = clause_to_component.get(source_clause_id, "")
        rule["component_id"] = comp_id
        if not str(rule.get("norm_ref", "")).strip():
            rule["unresolved"] = True
            rule["enabled"] = False
            rule["unresolved_reason"] = "missing_norm_ref"
            rule["source_ref"] = ""
        if not source_clause_id or not comp_id:
            rule["enabled"] = False
            rule["unresolved"] = True
            rule["unresolved_reason"] = "missing_source_ref" if not source_clause_id else "component_missing"
        if not str(rule.get("source_ref", "")).strip():
            rule["source_ref"] = str(rule.get("norm_ref", "")).strip()
    unresolved_queue_stats = _enqueue_unresolved_rules(job_id, rules)

    # Gate generation from Rules only (normRef lineage enforced).
    gates = []
    rules_by_component: Dict[str, List[Dict[str, Any]]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        comp_id = str(rule.get("component_id", "")).strip()
        if not comp_id:
            continue
        rules_by_component.setdefault(comp_id, []).append(rule)

    attempted_gate_count = 0
    skipped_gate_reasons: List[str] = []
    executable_component_ids = {
        str(c.get("component_id", "")).strip()
        for c in components
        if isinstance(c, dict) and bool(c.get("executable", False))
    }
    for comp_id in sorted(executable_component_ids):
        attempted_gate_count += 1
        raw_comp_rules = rules_by_component.get(comp_id, [])
        comp_rules = [
            r for r in raw_comp_rules
            if isinstance(r, dict)
            and str(r.get("norm_ref", "")).strip()
            and str(r.get("source_ref", "")).strip()
            and str(r.get("field", "")).strip()
            and str(r.get("operator", "")).strip() in {"exists", "between", ">=", "<=", ">", "<", "==", "!="}
        ]
        rule_ids = [str(r.get("rule_id", "")).strip() for r in comp_rules if str(r.get("rule_id", "")).strip()]
        norm_refs = [str(r.get("norm_ref", "")).strip() for r in comp_rules if str(r.get("norm_ref", "")).strip()]
        enabled_rules = [r for r in comp_rules if bool(r.get("enabled", False))]
        unresolved = len(enabled_rules) == 0 or any(bool(r.get("unresolved", False)) for r in comp_rules)
        unresolved_reason = ""
        if not rule_ids:
            unresolved = True
            unresolved_reason = "rules_not_structured"
        elif any(bool(r.get("unresolved", False)) for r in comp_rules):
            unresolved_reason = "rule_unresolved_or_disabled"
        if len(norm_refs) != len(rule_ids):
            unresolved = True
            unresolved_reason = "rule_missing_norm_ref"
        logic = "ALL_PASS"
        synth = _synthesize_gate_from_rules(comp_rules)
        gate = {
            "gate_id": f"gate.{comp_id}",
            "component_id": comp_id,
            "norm_refs": sorted(set(norm_refs)),
            "rules": rule_ids,
            # backward-compatible alias
            "rule_ids": rule_ids,
            "logic": logic,
            "unresolved": unresolved,
            "enabled": not unresolved,
            "unresolved_reason": "" if not unresolved else (unresolved_reason or "rule_unresolved_or_disabled"),
            "source_model": "rule_only",
            "traceable": bool(len(rule_ids) > 0 and len(norm_refs) > 0),
            "executable": bool((not unresolved) and len(enabled_rules) > 0),
            "gate_type": str(synth.get("gate_type") or "threshold_check"),
            "decision_logic": str(synth.get("decision_logic") or "FAIL_IF_MISMATCH"),
        }
        if unresolved:
            skipped_gate_reasons.append(str(gate.get("unresolved_reason") or "gate_unresolved"))
            # Hard rule: Gate must be generated from valid Rule set.
            # Unresolved gate rows are not emitted as generated gates.
            continue
        gates.append(gate)

    if skipped_gate_reasons:
        package["review_status"] = "pending_review"
        package["gate_review_required"] = True
        package["gate_review_reasons"] = sorted(list(set([str(x) for x in skipped_gate_reasons if str(x).strip()])))
        package["updated_at"] = _utc_now()
        _save_review_package(package)

    gate_ids_by_component: Dict[str, List[str]] = {}
    for g in gates:
        cid = str(g.get("component_id", ""))
        gid = str(g.get("gate_id", ""))
        if cid and gid:
            gate_ids_by_component.setdefault(cid, []).append(gid)

    rule_ids_by_component: Dict[str, List[str]] = {}
    for r in rules:
        if not isinstance(r, dict):
            continue
        cid = str(r.get("component_id", "")).strip()
        rid = str(r.get("rule_id", "")).strip()
        if cid and rid:
            rule_ids_by_component.setdefault(cid, []).append(rid)

    for comp in components:
        if not isinstance(comp, dict):
            continue
        cid = str(comp.get("component_id", "")).strip()
        if not cid:
            continue
        comp_rules = rule_ids_by_component.get(cid, [])
        comp_gates = gate_ids_by_component.get(cid, [])
        comp["rules"] = comp_rules
        comp["gates"] = comp_gates
        if bool(comp.get("executable", False)):
            if comp_rules and comp_gates:
                comp["status"] = "active"
            elif comp_rules and not comp_gates:
                comp["status"] = "rule_only"
            else:
                comp["status"] = "unresolved"
        else:
            comp["status"] = "core_only"

    # DTO / ExecutorSpec are runtime-derived only (from Component + Rule + Gate).
    dtos = []
    execspecs = []
    for comp in components:
        if not isinstance(comp, dict) or not bool(comp.get("executable", False)):
            continue
        comp_id = str(comp.get("component_id", "")).strip()
        if not comp_id:
            continue
        related_rule_ids = rule_ids_by_component.get(comp_id, [])
        related_gate_ids = gate_ids_by_component.get(comp_id, [])
        dto_id = f"dto.{comp_id}"
        comp_rules_full = [r for r in rules if isinstance(r, dict) and str(r.get("component_id", "")).strip() == comp_id]
        dto_fields = _build_dto_fields_for_component(comp, comp_rules_full)
        dto_norm_refs = sorted(
            {
                str(r.get("norm_ref", "")).strip()
                for r in comp_rules_full
                if str(r.get("norm_ref", "")).strip()
            }
        )
        dtos.append(
            {
                "dto_id": dto_id,
                "component_id": comp_id,
                "generated_from_rule_ids": related_rule_ids,
                "generated_from_norm_refs": dto_norm_refs,
                "execution_only": True,
                "not_for_normative_judgement": True,
                "source_model": "rule_normref_derived",
                "fields": dto_fields,
            }
        )
        execspecs.append(
            {
                "executor_spec_id": f"execspec.{comp_id}",
                "component_id": comp_id,
                "dto_id": dto_id,
                "calculation_path": [],
                "rules": related_rule_ids,
                "gate": {"gate_ids": related_gate_ids},
                "output_schema": {"result": "PASS | FAIL", "details": []},
                "unresolved": len(related_rule_ids) == 0 or len(related_gate_ids) == 0,
            }
        )

    for e in execspecs:
        cid = str(e.get("component_id", ""))
        e["gate"] = {"gate_ids": gate_ids_by_component.get(cid, [])}
        if not gate_ids_by_component.get(cid):
            e["unresolved"] = True

    normdoc_id_seed = f"{std_code}@{version_tag or 'v1'}"

    # Proof templates for each executable component.
    proof_templates: List[Dict[str, Any]] = []
    for comp in components:
        if not bool(comp.get("executable", False)):
            continue
        cid = str(comp.get("component_id", "")).strip()
        if not cid:
            continue
        comp_clause_ids = comp.get("source_clause_ids", [])
        if not isinstance(comp_clause_ids, list):
            comp_clause_ids = []
        comp_rule_ids = [
            str(r.get("rule_id", ""))
            for r in rules
            if isinstance(r, dict)
            and str(r.get("component_id", "")) == cid
        ]
        comp_gate_ids = gate_ids_by_component.get(cid, [])
        proof = {
            "proof_id": f"proof.{cid}",
            "component_id": cid,
            "rule_ids": comp_rule_ids,
            "gate_ids": comp_gate_ids,
            "required_evidence": [
                "source_clause_snapshot",
                "measurement_or_process_record",
                "gate_evaluation_result",
            ],
            "input_hash_required": True,
            "execution_trace_required": True,
            "signature_required": True,
            "timestamp_required": True,
            "derive_source": "Component+Rule+Gate",
            "source_clause_ids": [str(x) for x in comp_clause_ids if str(x).strip()],
            "normdoc_id": normdoc_id_seed,
            "norm_ref": resolved_normref,
        }
        proof_templates.append(proof)
    def _is_likely_truncated_clause_text(text: str) -> bool:
        s = str(text or "").strip()
        if not s:
            return True
        # no terminal punctuation and ends with connective/function word
        if (not re.search(r"[。！？；：:]$", s)) and re.search(r"[并及与或运按由应将为在对从向至于其该等时后前内外上下一二三四五六七八九十]$", s):
            return True
        if len(s) >= 24 and ("\n" not in s) and (not re.search(r"[。！？；：:]$", s)):
            return True
        return False

    clause_text_quality_rows: List[Dict[str, Any]] = []
    for node in clause_tree_nodes:
        if not isinstance(node, dict):
            continue
        ntype = str(node.get("type", "")).strip().lower()
        if ntype not in {"clause", "paragraph", "article"}:
            continue
        cid = str(node.get("id", "")).strip()
        src_text = str(node.get("source_text") or node.get("content") or node.get("name") or "").strip()
        if not cid:
            continue
        if _is_likely_truncated_clause_text(src_text):
            clause_text_quality_rows.append(
                {
                    "clause_id": cid,
                    "source_text_tail": src_text[-48:] if len(src_text) > 48 else src_text,
                    "source_page": int(node.get("source_page", 0) or 0),
                    "reason": "possible_truncated_text",
                }
            )

    audit = {
        "valid": True,
        "audit_status": "PASS",
        "coverage": {
            "spec": True,
            "catalog": True,
            "catalog_count": len(catalog_rows),
            "clause_tree_count": len(clause_tree_nodes),
            "work_items": len([c for c in components if str(c.get("type")) == "WorkItem"]),
            "measured_items": len(measured_items),
            "rules": len(rules),
            "gates": len(gates),
            "dto_schemas": len(dtos),
            "proofs": len(proof_templates),
        },
        "errors": [],
        "blockers": [],
        "warnings": ([] if approved else ["no approved candidates"]),
        "publishable": False,
        "next_actions": [],
        "normRef": resolved_normref,
        "clause_text_quality": {
            "possible_truncated_count": len(clause_text_quality_rows),
            "possible_truncated_sample": clause_text_quality_rows[:30],
        },
    }
    rule_generation_reason = "ok"
    rule_generation_error = False
    if classification_generation_failed:
        rule_generation_error = True
        rule_generation_reason = "classification failed: clause_tree not ready"
    elif len(clause_classifications) > 0 and len(rules) == 0:
        rule_generation_error = True
        rule_generation_reason = "rule_generation_failed"
    elif rule_generation_input_count > 0 and len(rules) == 0:
        rule_generation_error = True
        rule_generation_reason = "rule_generation_failed"
    audit["rule_generation"] = {
        "input_count": int(rule_generation_input_count),
        "generated_count": int(len(rules)),
        "error": bool(rule_generation_error),
        "reason": rule_generation_reason,
    }
    if classification_generation_failed:
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append("classification_generation_failed: clause_tree=0 or missing chapter/section")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    if rule_generation_error:
        errs = audit.get("errors", [])
        if not isinstance(errs, list):
            errs = []
        errs.append("rule_generation_failed")
        audit["errors"] = errs
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    if clause_tree_generation_error:
        audit["clause_tree_generation_error"] = clause_tree_generation_error
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append(f"clause_tree_generation_error: {clause_tree_generation_error.get('reason')}")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    if clause_text_quality_rows:
        warnings = audit.get("warnings", [])
        if not isinstance(warnings, list):
            warnings = []
        warnings.append(f"possible_truncated_clause_text_count={len(clause_text_quality_rows)}")
        audit["warnings"] = warnings
    # Pipeline debug snapshot
    classification_counter: Dict[str, int] = {}
    for item in clause_classifications:
        key = str(item.get("rule_type", "unknown")).strip() or "unknown"
        classification_counter[key] = classification_counter.get(key, 0) + 1
    component_type_counter: Dict[str, int] = {}
    executable_true = 0
    executable_false = 0
    for item in components:
        ctype = str(item.get("type", "unknown")).strip() or "unknown"
        component_type_counter[ctype] = component_type_counter.get(ctype, 0) + 1
        if bool(item.get("executable", False)):
            executable_true += 1
        else:
            executable_false += 1
    unresolved_rule_count = len([r for r in rules if bool(r.get("unresolved", False))])
    unresolved_gate_count = len([g for g in gates if bool(g.get("unresolved", False))])
    unresolved_rule_rate = (float(unresolved_rule_count) / float(len(rules))) if len(rules) > 0 else 1.0
    rule_reason_counter: Dict[str, int] = {}
    for r in rules:
        reason = str(r.get("unresolved_reason") or "").strip()
        if reason:
            rule_reason_counter[reason] = rule_reason_counter.get(reason, 0) + 1
    for reason in skipped_rule_reasons:
        rule_reason_counter[reason] = rule_reason_counter.get(reason, 0) + 1
    gate_reason_counter: Dict[str, int] = {}
    for reason in skipped_gate_reasons:
        gate_reason_counter[reason] = gate_reason_counter.get(reason, 0) + 1
    for g in gates:
        if bool(g.get("unresolved", False)):
            reason = str(g.get("unresolved_reason") or "gate_unresolved").strip()
            gate_reason_counter[reason] = gate_reason_counter.get(reason, 0) + 1
    audit["pipeline_debug"] = {
        "classification_stats": classification_counter,
        "component_stats": {
            "by_type": component_type_counter,
            "executable_true_count": executable_true,
            "executable_false_count": executable_false,
        },
        "rule_generation_stats": {
            "attempted_rule_count": attempted_rule_count,
            "generated_rule_count": len(rules),
            "unresolved_rule_count": unresolved_rule_count,
            "skipped_rule_count": max(0, attempted_rule_count - len(rules)),
            "skipped_reasons_top10": sorted(
                [{"reason": k, "count": v} for k, v in rule_reason_counter.items()],
                key=lambda x: x["count"],
                reverse=True,
            )[:10],
        },
        "gate_generation_stats": {
            "attempted_gate_count": attempted_gate_count,
            "generated_gate_count": len(gates),
            "unresolved_gate_count": unresolved_gate_count,
            "skipped_gate_count": max(0, attempted_gate_count - len(gates)),
            "skipped_reasons_top10": sorted(
                [{"reason": k, "count": v} for k, v in gate_reason_counter.items()],
                key=lambda x: x["count"],
                reverse=True,
            )[:10],
        },
        "unresolved_queue_stats": unresolved_queue_stats,
    }
    executable_classification_count = sum(
        1 for item in clause_classifications
        if str(item.get("rule_type", "")).strip() in executable_clause_classes
    )
    metadata_noise_nodes_count = len(source_metadata_nodes)
    filtered_metadata_nodes_count = len(source_metadata_nodes)
    warnings = audit.get("warnings", [])
    if not isinstance(warnings, list):
        warnings = []
    warnings.append(f"metadata_noise_nodes_count={metadata_noise_nodes_count}")
    warnings.append(f"filtered_metadata_nodes_count={filtered_metadata_nodes_count}")
    audit["warnings"] = warnings
    audit["metadata_noise_nodes_count"] = metadata_noise_nodes_count
    audit["filtered_metadata_nodes_count"] = filtered_metadata_nodes_count
    # semantic consistency checks for catalog vs clause_tree
    catalog_body_like = [
        x for x in catalog_rows
        if str(x.get("type", "")).strip().lower() in {"clause", "paragraph", "table", "article", "item"}
    ]
    clause_tree_catalog_like = [
        x for x in clause_tree_nodes
        if str(x.get("type", "")).strip().lower() in {"chapter", "section", "appendix", "table_index"}
    ]
    clause_tree_content_like = [
        x for x in clause_tree_nodes
        if str(x.get("type", "")).strip().lower() in {"clause", "paragraph", "table"}
    ]
    if len(clause_tree_nodes) < len(catalog_rows):
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append("clause_tree_count < catalog_count")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
    if len(catalog_body_like) > max(5, int(len(catalog_rows) * 0.25)):
        warnings = audit.get("warnings", [])
        if not isinstance(warnings, list):
            warnings = []
        warnings.append(f"catalog contains too many body nodes ({len(catalog_body_like)}/{len(catalog_rows)})")
        audit["warnings"] = warnings
    if clause_tree_nodes and len(clause_tree_content_like) == 0 and len(clause_tree_catalog_like) == len(clause_tree_nodes):
        warnings = audit.get("warnings", [])
        if not isinstance(warnings, list):
            warnings = []
        warnings.append("clause_tree contains catalog-only nodes without content clauses")
        audit["warnings"] = warnings
    if executable_classification_count > 0 and len(rules) == 0:
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append("executable classifications exist but generated rules=0")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    if executable_classification_count > 0 and len(gates) == 0:
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append("executable classifications exist but generated gates=0")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    source_artifacts = package.get("source_artifacts", {}) if isinstance(package.get("source_artifacts", {}), dict) else {}
    preview_text = str(source_artifacts.get("source_text_preview", "") or "")
    file_detect = _detect_std_identity(source_file_name)
    pdf_detect = _detect_std_identity(preview_text)
    file_code = _format_std_code_display(str(file_detect.get("std_code", "")).strip())
    pdf_code = _format_std_code_display(str(pdf_detect.get("std_code", "")).strip())
    if file_code and _normalize_code(file_code) != _normalize_code(std_code):
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append(f"spec_code mismatch with filename: {std_code} vs {file_code}")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    if pdf_code and _normalize_code(pdf_code) != _normalize_code(std_code):
        blockers = audit.get("blockers", [])
        if not isinstance(blockers, list):
            blockers = []
        blockers.append(f"spec_code mismatch with pdf_preview: {std_code} vs {pdf_code}")
        audit["blockers"] = blockers
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    if file_code and pdf_code and _normalize_code(file_code) != _normalize_code(pdf_code):
        warnings = audit.get("warnings", [])
        if not isinstance(warnings, list):
            warnings = []
        warnings.append(f"spec_code mismatch between filename ({file_code}) and pdf_preview ({pdf_code})")
        audit["warnings"] = warnings
    if is_jtgt3650:
        acceptance = _jtgt3650_acceptance_audit(spec, catalog_rows, components, rules, gates)
        audit["acceptance_profile"] = acceptance
        if not bool(acceptance.get("passed", False)):
            audit["audit_status"] = "FAIL"
            blockers = audit.get("blockers", [])
            if not isinstance(blockers, list):
                blockers = []
            blockers.extend([str(x) for x in acceptance.get("blockers", []) if str(x).strip()])
            audit["blockers"] = blockers

    norm_ref_index = _build_norm_ref_index(
        normref_meta=normref_meta,
        std_code=std_code,
        clause_tree_nodes=clause_tree_nodes,
        catalog_rows=catalog_rows,
        clause_classifications=clause_classifications,
        components=components,
        rules=rules,
    )
    table_structured = [x for x in package.get("table_structured", []) if isinstance(x, dict)] if isinstance(package.get("table_structured"), list) else []
    formula_rows = [x for x in package.get("formulas", []) if isinstance(x, dict)] if isinstance(package.get("formulas"), list) else []
    layout_semantic_ir = _build_layout_semantic_ir(
        spec=spec,
        clause_tree_nodes=clause_tree_nodes,
        table_structured=table_structured,
        formulas=formula_rows,
    )
    cross_page_context = _build_cross_page_context(
        spec=spec,
        clause_tree_nodes=clause_tree_nodes,
        table_structured=table_structured,
    )
    semantic_triples = _build_semantic_triples_artifact(
        spec=spec,
        clause_tree_nodes=clause_tree_nodes,
    )
    slot_mapping_recommendations = _build_slot_mapping_recommendations_artifact(
        job_id=job_id,
        spec=spec,
        clause_tree_nodes=clause_tree_nodes,
        semantic_triples=semantic_triples,
        components=components,
        blueprint_metadata=_load_system_config(),
    )
    slot_conflict_report = _build_slot_conflict_report(
        job_id=job_id,
        spec_code=str(spec.get("spec_code") or spec.get("spec_id") or "").strip(),
        recommendations=slot_mapping_recommendations,
    )
    critical_slots = set(slot_conflict_report.get("critical_slots", []) if isinstance(slot_conflict_report.get("critical_slots"), list) else [])
    if critical_slots:
        rows = slot_mapping_recommendations.get("recommended_slot_keys", []) if isinstance(slot_mapping_recommendations.get("recommended_slot_keys"), list) else []
        blocked = 0
        for row in rows:
            if not isinstance(row, dict):
                continue
            slot = str(row.get("auto_bind_slotKey") or "").strip()
            if slot and slot in critical_slots and str(row.get("decision") or "").strip() == "auto_bind":
                row["decision"] = "human_review"
                row["auto_bind_slotKey"] = ""
                row["critical_conflict_blocked"] = True
                row["block_reason"] = "critical_slot_conflict"
                blocked += 1
        slot_mapping_recommendations["auto_bind_count"] = len([x for x in rows if isinstance(x, dict) and str(x.get("decision") or "") == "auto_bind"])
        slot_mapping_recommendations["human_review_count"] = len(rows) - int(slot_mapping_recommendations.get("auto_bind_count", 0) or 0)
        slot_mapping_recommendations["critical_conflict_blocked_count"] = blocked
    mapping_memory = _build_mapping_memory_artifact(job_id)
    tolerance_extraction = _build_tolerance_extraction_artifact(
        spec=spec,
        clause_tree_nodes=clause_tree_nodes,
    )
    formula_ir = _build_formula_ir_artifact(
        spec=spec,
        formulas=formula_rows,
        rules=rules,
    )
    def _rule_row_isomorphic(row: Dict[str, Any]) -> bool:
        op = str(row.get("operator", "")).strip()
        field = str(row.get("field", "")).strip()
        unit = str(row.get("unit", "")).strip()
        norm_ref = str(row.get("norm_ref", "")).strip()
        min_v = row.get("min")
        max_v = row.get("max")
        if not field:
            return False
        if field == "measured_value" and op != "exists":
            return False
        if not unit or not norm_ref:
            if op != "exists" or not norm_ref:
                return False
        if bool(row.get("unresolved", False)):
            return False
        if op == "between":
            return min_v is not None and max_v is not None
        if op in {">=", ">", "==", "!="}:
            return min_v is not None or max_v is not None
        if op in {"<=", "<"}:
            return max_v is not None or min_v is not None
        if op == "exists":
            return True
        return False

    def _gate_row_isomorphic(row: Dict[str, Any], known_rule_ids: set[str]) -> bool:
        if str(row.get("source_model", "")).strip().lower() != "rule_only":
            return False
        if bool(row.get("unresolved", False)):
            return False
        rule_ids = [str(x).strip() for x in (row.get("rules") or []) if str(x).strip()]
        if not rule_ids:
            return False
        if any(rule_id not in known_rule_ids for rule_id in rule_ids):
            return False
        norm_refs = [str(x).strip() for x in (row.get("norm_refs") or []) if str(x).strip()]
        return len(norm_refs) > 0

    normref_count = int(norm_ref_index.get("count", 0) or 0) if isinstance(norm_ref_index, dict) else 0
    component_to_specir: Dict[str, str] = {}
    for c in components:
        if not isinstance(c, dict):
            continue
        comp_id = str(c.get("component_id") or "").strip()
        specir_id = str(c.get("specir_id") or comp_id).strip()
        if comp_id and specir_id:
            component_to_specir[comp_id] = specir_id
    for r in rules:
        if not isinstance(r, dict):
            continue
        comp_id = str(r.get("component_id") or "").strip()
        source_specir_id = str(r.get("source_specir_id") or r.get("specir_id") or "").strip()
        if (not source_specir_id) and comp_id:
            source_specir_id = component_to_specir.get(comp_id, "")
        if source_specir_id:
            r["source_specir_id"] = source_specir_id
            r["specir_id"] = source_specir_id
        r["specir_version"] = str(r.get("specir_version") or "v1").strip() or "v1"
    for g in gates:
        if not isinstance(g, dict):
            continue
        rule_ids = g.get("rules", g.get("rule_ids", []))
        if isinstance(rule_ids, list):
            refs = [str(x).strip() for x in rule_ids if str(x).strip()]
            g["rule_refs"] = refs
            g["ruleRefs"] = refs
    rule_rows = [r for r in rules if isinstance(r, dict)]
    ready_rule_rows = [r for r in rule_rows if _rule_row_isomorphic(r)]
    ready_rule_ids_set = {str(r.get("rule_id", "")).strip() for r in ready_rule_rows if str(r.get("rule_id", "")).strip()}
    rule_isomorphic_ready = bool(normref_count > 0 and len(ready_rule_rows) > 0)
    gate_rows = [g for g in gates if isinstance(g, dict)]
    ready_gate_rows = [g for g in gate_rows if _gate_row_isomorphic(g, ready_rule_ids_set)]
    gate_isomorphic_ready = bool(rule_isomorphic_ready and len(ready_gate_rows) > 0)
    if normref_count <= 0:
        rule_generation_status = "blocked"
        rule_generation_reason = "no_norm_ref"
    elif classification_generation_failed or rule_generation_error:
        rule_generation_status = "blocked"
        rule_generation_reason = "parse_failed"
    elif not rule_isomorphic_ready:
        rule_generation_status = "blocked"
        rule_generation_reason = "non_isomorphic_rule"
    else:
        rule_generation_status = "success"
        rule_generation_reason = "isomorphic_ready"
    if not rule_isomorphic_ready:
        gate_generation_status = "blocked"
        gate_generation_reason = "rule_blocked"
    elif not gate_isomorphic_ready:
        gate_generation_status = "blocked"
        gate_generation_reason = "non_isomorphic_gate"
    else:
        gate_generation_status = "success"
        gate_generation_reason = "isomorphic_ready"

    artifacts: Dict[str, Any] = {
        "01_spec.json": spec,
        "02_catalog.json": catalog,
        "03_clause_tree.json": {
            "valid": bool(len(clause_tree_nodes) > 0 and has_chapter_or_section),
            "count": len(clause_tree_nodes),
            "clause_tree": clause_tree,
            # backward-compatible field for consumers that expect flat nodes
            "nodes": clause_tree_nodes,
            "source_metadata": source_metadata_nodes,
            "status": "ok" if (len(clause_tree_nodes) > 0 and has_chapter_or_section) else "failed",
        },
        "04_clause_classification.json": {
            "valid": bool(not classification_generation_failed and len(clause_classifications) > 0),
            "count": len(clause_classifications),
            "classifications": clause_classifications,
            "status": "ok" if (not classification_generation_failed and len(clause_classifications) > 0) else "failed",
        },
        "layout_semantic_ir.json": layout_semantic_ir,
        "cross_page_context.json": cross_page_context,
        "semantic_triples.json": semantic_triples,
        "slot_mapping_recommendations.json": slot_mapping_recommendations,
        "slot_conflict_report.json": slot_conflict_report,
        "mapping_memory.json": mapping_memory,
        "tolerance_extraction.json": tolerance_extraction,
        "formula_ir.json": formula_ir,
        "05_components.json": {"valid": True, "count": len(components), "components": components},
        "06_dto_schema.json": {"valid": True, "count": len(dtos), "dto_schemas": dtos},
        "07_rules.json": {
            "valid": bool(rule_isomorphic_ready),
            "count": len(rules),
            "rule_generation_status": rule_generation_status,
            "rule_generation_reason": rule_generation_reason,
            "rules": rules,
        },
        "08_gates.json": {
            "valid": bool(gate_isomorphic_ready),
            "count": len(gates),
            "gate_generation_status": gate_generation_status,
            "gate_generation_reason": gate_generation_reason,
            "gates": gates,
        },
        "09_states.json": {"valid": True, "count": len(states), "states": states},
        "10_proof_templates.json": {"valid": True, "count": len(proof_templates), "proof_templates": proof_templates},
        "norm_ref_index.json": norm_ref_index,
        "12_pipeline_audit.json": audit,
    }

    schema_map = _schema_map()
    validations: Dict[str, Any] = {}
    artifact_summaries: Dict[str, Any] = {}
    files: Dict[str, str] = {}
    for name, payload in artifacts.items():
        files[name] = _write_artifact_json(job_id, name, payload)
        errs = _simple_json_schema_validate(payload, schema_map.get(name, {"type": "object"}))
        schema_valid = len(errs) == 0
        payload["valid"] = bool(payload.get("valid", True) and schema_valid)
        _write_artifact_json(job_id, name, payload)
        validations[name] = {
            "schema_valid": schema_valid,
            "business_valid": True,
            "valid": schema_valid,
            "errors": errs,
        }
        if isinstance(payload, dict):
            count_value = payload.get("count")
            if count_value is None:
                if "rules" in payload and isinstance(payload.get("rules"), list):
                    count_value = len(payload.get("rules", []))
                elif "catalog" in payload and isinstance(payload.get("catalog"), list):
                    count_value = len(payload.get("catalog", []))
                else:
                    count_value = 1
            artifact_summaries[name] = {
                "generated": True,
                "valid": bool(payload.get("valid", False)),
                "count": int(count_value) if isinstance(count_value, (int, float)) else 0,
                "status": str(payload.get("status") or ("ok" if bool(payload.get("valid", False)) else "invalid")),
            }
        else:
            artifact_summaries[name] = {"generated": True, "valid": schema_valid, "count": 0, "status": "ok" if schema_valid else "invalid"}

    primary_assets = {
        "01_spec.json",
        "02_catalog.json",
        "03_clause_tree.json",
        "04_clause_classification.json",
        "05_components.json",
        "07_rules.json",
        "08_gates.json",
    }
    secondary_assets = {
        "06_dto_schema.json",
        "09_states.json",
        "10_proof_templates.json",
    }
    # NormDoc should depend on primary assets only. Secondary derivatives do not block core establishment.
    pre_normdoc_ok = all(
        bool((validations.get(name) or {}).get("valid", False))
        for name in primary_assets
        if name in validations
    )
    bundle_seed = {
        "spec": artifacts.get("01_spec.json", {}),
        "catalog": artifacts.get("02_catalog.json", {}),
        "components": artifacts.get("05_components.json", {}),
        "rules": artifacts.get("07_rules.json", {}),
        "gates": artifacts.get("08_gates.json", {}),
        # Secondary derivatives are referenced in NormDoc but not required for core establishment.
        "dto_schemas": artifacts.get("06_dto_schema.json", {}),
        "states": artifacts.get("09_states.json", {}),
        "proof_templates": artifacts.get("10_proof_templates.json", {}),
    }
    bundle_hash = _stable_json_hash(bundle_seed)
    normdoc_norm_refs = sorted(
        {
            str((r or {}).get("norm_ref", "")).strip()
            for r in rules
            if isinstance(r, dict) and str((r or {}).get("norm_ref", "")).strip()
        }
    )
    normdoc_specir_refs = sorted(
        {
            str((r or {}).get("source_specir_id") or (r or {}).get("specir_id") or "").strip()
            for r in rules
            if isinstance(r, dict) and str((r or {}).get("source_specir_id") or (r or {}).get("specir_id") or "").strip()
        }
    )
    normdoc = {
        "valid": bool(pre_normdoc_ok),
        "normdoc_id": normdoc_id_seed,
        "source_job_id": job_id,
        "created_from_job_id": job_id,
        "spec": {
            "spec_id": std_code,
            "spec_code": std_code,
            "spec_name": package_title or std_code,
            "spec_type": package_spec_type,
            "source_pdf_hash": source_pdf_hash,
            "source_doc_hash": source_doc_hash,
        },
        "spec_id": std_code,
        "spec_code": std_code,
        "standard_code": std_code,
        "spec_name": package_title or std_code,
        "spec_type": package_spec_type,
        "header": {
            "standard_id": std_code,
            "spec_id": std_code,
            "version": version_tag or "v1",
            "title": package_title or std_code,
        },
        "version": version_tag or "v1",
        "status": "draft",
        "catalog": artifacts.get("02_catalog.json", {}).get("catalog", []),
        "body": {
            "catalog": artifacts.get("02_catalog.json", {}).get("catalog", []),
            "components": artifacts.get("05_components.json", {}).get("components", []),
            "rules": artifacts.get("07_rules.json", {}).get("rules", []),
            "gates": artifacts.get("08_gates.json", {}).get("gates", []),
            "norm_refs": normdoc_norm_refs,
        },
        "gate": {
            "gates": artifacts.get("08_gates.json", {}).get("gates", []),
        },
        "norm_refs": normdoc_norm_refs,
        "specir_refs": normdoc_specir_refs,
        "source_refs": {
            "clause_tree_ref": {
                "artifact": "03_clause_tree.json",
                "count": len(clause_tree_nodes),
            },
            "classification_ref": {
                "artifact": "04_clause_classification.json",
                "count": len(clause_classifications),
            },
        },
        "components": artifacts.get("05_components.json", {}).get("components", []),
        "rules": artifacts.get("07_rules.json", {}).get("rules", []),
        "gates": artifacts.get("08_gates.json", {}).get("gates", []),
        "dto_refs": [str((x or {}).get("dto_id", "")).strip() for x in artifacts.get("06_dto_schema.json", {}).get("dto_schemas", []) if isinstance(x, dict) and str((x or {}).get("dto_id", "")).strip()],
        "dto_role": {
            "execution_interface_only": True,
            "normative_source_of_truth": False,
            "derived_from": ["rules", "norm_ref"],
            "reverse_inference_to_rules_forbidden": True,
        },
        "proof_template_refs": [str((x or {}).get("proof_id", "")).strip() for x in artifacts.get("10_proof_templates.json", {}).get("proof_templates", []) if isinstance(x, dict) and str((x or {}).get("proof_id", "")).strip()],
        "executor_spec_refs": [str((x or {}).get("executor_spec_id", "")).strip() for x in execspecs if isinstance(x, dict) and str((x or {}).get("executor_spec_id", "")).strip()],
        "states": artifacts.get("09_states.json", {}).get("states", []),
        "proof_templates": artifacts.get("10_proof_templates.json", {}).get("proof_templates", []),
        "source_pdf_hash": source_pdf_hash,
        "source_doc_hash": source_doc_hash,
        "bundle_hash": bundle_hash,
        "published_at": "",
        "publisher": "",
        "validations": {},
        "publishable": False,
        "blockers": [],
        "invalid_reasons": [],
        "reason": "",
        "immutable_after_publish": True,
        "generated_from_validated_artifacts": bool(pre_normdoc_ok),
        "normRef": resolved_normref,
        "source_model": "normref_only",
    }
    artifacts["11_normdoc.json"] = normdoc
    files["11_normdoc.json"] = _write_artifact_json(job_id, "11_normdoc.json", normdoc)
    normdoc_errs = _simple_json_schema_validate(normdoc, schema_map.get("11_normdoc.json", {"type": "object"}))
    normdoc_ok = len(normdoc_errs) == 0 and bool(pre_normdoc_ok)
    validations["11_normdoc.json"] = {
        "schema_valid": len(normdoc_errs) == 0,
        "business_valid": bool(pre_normdoc_ok),
        "valid": normdoc_ok,
        "errors": normdoc_errs if normdoc_errs else ([] if pre_normdoc_ok else ["upstream_artifact_validation_failed"]),
    }
    normdoc["valid"] = normdoc_ok
    files["11_normdoc.json"] = _write_artifact_json(job_id, "11_normdoc.json", normdoc)
    artifact_summaries["11_normdoc.json"] = {
        "generated": True,
        "valid": normdoc_ok,
        "count": 1,
        "status": "ok" if normdoc_ok else "invalid",
    }

    # Business validations (not just JSON schema)
    business_errors: List[str] = []
    is_quality_assessment_spec = (
        ("质量" in str(package_spec_type or "")) and ("评定" in str(package_spec_type or ""))
    ) or (
        ("质量" in str(normdoc.get("spec_type", ""))) and ("评定" in str(normdoc.get("spec_type", "")))
    )
    components_count = len(components)
    executable_components_count = len([c for c in components if bool(c.get("executable", False))])
    dto_schema_count = len(dtos)
    rules_count = len(rules)
    gates_count = len(gates)
    catalog_count = len(catalog_rows)
    clause_tree_count = len(clause_tree_nodes)
    normdoc_count_mismatch = []
    if len(normdoc.get("catalog", [])) != catalog_count:
        normdoc_count_mismatch.append("catalog")
    if len(normdoc.get("components", [])) != components_count:
        normdoc_count_mismatch.append("components")
    if len(normdoc.get("rules", [])) != rules_count:
        normdoc_count_mismatch.append("rules")
    if len(normdoc.get("gates", [])) != gates_count:
        normdoc_count_mismatch.append("gates")
    if clause_tree_count < catalog_count:
        business_errors.append("clause_tree_count < catalog_count")
    if catalog_count <= 0:
        business_errors.append("catalog_count <= 0")
    if clause_tree_count <= 0:
        business_errors.append("clause_tree_count <= 0")
    if not has_chapter_or_section:
        business_errors.append("clause_tree missing chapter/section")
    if components_count <= 0:
        business_errors.append("components_count <= 0")
    if rules_count <= 0:
        business_errors.append("rules_count <= 0")
    if rules_count > 0 and gates_count <= 0:
        business_errors.append("rules_count > 0 but gates_count <= 0")
    if normdoc_count_mismatch:
        business_errors.append(f"normdoc_count_mismatch: {', '.join(normdoc_count_mismatch)}")
    if str(normdoc.get("source_job_id", "")).strip() != job_id:
        business_errors.append("normdoc.source_job_id mismatch")
    # Base release gate: 01~05 must be non-empty.
    base_pipeline_ready = bool(
        str(spec.get("spec_id", "")).strip()
        and catalog_count > 0
        and clause_tree_count > 0
        and len(clause_classifications) > 0
        and components_count > 0
    )
    if not base_pipeline_ready:
        business_errors.append("pipeline_base_incomplete: require 01_spec/02_catalog/03_clause_tree/04_classification/05_components > 0")
    # Executability core depends on Rule/Gate regardless of spec_type.
    executable_core_ready = bool(rules_count > 0 and gates_count > 0)
    if not executable_core_ready:
        business_errors.append("rule_gate_not_ready")

    if business_errors:
        errs = audit.get("errors", [])
        if not isinstance(errs, list):
            errs = []
        errs.extend(business_errors)
        audit["errors"] = errs
        audit["audit_status"] = "FAIL"
        audit["valid"] = False
    audit["publishable"] = bool(audit.get("valid", False) and len(audit.get("blockers", [])) == 0 and len(audit.get("errors", [])) == 0)
    if rules_count == 0 or gates_count == 0:
        audit["publishable"] = False

    # Reflect business validation into per-artifact flags
    required_non_empty_artifacts = {"02_catalog.json", "03_clause_tree.json", "05_components.json"}
    key_business_results: Dict[str, bool] = {}
    for key in list(validations.keys()):
        schema_valid = bool((validations.get(key) or {}).get("schema_valid"))
        business_valid = True
        if key in required_non_empty_artifacts:
            if key == "02_catalog.json":
                business_valid = catalog_count > 0
            elif key == "03_clause_tree.json":
                business_valid = clause_tree_count > 0 and has_chapter_or_section
            elif key == "05_components.json":
                business_valid = components_count > 0
        elif key == "07_rules.json":
            business_valid = bool(rule_isomorphic_ready)
        elif key == "08_gates.json":
            business_valid = bool(gate_isomorphic_ready)
        elif key == "06_dto_schema.json":
            # DTO belongs to runtime/form execution derivatives, not normative core assets.
            business_valid = True
        elif key == "11_normdoc.json":
            business_valid = not business_errors
        elif key == "12_pipeline_audit.json":
            business_valid = bool(audit.get("publishable", False))
        validations[key]["business_valid"] = business_valid
        validations[key]["valid"] = bool(schema_valid and business_valid)
        key_business_results[key] = bool(business_valid)

    # Any critical artifact business_valid=false => pipeline is not publishable.
    critical_business_artifacts = {
        "02_catalog.json",
        "03_clause_tree.json",
        "05_components.json",
        "07_rules.json",
        "08_gates.json",
    }
    if any(not key_business_results.get(name, True) for name in critical_business_artifacts):
        audit["publishable"] = False
        validations.setdefault("12_pipeline_audit.json", {}).update(
            {
                "business_valid": False,
                "valid": bool(
                    bool((validations.get("12_pipeline_audit.json") or {}).get("schema_valid", False))
                    and False
                ),
            }
        )
    normdoc_business_valid = bool(validations.get("11_normdoc.json", {}).get("business_valid", False))
    rule_has_norm_ref_all = bool(len(rules) > 0 and all(str((r or {}).get("norm_ref", "")).strip() for r in rules if isinstance(r, dict)))
    body_obj = normdoc.get("body", {}) if isinstance(normdoc.get("body", {}), dict) else {}
    header_obj = normdoc.get("header", {}) if isinstance(normdoc.get("header", {}), dict) else {}
    gate_obj = normdoc.get("gate", {}) if isinstance(normdoc.get("gate", {}), dict) else {}
    body_rules_count = len(body_obj.get("rules", [])) if isinstance(body_obj.get("rules", []), list) else 0
    gate_logic_count = len(gate_obj.get("gates", [])) if isinstance(gate_obj.get("gates", []), list) else 0
    norm_refs_count = len(normdoc.get("norm_refs", [])) if isinstance(normdoc.get("norm_refs", []), list) else 0
    header_valid = bool(
        str(header_obj.get("standard_id", "")).strip()
        and str(header_obj.get("version", "")).strip()
    )
    invalid_reasons: List[str] = []
    if not header_valid:
        invalid_reasons.append("缺少 Header（标准信息）")
    if rules_count <= 0:
        invalid_reasons.append("无规则")
    if gates_count <= 0:
        invalid_reasons.append("无判定逻辑")
    if body_rules_count <= 0:
        invalid_reasons.append("Body.rules 为空")
    if gate_logic_count <= 0:
        invalid_reasons.append("Gate 为空")
    if norm_refs_count <= 0:
        invalid_reasons.append("norm_refs 为空")
    if not rule_has_norm_ref_all:
        invalid_reasons.append("存在规则缺少 norm_ref")
    if not rule_isomorphic_ready:
        invalid_reasons.append("Rule 未满足同构约束")
    if not gate_isomorphic_ready:
        invalid_reasons.append("Gate 未满足同构约束")

    release_ready = bool(
        base_pipeline_ready
        and executable_core_ready
        and rule_isomorphic_ready
        and gate_isomorphic_ready
        and len(invalid_reasons) == 0
    )
    if release_ready:
        normdoc["status"] = "ready_to_publish"
        normdoc["reason"] = "pipeline 完整且业务校验通过。"
    else:
        if not rule_isomorphic_ready or not gate_isomorphic_ready or normref_count <= 0:
            normdoc["status"] = "blocked"
            normdoc["reason"] = "NormDoc 被上游同构门禁阻断。"
        else:
            normdoc["status"] = "invalid_normdoc"
            normdoc["reason"] = "NormDoc 不满足可执行规范要求。"
    normdoc["invalid_reasons"] = invalid_reasons

    audit_blockers = audit.get("blockers", []) if isinstance(audit.get("blockers"), list) else []
    audit_errors = audit.get("errors", []) if isinstance(audit.get("errors"), list) else []
    normdoc["blockers"] = [str(x) for x in [*audit_blockers, *audit_errors] if str(x).strip()]

    normdoc["executable"] = bool(rules_count > 0 and gates_count > 0)
    normdoc["executable_reason"] = (
        "rule_gate_ready" if normdoc["executable"] else "rule_or_gate_missing"
    )
    normdoc["publishable"] = bool(normdoc.get("status") == "ready_to_publish" and audit.get("publishable", False))
    if not normdoc["publishable"]:
        audit["publishable"] = False
        validations.setdefault("12_pipeline_audit.json", {}).update(
            {
                "business_valid": False,
                "valid": bool((validations.get("12_pipeline_audit.json", {}) or {}).get("schema_valid", False) and False),
            }
        )

    validations.setdefault("11_normdoc.json", {})
    validations["11_normdoc.json"]["business_valid"] = bool(normdoc.get("status") == "ready_to_publish")
    validations["11_normdoc.json"]["valid"] = bool(
        bool(validations["11_normdoc.json"].get("schema_valid", False))
        and bool(validations["11_normdoc.json"]["business_valid"])
    )
    normdoc["valid"] = bool(validations["11_normdoc.json"]["valid"])
    artifact_summaries["11_normdoc.json"]["valid"] = bool(normdoc["valid"])
    artifact_summaries["11_normdoc.json"]["status"] = "ok" if bool(normdoc["valid"]) else "invalid"
    normdoc["validations"] = {
        "catalog_count": catalog_count,
        "clause_tree_count": clause_tree_count,
        "components_count": components_count,
        "dto_schemas_count": dto_schema_count,
        "rules_count": rules_count,
        "gates_count": gates_count,
        "states_count": len(states),
        "proof_templates_count": len(proof_templates),
    }
    normdoc["asset_layers"] = {
        "normative_core": {
            "chain": ["Spec", "Catalog", "Component", "Rule", "Gate", "NormDoc", "RuleStore"],
            "spec_count": 1 if str(spec.get("spec_id", "")).strip() else 0,
            "catalog_count": catalog_count,
            "component_count": components_count,
            "rule_count": rules_count,
            "gate_count": gates_count,
            "ready": bool(base_pipeline_ready and executable_core_ready),
        },
        "runtime_derived": {
            "chain": ["Component+Rule+Gate", "DTO", "ExecutorSpec", "ProofTemplate", "RuntimeExecution"],
            "dto_schema_count": dto_schema_count,
            "executor_spec_count": len(execspecs),
            "proof_template_count": len(proof_templates),
        },
    }
    normdoc["layerpeg"] = _build_layerpeg_from_normdoc_artifacts(
        normdoc=normdoc,
        audit=audit if isinstance(audit, dict) else {},
        job_id=job_id,
    )
    files["11_normdoc.json"] = _write_artifact_json(job_id, "11_normdoc.json", normdoc)
    # persist updated audit after business validation pass
    files["12_pipeline_audit.json"] = _write_artifact_json(job_id, "12_pipeline_audit.json", audit)

    index = {
        "job_id": job_id,
        "normRef": resolved_normref,
        "std_code": std_code,
        "spec_code": std_code,
        "spec_version": version_tag or "v1",
        "source_doc_hash": source_doc_hash,
        "title": package_title,
        "spec_type": package_spec_type,
        "version": version_tag or "v1",
        "generated_at": _utc_now(),
        "valid": all(bool(v.get("valid")) for v in validations.values()),
        "files": files,
        "validations": validations,
        "artifact_summaries": artifact_summaries,
    }
    files["00_pipeline_index.json"] = _write_artifact_json(job_id, "00_pipeline_index.json", index)
    return index


def call_gate_validate(
    api_params: Dict[str, Any],
    normdoc: Optional[Dict[str, Any]] = None,
    project: Optional[Dict[str, Any]] = None,
    cross_spec_links: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    if str(GATE_URL).startswith("local://"):
        if normdoc:
            return evaluate_normdoc_gate(
                api_params,
                normdoc,
                project=project,
                cross_spec_links=cross_spec_links,
            )
        return {"error": "Gate本地模式缺少normdoc上下文，无法执行判定。"}

    try:
        resp = requests.post(GATE_URL, json=api_params, timeout=5)
        resp.raise_for_status()
        return resp.json()
    except Exception as exc:
        if normdoc:
            local_result = evaluate_normdoc_gate(
                api_params,
                normdoc,
                project=project,
                cross_spec_links=cross_spec_links,
            )
            local_result["fallback_reason"] = f"Gate引擎未就绪: {exc}"
            return local_result
        return {"error": f"Gate引擎未就绪: {exc}"}


def generate_natural_reply(intent: NLIntent, gate_result: Dict[str, Any]) -> str:
    if "error" in gate_result:
        return "Gate 引擎当前不可用，已完成语义解析。请稍后重试或检查 Gate 服务。"

    status = str(gate_result.get("status", "")).upper()
    section = intent.entities.get("stake", "该点")
    form = intent.form_type or "该项"

    if status == "PASS":
        return f"{section} {form} 合格。"
    if status == "BLOCKED":
        reason = "不符合标准"
        results = gate_result.get("results")
        if isinstance(results, list) and results:
            reason = results[0].get("message", reason)
        return f"{section} {form} 不合格：{reason}"
    if status == "WARNING":
        return f"{section} {form} 存在告警，请复核原始数据。"

    return f"已解析 {section} {form}，等待 Gate 返回判定。"


def merge_cross_spec_into_gate_result(
    gate_result: Dict[str, Any],
    cross_spec_links: Optional[Dict[str, Any]],
    api_params: Dict[str, Any],
    project: Dict[str, Any],
) -> Dict[str, Any]:
    if not cross_spec_links:
        return gate_result

    result = dict(gate_result)
    result["cross_spec_links"] = cross_spec_links
    existing_results = result.get("results")
    if isinstance(existing_results, list) and any(
        str(item.get("source", "")).lower() == "cross_spec" for item in existing_results if isinstance(item, dict)
    ):
        return result

    issues = evaluate_cross_spec_consistency(cross_spec_links, api_params, project)
    if not issues:
        return result

    current_results = result.get("results")
    if not isinstance(current_results, list):
        current_results = []
    current_results.extend(issues)
    result["results"] = current_results

    if any(str(item.get("severity", "")).lower() == "blocking" for item in issues):
        result["status"] = "BLOCKED"
    elif str(result.get("status", "")).upper() == "PASS":
        result["status"] = "WARNING"

    return result


@app.post("/v1/gate/validate")
def gate_validate_local(payload: Dict[str, Any]) -> Dict[str, Any]:
    project_id_raw = str(payload.get("project_id", "GXX_2024_XXX")).strip() or "GXX_2024_XXX"
    project_id = project_id_raw.replace("-", "_")
    form_type = str(payload.get("form_type", "")).strip()
    if not form_type:
        return {
            "status": "WARNING",
            "source": "local_normdoc_gate",
            "results": [{"message": "缺少form_type，无法执行Gate判定"}],
        }
    try:
        project = load_project_config(project_id)
        normdoc = load_normdoc_for_form(project, form_type)
        links = payload.get("cross_spec_links")
        if not isinstance(links, dict):
            links = resolve_cross_spec_links(normdoc, payload, project)
        return evaluate_normdoc_gate(payload, normdoc, project=project, cross_spec_links=links)
    except Exception as exc:
        return {
            "status": "WARNING",
            "source": "local_normdoc_gate",
            "results": [{"message": f"Gate判定异常: {exc}"}],
        }


