@app.post("/normref/ingest/upload")
async def normref_ingest_upload(
    file: UploadFile = File(...),
    std_code: str = Form(""),
    level: str = Form("industry"),
    title: str = Form(""),
    publish: bool = Form(False),
    write_to_docs: bool = Form(False),
    version_tag: str = Form(""),
    approve_threshold: float = Form(0.75),
    ocr_max_pages: int = Form(0),
    ai_preprocess: bool = Form(False),
    ai_model: str = Form("deepseek-chat"),
) -> Dict[str, Any]:
    original_filename = str(file.filename or "upload.pdf")
    filename = _safe_upload_name(original_filename)
    if not original_filename.lower().endswith(".pdf"):
        raise HTTPException(status_code=400, detail="仅支持上传 PDF 文件。")

    NORMREF_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    file_tag = datetime.utcnow().strftime("%Y%m%d%H%M%S") + "-" + os.urandom(4).hex()
    save_path = NORMREF_UPLOAD_DIR / f"{file_tag}-{filename}"

    try:
        data = await file.read()
        if not data:
            raise HTTPException(status_code=400, detail="上传文件为空。")
        save_path.write_bytes(data)
    finally:
        await file.close()

    spec_identity = _resolve_ingest_spec_identity(
        original_filename=original_filename,
        file_bytes=data,
        provided_std_code=std_code,
        provided_level=level,
        provided_title=title,
    )
    resolved_std_code = str(spec_identity.get("resolved_std_code", "")).strip() or "UNKNOWN-STD"
    resolved_level = str(spec_identity.get("resolved_level", "")).strip() or "industry"
    resolved_title = str(spec_identity.get("resolved_title", "")).strip()
    resolved_spec_type = str(spec_identity.get("resolved_spec_type", "")).strip() or _infer_spec_type(resolved_std_code, resolved_title)
    effective_ocr_max_pages = 0 if int(ocr_max_pages or 0) <= 0 else int(ocr_max_pages)

    publish_requested = bool(publish or write_to_docs)
    run_id = f"run-{uuid.uuid4().hex[:16]}"
    run_record = _create_ingest_run_record(
        run_id=run_id,
        uploaded_file=str(save_path),
        std_code=resolved_std_code,
        title=resolved_title,
        level=resolved_level,
        spec_type=resolved_spec_type,
        ocr_max_pages=effective_ocr_max_pages,
    )
    with _ingest_runs_lock:
        _ingest_runs[run_id] = run_record

    def _worker() -> None:
        try:
            started_at = time.time()
            ingest_timeout_sec = int(os.getenv("NORMREF_INGEST_TIMEOUT_SEC", "900") or "900")
            _set_ingest_run(run_id, {"status": "running", "progress": 5, "stage": "ingest", "message": "正在解析PDF并抽取条款..."})
            ingest_done = threading.Event()
            heartbeat_error: List[str] = []

            def _ingest_heartbeat() -> None:
                # Keep UI alive during long OCR/text extraction stage.
                try:
                    steps = [8, 12, 16, 20, 24, 28, 32, 36, 40, 45, 50]
                    i = 0
                    while not ingest_done.wait(3.0):
                        elapsed = int(max(0, time.time() - started_at))
                        _set_ingest_run(
                            run_id,
                            {
                                "status": "running",
                                "progress": steps[i % len(steps)],
                                "stage": "ingest",
                                "message": f"正在解析PDF并抽取条款（OCR/目录识别中，已耗时 {elapsed}s / 超时阈值 {ingest_timeout_sec}s）...",
                            },
                        )
                        i += 1
                except Exception as hb_exc:
                    heartbeat_error.append(str(hb_exc))

            hb_thread = threading.Thread(target=_ingest_heartbeat, daemon=True)
            hb_thread.start()
            try:
                result = _run_normref_ingest_upload(
                    pdf_path=save_path,
                    std_code=resolved_std_code,
                    level=resolved_level,
                    title=resolved_title,
                    publish=False,
                    write_to_docs=False,
                    version_tag=version_tag.strip() or datetime.utcnow().strftime("%Y-%m"),
                    approve_threshold=approve_threshold,
                    ocr_max_pages=effective_ocr_max_pages,
                    ai_preprocess=ai_preprocess,
                    ai_model=ai_model,
                )
            finally:
                ingest_done.set()
            report = result.get("report", {})
            status = "completed"
            if isinstance(report, dict) and report.get("ok") is False:
                status = "review_required"
            if int(result.get("return_code", 0)) not in (0, 1):
                status = "failed"
            error_excerpt = ""
            if status == "failed":
                raw_err = str(result.get("stderr", "") or "").strip()
                raw_out = str(result.get("stdout", "") or "").strip()
                error_excerpt = (raw_err or raw_out).splitlines()[0].strip() if (raw_err or raw_out) else ""
            error_policy: Optional[Dict[str, Any]] = None
            if int(result.get("return_code", 0) or 0) == 124:
                error_policy = _error_strategy(
                    ERROR_BUILD_TIMEOUT,
                    detail=f"ingest timeout after {int(result.get('timeout_sec', 0) or 0)}s",
                )

            _set_ingest_run(run_id, {"progress": 55, "stage": "register", "message": "正在注册审查任务..."})
            review_job_ids = _register_ingest_jobs_for_review(
                result,
                input_file=str(save_path),
                force_std_code=resolved_std_code,
                force_title=resolved_title,
                force_level=resolved_level,
                force_spec_type=resolved_spec_type,
            )
            ocr_merge_report = _build_ocr_hybrid_merge_report(report if isinstance(report, dict) else {})
            ocr_rows = ocr_merge_report.get("jobs", []) if isinstance(ocr_merge_report.get("jobs"), list) else []
            row_by_job: Dict[str, Dict[str, Any]] = {}
            for row in ocr_rows:
                if not isinstance(row, dict):
                    continue
                jid = str(row.get("job_id") or "").strip()
                if jid:
                    row_by_job[jid] = row
            # persist per-job artifact and route OCR conflicts to review queue
            for rid in review_job_ids:
                per_job_report = {
                    "schema_version": "ocr_merge_report.v1",
                    "generated_at": _utc_now(),
                    "strategy": ocr_merge_report.get("strategy", "pdf_text_layer_first_ocr_fallback"),
                    "job": row_by_job.get(rid, {"job_id": rid, "route_to_review_queue": False}),
                }
                _write_artifact_json(rid, "ocr_merge_report.json", per_job_report)
                row = row_by_job.get(rid, {})
                if isinstance(row, dict) and bool(row.get("route_to_review_queue", False)):
                    try:
                        pkg = _load_review_package(rid)
                        pkg["review_status"] = "pending_review"
                        pkg["ocr_conflicts"] = row.get("conflicts", [])
                        pkg["updated_at"] = _utc_now()
                        _save_review_package(pkg)
                    except Exception:
                        pass

            artifact_runs: List[Dict[str, Any]] = []
            resolved_version = version_tag.strip() or datetime.utcnow().strftime("%Y-%m")
            spec_seg = _normalize_normref_seg(resolved_std_code, "unknown-spec")
            seed_normref = f"v://std/{spec_seg}/chapter/section/table/measured_value"
            _set_ingest_run(run_id, {"progress": 72, "stage": "artifacts", "message": "正在生成Catalog / normRef / Rule / Gate / NormDoc..."})
            for rid in review_job_ids:
                try:
                    index = _run_normref_artifact_pipeline(
                        job_id=rid,
                        version_tag=resolved_version,
                        source_file=str(save_path),
                        normref_input=seed_normref,
                    )
                    artifact_runs.append({"job_id": rid, "ok": True, "index": index})
                except Exception as exc:
                    artifact_runs.append({"job_id": rid, "ok": False, "error": str(exc)})
            artifact_ok_count = sum(1 for x in artifact_runs if bool((x or {}).get("ok")))
            artifact_fail_count = sum(1 for x in artifact_runs if not bool((x or {}).get("ok")))
            if review_job_ids and artifact_ok_count <= 0:
                status = "failed"

            parse_failure_reasons: List[str] = []
            report_jobs = report.get("jobs", []) if isinstance(report, dict) else []
            if isinstance(report_jobs, list) and report_jobs:
                first_job = report_jobs[0] if isinstance(report_jobs[0], dict) else {}
                first_job_payload = first_job.get("job", {}) if isinstance(first_job.get("job", {}), dict) else {}
                parse_failure_reasons = [str(x) for x in first_job_payload.get("parse_failure_reasons", []) if str(x).strip()]

            parse_acceptance = _build_parse_acceptance_status(
                input_file=str(save_path),
                std_code=resolved_std_code,
                normref_count=0,
                normref_item_count=0,
                catalog_minimum_passed=False if _is_jtgt3650_spec(resolved_std_code, resolved_title) else True,
                parse_failure_reasons=parse_failure_reasons,
            )
            if review_job_ids:
                stats = _collect_normref_stats_for_job(review_job_ids[0])
                catalog_acceptance = _collect_catalog_acceptance_for_job(
                    review_job_ids[0],
                    resolved_std_code,
                    resolved_title,
                )
                parse_acceptance = _build_parse_acceptance_status(
                    input_file=str(save_path),
                    std_code=resolved_std_code,
                    normref_count=stats.get("normref_count", 0),
                    normref_item_count=stats.get("normref_item_count", 0),
                    catalog_minimum_passed=bool(catalog_acceptance.get("passed", True)),
                    catalog_missing=[str(x) for x in catalog_acceptance.get("missing", []) if str(x).strip()],
                    parse_failure_reasons=parse_failure_reasons,
                )

            if int(ocr_merge_report.get("conflict_total", 0) or 0) > 0 and status == "completed":
                status = "review_required"

            identity_check = _build_std_identity_check(
                provided_std_code=resolved_std_code,
                provided_level=resolved_level,
                filename=original_filename,
                ingest_payload=result,
            )
            payload = {
                "status": status,
                "uploaded_file": str(save_path),
                "std_code": resolved_std_code,
                "title": resolved_title,
                "spec_type": resolved_spec_type,
                "level": resolved_level,
                "ocr_max_pages": effective_ocr_max_pages,
                "lifecycle_guard": {
                    "publish_requested": publish_requested,
                    "publish_applied": False,
                    "message": "已禁用上传阶段直接发布；请按“人工校验→专家签名→生成NormDoc→发布”流程执行。",
                },
                "identity_check": identity_check,
                "review_job_ids": review_job_ids,
                "artifact_runs": artifact_runs,
                "artifact_summary": {
                    "ok_count": artifact_ok_count,
                    "fail_count": artifact_fail_count,
                },
                "parse_acceptance": parse_acceptance,
                "ingest": result,
                "ocr_merge_report": ocr_merge_report,
            }
            if error_policy is not None:
                payload["error_policy"] = error_policy
            _set_ingest_run(run_id, {
                "status": "completed" if status in {"completed", "review_required"} else "failed",
                "progress": 100,
                "stage": "done",
                "message": "处理完成。" if status in {"completed", "review_required"} else ("处理失败：未生成可用 artifacts。" + (f" 详情：{error_excerpt}" if error_excerpt else "")),
                "error": error_excerpt or None,
                "review_job_ids": review_job_ids,
                "result": payload,
            })
        except Exception as exc:
            _set_ingest_run(run_id, {
                "status": "failed",
                "progress": 100,
                "stage": "failed",
                "message": "处理失败。",
                "error": str(exc),
            })

    threading.Thread(target=_worker, daemon=True).start()
    return {
        "status": "accepted",
        "run_id": run_id,
        "uploaded_file": str(save_path),
        "std_code": resolved_std_code,
        "title": resolved_title,
        "spec_type": resolved_spec_type,
        "level": resolved_level,
        "ocr_max_pages": effective_ocr_max_pages,
        "progress": 0,
        "stage": "queued",
        "message": "任务已创建，后台处理中。",
        "review_job_ids": [],
    }


