@app.get("/normref/ingest/jobs/{job_id}")
def normref_ingest_job(job_id: str) -> Dict[str, Any]:
    package = _load_review_package(job_id)
    stats = _collect_normref_stats_for_job(job_id)
    catalog_acceptance = _collect_catalog_acceptance_for_job(
        job_id,
        str(package.get("std_code", "")),
        str(package.get("title", "")),
    )
    source_artifacts_obj = (package.get("source_artifacts", {}) or {})
    raw_reasons = source_artifacts_obj.get("parse_failure_reasons", []) if isinstance(source_artifacts_obj, dict) else []
    package_reasons = [
        str(x)
        for x in (raw_reasons if isinstance(raw_reasons, list) else [])
        if str(x).strip()
    ]
    package["parse_acceptance"] = _build_parse_acceptance_status(
        input_file=str((package.get("source_artifacts", {}) or {}).get("input_file", "")),
        std_code=str(package.get("std_code", "")),
        normref_count=stats.get("normref_count", 0),
        normref_item_count=stats.get("normref_item_count", 0),
        catalog_minimum_passed=bool(catalog_acceptance.get("passed", True)),
        catalog_missing=[str(x) for x in catalog_acceptance.get("missing", []) if str(x).strip()],
        parse_failure_reasons=package_reasons,
    )
    existing_binding_summary = package.get("clause_binding_summary", {})
    has_existing_binding = isinstance(existing_binding_summary, dict) and int(existing_binding_summary.get("total", 0) or 0) > 0
    # Performance guard: avoid expensive full refresh on every job detail read.
    # Bindings are refreshed during artifact pipeline; only recompute when missing.
    if has_existing_binding:
        package["clause_binding_summary"] = existing_binding_summary
    else:
        package["clause_binding_summary"] = _refresh_review_candidate_clause_bindings(package)
    package["updated_at"] = _utc_now()
    _save_review_package(package)
    return package


def _artifact_exists(job_id: str, name: str) -> bool:
    return (_artifact_dir_for_job(job_id) / name).exists()


def _read_artifact_payload(job_id: str, name: str) -> Dict[str, Any]:
    path = _artifact_dir_for_job(job_id) / name
    if not path.exists():
        return {}
    try:
        obj = json.loads(path.read_text(encoding="utf-8-sig"))
        return obj if isinstance(obj, dict) else {}
    except Exception:
        return {}


def _build_specir_knowledge_graph(job_id: str) -> Dict[str, Any]:
    specir = _read_artifact_payload(job_id, "13_specir.json")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    comps_doc = _read_artifact_payload(job_id, "05_components.json")
    normref_idx = _read_artifact_payload(job_id, "norm_ref_index.json")
    normdoc_doc = _read_artifact_payload(job_id, "11_normdoc.json")
    packs = _find_rulepacks_by_job(job_id)
    rulepack = {}
    if packs:
        try:
            rulepack = json.loads(packs[0].read_text(encoding="utf-8"))
        except Exception:
            rulepack = {}
    meta = rulepack.get("meta", {}) if isinstance(rulepack.get("meta"), dict) else {}
    form_code = str(meta.get("form_code") or "").strip()

    nodes: Dict[str, Dict[str, Any]] = {}
    edges: List[Dict[str, Any]] = []
    def _add_node(node_id: str, ntype: str, label: str, extra: Optional[Dict[str, Any]] = None) -> None:
        nid = str(node_id or "").strip()
        if not nid:
            return
        if nid not in nodes:
            nodes[nid] = {"id": nid, "type": ntype, "label": label, **(extra or {})}
    def _add_edge(src: str, dst: str, rel: str) -> None:
        s = str(src or "").strip()
        d = str(dst or "").strip()
        if not s or not d:
            return
        edges.append({"source": s, "target": d, "relation": rel})

    std_code = str(meta.get("spec_code") or "").strip() or str((specir.get("meta") if isinstance(specir.get("meta"), dict) else {}).get("spec_code") or "").strip()
    std_id = f"standard:{std_code or 'unknown'}"
    _add_node(std_id, "Standard", std_code or "unknown")
    fc_id = f"form:{form_code or 'unknown'}"
    _add_node(fc_id, "Form", form_code or "unknown")
    rp_name = str(packs[0].name if packs else "").strip()
    rp_id = f"rulepack:{rp_name or 'unknown'}"
    _add_node(rp_id, "Rulepack", rp_name or "unknown", {"job_id": job_id})
    _add_edge(fc_id, rp_id, "generates")

    slots = specir.get("slots", []) if isinstance(specir.get("slots"), list) else []
    for s in slots:
        if not isinstance(s, dict):
            continue
        slot_key = str(s.get("slotKey") or s.get("slot") or "").strip()
        if not slot_key:
            continue
        sid = f"slot:{slot_key}"
        _add_node(sid, "Slot", slot_key)
        _add_edge(sid, fc_id, "binds_to")

    spec_items = specir.get("items", []) if isinstance(specir.get("items"), list) else []
    if len(spec_items) == 0 and isinstance(specir.get("specir"), list):
        spec_items = specir.get("specir", [])  # fallback
    for idx, it in enumerate(spec_items, start=1):
        if not isinstance(it, dict):
            continue
        sid_raw = str(it.get("specir_id") or it.get("id") or f"specir_{idx}").strip()
        sid = f"specir:{sid_raw}"
        source_clause = str(it.get("source_clause") or it.get("source_clause_id") or "").strip()
        _add_node(sid, "SpecIR", sid_raw, {"source_clause": source_clause})
        _add_edge(sid, rp_id, "generates")
        if source_clause:
            cid = f"clause:{source_clause}"
            _add_node(cid, "Clause", source_clause)
            _add_edge(cid, sid, "derived_from")
            _add_edge(std_id, cid, "references")
        slot_key = str(it.get("slot") or it.get("slotKey") or it.get("field") or "").strip()
        if slot_key:
            sl_id = f"slot:{slot_key}"
            _add_node(sl_id, "Slot", slot_key)
            _add_edge(sid, sl_id, "binds_to")

    rules = rules_doc.get("rules", []) if isinstance(rules_doc.get("rules"), list) else []
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid_raw = str(r.get("rule_id") or r.get("id") or "").strip()
        if not rid_raw:
            continue
        rid = f"rule:{rid_raw}"
        _add_node(rid, "Rule", rid_raw, {"field": str(r.get("field") or "").strip()})
        _add_edge(rid, rp_id, "used_by")
        slot_key = str(r.get("component_id") or r.get("slot") or r.get("field") or "").strip()
        slot_node_id = ""
        if slot_key:
            sid = f"slot:{slot_key}"
            slot_node_id = sid
            _add_node(sid, "Slot", slot_key)
            _add_edge(rid, sid, "binds_to")
        norm_ref = str(r.get("norm_ref") or "").strip()
        if norm_ref:
            nid = f"normRef:{norm_ref}"
            _add_node(nid, "normRef", norm_ref)
            _add_edge(rid, nid, "references")
            _add_edge(nid, slot_node_id or rid, "binds_to")
            _add_edge(rp_id, nid, "references")
            parsed = _parse_normref_uri(norm_ref) if norm_ref.startswith("v://") else {}
            clause_id = str(parsed.get("clause") or "").strip() if isinstance(parsed, dict) else ""
            if clause_id:
                cid = f"clause:{clause_id}"
                _add_node(cid, "Clause", clause_id)
                _add_edge(cid, nid, "derived_from")
                _add_edge(std_id, cid, "references")

    gates = gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid_raw = str(g.get("gate_id") or g.get("id") or "").strip()
        if not gid_raw:
            continue
        gid = f"gate:{gid_raw}"
        _add_node(gid, "Gate", gid_raw, {"operator": str(g.get("operator") or g.get("decision_logic") or "").strip()})
        for rr in _gate_rule_ids(g):
            rid = f"rule:{rr}"
            _add_node(rid, "Rule", rr)
            _add_edge(rid, gid, "generates")
            _add_edge(gid, rid, "used_by")

    entries = normref_idx.get("entries", []) if isinstance(normref_idx.get("entries"), list) else []
    for e in entries:
        if not isinstance(e, dict):
            continue
        norm_ref = str(e.get("normRef") or "").strip()
        if norm_ref:
            nid = f"normRef:{norm_ref}"
            _add_node(nid, "normRef", norm_ref)
            _add_edge(fc_id, nid, "references")

    components = comps_doc.get("components", []) if isinstance(comps_doc.get("components"), list) else []
    for c in components:
        if not isinstance(c, dict):
            continue
        cid_raw = str(c.get("component_id") or c.get("id") or "").strip()
        if not cid_raw:
            continue
        cid = f"component:{cid_raw}"
        _add_node(cid, "Component", cid_raw)
        _add_edge(cid, fc_id, "binds_to")
        for rk in ("rule_ids", "rules"):
            rv = c.get(rk)
            if isinstance(rv, list):
                for rid_raw in rv:
                    rid = str(rid_raw).strip()
                    if rid:
                        _add_node(f"rule:{rid}", "Rule", rid)
                        _add_edge(f"rule:{rid}", cid, "used_by")

    if isinstance(normdoc_doc, dict):
        nd_id_raw = str(normdoc_doc.get("normdoc_id") or normdoc_doc.get("id") or f"{form_code}:{job_id}").strip()
        nd_id = f"normdoc:{nd_id_raw}"
        _add_node(nd_id, "NormDoc", nd_id_raw)
        _add_edge(rp_id, nd_id, "generates")

    cur_norm_id = str(meta.get("spec_code") or meta.get("norm_id") or "").strip()
    # Extend graph with cross-form rulepacks from same norm to build form impact graph.
    form_slots: Dict[str, set[str]] = {}
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        m = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        nrm = str(m.get("spec_code") or m.get("norm_id") or "").strip()
        if cur_norm_id and nrm and nrm != cur_norm_id:
            continue
        fc = str(m.get("form_code") or "").strip()
        if not fc:
            continue
        cur_fc = f"form:{fc}"
        cur_rp = f"rulepack:{p.name}"
        _add_node(cur_fc, "Form", fc)
        _add_node(cur_rp, "Rulepack", p.name, {"norm_id": nrm})
        _add_edge(cur_fc, cur_rp, "generates")
        rules_rows = doc.get("rules", []) if isinstance(doc.get("rules"), list) else []
        for r in rules_rows:
            if not isinstance(r, dict):
                continue
            rid_raw = str(r.get("rule_id") or r.get("id") or "").strip()
            if rid_raw:
                rid = f"rule:{rid_raw}"
                _add_node(rid, "Rule", rid_raw, {"field": str(r.get("field") or "").strip()})
                _add_edge(rid, cur_rp, "used_by")
            slot_key = str(r.get("component_id") or r.get("slot") or r.get("field") or "").strip()
            if slot_key:
                sid = f"slot:{slot_key}"
                _add_node(sid, "Slot", slot_key)
                _add_edge(sid, cur_fc, "binds_to")
                if rid_raw:
                    _add_edge(f"rule:{rid_raw}", sid, "binds_to")
                form_slots.setdefault(fc, set()).add(slot_key)
            nr = str(r.get("norm_ref") or "").strip()
            if nr:
                nid = f"normRef:{nr}"
                _add_node(nid, "normRef", nr)
                if rid_raw:
                    _add_edge(f"rule:{rid_raw}", nid, "references")
                _add_edge(cur_rp, nid, "references")
            sp = str(r.get("source_specir_id") or r.get("specir_id") or "").strip()
            if sp:
                spid = f"specir:{fc}:{sp}"
                _add_node(spid, "SpecIR", sp, {"form_code": fc})
                _add_edge(spid, cur_rp, "generates")
                if rid_raw:
                    _add_edge(spid, f"rule:{rid_raw}", "used_by")
    all_forms = sorted(form_slots.keys())
    for i, left in enumerate(all_forms):
        for right in all_forms[i + 1 :]:
            overlap = sorted(list(form_slots.get(left, set()).intersection(form_slots.get(right, set()))))
            if not overlap:
                continue
            lf = f"form_code:{left}"
            rf = f"form_code:{right}"
            _add_edge(lf, rf, "conflicts_with")
            _add_edge(rf, lf, "conflicts_with")

    graph = {
        "schema_version": "specir_knowledge_graph.v3",
        "graph_schema": {
            "node_types": ["Standard", "Clause", "normRef", "SpecIR", "Slot", "Rule", "Gate", "Component", "Form", "Rulepack", "NormDoc"],
            "edge_types": ["derived_from", "references", "binds_to", "generates", "used_by", "overrides", "conflicts_with"],
        },
        "job_id": job_id,
        "generated_at": _utc_now(),
        "form_code": form_code,
        "node_count": len(nodes),
        "edge_count": len(edges),
        "nodes": list(nodes.values()),
        "edges": edges,
    }
    _write_artifact_json(job_id, "specir_knowledge_graph.json", graph)
    return graph


def _build_norm_knowledge_graph(job_id: str) -> Dict[str, Any]:
    clause_doc = _read_artifact_payload(job_id, "03_clause_tree.json")
    triples_doc = _read_artifact_payload(job_id, "semantic_triples.json")
    slot_map_doc = _read_artifact_payload(job_id, "slot_mapping_recommendations.json")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    runtime_graph = _build_runtime_dependency_graph(job_id)
    packs = _find_rulepacks_by_job(job_id)
    form_code = "unknown"
    norm_id = ""
    if packs:
        try:
            rp = json.loads(packs[0].read_text(encoding="utf-8-sig"))
            meta = rp.get("meta", {}) if isinstance(rp.get("meta"), dict) else {}
            form_code = str(meta.get("form_code") or "unknown").strip() or "unknown"
            norm_id = str(meta.get("spec_code") or meta.get("norm_id") or "").strip()
        except Exception:
            pass

    nodes: Dict[str, Dict[str, Any]] = {}
    edges: List[Dict[str, Any]] = []
    def _add_node(node_id: str, ntype: str, label: str, extra: Optional[Dict[str, Any]] = None) -> None:
        nid = str(node_id or "").strip()
        if not nid:
            return
        if nid not in nodes:
            nodes[nid] = {"id": nid, "type": ntype, "label": label, **(extra or {})}
    def _add_edge(src: str, dst: str, rel: str) -> None:
        s = str(src or "").strip()
        d = str(dst or "").strip()
        if s and d:
            edges.append({"source": s, "target": d, "relation": rel})

    fid = f"form:{form_code}"
    _add_node(fid, "Form", form_code, {"norm_id": norm_id})

    clause_nodes = clause_doc.get("nodes", []) if isinstance(clause_doc.get("nodes"), list) else []
    for c in clause_nodes:
        if not isinstance(c, dict):
            continue
        cid_raw = str(c.get("clause_id") or c.get("id") or "").strip()
        if not cid_raw:
            continue
        cid = f"clause:{cid_raw}"
        _add_node(cid, "Clause", cid_raw, {"content": str(c.get("content") or "").strip()[:200]})
        _add_edge(fid, cid, "has_clause")

    triples = triples_doc.get("triples", []) if isinstance(triples_doc.get("triples"), list) else []
    for i, t in enumerate(triples, start=1):
        if not isinstance(t, dict):
            continue
        sid_raw = str(t.get("semantic_id") or f"{t.get('clause_id') or 'clause'}:{i}").strip()
        sid = f"semantic:{sid_raw}"
        subject = str(t.get("subject") or "").strip()
        _add_node(sid, "Semantic", subject or sid_raw, {"operator": str(t.get("operator") or "").strip(), "unit": str(t.get("unit") or "").strip()})
        clause_id = str(t.get("clause_id") or "").strip()
        if clause_id:
            _add_edge(f"clause:{clause_id}", sid, "extracts_semantic")

    recs = slot_map_doc.get("recommended_slot_keys", []) if isinstance(slot_map_doc.get("recommended_slot_keys"), list) else []
    for r in recs:
        if not isinstance(r, dict):
            continue
        clause_id = str(r.get("clause_id") or "").strip()
        subject = str(r.get("subject") or "").strip()
        sem_key = f"semantic:{clause_id}:{subject}" if clause_id and subject else ""
        slot = str(r.get("auto_bind_slotKey") or "").strip()
        if not slot:
            tops = r.get("recommended_slot_keys", []) if isinstance(r.get("recommended_slot_keys"), list) else []
            if tops and isinstance(tops[0], dict):
                slot = str(tops[0].get("slotKey") or "").strip()
        if not slot:
            continue
        sl = f"slot:{slot}"
        _add_node(sl, "Slot", slot)
        _add_edge(sl, fid, "belongs_to_form")
        if sem_key:
            _add_edge(sem_key, sl, "maps_to_slot")

    rules = rules_doc.get("rules", []) if isinstance(rules_doc.get("rules"), list) else []
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid_raw = str(r.get("rule_id") or r.get("id") or "").strip()
        if not rid_raw:
            continue
        rid = f"rule:{rid_raw}"
        _add_node(rid, "Rule", rid_raw, {"norm_ref": str(r.get("norm_ref") or "").strip()})
        _add_edge(fid, rid, "has_rule")
        slot = str(r.get("component_id") or r.get("slot") or r.get("field") or "").strip()
        if slot:
            _add_node(f"slot:{slot}", "Slot", slot)
            _add_edge(f"slot:{slot}", rid, "drives_rule")

    gates = gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid_raw = str(g.get("gate_id") or g.get("id") or "").strip()
        if not gid_raw:
            continue
        gid = f"gate:{gid_raw}"
        _add_node(gid, "Gate", gid_raw)
        _add_edge(fid, gid, "has_gate")
        for rid in _gate_rule_ids(g):
            _add_edge(f"rule:{rid}", gid, "feeds_gate")

    rt_nodes = runtime_graph.get("nodes", []) if isinstance(runtime_graph.get("nodes"), list) else []
    rt_edges = runtime_graph.get("edges", []) if isinstance(runtime_graph.get("edges"), list) else []
    for n in rt_nodes:
        if not isinstance(n, dict):
            continue
        nid = str(n.get("id") or "").strip()
        ntype = str(n.get("type") or "").strip()
        if ntype == "Runtime":
            _add_node(nid, "Runtime", str(n.get("label") or nid))
        elif ntype == "Proof":
            _add_node(nid, "Proof", str(n.get("label") or nid))
    for e in rt_edges:
        if not isinstance(e, dict):
            continue
        s = str(e.get("source") or "").strip()
        d = str(e.get("target") or "").strip()
        rel = str(e.get("relation") or "").strip()
        if s and d:
            _add_edge(s, d, rel)

    graph = {
        "schema_version": "norm_knowledge_graph.v1",
        "job_id": job_id,
        "generated_at": _utc_now(),
        "norm_id": norm_id,
        "form_code": form_code,
        "node_count": len(nodes),
        "edge_count": len(edges),
        "nodes": list(nodes.values()),
        "edges": edges,
    }
    _write_artifact_json(job_id, "norm_knowledge_graph.json", graph)
    return graph


def _query_specir_knowledge_graph(graph: Dict[str, Any], *, q: str = "", node_type: str = "", node_id: str = "", max_depth: int = 1) -> Dict[str, Any]:
    nodes = graph.get("nodes", []) if isinstance(graph.get("nodes"), list) else []
    edges = graph.get("edges", []) if isinstance(graph.get("edges"), list) else []
    ql = str(q or "").strip().lower()
    t = str(node_type or "").strip().lower()
    nid = str(node_id or "").strip()
    seeds: set[str] = set()
    for n in nodes:
        if not isinstance(n, dict):
            continue
        cur_id = str(n.get("id") or "").strip()
        cur_type = str(n.get("type") or "").strip().lower()
        label = str(n.get("label") or "").strip().lower()
        if nid and cur_id == nid:
            seeds.add(cur_id)
            continue
        if t and cur_type != t:
            continue
        if ql and (ql not in cur_id.lower() and ql not in label):
            continue
        if (t or ql) and cur_id:
            seeds.add(cur_id)
    if not seeds and nodes:
        seeds.add(str((nodes[0] or {}).get("id") or ""))
        seeds.discard("")
    depth = max(0, min(int(max_depth or 1), 4))
    seen: set[str] = set(seeds)
    frontier: set[str] = set(seeds)
    for _ in range(depth):
        nxt: set[str] = set()
        for e in edges:
            if not isinstance(e, dict):
                continue
            s = str(e.get("source") or "").strip()
            d = str(e.get("target") or "").strip()
            if s in frontier and d and d not in seen:
                nxt.add(d)
            if d in frontier and s and s not in seen:
                nxt.add(s)
        if not nxt:
            break
        seen.update(nxt)
        frontier = nxt
    sub_nodes = [n for n in nodes if isinstance(n, dict) and str(n.get("id") or "").strip() in seen]
    sub_edges = [e for e in edges if isinstance(e, dict) and str(e.get("source") or "").strip() in seen and str(e.get("target") or "").strip() in seen]
    return {"seeds": sorted(list(seeds)), "nodes": sub_nodes, "edges": sub_edges, "node_count": len(sub_nodes), "edge_count": len(sub_edges)}


def _semantic_search_norm_knowledge_graph(job_id: str, query: str, *, top_k: int = 10, min_similarity: float = 0.2) -> Dict[str, Any]:
    q = str(query or "").strip()
    if not q:
        raise HTTPException(status_code=400, detail="query 不能为空")
    graph = _build_norm_knowledge_graph(job_id)
    nodes = graph.get("nodes", []) if isinstance(graph.get("nodes"), list) else []
    scored: List[Tuple[float, Dict[str, Any]]] = []
    for n in nodes:
        if not isinstance(n, dict):
            continue
        nid = str(n.get("id") or "").strip()
        ntype = str(n.get("type") or "").strip()
        label = str(n.get("label") or "").strip()
        payload = n.get("payload", {}) if isinstance(n.get("payload"), dict) else {}
        content = " ".join(
            [
                nid,
                label,
                str(n.get("content") or ""),
                str(payload.get("content") or ""),
                str(payload.get("norm_ref") or ""),
            ]
        ).strip()
        sim = max(_jaccard_similarity(q, label), _jaccard_similarity(q, content))
        if sim < float(min_similarity):
            continue
        scored.append((sim, {"id": nid, "type": ntype, "label": label, "similarity": round(sim, 4)}))
    scored.sort(key=lambda x: x[0], reverse=True)
    hits = [row for _, row in scored[: max(1, int(top_k or 10))]]

    clauses = [x for x in hits if str(x.get("type") or "") == "Clause"]
    specir = [x for x in hits if str(x.get("type") or "") == "Semantic"]
    rules = [x for x in hits if str(x.get("type") or "") == "Rule"]
    gates = [x for x in hits if str(x.get("type") or "") == "Gate"]

    slot_labels = [str(x.get("label") or "").strip() for x in hits if str(x.get("type") or "") == "Slot" and str(x.get("label") or "").strip()]
    source_form = str(graph.get("form_code") or "").strip()
    norm_id = str(graph.get("norm_id") or "").strip()
    propagation = _compute_cross_form_propagation(
        clause_text=q,
        slots=slot_labels[:6],
        norm_id=norm_id,
        source_form=source_form,
        min_confidence=0.35,
        top_k=max(5, int(top_k or 10)),
    )
    affected_forms = propagation.get("affected_forms", []) if isinstance(propagation.get("affected_forms"), list) else []

    return {
        "status": "ok",
        "job_id": job_id,
        "query": q,
        "semantic_retrieval": {
            "top_k": int(top_k or 10),
            "min_similarity": float(min_similarity),
            "total_hits": len(hits),
        },
        "clauses": clauses,
        "specir": specir,
        "rules": rules,
        "gates": gates,
        "affected_forms": affected_forms,
    }


def _infer_form_code_from_question(question: str) -> str:
    q = str(question or "").strip().lower()
    alias = {
        "桥施13": "bridge_shi_13",
        "桥施14": "bridge_shi_14",
        "桥施15": "bridge_shi_15",
        "桥施17": "bridge_shi_17",
        "bridge13": "bridge_shi_13",
        "bridge14": "bridge_shi_14",
        "bridge15": "bridge_shi_15",
        "bridge17": "bridge_shi_17",
    }
    for k, v in alias.items():
        if k.lower() in q:
            return v
    return ""


def _norm_qa_engine(job_id: str, question: str, *, top_k: int = 20, min_similarity: float = 0.2) -> Dict[str, Any]:
    q = str(question or "").strip()
    if not q:
        raise HTTPException(status_code=400, detail="question 不能为空")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    proof_doc = _read_artifact_payload(job_id, "10_proof_templates.json")
    clause_doc = _read_artifact_payload(job_id, "03_clause_tree.json")
    normref_doc = _read_artifact_payload(job_id, "norm_ref_index.json")
    graph = _build_norm_knowledge_graph(job_id)
    target_form = _infer_form_code_from_question(q)
    form_code = str(graph.get("form_code") or "").strip()
    enforce_form = bool(target_form and form_code and target_form == form_code)

    rule_rows = rules_doc.get("rules", []) if isinstance(rules_doc.get("rules"), list) else []
    gate_rows = gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []
    proof_rows = proof_doc.get("proof_templates", []) if isinstance(proof_doc.get("proof_templates"), list) else []
    clause_rows = clause_doc.get("nodes", []) if isinstance(clause_doc.get("nodes"), list) else []
    norm_rows = normref_doc.get("entries", []) if isinstance(normref_doc.get("entries"), list) else []

    clause_page_map: Dict[str, int] = {}
    for c in clause_rows:
        if not isinstance(c, dict):
            continue
        cid = str(c.get("clause_id") or c.get("id") or "").strip()
        page = c.get("source_page", c.get("page_no", c.get("page", 0)))
        if cid and isinstance(page, (int, float)):
            clause_page_map[cid] = int(page)
    normref_page_map: Dict[str, int] = {}
    for n in norm_rows:
        if not isinstance(n, dict):
            continue
        ref = str(n.get("normRef") or "").strip()
        page = n.get("page", n.get("source_page", 0))
        if ref and isinstance(page, (int, float)):
            normref_page_map[ref] = int(page)

    scored_rules: List[Tuple[float, Dict[str, Any]]] = []
    for r in rule_rows:
        if not isinstance(r, dict):
            continue
        text = " ".join(
            [
                str(r.get("rule_id") or ""),
                str(r.get("field") or ""),
                str(r.get("slot") or ""),
                str(r.get("component_id") or ""),
                str(r.get("norm_ref") or ""),
                str(r.get("source_clause_id") or r.get("source_clause") or ""),
                str(r.get("operator") or ""),
                str(r.get("unit") or ""),
            ]
        ).strip()
        sim = _jaccard_similarity(q, text)
        if sim < float(min_similarity):
            continue
        scored_rules.append((sim, {**r, "similarity": round(sim, 4)}))
    scored_rules.sort(key=lambda x: x[0], reverse=True)
    rules = [x for _, x in scored_rules[: max(1, int(top_k or 20))]]
    rule_ids = {str(r.get("rule_id") or r.get("id") or "").strip() for r in rules if isinstance(r, dict)}
    rule_ids.discard("")

    gates: List[Dict[str, Any]] = []
    gate_ids: set[str] = set()
    for g in gate_rows:
        if not isinstance(g, dict):
            continue
        gr = {str(x).strip() for x in _gate_rule_ids(g) if str(x).strip()}
        if gr.intersection(rule_ids):
            gid = str(g.get("gate_id") or g.get("id") or "").strip()
            if gid and gid not in gate_ids:
                gate_ids.add(gid)
                gates.append({**g, "matched_rule_ids": sorted(list(gr.intersection(rule_ids)))})

    proofs: List[Dict[str, Any]] = []
    for p in proof_rows:
        if not isinstance(p, dict):
            continue
        p_gate_ids = {str(x).strip() for x in (p.get("gate_ids", []) if isinstance(p.get("gate_ids"), list) else []) if str(x).strip()}
        if p_gate_ids.intersection(gate_ids):
            proofs.append({**p, "matched_gate_ids": sorted(list(p_gate_ids.intersection(gate_ids)))})
            continue
        src_ids = {str(x).strip() for x in (p.get("source_clause_ids", []) if isinstance(p.get("source_clause_ids"), list) else []) if str(x).strip()}
        if src_ids:
            for r in rules:
                sc = str(r.get("source_clause_id") or r.get("source_clause") or "").strip()
                if sc and sc in src_ids:
                    proofs.append({**p, "matched_gate_ids": []})
                    break

    clause_ids: set[str] = set()
    norm_refs: set[str] = set()
    for r in rules:
        clause = str(r.get("source_clause_id") or r.get("source_clause") or "").strip()
        if clause:
            clause_ids.add(clause)
        nr = str(r.get("norm_ref") or "").strip()
        if nr:
            norm_refs.add(nr)
    clauses: List[Dict[str, Any]] = []
    for c in clause_rows:
        if not isinstance(c, dict):
            continue
        cid = str(c.get("clause_id") or c.get("id") or "").strip()
        if cid and cid in clause_ids:
            clauses.append(c)
    if not clauses:
        for c in clause_rows:
            if not isinstance(c, dict):
                continue
            txt = " ".join([str(c.get("title") or ""), str(c.get("content") or "")]).strip()
            sim = _jaccard_similarity(q, txt)
            if sim >= float(min_similarity):
                clauses.append({**c, "similarity": round(sim, 4)})
        clauses = sorted(clauses, key=lambda x: float(x.get("similarity", 0.0) or 0.0), reverse=True)[: max(1, int(top_k or 20))]

    source_pages: set[int] = set()
    for cid in clause_ids:
        if cid in clause_page_map:
            source_pages.add(int(clause_page_map[cid]))
    for nr in norm_refs:
        if nr in normref_page_map:
            source_pages.add(int(normref_page_map[nr]))
    for c in clauses:
        page = c.get("source_page", c.get("page_no", c.get("page", None)))
        if isinstance(page, (int, float)):
            source_pages.add(int(page))

    answer = ""
    if "gate" in q.lower() and ("使用了" in q or "uses" in q.lower()):
        answer = f"共检索到 {len(gates)} 个 Gate 使用相关规则。"
    else:
        answer = f"已检索到 rules={len(rules)}, gates={len(gates)}, clauses={len(clauses)}。"
    if target_form:
        answer = f"{target_form}: {answer}"
    if enforce_form is False and target_form:
        answer += "（当前 job 对应表单与问题表单不一致，结果基于当前 job。）"

    return {
        "status": "ok",
        "job_id": job_id,
        "question": q,
        "answer": answer,
        "clauses": clauses,
        "rules": rules,
        "gates": gates,
        "proof": proofs,
        "source_pages": sorted(list(source_pages)),
        "semantic_retrieval": {"top_k": int(top_k or 20), "min_similarity": float(min_similarity)},
    }


def _impact_analysis_specir_graph(graph: Dict[str, Any], node_ids: List[str], max_depth: int = 2) -> Dict[str, Any]:
    q = _query_specir_knowledge_graph(graph, node_id="", max_depth=max_depth)
    seeds = {str(x).strip() for x in node_ids if str(x).strip()}
    if seeds:
        q = _query_specir_knowledge_graph(graph, node_id="", max_depth=max_depth)
        nodes = graph.get("nodes", []) if isinstance(graph.get("nodes"), list) else []
        edges = graph.get("edges", []) if isinstance(graph.get("edges"), list) else []
        seen: set[str] = set(seeds)
        frontier: set[str] = set(seeds)
        for _ in range(max(0, min(int(max_depth or 2), 5))):
            nxt: set[str] = set()
            for e in edges:
                if not isinstance(e, dict):
                    continue
                s = str(e.get("source") or "").strip()
                d = str(e.get("target") or "").strip()
                if s in frontier and d and d not in seen:
                    nxt.add(d)
                if d in frontier and s and s not in seen:
                    nxt.add(s)
            if not nxt:
                break
            seen.update(nxt)
            frontier = nxt
        q = {
            "seeds": sorted(list(seeds)),
            "nodes": [n for n in nodes if isinstance(n, dict) and str(n.get("id") or "").strip() in seen],
            "edges": [e for e in edges if isinstance(e, dict) and str(e.get("source") or "").strip() in seen and str(e.get("target") or "").strip() in seen],
        }
    by_type: Dict[str, int] = {}
    for n in q.get("nodes", []):
        if not isinstance(n, dict):
            continue
        tp = str(n.get("type") or "unknown").strip()
        by_type[tp] = by_type.get(tp, 0) + 1
    affected_forms = sorted(
        list(
            {
                str(n.get("label") or "").strip()
                for n in (q.get("nodes", []) if isinstance(q.get("nodes"), list) else [])
                if isinstance(n, dict) and str(n.get("type") or "").strip() == "Form" and str(n.get("label") or "").strip()
            }
        )
    )
    affected_rulepacks = sorted(
        list(
            {
                str(n.get("label") or "").strip()
                for n in (q.get("nodes", []) if isinstance(q.get("nodes"), list) else [])
                if isinstance(n, dict) and str(n.get("type") or "").strip() == "Rulepack" and str(n.get("label") or "").strip()
            }
        )
    )
    affected_rules = sorted(
        list(
            {
                str(n.get("label") or "").strip()
                for n in (q.get("nodes", []) if isinstance(q.get("nodes"), list) else [])
                if isinstance(n, dict) and str(n.get("type") or "").strip() == "Rule" and str(n.get("label") or "").strip()
            }
        )
    )
    affected_gates = sorted(
        list(
            {
                str(n.get("label") or "").strip()
                for n in (q.get("nodes", []) if isinstance(q.get("nodes"), list) else [])
                if isinstance(n, dict) and str(n.get("type") or "").strip() == "Gate" and str(n.get("label") or "").strip()
            }
        )
    )
    affected_normdocs = sorted(
        list(
            {
                str(n.get("label") or "").strip()
                for n in (q.get("nodes", []) if isinstance(q.get("nodes"), list) else [])
                if isinstance(n, dict) and str(n.get("type") or "").strip() == "NormDoc" and str(n.get("label") or "").strip()
            }
        )
    )
    return {
        "status": "ok",
        "seed_nodes": q.get("seeds", []),
        "affected_nodes": q.get("nodes", []),
        "affected_edges": q.get("edges", []),
        "summary": {
            "node_count": len(q.get("nodes", [])),
            "edge_count": len(q.get("edges", [])),
            "by_type": by_type,
            "affected_forms": affected_forms,
            "affected_rulepacks": affected_rulepacks,
            "affected_rules": affected_rules,
            "affected_gates": affected_gates,
            "affected_normdocs": affected_normdocs,
        },
    }


def _auto_propagate_on_form_impact_graph(graph: Dict[str, Any], *, seed_node_ids: List[str], max_depth: int = 2, min_confidence: float = 0.35) -> Dict[str, Any]:
    impact = _impact_analysis_specir_graph(graph, seed_node_ids, max_depth=max_depth)
    nodes = impact.get("affected_nodes", []) if isinstance(impact.get("affected_nodes"), list) else []
    edges = impact.get("affected_edges", []) if isinstance(impact.get("affected_edges"), list) else []
    seeds = {str(x).strip() for x in (impact.get("seed_nodes", []) if isinstance(impact.get("seed_nodes"), list) else []) if str(x).strip()}

    node_by_id: Dict[str, Dict[str, Any]] = {str(n.get("id") or "").strip(): n for n in nodes if isinstance(n, dict) and str(n.get("id") or "").strip()}
    seed_slots: set[str] = set()
    seed_normrefs: set[str] = set()
    explicit_seed_forms: set[str] = set()
    inferred_seed_forms: set[str] = set()
    for sid in seeds:
        n = node_by_id.get(sid, {})
        tp = str(n.get("type") or "").strip()
        lb = str(n.get("label") or "").strip()
        if tp == "slot":
            seed_slots.add(lb)
        elif tp == "normRef":
            seed_normrefs.add(lb)
        elif tp == "form_code":
            explicit_seed_forms.add(lb)
    for e in edges:
        if not isinstance(e, dict):
            continue
        s = str(e.get("source") or "").strip()
        d = str(e.get("target") or "").strip()
        if s in seeds or d in seeds:
            for nid in [s, d]:
                n = node_by_id.get(nid, {})
                tp = str(n.get("type") or "").strip()
                lb = str(n.get("label") or "").strip()
                if tp == "slot" and lb:
                    seed_slots.add(lb)
                if tp == "normRef" and lb:
                    seed_normrefs.add(lb)
                if tp == "form_code" and lb:
                    inferred_seed_forms.add(lb)

    seed_forms = explicit_seed_forms if explicit_seed_forms else set()

    form_slots: Dict[str, set[str]] = {}
    form_normrefs: Dict[str, set[str]] = {}
    for e in edges:
        if not isinstance(e, dict):
            continue
        s = str(e.get("source") or "").strip()
        d = str(e.get("target") or "").strip()
        sn = node_by_id.get(s, {})
        dn = node_by_id.get(d, {})
        st = str(sn.get("type") or "").strip()
        dt = str(dn.get("type") or "").strip()
        sl = str(sn.get("label") or "").strip()
        dl = str(dn.get("label") or "").strip()
        if st == "form_code" and dt == "slot" and sl and dl:
            form_slots.setdefault(sl, set()).add(dl)
        if st == "rule" and dt == "normRef" and dl:
            # recover form from rule inbound edge
            for e2 in edges:
                if not isinstance(e2, dict):
                    continue
                if str(e2.get("target") or "").strip() == s:
                    src2 = str(e2.get("source") or "").strip()
                    n2 = node_by_id.get(src2, {})
                    if str(n2.get("type") or "").strip() == "form_code":
                        form_normrefs.setdefault(str(n2.get("label") or "").strip(), set()).add(dl)

    def _jac(a: set[str], b: set[str]) -> float:
        if not a or not b:
            return 0.0
        return float(len(a.intersection(b))) / float(max(1, len(a.union(b))))

    rows: List[Dict[str, Any]] = []
    for n in nodes:
        if not isinstance(n, dict) or str(n.get("type") or "").strip() != "form_code":
            continue
        fc = str(n.get("label") or "").strip()
        if not fc or fc in seed_forms:
            continue
        slot_score = _jac(seed_slots, form_slots.get(fc, set()))
        normref_score = _jac(seed_normrefs, form_normrefs.get(fc, set()))
        connected = 1.0 if any(
            isinstance(e, dict)
            and (
                (str(e.get("source") or "").strip() in seeds and str(node_by_id.get(str(e.get("target") or "").strip(), {}).get("label") or "").strip() == fc)
                or (str(e.get("target") or "").strip() in seeds and str(node_by_id.get(str(e.get("source") or "").strip(), {}).get("label") or "").strip() == fc)
            )
            for e in edges
        ) else 0.0
        confidence = 0.5 * slot_score + 0.35 * normref_score + 0.15 * connected
        if confidence < float(min_confidence):
            continue
        rows.append(
            {
                "form_code": fc,
                "confidence": round(confidence, 4),
                "score_breakdown": {
                    "slot_overlap": round(slot_score, 4),
                    "normref_overlap": round(normref_score, 4),
                    "graph_connectivity": round(connected, 4),
                },
            }
        )
    rows.sort(key=lambda x: float(x.get("confidence", 0.0) or 0.0), reverse=True)
    return {"status": "ok", "seed_nodes": sorted(list(seeds)), "affected_forms": rows, "count": len(rows)}


def _graph_from_rulepack_doc(rulepack_name: str, doc: Dict[str, Any]) -> Dict[str, Any]:
    nodes: Dict[str, Dict[str, Any]] = {}
    edges: List[Dict[str, Any]] = []

    def _add_node(node_id: str, ntype: str, label: str) -> None:
        nid = str(node_id or "").strip()
        if not nid:
            return
        if nid not in nodes:
            nodes[nid] = {"id": nid, "type": ntype, "label": label}

    def _add_edge(src: str, dst: str, rel: str) -> None:
        s = str(src or "").strip()
        d = str(dst or "").strip()
        if s and d:
            edges.append({"source": s, "target": d, "relation": rel})

    meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
    fc = str(meta.get("form_code") or "").strip() or "unknown"
    fc_id = f"form_code:{fc}"
    rp_id = f"rulepack:{rulepack_name}"
    _add_node(fc_id, "form_code", fc)
    _add_node(rp_id, "rulepack", rulepack_name)
    _add_edge(fc_id, rp_id, "has_rulepack")
    rules = doc.get("rules", []) if isinstance(doc.get("rules"), list) else []
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip()
        if rid:
            ridn = f"rule:{rid}"
            _add_node(ridn, "rule", rid)
            _add_edge(fc_id, ridn, "has_rule")
            _add_edge(rp_id, ridn, "contains_rule")
        slot = str(r.get("component_id") or r.get("slot") or r.get("field") or "").strip()
        if slot:
            sid = f"slot:{slot}"
            _add_node(sid, "slot", slot)
            _add_edge(fc_id, sid, "has_slot")
            if rid:
                _add_edge(f"rule:{rid}", sid, "uses_slot")
        nr = str(r.get("norm_ref") or "").strip()
        if nr:
            nid = f"normRef:{nr}"
            _add_node(nid, "normRef", nr)
            if rid:
                _add_edge(f"rule:{rid}", nid, "traces_to")
    return {"nodes": list(nodes.values()), "edges": edges}


def _diff_form_impact_graph_versions(*, job_id: str, left_rulepack: str = "", right_rulepack: str = "") -> Dict[str, Any]:
    target_packs = _find_rulepacks_by_job(job_id)
    if not target_packs:
        raise HTTPException(status_code=404, detail="当前 job 未找到 rulepack")
    cur_doc = json.loads(target_packs[0].read_text(encoding="utf-8"))
    cur_meta = cur_doc.get("meta", {}) if isinstance(cur_doc.get("meta"), dict) else {}
    cur_form = str(cur_meta.get("form_code") or "").strip()

    pool: List[Path] = []
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        if str(meta.get("form_code") or "").strip() == cur_form:
            pool.append(p)
    pool = sorted(pool, key=lambda x: x.stat().st_mtime, reverse=True)
    if left_rulepack and right_rulepack:
        left_p = next((p for p in pool if p.name == left_rulepack), None)
        right_p = next((p for p in pool if p.name == right_rulepack), None)
    else:
        left_p = pool[1] if len(pool) >= 2 else None
        right_p = pool[0] if len(pool) >= 1 else None
    if left_p is None or right_p is None:
        raise HTTPException(status_code=400, detail="缺少可用于 Diff 的两个 rulepack 版本")

    left_doc = json.loads(left_p.read_text(encoding="utf-8"))
    right_doc = json.loads(right_p.read_text(encoding="utf-8"))
    lg = _graph_from_rulepack_doc(left_p.name, left_doc)
    rg = _graph_from_rulepack_doc(right_p.name, right_doc)

    def _node_key(n: Dict[str, Any]) -> str:
        return f"{str(n.get('type') or '')}:{str(n.get('label') or '')}"

    ln = {_node_key(n): n for n in (lg.get("nodes", []) if isinstance(lg.get("nodes"), list) else []) if isinstance(n, dict)}
    rn = {_node_key(n): n for n in (rg.get("nodes", []) if isinstance(rg.get("nodes"), list) else []) if isinstance(n, dict)}
    le = {
        f"{str(e.get('source') or '')}|{str(e.get('target') or '')}|{str(e.get('relation') or '')}"
        for e in (lg.get("edges", []) if isinstance(lg.get("edges"), list) else [])
        if isinstance(e, dict)
    }
    re = {
        f"{str(e.get('source') or '')}|{str(e.get('target') or '')}|{str(e.get('relation') or '')}"
        for e in (rg.get("edges", []) if isinstance(rg.get("edges"), list) else [])
        if isinstance(e, dict)
    }

    added_nodes = sorted([k for k in rn.keys() if k not in ln.keys()])
    removed_nodes = sorted([k for k in ln.keys() if k not in rn.keys()])
    added_edges = sorted([k for k in re if k not in le])
    removed_edges = sorted([k for k in le if k not in re])
    return {
        "status": "ok",
        "left_rulepack": left_p.name,
        "right_rulepack": right_p.name,
        "summary": {
            "added_node_count": len(added_nodes),
            "removed_node_count": len(removed_nodes),
            "added_edge_count": len(added_edges),
            "removed_edge_count": len(removed_edges),
        },
        "added_nodes": added_nodes[:300],
        "removed_nodes": removed_nodes[:300],
        "added_edges": added_edges[:500],
        "removed_edges": removed_edges[:500],
    }


def _rulepack_rules_by_id(doc: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    rules = doc.get("rules", []) if isinstance(doc.get("rules"), list) else []
    out: Dict[str, Dict[str, Any]] = {}
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip()
        if rid:
            out[rid] = r
    return out


def _rulepack_gates_by_id(doc: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    gates = doc.get("gates", []) if isinstance(doc.get("gates"), list) else []
    out: Dict[str, Dict[str, Any]] = {}
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip()
        if gid:
            out[gid] = g
    return out


def _generate_rulepack_patch(*, form_code: str, base_version: str, target_version: str) -> Dict[str, Any]:
    base_doc = json.loads(_rulepack_name_to_path(base_version).read_text(encoding="utf-8"))
    target_doc = json.loads(_rulepack_name_to_path(target_version).read_text(encoding="utf-8"))
    base_rules = _rulepack_rules_by_id(base_doc)
    target_rules = _rulepack_rules_by_id(target_doc)
    base_gates = _rulepack_gates_by_id(base_doc)
    target_gates = _rulepack_gates_by_id(target_doc)

    added_rules: List[Dict[str, Any]] = []
    removed_rules: List[Dict[str, Any]] = []
    modified_gates: List[Dict[str, Any]] = []
    for rid, row in target_rules.items():
        if rid not in base_rules:
            added_rules.append(
                {
                    "rule_id": rid,
                    "field": str(row.get("field") or "").strip(),
                    "operator": str(row.get("operator") or "").strip(),
                    "threshold": row.get("threshold"),
                    "unit": str(row.get("unit") or "").strip(),
                }
            )
    for rid, row in base_rules.items():
        if rid not in target_rules:
            removed_rules.append(
                {
                    "rule_id": rid,
                    "field": str(row.get("field") or "").strip(),
                    "operator": str(row.get("operator") or "").strip(),
                    "threshold": row.get("threshold"),
                    "unit": str(row.get("unit") or "").strip(),
                }
            )
    for gid, g2 in target_gates.items():
        g1 = base_gates.get(gid)
        if not isinstance(g1, dict):
            continue
        sig1 = _stable_json_hash(
            {
                "operator": g1.get("operator"),
                "decision_logic": g1.get("decision_logic"),
                "rule_ids": sorted(_gate_rule_ids(g1)),
                "norm_refs": sorted([str(x).strip() for x in (g1.get("norm_refs", []) if isinstance(g1.get("norm_refs"), list) else []) if str(x).strip()]),
            }
        )
        sig2 = _stable_json_hash(
            {
                "operator": g2.get("operator"),
                "decision_logic": g2.get("decision_logic"),
                "rule_ids": sorted(_gate_rule_ids(g2)),
                "norm_refs": sorted([str(x).strip() for x in (g2.get("norm_refs", []) if isinstance(g2.get("norm_refs"), list) else []) if str(x).strip()]),
            }
        )
        if sig1 != sig2:
            modified_gates.append(
                {
                    "gate_id": gid,
                    "before": {
                        "operator": g1.get("operator"),
                        "decision_logic": g1.get("decision_logic"),
                        "rule_ids": sorted(_gate_rule_ids(g1)),
                    },
                    "after": {
                        "operator": g2.get("operator"),
                        "decision_logic": g2.get("decision_logic"),
                        "rule_ids": sorted(_gate_rule_ids(g2)),
                    },
                }
            )

    return {
        "added_rules": added_rules,
        "removed_rules": removed_rules,
        "modified_gates": modified_gates,
        "affected_forms": [form_code] if form_code else [],
    }


def _resolve_patch_versions(form_code: str, base_version: str, target_version: str) -> Tuple[str, str]:
    base_v = str(base_version or "").strip()
    target_v = str(target_version or "").strip()
    if base_v and target_v:
        return base_v, target_v
    if not form_code:
        raise HTTPException(status_code=400, detail="form_code/base_version/target_version 至少提供 form_code")
    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg.get("forms"), dict) else {}
    cur = forms.get(form_code, {}) if isinstance(forms.get(form_code), dict) else {}
    hist = cur.get("history", []) if isinstance(cur.get("history"), list) else []
    releases = [x for x in hist if isinstance(x, dict) and str(x.get("action") or "").strip().lower() == "release"]
    if not target_v:
        target_v = str(cur.get("active_version") or "").strip()
    if not base_v:
        prev = ""
        for row in reversed(releases):
            to_v = str(row.get("to_version") or row.get("version") or "").strip()
            if target_v and to_v == target_v:
                prev = str(row.get("from_version") or "").strip()
                if prev:
                    break
        base_v = prev
    if not base_v or not target_v:
        raise HTTPException(status_code=400, detail="无法解析 base/target 版本，请显式传入 base_version/target_version")
    return base_v, target_v


def _shared_rule_slot(rule: Dict[str, Any]) -> str:
    return str(rule.get("component_id") or rule.get("slot") or rule.get("field") or "").strip()


def _shared_rule_semantic_sig(rule: Dict[str, Any]) -> str:
    field = str(rule.get("field") or "").strip().lower()
    op = str(rule.get("operator") or "").strip().lower()
    unit = str(rule.get("unit") or "").strip().lower()
    norm_ref = str(rule.get("norm_ref") or "").strip().lower()
    source_clause = str(rule.get("source_clause_id") or rule.get("source_clause") or "").strip().lower()
    return _stable_json_hash({"field": field, "op": op, "unit": unit, "norm_ref": norm_ref, "source_clause": source_clause})


def _shared_rule_threshold_sig(rule: Dict[str, Any]) -> str:
    th = rule.get("threshold", {}) if isinstance(rule.get("threshold"), dict) else {}
    raw = {
        "min": th.get("min"),
        "max": th.get("max"),
        "value": th.get("value"),
        "unit": th.get("unit"),
        "operator": th.get("operator"),
    }
    return _stable_json_hash(raw)


def _build_shared_rule_clusters(*, norm_id: str, current_rulepack_name: str, current_payload: Dict[str, Any]) -> Dict[str, Any]:
    candidates: List[Tuple[str, Dict[str, Any]]] = []
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        nid = str(meta.get("spec_code") or meta.get("norm_id") or "").strip()
        if norm_id and nid and nid != norm_id:
            continue
        candidates.append((p.name, doc))
    candidates.append((current_rulepack_name, current_payload))

    buckets: Dict[str, List[Dict[str, Any]]] = {}
    for rp_name, doc in candidates:
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        fc = str(meta.get("form_code") or "").strip()
        rules = doc.get("rules", []) if isinstance(doc.get("rules"), list) else []
        for r in rules:
            if not isinstance(r, dict):
                continue
            rid = str(r.get("rule_id") or r.get("id") or "").strip()
            if not rid:
                continue
            slot = _shared_rule_slot(r)
            sem = _shared_rule_semantic_sig(r)
            ths = _shared_rule_threshold_sig(r)
            if not slot or not sem or not ths:
                continue
            key = f"{slot}|{sem}|{ths}"
            buckets.setdefault(key, []).append(
                {
                    "rulepack": rp_name,
                    "form_code": fc,
                    "rule_id": rid,
                    "slot": slot,
                    "semantic_sig": sem,
                    "threshold_sig": ths,
                }
            )

    clusters: List[Dict[str, Any]] = []
    for key, items in buckets.items():
        forms = sorted(list({str(x.get("form_code") or "").strip() for x in items if str(x.get("form_code") or "").strip()}))
        if len(forms) < 2:
            continue
        first = items[0] if items else {}
        cid = f"src_{_stable_json_hash({'k': key})[:16]}"
        clusters.append(
            {
                "cluster_id": cid,
                "slot": str(first.get("slot") or "").strip(),
                "semantic_sig": str(first.get("semantic_sig") or "").strip(),
                "threshold_sig": str(first.get("threshold_sig") or "").strip(),
                "forms": forms,
                "form_count": len(forms),
                "rule_count": len(items),
                "rules": items,
            }
        )
    clusters.sort(key=lambda x: (int(x.get("form_count") or 0), int(x.get("rule_count") or 0)), reverse=True)

    current_refs: Dict[str, List[str]] = {}
    for c in clusters:
        cid = str(c.get("cluster_id") or "").strip()
        for row in (c.get("rules", []) if isinstance(c.get("rules"), list) else []):
            if not isinstance(row, dict):
                continue
            if str(row.get("rulepack") or "").strip() != current_rulepack_name:
                continue
            rid = str(row.get("rule_id") or "").strip()
            if rid:
                current_refs.setdefault(rid, []).append(cid)

    report = {
        "schema_version": "shared_rule_clusters.v1",
        "generated_at": _utc_now(),
        "norm_id": norm_id,
        "current_rulepack": current_rulepack_name,
        "cluster_count": len(clusters),
        "clusters": clusters,
        "current_rule_references": current_refs,
    }
    return report


def _cross_norm_relationship_analysis(job_id: str, graph: Dict[str, Any]) -> Dict[str, Any]:
    packs = _find_rulepacks_by_job(job_id)
    if not packs:
        return {"status": "ok", "relations": [], "summary": {"total": 0}}
    cur = json.loads(packs[0].read_text(encoding="utf-8"))
    cur_meta = cur.get("meta", {}) if isinstance(cur.get("meta"), dict) else {}
    cur_form = str(cur_meta.get("form_code") or "").strip()
    cur_spec = str(cur_meta.get("spec_code") or cur_meta.get("norm_id") or "").strip()
    cur_ver = str(cur_meta.get("norm_version") or cur_meta.get("spec_version") or "").strip()
    cur_normrefs = {
        str((n or {}).get("label") or "").strip()
        for n in (graph.get("nodes", []) if isinstance(graph.get("nodes"), list) else [])
        if isinstance(n, dict) and str(n.get("type") or "").strip() == "normRef"
    }
    relations: List[Dict[str, Any]] = []
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        form = str(meta.get("form_code") or "").strip()
        spec = str(meta.get("spec_code") or meta.get("norm_id") or "").strip()
        ver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        if form != cur_form or spec != cur_spec or ver == cur_ver:
            continue
        refs = {
            str((r or {}).get("norm_ref") or "").strip()
            for r in (doc.get("rules", []) if isinstance(doc.get("rules"), list) else [])
            if isinstance(r, dict) and str((r or {}).get("norm_ref") or "").strip()
        }
        overlap = sorted(list(cur_normrefs.intersection(refs)))
        if overlap:
            relations.append(
                {
                    "target_rulepack": p.name,
                    "target_norm_version": ver,
                    "shared_normref_count": len(overlap),
                    "shared_normrefs": overlap[:100],
                }
            )
    relations.sort(key=lambda x: int(x.get("shared_normref_count", 0) or 0), reverse=True)
    return {"status": "ok", "job_id": job_id, "current_norm_version": cur_ver, "relations": relations, "summary": {"total": len(relations)}}


def _build_production_release_pipeline_report(job_id: str, request: ProductionReleasePipelineRequest) -> Dict[str, Any]:
    steps: List[Dict[str, Any]] = []

    def _append_step(name: str, status: str, logs: List[str], artifacts: List[str]) -> None:
        steps.append({"name": name, "status": status, "logs": logs, "artifacts": artifacts})

    package = _load_review_package(job_id)
    candidates = [x for x in (package.get("candidates", []) if isinstance(package.get("candidates"), list) else []) if isinstance(x, dict)]
    publish_gate = _build_publish_blocking_rule_engine(job_id)
    publish_state = str(publish_gate.get("publish_state") or "draft").strip() or "draft"

    # 1) SpecIR Approved
    step_logs: List[str] = []
    approved_ok = _all_candidates_approved(candidates)
    step_logs.append(f"approved_candidates={len([x for x in candidates if _normalize_candidate_status(str(x.get('status', ''))) == 'approved'])}/{len(candidates)}")
    _append_step(
        "SpecIR Approved",
        "success" if approved_ok else "failed",
        step_logs,
        [str((_artifact_dir_for_job(job_id) / "13_specir.json").resolve())],
    )
    if not approved_ok:
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "publish_state": publish_state if publish_state in {"draft", "review_required", "blocked", "publish_ready", "published", "rollbacked"} else "blocked",
            "stopped_at": "SpecIR Approved",
            "steps": steps,
            "publish_report": publish_gate,
            "blocked_reason": publish_gate.get("blocked_reasons", []),
            "impacted_forms": publish_gate.get("impacted_forms", []),
            "missing_dependencies": publish_gate.get("missing_dependencies", []),
            "generated_at": _utc_now(),
        }

    # collect job rulepacks/forms
    job_rulepacks = _find_rulepacks_by_job(job_id)
    form_codes: List[str] = []
    version_by_form: Dict[str, str] = {}
    for p in job_rulepacks:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        fc = str(meta.get("form_code") or "").strip()
        ver = p.name
        if fc:
            form_codes.append(fc)
            version_by_form[fc] = ver

    # 2) Regression
    step_logs = []
    auto_reg = _trigger_auto_regression_for_job(job_id, reason="production_release_pipeline")
    reg_ok = str(auto_reg.get("status", "")).strip().lower() == "ok"
    step_logs.append(f"auto_regression_status={auto_reg.get('status', '')}")
    if reg_ok:
        try:
            _assert_auto_regression_pass_for_forms(sorted(list(set(form_codes))))
            step_logs.append("auto_regression_pass_for_forms=true")
        except Exception as exc:
            reg_ok = False
            step_logs.append(f"auto_regression_assert_failed={exc}")
    _append_step(
        "Regression",
        "success" if reg_ok else "failed",
        step_logs,
        [str((_artifact_dir_for_job(job_id) / "auto_regression_report.json").resolve())],
    )
    if not reg_ok:
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "stopped_at": "Regression",
            "steps": steps,
            "generated_at": _utc_now(),
        }

    # 3) Golden Set
    step_logs = []
    golden_ok = True
    for p in job_rulepacks:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            golden_ok = False
            step_logs.append(f"{p.name}: invalid_json")
            continue
        golden = doc.get("golden_compare", {}) if isinstance(doc.get("golden_compare"), dict) else {}
        passed = bool(golden.get("passed", True))
        step_logs.append(f"{p.name}: golden_passed={passed}")
        if not passed:
            golden_ok = False
    _append_step("Golden Set", "success" if golden_ok else "failed", step_logs, [str((_artifact_dir_for_job(job_id) / "golden_diff_report.json").resolve())])
    if not golden_ok:
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "stopped_at": "Golden Set",
            "steps": steps,
            "generated_at": _utc_now(),
        }

    # 4) Quality Gate
    step_logs = []
    qg = _final_publish_gate_check(job_id, req_signature=str(request.signature or "").strip())
    qg_ok = bool(qg.get("ok", False))
    step_logs.append(f"quality_gate_ok={qg_ok}")
    if not qg_ok:
        step_logs.extend([str(x) for x in (qg.get("blockers", []) if isinstance(qg.get("blockers"), list) else [])[:20]])
    _append_step("Quality Gate", "success" if qg_ok else "failed", step_logs, [str((_artifact_dir_for_job(job_id) / "quality_gate_result.json").resolve())])
    if (not qg_ok) or (not bool(publish_gate.get("publishable", False))):
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "stopped_at": "Quality Gate",
            "steps": steps,
            "publish_state": "blocked",
            "publish_report": publish_gate,
            "blocked_reason": publish_gate.get("blocked_reasons", []),
            "impacted_forms": publish_gate.get("impacted_forms", []),
            "missing_dependencies": publish_gate.get("missing_dependencies", []),
            "generated_at": _utc_now(),
        }

    # 5) Gray Release
    step_logs = []
    gray_ok = True
    if request.dry_run:
        step_logs.append("dry_run=true, skip gray release execution")
    else:
        for fc in sorted(list(set(form_codes))):
            ver = version_by_form.get(fc, "")
            if not ver:
                gray_ok = False
                step_logs.append(f"{fc}: missing_rulepack_version")
                continue
            try:
                out = release_rulepack_by_form(
                    RulepackReleaseRequest(
                        form_code=fc,
                        version=ver,
                        canary_version="",
                        project_id="",
                        gray_ratio=float(request.gray_ratio or 0.1),
                        operator=str(request.published_by or "").strip() or "expert.001",
                    )
                )
                step_logs.append(f"{fc}: gray_release_ok version={ver} gray_ratio={request.gray_ratio}")
                if isinstance(out, dict) and str(out.get("status", "")).strip() != "ok":
                    gray_ok = False
            except Exception as exc:
                gray_ok = False
                step_logs.append(f"{fc}: gray_release_failed {exc}")
    _append_step("Gray Release", "success" if gray_ok else "failed", step_logs, [str(RULEPACK_RELEASE_REGISTRY_PATH.resolve())])
    if not gray_ok:
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "stopped_at": "Gray Release",
            "steps": steps,
            "generated_at": _utc_now(),
        }

    # 6) Runtime Validation
    step_logs = []
    smoke = _run_runtime_smoke_for_job(job_id)
    runtime_ok = bool(smoke.get("passed", False))
    step_logs.append(f"runtime_smoke_passed={runtime_ok}")
    step_logs.append(f"failed_rulepacks={int(smoke.get('failed_rulepacks', 0) or 0)}")
    _append_step("Runtime Validation", "success" if runtime_ok else "failed", step_logs, [str((_artifact_dir_for_job(job_id) / "runtime_smoke_report.json").resolve())])
    if not runtime_ok:
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "stopped_at": "Runtime Validation",
            "steps": steps,
            "generated_at": _utc_now(),
        }

    # 7) Full Release
    step_logs = []
    full_ok = True
    if request.dry_run:
        step_logs.append("dry_run=true, skip full release execution")
    else:
        for fc in sorted(list(set(form_codes))):
            ver = version_by_form.get(fc, "")
            if not ver:
                full_ok = False
                step_logs.append(f"{fc}: missing_rulepack_version")
                continue
            try:
                out = release_rulepack_by_form(
                    RulepackReleaseRequest(
                        form_code=fc,
                        version=ver,
                        canary_version="",
                        project_id="",
                        gray_ratio=0.0,
                        operator=str(request.published_by or "").strip() or "expert.001",
                    )
                )
                step_logs.append(f"{fc}: full_release_ok version={ver}")
                if isinstance(out, dict) and str(out.get("status", "")).strip() != "ok":
                    full_ok = False
            except Exception as exc:
                full_ok = False
                step_logs.append(f"{fc}: full_release_failed {exc}")
    _append_step("Full Release", "success" if full_ok else "failed", step_logs, [str(RULEPACK_RELEASE_REGISTRY_PATH.resolve())])
    if not full_ok:
        return {
            "schema_version": "production_release_pipeline.v1",
            "job_id": job_id,
            "status": "failed",
            "stopped_at": "Full Release",
            "steps": steps,
            "generated_at": _utc_now(),
        }

    final_state = "published" if not bool(request.dry_run) else "publish_ready"
    return {
        "schema_version": "production_release_pipeline.v1",
        "job_id": job_id,
        "status": "success",
        "publish_state": final_state,
        "stopped_at": "",
        "steps": steps,
        "publish_report": publish_gate,
        "blocked_reason": [],
        "impacted_forms": publish_gate.get("impacted_forms", []),
        "missing_dependencies": publish_gate.get("missing_dependencies", []),
        "dry_run_report": {
            "publish_report": publish_gate,
            "blocked_reason": publish_gate.get("blocked_reasons", []),
            "impacted_forms": publish_gate.get("impacted_forms", []),
            "missing_dependencies": publish_gate.get("missing_dependencies", []),
        },
        "generated_at": _utc_now(),
    }

def _all_candidates_approved(candidates: List[Dict[str, Any]]) -> bool:
    if not candidates:
        return False
    for c in candidates:
        if _normalize_candidate_status(str(c.get("status", ""))) != "approved":
            return False
    return True


def _build_publish_blocking_rule_engine(job_id: str) -> Dict[str, Any]:
    art_dir = _artifact_dir_for_job(job_id)
    specir_doc = _read_artifact_payload(job_id, "13_specir.json")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    pipe_audit = _read_artifact_payload(job_id, "12_pipeline_audit.json")
    review_pkg = _load_review_package(job_id)
    rulepacks = _find_rulepacks_by_job(job_id)

    spec_items = [x for x in (specir_doc.get("items", []) if isinstance(specir_doc.get("items"), list) else []) if isinstance(x, dict)]
    semantic_conflict_count = len([
        x for x in spec_items
        if str(x.get("semantic_status") or "").strip().lower() in {"conflicted"}
    ])
    unresolved_semantic_count = len([
        x for x in spec_items
        if str(x.get("semantic_status") or "").strip().lower() in {"ambiguous", "conflicted", "rejected"}
    ])
    low_confidence_pending = len([
        x for x in spec_items
        if float(x.get("confidence", 0.0) or 0.0) < 0.5
        and str(x.get("review_status") or "").strip().lower() not in {"approved"}
    ])

    rule_rows = [x for x in (rules_doc.get("rules", []) if isinstance(rules_doc.get("rules"), list) else []) if isinstance(x, dict)]
    blocked_rule_count = len([
        x for x in rule_rows
        if bool(x.get("unresolved"))
        or str(x.get("execution_status") or "").strip().lower() in {"not_executable", "needs_slot", "needs_formula", "needs_runtime"}
    ])
    gate_rows = [x for x in (gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []) if isinstance(x, dict)]
    blocked_gate_count = len([
        x for x in gate_rows
        if len(_gate_rule_ids(x)) <= 0
    ])

    manual_reviews = pipe_audit.get("manual_reviews", []) if isinstance(pipe_audit.get("manual_reviews"), list) else []
    specir_review_ids = {
        str(x.get("object_id") or "").strip()
        for x in manual_reviews
        if isinstance(x, dict) and str(x.get("object_type") or "").strip().lower() == "specir"
    }
    specir_total = len([x for x in spec_items if str(x.get("specir_id") or x.get("component_id") or "").strip()])
    unsigned_review_count = max(specir_total - len(specir_review_ids), 0)
    rejected_review_count = len([
        x for x in manual_reviews
        if isinstance(x, dict)
        and str(x.get("object_type") or "").strip().lower() == "specir"
        and str(x.get("decision") or "").strip().lower() in {"reject", "rejected"}
    ])

    unrelated_assets = 0
    noise_count = 0
    impacted_forms: List[str] = []
    missing_dependencies: List[str] = []
    for p in rulepacks:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        fc = str(meta.get("form_code") or "").strip()
        if fc and fc not in impacted_forms:
            impacted_forms.append(fc)
        wf = doc.get("whitelist_filtering", {}) if isinstance(doc.get("whitelist_filtering"), dict) else {}
        noise_count += int(wf.get("removed_noise_count", 0) or 0)
        removed_reason = wf.get("removed_reason", {}) if isinstance(wf.get("removed_reason"), dict) else {}
        unrelated_assets += sum(int(v or 0) for _, v in removed_reason.items() if "unrelated" in str(_).lower())
        if not doc.get("rules"):
            missing_dependencies.append(f"{p.name}:missing_rules")
        if not doc.get("gates"):
            missing_dependencies.append(f"{p.name}:missing_gates")
        if not doc.get("slot_manifest"):
            sm = art_dir / "slot_manifest.json"
            if not sm.exists():
                missing_dependencies.append(f"{p.name}:missing_slot_manifest")

    blockers: List[str] = []
    if semantic_conflict_count > 0:
        blockers.append(f"SpecIR.semantic_conflict_count={semantic_conflict_count}")
    if unresolved_semantic_count > 0:
        blockers.append(f"SpecIR.unresolved_semantic={unresolved_semantic_count}")
    if low_confidence_pending > 0:
        blockers.append(f"SpecIR.low_confidence_pending={low_confidence_pending}")
    if blocked_rule_count > 0:
        blockers.append(f"Rule.blocked_rule_count={blocked_rule_count}")
    if blocked_gate_count > 0:
        blockers.append(f"Gate.blocked_gate_count={blocked_gate_count}")
    if unsigned_review_count > 0:
        blockers.append(f"Review.unsigned_review_count={unsigned_review_count}")
    if rejected_review_count > 0:
        blockers.append(f"Review.rejected_review_count={rejected_review_count}")
    if unrelated_assets > 0:
        blockers.append(f"Rulepack.unrelated_assets={unrelated_assets}")
    if noise_count > 0:
        blockers.append(f"Rulepack.noise_count={noise_count}")
    blockers.extend([f"MissingDependency.{x}" for x in missing_dependencies])

    publish_state = "publish_ready"
    if len(manual_reviews) == 0:
        publish_state = "draft"
    if unsigned_review_count > 0:
        publish_state = "review_required"
    if blockers:
        publish_state = "blocked"

    return {
        "schema_version": "publish_blocking_rule_engine.v1",
        "job_id": job_id,
        "publish_state": publish_state,
        "publishable": len(blockers) == 0,
        "checks": {
            "semantic_conflict_count": semantic_conflict_count,
            "unresolved_semantic_count": unresolved_semantic_count,
            "low_confidence_pending": low_confidence_pending,
            "blocked_rule_count": blocked_rule_count,
            "blocked_gate_count": blocked_gate_count,
            "unsigned_review_count": unsigned_review_count,
            "rejected_review_count": rejected_review_count,
            "unrelated_assets": unrelated_assets,
            "noise_count": noise_count,
        },
        "blocked_reasons": blockers,
        "impacted_forms": sorted(list(set(impacted_forms))),
        "missing_dependencies": missing_dependencies,
        "generated_at": _utc_now(),
    }


def _build_production_readiness_report(job_id: str) -> Dict[str, Any]:
    art_dir = _artifact_dir_for_job(job_id)
    sys_cfg = _load_system_config()
    unresolved_rate_threshold = float((sys_cfg.get("production_readiness_unresolved_rate_threshold", 0.02) if isinstance(sys_cfg, dict) else 0.02) or 0.02)
    gate_coverage_threshold = float((sys_cfg.get("production_readiness_gate_coverage_threshold", 0.98) if isinstance(sys_cfg, dict) else 0.98) or 0.98)
    key_field_accuracy_threshold = float((sys_cfg.get("production_readiness_key_field_accuracy_threshold", 0.99) if isinstance(sys_cfg, dict) else 0.99) or 0.99)
    quality_build_failure_threshold = float((sys_cfg.get("production_readiness_quality_build_failure_rate_threshold", 0.05) if isinstance(sys_cfg, dict) else 0.05) or 0.05)
    quality_publish_success_threshold = float((sys_cfg.get("production_readiness_quality_publish_success_rate_threshold", 0.95) if isinstance(sys_cfg, dict) else 0.95) or 0.95)

    publish_gate = _production_publish_gate_check(job_id)
    smoke = _run_runtime_smoke_for_job(job_id)
    unresolved_summary = _collect_rulepack_unresolved_summary_for_job(job_id)

    # Regression: use latest auto regression assertion for all forms in this job.
    job_rulepacks = _find_rulepacks_by_job(job_id)
    form_codes: List[str] = []
    norm_versions: List[str] = []
    for p in job_rulepacks:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        fc = str(meta.get("form_code") or "").strip()
        nv = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        if fc:
            form_codes.append(fc)
        if nv:
            norm_versions.append(nv)
    uniq_forms = sorted(list(set([x for x in form_codes if x])))
    regression_pass = False
    regression_error = ""
    try:
        auto_reg = _trigger_auto_regression_for_job(job_id, reason="production_readiness_check")
        if str(auto_reg.get("status", "")).strip().lower() == "ok":
            _assert_auto_regression_pass_for_forms(uniq_forms)
            regression_pass = True
        else:
            regression_error = str(auto_reg.get("reason") or auto_reg.get("status") or "auto_regression_failed")
    except Exception as exc:
        regression_error = str(exc)

    # Golden Set / gate coverage / key field accuracy are in publish gate report.
    pg_checks = publish_gate.get("checks", {}) if isinstance(publish_gate.get("checks"), dict) else {}
    pg_summary = publish_gate.get("summary", {}) if isinstance(publish_gate.get("summary"), dict) else {}
    golden_pass = bool(pg_checks.get("golden_set_pass", False))
    gate_coverage = float(pg_summary.get("min_gate_coverage_rate", 0.0) or 0.0)
    key_field_accuracy = float(pg_summary.get("key_field_accuracy", 0.0) or 0.0)

    # Traceability complete: must pass final gate's traceability check.
    final_gate = _final_publish_gate_check(job_id, req_signature="readiness_check_signature")
    final_checks = final_gate.get("checks", {}) if isinstance(final_gate.get("checks"), dict) else {}
    traceability_complete = bool(final_checks.get("traceability_complete", False))

    # Publish gate complete
    publish_gate_complete = bool(publish_gate.get("ok", False))

    # Rollback available: find previous release version per form.
    rollback_rows: List[Dict[str, Any]] = []
    rollback_available = True if uniq_forms else False
    for fc in uniq_forms:
        prev = _find_previous_release_version(fc)
        ok = bool(prev)
        rollback_rows.append({"form_code": fc, "previous_release_version": prev, "available": ok})
        if not ok:
            rollback_available = False

    # Quality dashboard healthy
    use_fc = uniq_forms[0] if len(uniq_forms) == 1 else ""
    use_nv = norm_versions[0] if len(set(norm_versions)) == 1 and norm_versions else ""
    quality = _collect_quality_dashboard(form_code=use_fc, norm_version=use_nv, date_from="", date_to="")
    overview = quality.get("overview", {}) if isinstance(quality.get("overview"), dict) else {}
    publish_quality = quality.get("publish_quality", {}) if isinstance(quality.get("publish_quality"), dict) else {}
    build_failure_rate = float(overview.get("build_failure_rate", 1.0) or 1.0)
    publish_success_rate = float(publish_quality.get("publish_success_rate", 0.0) or 0.0)
    quality_dashboard_healthy = (build_failure_rate <= quality_build_failure_threshold) and (publish_success_rate >= quality_publish_success_threshold)

    # unresolved_rate
    unresolved_count = int(unresolved_summary.get("unresolved_count", 0) or 0)
    rules_total = int(unresolved_summary.get("rule_total", 0) or 0)
    unresolved_rate = (float(unresolved_count) / float(rules_total)) if rules_total > 0 else 0.0
    unresolved_rate_ok = unresolved_rate < unresolved_rate_threshold

    gate_coverage_ok = gate_coverage >= gate_coverage_threshold
    key_field_accuracy_ok = key_field_accuracy >= key_field_accuracy_threshold
    runtime_smoke_pass = bool(smoke.get("passed", False))

    checks = [
        {"id": 1, "name": "Golden Set pass", "passed": golden_pass},
        {"id": 2, "name": "Regression pass", "passed": regression_pass, "error": regression_error},
        {"id": 3, "name": "Runtime smoke pass", "passed": runtime_smoke_pass},
        {"id": 4, "name": "Traceability complete", "passed": traceability_complete},
        {"id": 5, "name": "Publish gate complete", "passed": publish_gate_complete},
        {"id": 6, "name": "Rollback available", "passed": rollback_available, "items": rollback_rows},
        {"id": 7, "name": "Quality dashboard healthy", "passed": quality_dashboard_healthy},
        {"id": 8, "name": "unresolved_rate < threshold", "passed": unresolved_rate_ok, "actual": unresolved_rate, "threshold": unresolved_rate_threshold},
        {"id": 9, "name": "gate_coverage >= 98%", "passed": gate_coverage_ok, "actual": gate_coverage, "threshold": gate_coverage_threshold},
        {"id": 10, "name": "key_field_accuracy >= 99%", "passed": key_field_accuracy_ok, "actual": key_field_accuracy, "threshold": key_field_accuracy_threshold},
    ]
    pass_count = len([x for x in checks if bool(x.get("passed", False))])
    total = len(checks)
    all_pass = pass_count == total
    critical_ids = {1, 2, 3, 4, 5, 6}
    critical_all_pass = all(bool(x.get("passed", False)) for x in checks if int(x.get("id", 0) or 0) in critical_ids)
    if all_pass:
        readiness_status = "production_ready"
    elif critical_all_pass:
        readiness_status = "staging_ready"
    else:
        readiness_status = "not_ready"

    blockers = [f"{int(x.get('id', 0) or 0)}.{x.get('name', '')}" for x in checks if not bool(x.get("passed", False))]
    report = {
        "schema_version": "production_readiness_report.v1",
        "job_id": job_id,
        "readiness_status": readiness_status,
        "summary": {"passed": pass_count, "total": total, "all_pass": all_pass, "critical_all_pass": critical_all_pass},
        "checks": checks,
        "blockers": blockers,
        "metrics": {
            "unresolved_rate": unresolved_rate,
            "unresolved_rate_threshold": unresolved_rate_threshold,
            "gate_coverage": gate_coverage,
            "gate_coverage_threshold": gate_coverage_threshold,
            "key_field_accuracy": key_field_accuracy,
            "key_field_accuracy_threshold": key_field_accuracy_threshold,
            "quality_build_failure_rate": build_failure_rate,
            "quality_publish_success_rate": publish_success_rate,
        },
        "artifacts": {
            "publish_gate_report": str((art_dir / "publish_gate_report.json").resolve()),
            "runtime_smoke_report": str((art_dir / "runtime_smoke_report.json").resolve()),
            "auto_regression_report": str((art_dir / "auto_regression_report.json").resolve()),
            "quality_gate_result": str((art_dir / "quality_gate_result.json").resolve()),
        },
        "generated_at": _utc_now(),
    }
    out_path = art_dir / "production_readiness_report.json"
    out_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    report["report_path"] = str(out_path.resolve())
    return report


def _build_third_stage_readiness_report(job_id: str, *, unresolved_reduction_target: float = 0.70) -> Dict[str, Any]:
    art_dir = _artifact_dir_for_job(job_id)
    slot_map = _read_artifact_payload(job_id, "slot_mapping_recommendations.json")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    review_pkg = _load_review_package(job_id)
    prod = _build_production_readiness_report(job_id)
    obs = _load_obs_metrics()

    slot_total = int(slot_map.get("count", 0) or 0) if isinstance(slot_map, dict) else 0
    auto_bind_count = int(slot_map.get("auto_bind_count", 0) or 0) if isinstance(slot_map, dict) else 0
    auto_slot_mapping_rate = (float(auto_bind_count) / float(slot_total)) if slot_total > 0 else 0.0

    summary = review_pkg.get("review_summary", {}) if isinstance(review_pkg.get("review_summary"), dict) else {}
    approved = int(summary.get("approved", 0) or 0)
    rejected = int(summary.get("rejected", 0) or 0)
    auto_bind_accuracy = (float(approved) / float(approved + rejected)) if (approved + rejected) > 0 else 0.0

    unresolved_summary = _collect_rulepack_unresolved_summary_for_job(job_id)
    unresolved_now = int(unresolved_summary.get("unresolved_count", 0) or 0)
    unresolved_baseline = int(obs.get("last_unresolved_count", unresolved_now) or unresolved_now)
    if unresolved_baseline <= 0:
        unresolved_reduction = 1.0 if unresolved_now <= 0 else 0.0
    else:
        unresolved_reduction = max(0.0, min(1.0, float(unresolved_baseline - unresolved_now) / float(unresolved_baseline)))

    gates = gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []
    gate_total = len([g for g in gates if isinstance(g, dict)])
    gate_resolved = len([g for g in gates if isinstance(g, dict) and not bool(g.get("unresolved", False))])
    gate_auto_synthesis_rate = (float(gate_resolved) / float(gate_total)) if gate_total > 0 else 0.0

    prod_metrics = prod.get("metrics", {}) if isinstance(prod.get("metrics"), dict) else {}
    norm_diff_accuracy = float(prod_metrics.get("key_field_accuracy", 0.0) or 0.0)

    prod_checks = prod.get("checks", []) if isinstance(prod.get("checks"), list) else []
    regression_stable = any(int(c.get("id", 0) or 0) == 2 and bool(c.get("passed", False)) for c in prod_checks if isinstance(c, dict))
    rollback_stable = any(int(c.get("id", 0) or 0) == 6 and bool(c.get("passed", False)) for c in prod_checks if isinstance(c, dict))

    candidate_count = int(review_pkg.get("candidate_count", 0) or 0)
    pending = int(summary.get("draft", 0) or 0) + int(summary.get("extracted", 0) or 0) + int(summary.get("reviewed", 0) or 0)
    binding = review_pkg.get("clause_binding_summary", {}) if isinstance(review_pkg.get("clause_binding_summary"), dict) else {}
    binding_pending = int(binding.get("pending", 0) or 0)
    pending_rate = (float(pending) / float(candidate_count)) if candidate_count > 0 else 0.0
    review_queue_healthy = (pending_rate <= 0.15) and (binding_pending == 0)

    checks = [
        {"id": 1, "name": "自动 slot mapping >= 90%", "actual": auto_slot_mapping_rate, "threshold": 0.90, "passed": auto_slot_mapping_rate >= 0.90},
        {"id": 2, "name": "auto_bind accuracy >= 92%", "actual": auto_bind_accuracy, "threshold": 0.92, "passed": auto_bind_accuracy >= 0.92},
        {"id": 3, "name": "unresolved 降低 70%", "actual": unresolved_reduction, "threshold": float(unresolved_reduction_target), "passed": unresolved_reduction >= float(unresolved_reduction_target), "baseline": unresolved_baseline, "current": unresolved_now},
        {"id": 4, "name": "gate auto synthesis >= 85%", "actual": gate_auto_synthesis_rate, "threshold": 0.85, "passed": gate_auto_synthesis_rate >= 0.85},
        {"id": 5, "name": "norm diff accuracy >= 95%", "actual": norm_diff_accuracy, "threshold": 0.95, "passed": norm_diff_accuracy >= 0.95},
        {"id": 6, "name": "regression stable", "actual": regression_stable, "threshold": True, "passed": regression_stable},
        {"id": 7, "name": "rollback stable", "actual": rollback_stable, "threshold": True, "passed": rollback_stable},
        {"id": 8, "name": "review queue healthy", "actual": review_queue_healthy, "threshold": True, "passed": review_queue_healthy, "pending_rate": pending_rate, "binding_pending": binding_pending},
    ]
    passed_count = len([x for x in checks if bool(x.get("passed", False))])
    if passed_count == len(checks):
        stage_status = "ai_native_ready"
    elif passed_count >= 6 and bool(checks[0].get("passed")) and bool(checks[5].get("passed")) and bool(checks[7].get("passed")):
        stage_status = "ai_assisted_ready"
    else:
        stage_status = "not_ready"

    report = {
        "schema_version": "third_stage_readiness.v1",
        "job_id": job_id,
        "status": stage_status,
        "summary": {"passed": passed_count, "total": len(checks)},
        "checks": checks,
        "generated_at": _utc_now(),
    }
    out_path = art_dir / "third_stage_readiness.json"
    out_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    report["report_path"] = str(out_path.resolve())
    return report


def _pipeline_next_action(stage_key: str) -> str:
    mp = {
        "pdf": "上传 PDF 并触发 ingest",
        "document_ir": "重跑 artifact pipeline 生成 Document IR",
        "normref": "修复条款解析并生成 norm_ref_index",
        "specir": "生成/重建 SpecIR（13_specir.json）",
        "review_queue": "进入 Review Queue 完成人工审校",
        "approved_specir": "完成 approve + checklist + 签字链",
        "rulepack": "构建 Rulepack 并修复 schema/traceability",
        "publish": "执行发布工作流（publish-workflow）",
    }
    return mp.get(stage_key, "排查阻断项并重试")


def _build_status_aggregation(job_id: str) -> Dict[str, Any]:
    specir_doc = _read_artifact_payload(job_id, "13_specir.json")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    rulepacks = _find_rulepacks_by_job(job_id)
    pipeline = normref_ingest_pipeline_status(job_id)

    spec_items = [x for x in (specir_doc.get("items", []) if isinstance(specir_doc.get("items"), list) else []) if isinstance(x, dict)]
    rules = [x for x in (rules_doc.get("rules", []) if isinstance(rules_doc.get("rules"), list) else []) if isinstance(x, dict)]
    gates = [x for x in (gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []) if isinstance(x, dict)]

    missing_slot_count = len([x for x in spec_items if str(x.get("execution_status") or "").strip().lower() == "needs_slot"])
    missing_formula_count = len([x for x in spec_items if str(x.get("execution_status") or "").strip().lower() == "needs_formula"])
    runtime_missing_count = len([x for x in spec_items if str(x.get("execution_status") or "").strip().lower() == "needs_runtime"])
    low_confidence_pending_count = len([
        x for x in spec_items
        if float(x.get("confidence", 0.0) or 0.0) < 0.5
        and str(x.get("review_status") or "").strip().lower() not in {"approved", "signed"}
    ])
    semantic_conflict_count = len([x for x in spec_items if str(x.get("semantic_status") or "").strip().lower() == "conflicted"])
    unresolved_semantic_count = len([
        x for x in spec_items
        if str(x.get("semantic_status") or "").strip().lower() in {"ambiguous", "conflicted", "rejected"}
    ])

    blocked_rule_count = len([
        x for x in rules
        if bool(x.get("unresolved", False))
        or str(x.get("execution_status") or "").strip().lower() in {"not_executable", "needs_slot", "needs_formula", "needs_runtime"}
    ])
    rule_ids = {
        str(x.get("rule_id") or x.get("ruleId") or x.get("id") or "").strip()
        for x in rules
        if str(x.get("rule_id") or x.get("ruleId") or x.get("id") or "").strip()
    }
    blocked_gate_count = 0
    for g in gates:
        refs = [str(x).strip() for x in _gate_rule_ids(g) if str(x).strip()]
        if len(refs) <= 0:
            blocked_gate_count += 1
            continue
        if any(rid not in rule_ids for rid in refs):
            blocked_gate_count += 1

    unresolved_summary = _collect_rulepack_unresolved_summary_for_job(job_id)
    unresolved_count = int(unresolved_summary.get("unresolved_count", 0) or 0)
    unsigned_review_count = int(_collect_manual_review_summary(job_id).get("pending_review", 0) or 0)
    rejected_review_count = int(_collect_manual_review_summary(job_id).get("rejected", 0) or 0)

    semantic_ready = (
        semantic_conflict_count == 0
        and unresolved_semantic_count == 0
        and low_confidence_pending_count == 0
    )
    execution_ready = (
        missing_slot_count == 0
        and missing_formula_count == 0
        and runtime_missing_count == 0
        and blocked_rule_count == 0
        and blocked_gate_count == 0
        and unresolved_count == 0
    )

    publish_schema_ok = True
    for rp in rulepacks:
        try:
            doc = json.loads(rp.read_text(encoding="utf-8-sig"))
        except Exception:
            publish_schema_ok = False
            break
        ok, _, _, _ = _validate_rulepack_schema_with_compat(doc if isinstance(doc, dict) else {})
        if not ok:
            publish_schema_ok = False
            break
    publish_ready = (
        semantic_ready
        and execution_ready
        and unsigned_review_count == 0
        and rejected_review_count == 0
        and publish_schema_ok
    )

    root_causes: List[Dict[str, Any]] = []
    if missing_slot_count > 0:
        root_causes.append({"code": "missing_slot", "count": missing_slot_count, "message": f"{missing_slot_count} 个 slot 未绑定"})
    if missing_formula_count > 0:
        root_causes.append({"code": "missing_formula", "count": missing_formula_count, "message": f"{missing_formula_count} 个公式缺失"})
    if low_confidence_pending_count > 0:
        root_causes.append({"code": "low_confidence_pending", "count": low_confidence_pending_count, "message": f"{low_confidence_pending_count} 个低置信度未审核"})
    if blocked_gate_count > 0:
        root_causes.append({"code": "blocked_gate", "count": blocked_gate_count, "message": f"{blocked_gate_count} 个 Gate 处于 blocked"})
    if unsigned_review_count > 0:
        root_causes.append({"code": "unsigned_review", "count": unsigned_review_count, "message": f"{unsigned_review_count} 个人工审核未完成"})
    if unresolved_count > 0:
        root_causes.append({"code": "unresolved_assets", "count": unresolved_count, "message": f"{unresolved_count} 个 unresolved 资产未消除"})

    return {
        "status": "ok",
        "job_id": job_id,
        "readiness": {
            "semantic_ready": semantic_ready,
            "execution_ready": execution_ready,
            "publish_ready": publish_ready,
        },
        "current": {
            "stage": str(pipeline.get("current_stage") or "").strip(),
            "blocker": str(pipeline.get("current_blocker") or "").strip(),
            "next_action": str(pipeline.get("next_action") or "").strip(),
        },
        "root_cause_summary": {
            "schema_version": "root_cause_summary.v1",
            "items": root_causes,
            "total_blockers": len(root_causes),
        },
        "counts": {
            "missing_slot_count": missing_slot_count,
            "missing_formula_count": missing_formula_count,
            "runtime_missing_count": runtime_missing_count,
            "low_confidence_pending_count": low_confidence_pending_count,
            "semantic_conflict_count": semantic_conflict_count,
            "unresolved_semantic_count": unresolved_semantic_count,
            "blocked_rule_count": blocked_rule_count,
            "blocked_gate_count": blocked_gate_count,
            "unsigned_review_count": unsigned_review_count,
            "rejected_review_count": rejected_review_count,
            "unresolved_count": unresolved_count,
        },
        "source_of_truth": {
            "specir": "13_specir.json",
            "rules": "07_rules.json",
            "gates": "08_gates.json",
            "rulepack_unresolved": "rulepack.unresolved",
            "pipeline_status": "/normref/ingest/jobs/{job_id}/pipeline-status",
        },
    }


@app.get("/normref/ingest/jobs/{job_id}/pipeline-status")
def normref_ingest_pipeline_status(job_id: str) -> Dict[str, Any]:
    package = _load_review_package(job_id)
    candidates = [x for x in package.get("candidates", []) if isinstance(x, dict)]
    index = _read_artifact_payload(job_id, "00_pipeline_index.json")
    validations = index.get("validations", {}) if isinstance(index.get("validations"), dict) else {}

    def _v_ok(name: str) -> bool:
        row = validations.get(name, {}) if isinstance(validations.get(name), dict) else {}
        return bool(row.get("schema_valid", False)) and bool(row.get("business_valid", False))

    spec_payload = _read_artifact_payload(job_id, "01_spec.json")
    catalog_payload = _read_artifact_payload(job_id, "02_catalog.json")
    clause_tree_payload = _read_artifact_payload(job_id, "03_clause_tree.json")
    normref_payload = _read_artifact_payload(job_id, "norm_ref_index.json")
    specir_payload = _read_artifact_payload(job_id, "13_specir.json")
    normdoc_payload = _read_artifact_payload(job_id, "11_normdoc.json")

    rulepacks = _find_rulepacks_by_job(job_id)
    rulepack_schema_ok = True
    for rp_path in rulepacks:
        try:
            rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
        except Exception:
            rulepack_schema_ok = False
            break
        ok, _, _, _ = _validate_rulepack_schema_with_compat(rp_doc if isinstance(rp_doc, dict) else {})
        if not ok:
            rulepack_schema_ok = False
            break

    unresolved_summary = _collect_rulepack_unresolved_summary_for_job(job_id)
    unresolved_count = int(unresolved_summary.get("unresolved_count", 0) or 0)
    final_gate = _final_publish_gate_check(job_id, req_signature="probe_signature")

    published_ok = False
    ndid = str(normdoc_payload.get("normdoc_id", "")).strip()
    if ndid:
        try:
            row = normdoc_repository.get(ndid)
            published_ok = bool(row is not None and str(row.status).strip().lower() == "published")
        except Exception:
            published_ok = False
    source_input_file = str(
        ((package.get("source_artifacts", {}) if isinstance(package.get("source_artifacts"), dict) else {}).get("input_file", ""))
    ).strip()

    stages: List[Dict[str, Any]] = [
        {
            "key": "pdf",
            "name": "PDF",
            "status": "success" if source_input_file else "failed",
            "artifacts": ["source_artifacts.input_file"],
            "blockers": [] if source_input_file else ["缺少源 PDF 路径"],
        },
        {
            "key": "document_ir",
            "name": "Document IR",
            "status": "success" if (_v_ok("01_spec.json") and _v_ok("02_catalog.json") and _v_ok("03_clause_tree.json")) else "failed",
            "artifacts": ["01_spec.json", "02_catalog.json", "03_clause_tree.json"],
            "blockers": [] if (_v_ok("01_spec.json") and _v_ok("02_catalog.json") and _v_ok("03_clause_tree.json")) else ["Document IR artifacts 缺失或校验失败"],
        },
        {
            "key": "normref",
            "name": "normRef",
            "status": "success" if (_artifact_exists(job_id, "norm_ref_index.json") and len(normref_payload.get("entries", []) if isinstance(normref_payload.get("entries"), list) else []) > 0) else "failed",
            "artifacts": ["norm_ref_index.json"],
            "blockers": [] if (_artifact_exists(job_id, "norm_ref_index.json") and len(normref_payload.get("entries", []) if isinstance(normref_payload.get("entries"), list) else []) > 0) else ["normRef 缺失或空"],
        },
        {
            "key": "specir",
            "name": "SpecIR",
            "status": "success" if (_artifact_exists(job_id, "13_specir.json") and int(specir_payload.get("count", 0) or 0) > 0) else "failed",
            "artifacts": ["13_specir.json"],
            "blockers": [] if (_artifact_exists(job_id, "13_specir.json") and int(specir_payload.get("count", 0) or 0) > 0) else ["SpecIR artifact 缺失或空"],
        },
        {
            "key": "review_queue",
            "name": "Review Queue",
            "status": "success" if len(candidates) > 0 else "failed",
            "artifacts": ["review_package.candidates"],
            "blockers": [] if len(candidates) > 0 else ["Review Queue 为空"],
        },
        {
            "key": "approved_specir",
            "name": "Approved SpecIR",
            "status": "success" if _all_candidates_approved(candidates) else "failed",
            "artifacts": ["review_package.candidates.status=approved", "workflow.signature_chain"],
            "blockers": [] if _all_candidates_approved(candidates) else ["存在未 approved 的 SpecIR 候选"],
        },
        {
            "key": "rulepack",
            "name": "Rulepack",
            "status": "success" if (len(rulepacks) > 0 and rulepack_schema_ok) else "failed",
            "artifacts": [str(p.name) for p in rulepacks] if rulepacks else [],
            "blockers": [] if (len(rulepacks) > 0 and rulepack_schema_ok) else ["Rulepack 缺失或 schema 非法"],
        },
        {
            "key": "publish",
            "name": "Publish",
            "status": "success" if published_ok else ("blocked" if not bool(final_gate.get("ok", False)) else "failed"),
            "artifacts": ["normdoc_repository.published", "publish_metrics.json"],
            "blockers": [] if published_ok else ([str(x) for x in final_gate.get("blockers", [])[:10]] if isinstance(final_gate.get("blockers"), list) else ["尚未发布"]),
        },
    ]

    # cascade block: once one stage fails, subsequent not-success stages become blocked (unless already success)
    failed_seen = False
    for row in stages:
        if row["status"] != "success" and not failed_seen:
            failed_seen = True
            continue
        if failed_seen and row["status"] != "success":
            row["status"] = "blocked"

    current = next((x for x in stages if x.get("status") != "success"), stages[-1])
    current_stage = str(current.get("name", "Publish"))
    blockers = [str(x) for x in current.get("blockers", []) if str(x).strip()] if isinstance(current.get("blockers"), list) else []
    current_blocker = blockers[0] if blockers else ""
    next_action = _pipeline_next_action(str(current.get("key", "")))

    # failure traceability summary
    trace = {
        "job_id": job_id,
        "review_status": str(package.get("review_status", "")).strip(),
        "unresolved_count": unresolved_count,
        "final_publish_gate_ok": bool(final_gate.get("ok", False)),
        "artifact_dir": str(_artifact_dir_for_job(job_id).resolve()),
    }

    return {
        "status": "ok",
        "job_id": job_id,
        "pipeline": stages,
        "current_stage": current_stage,
        "current_blocker": current_blocker,
        "next_action": next_action,
        "traceability": trace,
    }


