@app.get("/normref/ingest/jobs/{job_id}/candidates")
def normref_ingest_candidates(job_id: str) -> Dict[str, Any]:
    package = _load_review_package(job_id)
    existing_binding_summary = package.get("clause_binding_summary", {})
    has_existing_binding = isinstance(existing_binding_summary, dict) and int(existing_binding_summary.get("total", 0) or 0) > 0
    if has_existing_binding:
        package["clause_binding_summary"] = existing_binding_summary
    else:
        package["clause_binding_summary"] = _refresh_review_candidate_clause_bindings(package)
    package["updated_at"] = _utc_now()
    _save_review_package(package)
    candidates = [item for item in package.get("candidates", []) if isinstance(item, dict)]
    for item in candidates:
        status = _normalize_candidate_status(str(item.get("status", "")))
        item["status"] = status
        item["publish_candidate_eligible"] = bool(status == "reviewed")
    return {
        "job_id": job_id,
        "review_status": package.get("review_status", ""),
        "review_summary": package.get("review_summary", {}),
        "clause_binding_summary": package.get("clause_binding_summary", {}),
        "candidate_count": len(candidates),
        "candidates": candidates,
    }


