def _promote_candidate_to_reviewed(*, job_id: str, candidate_id: str, actor_id: str, actor_name: str, comment: str) -> None:
    package = _load_review_package(job_id)
    candidate = _find_candidate_in_package(package, candidate_id)
    status = _normalize_candidate_status(str(candidate.get("status", "")))
    if status == "draft":
        _apply_candidate_transition(
            job_id=job_id,
            candidate_id=candidate_id,
            to_status="extracted",
            actor_id=actor_id,
            actor_name=actor_name,
            actor_role="editor",
            comment=comment,
        )
        status = "extracted"
    if status == "extracted":
        _apply_candidate_transition(
            job_id=job_id,
            candidate_id=candidate_id,
            to_status="reviewed",
            actor_id=actor_id,
            actor_name=actor_name,
            actor_role="reviewer",
            comment=comment,
        )


@app.post("/normref/ingest/jobs/{job_id}/hitl-queue/{candidate_id}/decision")
def normref_ingest_hitl_decision(job_id: str, candidate_id: str, request: HitlQueueDecisionRequest) -> Dict[str, Any]:
    actor_id = str(request.reviewer_id or "").strip() or "expert.default"
    actor_name = str(request.reviewer_name or "").strip() or "领域专家"
    action = str(request.action or "").strip().lower()
    comment = str(request.comment or "").strip()
    if str(request.job_id or "").strip() and str(request.job_id).strip() != str(job_id).strip():
        raise HTTPException(status_code=400, detail="path job_id 与 body job_id 不一致。")

    if action == "accept":
        _promote_candidate_to_reviewed(job_id=job_id, candidate_id=candidate_id, actor_id=actor_id, actor_name=actor_name, comment=comment)
        result = _apply_candidate_transition(
            job_id=job_id,
            candidate_id=candidate_id,
            to_status="approved",
            actor_id=actor_id,
            actor_name=actor_name,
            actor_role="reviewer",
            comment=comment,
        )
        return {"status": "ok", "action": action, **result}

    if action == "reject":
        _promote_candidate_to_reviewed(job_id=job_id, candidate_id=candidate_id, actor_id=actor_id, actor_name=actor_name, comment=comment)
        result = _apply_candidate_transition(
            job_id=job_id,
            candidate_id=candidate_id,
            to_status="rejected",
            actor_id=actor_id,
            actor_name=actor_name,
            actor_role="reviewer",
            comment=comment,
        )
        return {"status": "ok", "action": action, **result}

    if action != "modify":
        raise HTTPException(status_code=400, detail=f"不支持的 action: {action}")

    package = _load_review_package(job_id)
    candidate = _find_candidate_in_package(package, candidate_id)
    old_slot_key = _candidate_slot_key(candidate)
    clause_text = str(
        candidate.get("clause_content")
        or candidate.get("source_text")
        or candidate.get("source_line")
        or candidate.get("clause_preview")
        or ""
    ).strip()
    raw_conf = candidate.get("confidence", 0.0)
    try:
        conf_before = float(raw_conf) if str(raw_conf).strip() else 0.0
    except Exception:
        conf_before = 0.0
    candidate_patch = request.candidate_patch if isinstance(request.candidate_patch, dict) else {}
    if candidate_patch:
        candidate.update(candidate_patch)
        candidate["updated_at"] = _utc_now()
        new_slot_key = _candidate_slot_key(candidate)
        if new_slot_key and old_slot_key and new_slot_key != old_slot_key:
            try:
                _append_reviewer_learning_item(
                    clause_text=clause_text,
                    slot_key=old_slot_key,
                    corrected_slot_key=new_slot_key,
                    action="corrected_mapping",
                    reviewer=actor_id,
                    confidence_before=conf_before,
                    candidate_id=candidate_id,
                    job_id=job_id,
                )
            except Exception:
                pass
    _save_review_package(package)
    patch_results: Dict[str, Any] = {"candidate_patch": candidate_patch}
    if isinstance(request.rule_patch, dict) and request.rule_patch:
        rule_id = str(candidate.get("rule_id") or "").strip()
        if rule_id:
            patch_results["rule_patch_result"] = _apply_asset_patch(
                AssetPatchRequest(
                    job_id=job_id,
                    object_type="rule",
                    object_id=rule_id,
                    patch=request.rule_patch,
                    reviewer_id=actor_id,
                    reviewer_name=actor_name,
                    comment=comment or "hitl modify rule patch",
                )
            )
    if isinstance(request.gate_patch, dict) and request.gate_patch:
        gate_id = str(candidate.get("gate_id") or "").strip()
        if gate_id:
            patch_results["gate_patch_result"] = _apply_asset_patch(
                AssetPatchRequest(
                    job_id=job_id,
                    object_type="gate",
                    object_id=gate_id,
                    patch=request.gate_patch,
                    reviewer_id=actor_id,
                    reviewer_name=actor_name,
                    comment=comment or "hitl modify gate patch",
                )
            )
    return {
        "status": "ok",
        "action": action,
        "job_id": job_id,
        "candidate_id": candidate_id,
        "result": patch_results,
    }


@app.get("/normref/ingest/reviewer-learning")
def normref_reviewer_learning(q: str = "", slot_key: str = "", top_k: int = 20) -> Dict[str, Any]:
    doc = _load_reviewer_learning_store()
    rows = doc.get("items", []) if isinstance(doc.get("items"), list) else []
    query = str(q or "").strip().lower()
    slot = str(slot_key or "").strip()
    out: List[Dict[str, Any]] = []
    for row in rows[::-1]:
        if not isinstance(row, dict):
            continue
        clause = str(row.get("clause_text") or "").strip()
        sk = str(row.get("slot_key") or "").strip()
        if slot and sk != slot:
            continue
        if query and query not in clause.lower():
            continue
        out.append(row)
        if len(out) >= max(1, int(top_k or 20)):
            break
    return {"status": "ok", "count": len(out), "items": out, "total": len(rows)}


