@app.get("/normref/ingest/jobs/{job_id}/artifacts")
def normref_ingest_artifacts(job_id: str) -> Dict[str, Any]:
    def _catalog_has_legacy_noise(cat_obj: Dict[str, Any]) -> bool:
        rows = cat_obj.get("catalog", []) if isinstance(cat_obj, dict) else []
        if not isinstance(rows, list) or not rows:
            return False
        for row in rows:
            if not isinstance(row, dict):
                continue
            rid = str(row.get("id", "")).strip()
            rtype = str(row.get("type", "")).strip().lower()
            title = str(row.get("title") or row.get("name") or "").strip()
            if rtype in {"chapter", "section", "clause"} and (rid == "0" or rid.startswith("0.")):
                return True
            if rtype in {"chapter", "section"} and re.search(r"[~～]\s*\d", title):
                return True
        return False

    def _rebuild_from_package() -> None:
        pkg = _load_review_package(job_id)
        src = str((pkg.get("source_artifacts", {}) or {}).get("input_file", "")).strip() if isinstance(pkg, dict) else ""
        std_code = str((pkg.get("std_code", "") or "")).strip()
        if not (src and Path(src).exists()):
            # Fallback for legacy/migrated jobs: artifacts can still be generated
            # from review package structure even when source file path is gone.
            src = str((pkg.get("uploaded_file", "") or "")).strip()
        if not src:
            src = "missing-source.pdf"
        version_tag = datetime.utcnow().strftime("%Y-%m")
        spec_seg = _normalize_normref_seg(std_code, "unknown-spec")
        seed_normref = f"v://std/{spec_seg}/chapter/section/table/measured_value"
        _run_normref_artifact_pipeline(
            job_id=job_id,
            version_tag=version_tag,
            source_file=src,
            normref_input=seed_normref,
        )

    def _rebuild_index_from_existing_files() -> None:
        artifact_dir = _artifact_dir_for_job(job_id)
        files_map: Dict[str, str] = {}
        artifact_summaries: Dict[str, Any] = {}
        validations: Dict[str, Any] = {}
        schema_map = _schema_map()
        for p in artifact_dir.glob("*.json"):
            name = p.name
            if name == "00_pipeline_index.json":
                continue
            files_map[name] = str(p)
            try:
                payload = json.loads(p.read_text(encoding="utf-8-sig"))
            except Exception:
                payload = {}
            count = 0
            if isinstance(payload, dict):
                raw_count = payload.get("count")
                if isinstance(raw_count, (int, float)):
                    count = int(raw_count)
                elif isinstance(payload.get("catalog"), list):
                    count = len(payload.get("catalog", []))
                elif isinstance(payload.get("rules"), list):
                    count = len(payload.get("rules", []))
                elif isinstance(payload.get("gates"), list):
                    count = len(payload.get("gates", []))
                elif isinstance(payload.get("entries"), list):
                    count = len(payload.get("entries", []))
            errs = _simple_json_schema_validate(payload, schema_map.get(name, {"type": "object"}))
            schema_valid = len(errs) == 0
            validations[name] = {
                "schema_valid": schema_valid,
                "business_valid": count > 0 if name in {"02_catalog.json", "03_clause_tree.json", "05_components.json"} else True,
                "valid": schema_valid,
                "errors": errs,
            }
            artifact_summaries[name] = {
                "generated": True,
                "valid": schema_valid,
                "count": count,
                "status": "ok" if schema_valid else "invalid",
            }
        index = {
            "job_id": job_id,
            "valid": all(bool((v or {}).get("schema_valid")) for v in validations.values()) if validations else False,
            "files": files_map,
            "validations": validations,
            "artifact_summaries": artifact_summaries,
            "created_at": _utc_now(),
            "updated_at": _utc_now(),
        }
        _write_artifact_json(job_id, "00_pipeline_index.json", index)

    index_path = _artifact_dir_for_job(job_id) / "00_pipeline_index.json"
    if not index_path.exists():
        # Lazy backfill: try to build artifacts from existing review package
        # so frontend does not dead-end on historical/missed artifact jobs.
        try:
            _rebuild_from_package()
        except Exception as exc:
            # Final fallback: if partial artifact JSON files already exist, rebuild index
            # to keep frontend visible instead of hard 404.
            try:
                _rebuild_index_from_existing_files()
            except Exception:
                raise HTTPException(status_code=404, detail=f"未找到任务 {job_id} 的 pipeline artifacts（且回补失败：{exc}）。")
    else:
        # Auto-heal legacy noisy catalogs (e.g., 0.x table metric rows parsed as chapters).
        try:
            cat_path = _artifact_dir_for_job(job_id) / "02_catalog.json"
            if cat_path.exists():
                cat_obj = json.loads(cat_path.read_text(encoding="utf-8-sig"))
                if _catalog_has_legacy_noise(cat_obj):
                    _rebuild_from_package()
        except Exception:
            # Non-fatal: keep serving existing artifacts if auto-heal fails.
            pass
    _register_required_artifacts_for_job(job_id, created_by="system.artifact_pipeline")
    return _refresh_artifact_business_valid(job_id)


@app.get("/normref/ingest/jobs/{job_id}/artifacts/{artifact_name}")
def normref_ingest_artifact_file(job_id: str, artifact_name: str) -> Dict[str, Any]:
    safe_name = _safe_upload_name(artifact_name)
    target = _artifact_dir_for_job(job_id) / safe_name
    if not target.exists():
        raise HTTPException(status_code=404, detail=f"未找到产物文件：{safe_name}")
    payload = json.loads(target.read_text(encoding="utf-8-sig"))
    if safe_name == "02_catalog.json" and isinstance(payload, dict):
        try:
            rows = payload.get("catalog", [])
            if isinstance(rows, list):
                pkg = _load_review_package(job_id)
                std_code = str((pkg.get("std_code", "") or "")).strip()
                pkg_title = str((pkg.get("title", "") or "")).strip()
                if _is_jtgt3650_spec(std_code, pkg_title):
                    rows = _ensure_jtgt3650_catalog([x for x in rows if isinstance(x, dict)])
                    rows = sorted(
                        rows,
                        key=lambda x: (
                            {"chapter": 1, "section": 2, "clause": 3, "table": 4}.get(str((x or {}).get("type", "")).strip().lower(), 9),
                            tuple(int(v) for v in re.findall(r"\d+", str((x or {}).get("id", "")).strip())),
                            str((x or {}).get("id", "")).strip(),
                        ),
                    )
                    payload["catalog"] = rows
                    payload["count"] = len(rows)
        except Exception:
            pass
    if safe_name == "07_rules.json" and isinstance(payload, dict):
        rules_raw = payload.get("rules", [])
        if isinstance(rules_raw, list):
            filtered_rules: List[Dict[str, Any]] = []
            filtered_count = 0
            for item in rules_raw:
                if not isinstance(item, dict):
                    continue
                norm_ref = str(item.get("norm_ref", "")).strip().lower()
                field_name = str(item.get("field", "")).strip().lower()
                unresolved = bool(item.get("unresolved", False))
                # Compatibility cleanup for historical placeholder rules.
                # These entries are synthetic appendix/k placeholders and
                # should never be treated as executable Rule outputs.
                is_placeholder = (
                    "/chapter/k/table/measured_value" in norm_ref
                    or (unresolved and field_name == "measured_value" and "/chapter/k/" in norm_ref)
                )
                if is_placeholder:
                    filtered_count += 1
                    continue
                filtered_rules.append(item)
            if filtered_count > 0:
                payload["rules"] = filtered_rules
                payload["rule_count"] = len(filtered_rules)
                payload["filtered_placeholder_rule_count"] = filtered_count
    return {
        "job_id": job_id,
        "artifact_name": safe_name,
        "payload": payload,
    }


