@app.post("/normref/unresolved-rules/{queue_id}/resolve")
def resolve_unresolved_rule(queue_id: str, request: UnresolvedRuleResolveRequest) -> Dict[str, Any]:
    queue = _load_layer2_store("unresolved_rule_queue")
    target: Optional[Dict[str, Any]] = None
    for item in queue:
        if isinstance(item, dict) and str(item.get("queue_id", "")).strip() == str(queue_id).strip():
            target = item
            break
    if target is None:
        raise HTTPException(status_code=404, detail=f"未找到 unresolved 队列项：{queue_id}")
    if str(target.get("status", "")).strip() == "resolved":
        return {"status": "ok", "message": "该队列项已解决", "item": target}

    operator = _normalize_rule_operator(request.operator)
    min_v = request.min
    max_v = request.max
    if operator == "between" and (min_v is None or max_v is None):
        raise HTTPException(status_code=400, detail="operator=between 时必须提供 min 和 max。")
    if operator in {">=", ">"} and min_v is None:
        raise HTTPException(status_code=400, detail=f"operator={operator} 时必须提供 min。")
    if operator in {"<=", "<"} and max_v is None:
        raise HTTPException(status_code=400, detail=f"operator={operator} 时必须提供 max。")

    field_name = _normalize_normref_seg(request.field, "measured_value")
    patch = {
        "field": field_name,
        "operator": operator,
        "min": min_v,
        "max": max_v,
        "unit": str(request.unit or "").strip(),
        "unresolved": False,
        "enabled": True,
        "unresolved_reason": "",
        "resolved": True,
        "resolved_at": _utc_now(),
        "resolved_by": str(request.reviewer_id or "").strip() or "expert.default",
    }
    job_id = str(target.get("job_id", "")).strip()
    rule_id = str(target.get("rule_id", "")).strip()
    if not job_id or not rule_id:
        raise HTTPException(status_code=400, detail="队列项缺少 job_id 或 rule_id，无法回写。")
    _patch_rule_in_artifacts(job_id, rule_id, patch)

    writeback_payload = {
        "job_id": job_id,
        "rule_id": rule_id,
        "norm_ref": str(target.get("norm_ref", "")).strip(),
        "source_clause_id": str(target.get("source_clause_id", "")).strip(),
        "field": field_name,
        "operator": operator,
        "min": min_v,
        "max": max_v,
        "unit": str(request.unit or "").strip(),
        "reviewer_id": str(request.reviewer_id or "").strip() or "expert.default",
        "reviewer_name": str(request.reviewer_name or "").strip() or "领域专家",
        "comment": str(request.comment or "").strip(),
        "resolved_at": patch["resolved_at"],
    }
    writeback_id = _writeback_resolved_rule_to_store(writeback_payload)

    target["status"] = "resolved"
    target["resolved"] = True
    target["resolved_at"] = patch["resolved_at"]
    target["resolution"] = writeback_payload
    _save_layer2_store("unresolved_rule_queue", queue)
    return {
        "status": "ok",
        "queue_id": queue_id,
        "writeback_id": writeback_id,
        "resolved": True,
        "rule_patch": patch,
    }


