def _normalize_standard_filename_token(value: str) -> str:
    text = str(value or "").strip()
    if not text:
        return "UNKNOWN-STANDARD"
    normalized = re.sub(r"[^0-9A-Za-z._-]+", "-", text.replace("/", "-"))
    normalized = re.sub(r"-{2,}", "-", normalized).strip("-")
    return normalized or "UNKNOWN-STANDARD"


def _normalize_bundle_version(value: str) -> str:
    text = str(value or "").strip()
    return text or "v1"


def _resolve_default_spec_paths(standard_code: str) -> Dict[str, Path]:
    normalized = _normalize_standard_filename_token(standard_code).lower()
    if "jtg-f80-1-2017" in normalized:
        return {
            "spec_md_path": REPO_ROOT / "docs" / "normref" / "std" / "jtg-f80-1-2017-compaction.spec.md",
            "spec_json_path": REPO_ROOT / "normdocs" / "library" / "cn" / "mot" / "jtg-f80-1-2017" / "compaction" / "spec.json",
            "specir_yaml_path": REPO_ROOT / "docs" / "normref" / "std" / "jtg-f80-1-2017-compaction.specir.yaml",
            "hash_manifest_path": REPO_ROOT / "normdocs" / "library" / "cn" / "mot" / "jtg-f80-1-2017" / "compaction" / "hash_manifest.json",
        }
    raise HTTPException(status_code=400, detail=f"未配置标准的默认 specbundle 路径：{standard_code}")


def _resolve_bundle_source_path(value: str, fallback: Path, *, field_name: str) -> Path:
    raw = str(value or "").strip()
    target = Path(raw).expanduser() if raw else fallback
    if not target.is_absolute():
        target = (REPO_ROOT / target).resolve()
    else:
        target = target.resolve()
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=400, detail=f"{field_name} 文件不存在：{target}")
    return target


def _read_bundle_hash(hash_manifest_path: Path) -> str:
    try:
        payload = json.loads(hash_manifest_path.read_text(encoding="utf-8-sig"))
    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail=f"hash_manifest.json 非法：{hash_manifest_path}") from exc
    bundle_hash = str(payload.get("bundle_hash", "")).strip()
    if not bundle_hash:
        raise HTTPException(status_code=400, detail=f"hash_manifest.json 缺少 bundle_hash：{hash_manifest_path}")
    return bundle_hash


def _extract_source_pdf_from_specir_yaml(specir_yaml_path: Path) -> str:
    text = specir_yaml_path.read_text(encoding="utf-8-sig")
    for line in text.splitlines():
        stripped = line.strip()
        if stripped.startswith("storage_uri:"):
            value = stripped.split(":", 1)[1].strip().strip('"').strip("'")
            if value:
                return value
    for line in text.splitlines():
        stripped = line.strip()
        if stripped.startswith("file_name:"):
            value = stripped.split(":", 1)[1].strip().strip('"').strip("'")
            if value:
                return value
    return str(specir_yaml_path)


def _compute_spec_counts(spec_json_path: Path) -> Tuple[int, int]:
    try:
        payload = json.loads(spec_json_path.read_text(encoding="utf-8-sig"))
    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail=f"spec.json 非法：{spec_json_path}") from exc
    if not isinstance(payload, dict):
        raise HTTPException(status_code=400, detail=f"spec.json 根对象非法：{spec_json_path}")
    rules = payload.get("rules")
    components = payload.get("components")
    rule_count = len(rules) if isinstance(rules, list) else 0
    component_count = len(components) if isinstance(components, list) else 0
    return rule_count, component_count


def _sha256_file(path: Path) -> str:
    return "sha256:" + hashlib.sha256(path.read_bytes()).hexdigest()


def _build_specbundle_sources_from_job(job_id: str, standard_code: str, version: str) -> Dict[str, Any]:
    art_dir = _artifact_dir_for_job(job_id)
    required = ["01_spec.json", "02_catalog.json", "07_rules.json", "08_gates.json", "11_normdoc.json"]
    missing = [name for name in required if not (art_dir / name).exists()]
    if missing:
        raise HTTPException(status_code=400, detail=f"任务 {job_id} 缺少产物文件：{', '.join(missing)}")

    def _read_art(name: str) -> Dict[str, Any]:
        p = art_dir / name
        try:
            payload = json.loads(p.read_text(encoding="utf-8-sig"))
            return payload if isinstance(payload, dict) else {}
        except Exception:
            return {}

    spec = _read_art("01_spec.json")
    catalog = _read_art("02_catalog.json")
    rules = _read_art("07_rules.json")
    gates = _read_art("08_gates.json")
    normdoc = _read_art("11_normdoc.json")
    normref_idx = _read_art("norm_ref_index.json")

    catalog_rows = [x for x in catalog.get("catalog", []) if isinstance(x, dict)] if isinstance(catalog.get("catalog"), list) else []
    rule_rows = [x for x in rules.get("rules", []) if isinstance(x, dict)] if isinstance(rules.get("rules"), list) else []
    gate_rows = [x for x in gates.get("gates", []) if isinstance(x, dict)] if isinstance(gates.get("gates"), list) else []
    normref_rows = [x for x in normref_idx.get("entries", []) if isinstance(x, dict)] if isinstance(normref_idx.get("entries"), list) else []

    spec_json_obj: Dict[str, Any] = {
        "standard_code": standard_code,
        "version": version,
        "source_job_id": job_id,
        "spec": spec,
        "catalog": catalog_rows,
        "rules": rule_rows,
        "gates": gate_rows,
        "norm_refs": normref_rows,
        "normdoc": {
            "normdoc_id": str(normdoc.get("normdoc_id", "")).strip(),
            "bundle_hash": str(normdoc.get("bundle_hash", "")).strip(),
            "status": str(normdoc.get("status", "")).strip(),
        },
    }

    md_lines: List[str] = [
        f"# {str(spec.get('spec_name') or standard_code).strip()}",
        "",
        f"- 标准编号: {standard_code}",
        f"- 版本: {version}",
        f"- 来源任务: {job_id}",
        "",
        "## Catalog 摘要",
        f"- chapter/section/clause/table 总计: {len(catalog_rows)}",
        "",
        "## Rule 摘要",
        f"- rule_count: {len(rule_rows)}",
        "",
        "## Gate 摘要",
        f"- gate_count: {len(gate_rows)}",
        "",
        "## normRef 摘要",
        f"- normRef_count: {len(normref_rows)}",
        "",
        "## 目录预览（前 30 条）",
    ]
    for row in catalog_rows[:30]:
        rid = str((row or {}).get("id", "")).strip()
        rtype = str((row or {}).get("type", "")).strip()
        title = str((row or {}).get("title") or (row or {}).get("name") or "").strip()
        md_lines.append(f"- {rid} {title} ({rtype})")
    md_lines.append("")

    pkg = _load_review_package(job_id)
    source_file = str((pkg.get("source_artifacts", {}) or {}).get("input_file", "")).strip() if isinstance(pkg, dict) else ""
    specir_yaml_text = "\n".join(
        [
            "specir:",
            f"  standard_code: \"{standard_code}\"",
            f"  version: \"{version}\"",
            f"  job_id: \"{job_id}\"",
            f"  storage_uri: \"{source_file or '-'}\"",
            f"  generated_at: \"{_utc_now()}\"",
        ]
    ) + "\n"

    build_dir = NORMREF_SPECBUNDLE_DIR / "_build" / _safe_upload_name(f"{job_id}-{standard_code}-{version}")
    build_dir.mkdir(parents=True, exist_ok=True)
    spec_md_path = build_dir / "spec.md"
    spec_json_path = build_dir / "spec.json"
    specir_yaml_path = build_dir / "specir.yaml"
    hash_manifest_path = build_dir / "hash_manifest.json"
    spec_md_path.write_text("\n".join(md_lines), encoding="utf-8")
    spec_json_path.write_text(json.dumps(spec_json_obj, ensure_ascii=False, indent=2), encoding="utf-8")
    specir_yaml_path.write_text(specir_yaml_text, encoding="utf-8")

    md_hash = _sha256_file(spec_md_path)
    json_hash = _sha256_file(spec_json_path)
    specir_hash = _sha256_file(specir_yaml_path)
    bundle_hash = _sha256_text(
        json.dumps(
            {
                "standard_code": standard_code,
                "version": version,
                "job_id": job_id,
                "md_hash": md_hash,
                "json_hash": json_hash,
                "specir_hash": specir_hash,
            },
            ensure_ascii=False,
            sort_keys=True,
            separators=(",", ":"),
        )
    )
    hash_manifest_path.write_text(
        json.dumps(
            {
                "standard_code": standard_code,
                "version": version,
                "bundle_hash": bundle_hash,
                "md_hash": md_hash,
                "json_hash": json_hash,
                "specir_hash": specir_hash,
                "generated_at": _utc_now(),
                "source_job_id": job_id,
            },
            ensure_ascii=False,
            indent=2,
        ),
        encoding="utf-8",
    )

    return {
        "spec_md_path": spec_md_path,
        "spec_json_path": spec_json_path,
        "specir_yaml_path": specir_yaml_path,
        "hash_manifest_path": hash_manifest_path,
        "bundle_hash": bundle_hash,
    }


def _ensure_bundle_bound_paths(
    *,
    specbundle_path: Path,
    specir_path: Path,
    spec_md_path: Path,
    spec_json_path: Path,
) -> None:
    for field_name, path_obj in {
        "specbundle_path": specbundle_path,
        "specir_path": specir_path,
        "spec_md_path": spec_md_path,
        "spec_json_path": spec_json_path,
    }.items():
        if not path_obj.exists() or not path_obj.is_file():
            raise HTTPException(status_code=400, detail=f"{field_name} 文件不存在：{path_obj}")


def _verify_specbundle_completeness(bundle_path: Path) -> None:
    required = {"spec.md", "spec.json", "specir.yaml", "README.txt", "hash_manifest.json"}
    try:
        with zipfile.ZipFile(bundle_path, mode="r") as zf:
            names = set(zf.namelist())
    except zipfile.BadZipFile as exc:
        raise HTTPException(status_code=400, detail=f"specbundle 非法 ZIP：{bundle_path}") from exc
    missing = sorted(required.difference(names))
    if missing:
        raise HTTPException(status_code=400, detail=f"specbundle 缺少文件：{', '.join(missing)}")


def _verify_specbundle_hashes(bundle_path: Path) -> Dict[str, Any]:
    _verify_specbundle_completeness(bundle_path)
    with zipfile.ZipFile(bundle_path, mode="r") as zf:
        spec_md_bytes = zf.read("spec.md")
        spec_json_bytes = zf.read("spec.json")
        specir_bytes = zf.read("specir.yaml")
        manifest_obj = json.loads(zf.read("hash_manifest.json").decode("utf-8-sig"))
    if not isinstance(manifest_obj, dict):
        raise HTTPException(status_code=400, detail=f"hash_manifest.json 非法：{bundle_path}")

    md_hash_actual = "sha256:" + hashlib.sha256(spec_md_bytes).hexdigest()
    json_hash_actual = "sha256:" + hashlib.sha256(spec_json_bytes).hexdigest()
    specir_hash_actual = "sha256:" + hashlib.sha256(specir_bytes).hexdigest()
    md_hash_expected = str(manifest_obj.get("md_hash", "")).strip()
    json_hash_expected = str(manifest_obj.get("json_hash", "")).strip()
    specir_hash_expected = str(manifest_obj.get("specir_hash", "")).strip()
    bundle_hash_expected = str(manifest_obj.get("bundle_hash", "")).strip()
    source_job_id = str(manifest_obj.get("source_job_id", "")).strip()

    bundle_hash_actual = _sha256_text(
        json.dumps(
            {
                "standard_code": str(manifest_obj.get("standard_code", "")).strip() or "",
                "version": str(manifest_obj.get("version", "")).strip() or "",
                "job_id": source_job_id,
                "md_hash": md_hash_actual,
                "json_hash": json_hash_actual,
                "specir_hash": specir_hash_actual,
            },
            ensure_ascii=False,
            sort_keys=True,
            separators=(",", ":"),
        )
    )
    # Backward compatibility: old bundles may not carry standard_code/version in manifest.
    # Recompute with a neutral seed when missing.
    if not bundle_hash_expected:
        bundle_hash_expected = bundle_hash_actual

    checks = {
        "md_hash_match": bool(md_hash_expected and md_hash_actual == md_hash_expected),
        "json_hash_match": bool(json_hash_expected and json_hash_actual == json_hash_expected),
        "specir_hash_match": bool(specir_hash_expected and specir_hash_actual == specir_hash_expected),
        "bundle_hash_match": bool(bundle_hash_expected == bundle_hash_actual),
    }
    valid = all(checks.values())
    return {
        "valid": valid,
        "checks": checks,
        "expected": {
            "md_hash": md_hash_expected,
            "json_hash": json_hash_expected,
            "specir_hash": specir_hash_expected,
            "bundle_hash": bundle_hash_expected,
        },
        "actual": {
            "md_hash": md_hash_actual,
            "json_hash": json_hash_actual,
            "specir_hash": specir_hash_actual,
            "bundle_hash": bundle_hash_actual,
        },
        "source_job_id": source_job_id,
    }


@app.post("/normref/specbundle/build")
def build_specbundle(request: BuildSpecBundleRequest) -> Dict[str, Any]:
    standard_code = str(request.standard_code or "").strip()
    if not standard_code:
        raise HTTPException(status_code=400, detail="standard_code 不能为空")
    version = _normalize_bundle_version(request.version)
    req_job_id = str(request.job_id or "").strip()
    all_custom_paths = all(
        str(x or "").strip()
        for x in [request.spec_md_path, request.spec_json_path, request.specir_yaml_path, request.hash_manifest_path]
    )

    if req_job_id and not all_custom_paths:
        built = _build_specbundle_sources_from_job(req_job_id, standard_code, version)
        spec_md_path = Path(str(built["spec_md_path"])).resolve()
        spec_json_path = Path(str(built["spec_json_path"])).resolve()
        specir_yaml_path = Path(str(built["specir_yaml_path"])).resolve()
        hash_manifest_path = Path(str(built["hash_manifest_path"])).resolve()
    else:
        default_paths = _resolve_default_spec_paths(standard_code)
        spec_md_path = _resolve_bundle_source_path(
            request.spec_md_path,
            default_paths["spec_md_path"],
            field_name="spec_md_path",
        )
        spec_json_path = _resolve_bundle_source_path(
            request.spec_json_path,
            default_paths["spec_json_path"],
            field_name="spec_json_path",
        )
        specir_yaml_path = _resolve_bundle_source_path(
            request.specir_yaml_path,
            default_paths["specir_yaml_path"],
            field_name="specir_yaml_path",
        )
        hash_manifest_path = _resolve_bundle_source_path(
            request.hash_manifest_path,
            default_paths["hash_manifest_path"],
            field_name="hash_manifest_path",
        )

    bundle_hash = _read_bundle_hash(hash_manifest_path)
    NORMREF_SPECBUNDLE_DIR.mkdir(parents=True, exist_ok=True)
    bundle_name = f"{_normalize_standard_filename_token(standard_code)}@{version}.specbundle"
    bundle_path = (NORMREF_SPECBUNDLE_DIR / bundle_name).resolve()

    try:
        manifest_obj = json.loads(hash_manifest_path.read_text(encoding="utf-8-sig"))
    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail=f"hash_manifest.json 非法：{hash_manifest_path}") from exc
    json_hash = str(manifest_obj.get("json_hash", "")).strip() or "-"
    md_hash = str(manifest_obj.get("md_hash", "")).strip() or "-"
    source_pdf = _extract_source_pdf_from_specir_yaml(specir_yaml_path)

    generated_at = datetime.utcnow().replace(microsecond=0).isoformat() + "Z"
    readme_text = "\n".join(
        [
            "SpecBot .specbundle",
            "",
            "用途：将规范的人读版与机读版打包为统一发布物，供 FormPeg / Gate / Executor 使用与审计追溯。",
            f"标准：{standard_code}",
            f"版本：{version}",
            f"生成时间：{generated_at}",
            f"来源 PDF：{source_pdf}",
            f"bundle_hash：{bundle_hash}",
            f"md_hash：{md_hash}",
            f"json_hash：{json_hash}",
        ]
    ) + "\n"

    with zipfile.ZipFile(bundle_path, mode="w", compression=zipfile.ZIP_DEFLATED) as zf:
        zf.write(spec_md_path, arcname="spec.md")
        zf.write(spec_json_path, arcname="spec.json")
        zf.write(specir_yaml_path, arcname="specir.yaml")
        zf.writestr("README.txt", readme_text.encode("utf-8"))
        zf.write(hash_manifest_path, arcname="hash_manifest.json")

    rule_count, component_count = _compute_spec_counts(spec_json_path)
    normdoc_id = f"{_normalize_standard_filename_token(standard_code)}@@{version}"
    existing_normdoc = normdoc_repository.get(normdoc_id)
    next_status: NormDocStatus = "draft"
    next_published_by = ""
    next_published_at = ""
    if existing_normdoc and existing_normdoc.status == "published":
        next_status = "published"
        next_published_by = existing_normdoc.published_by
        next_published_at = existing_normdoc.published_at

    normdoc_repository.upsert(
        NormDocCreatePayload(
            normdoc_id=normdoc_id,
            standard_code=standard_code,
            standard_name=standard_code,
            version=version,
            status=next_status,
            specbundle_path=str(bundle_path),
            bundle_hash=bundle_hash,
            specir_path=str(specir_yaml_path),
            spec_md_path=str(spec_md_path),
            spec_json_path=str(spec_json_path),
            created_by="specbot",
            published_by=next_published_by,
            published_at=next_published_at,
            rule_count=rule_count,
            component_count=component_count,
        )
    )

    return {
        "status": "ok",
        "source_mode": "job_artifacts" if req_job_id and not all_custom_paths else "static_or_custom_paths",
        "source_job_id": req_job_id,
        "normdoc_id": normdoc_id,
        "bundle_name": bundle_name,
        "bundle_path": str(bundle_path),
        "download_url": f"/normref/specbundle/download/{bundle_name}",
        "bundle_hash": bundle_hash,
    }


@app.get("/normref/specbundle/download/{bundle_name}")
def download_specbundle(bundle_name: str) -> FileResponse:
    safe_name = str(bundle_name or "").strip()
    if not safe_name or "/" in safe_name or "\\" in safe_name:
        raise HTTPException(status_code=400, detail="非法 bundle_name")
    bundle_path = (NORMREF_SPECBUNDLE_DIR / safe_name).resolve()
    if not bundle_path.exists() or not bundle_path.is_file():
        raise HTTPException(status_code=404, detail=f"未找到 specbundle：{safe_name}")
    return FileResponse(path=bundle_path, filename=safe_name, media_type="application/zip")


@app.post("/normref/specbundle/verify")
def verify_specbundle(request: SpecbundleVerifyRequest) -> Dict[str, Any]:
    bundle_name = str(request.bundle_name or "").strip()
    if not bundle_name:
        raise HTTPException(status_code=400, detail="bundle_name 不能为空")
    if "/" in bundle_name or "\\" in bundle_name:
        raise HTTPException(status_code=400, detail="非法 bundle_name")
    bundle_path = (NORMREF_SPECBUNDLE_DIR / bundle_name).resolve()
    if not bundle_path.exists() or not bundle_path.is_file():
        raise HTTPException(status_code=404, detail=f"未找到 specbundle：{bundle_name}")
    report = _verify_specbundle_hashes(bundle_path)
    return {
        "status": "ok" if bool(report.get("valid")) else "invalid",
        "bundle_name": bundle_name,
        "bundle_path": str(bundle_path),
        **report,
    }


def _collect_target_rule_ids_from_specbundle(form_code: str) -> set[str]:
    """
    Resolve rule ids for the selected form dynamically from specbundle data.
    This avoids hardcoding per-table clause ranges in rulepack export.
    """
    bid, bver = _resolve_form_bundle(form_code)
    bundle = _load_specbundle(bid, bver, form_code)
    target_ids: set[str] = set()
    for row in bundle.get("rules", []):
        if not isinstance(row, dict):
            continue
        rid = str(row.get("ruleId") or row.get("rule_id") or "").strip()
        if rid:
            target_ids.add(rid)
    for row in bundle.get("fieldRuleMap", []):
        if not isinstance(row, dict):
            continue
        rid = str(row.get("ruleId") or "").strip()
        if rid:
            target_ids.add(rid)
        rule_ids = row.get("ruleIds")
        if isinstance(rule_ids, list):
            for item in rule_ids:
                iid = str(item or "").strip()
                if iid:
                    target_ids.add(iid)
    return target_ids


def _load_form_rule_whitelist(form_code: str) -> set[str]:
    obj = _load_env_config_json("form_rule_whitelists.json", fallback_path=FORM_RULE_WHITELIST_PATH)
    rows = obj.get(str(form_code).strip(), []) if isinstance(obj, dict) else []
    if not isinstance(rows, list):
        return set()
    return {str(x).strip() for x in rows if str(x).strip()}


def _load_form_asset_whitelist(form_code: str) -> Dict[str, set[str]]:
    out = {
        "allowed_specir_ids": set(),
        "allowed_components": set(),
        "allowed_rules": set(),
        "allowed_gates": set(),
        "allowed_normRefs": set(),
    }
    obj = _load_env_config_json("form_asset_whitelists.json", fallback_path=FORM_ASSET_WHITELIST_PATH)
    cfg = obj.get(str(form_code).strip(), {}) if isinstance(obj, dict) else {}
    if not isinstance(cfg, dict):
        return out
    for key in out.keys():
        rows = cfg.get(key, [])
        if isinstance(rows, list):
            out[key] = {str(x).strip() for x in rows if str(x).strip()}
    return out


def _load_form_rule_overrides(form_code: str) -> Dict[str, Dict[str, Any]]:
    obj = _load_env_config_json("form_rule_overrides.json", fallback_path=FORM_RULE_OVERRIDE_PATH)
    root = obj.get(str(form_code).strip(), {}) if isinstance(obj, dict) else {}
    if not isinstance(root, dict):
        return {}
    out: Dict[str, Dict[str, Any]] = {}
    for rule_id, patch in root.items():
        rid = str(rule_id).strip()
        if not rid or not isinstance(patch, dict):
            continue
        out[rid] = patch
    return out


def _load_rule_golden_cases() -> List[Dict[str, Any]]:
    # Prefer new golden_set.json; fallback to legacy golden_cases.json.
    gset = _load_env_config_json("golden_set.json", fallback_path=RULE_GOLDEN_SET_PATH)
    if isinstance(gset, dict):
        forms = gset.get("forms", {})
        if isinstance(forms, dict):
            rows: List[Dict[str, Any]] = []
            for form_code, form_obj in forms.items():
                if not isinstance(form_obj, dict):
                    continue
                samples = form_obj.get("samples", [])
                if not isinstance(samples, list):
                    continue
                ver = str(form_obj.get("version") or gset.get("golden_version") or "v1").strip()
                for s in samples:
                    if not isinstance(s, dict):
                        continue
                    row = dict(s)
                    row.setdefault("form_code", str(form_code).strip())
                    row.setdefault("version", ver)
                    rows.append(row)
            if rows:
                return rows
    obj = _load_env_config_json("golden_cases.json", fallback_path=RULE_GOLDEN_CASES_PATH)
    if isinstance(obj, dict):
        rows = obj.get("cases", [])
        if isinstance(rows, list):
            return [x for x in rows if isinstance(x, dict)]
        return []
    if isinstance(obj, list):
        return [x for x in obj if isinstance(x, dict)]
    return []


def _load_rule_golden_set_doc() -> Dict[str, Any]:
    obj = _load_env_config_json("golden_set.json", fallback_path=RULE_GOLDEN_SET_PATH)
    return obj if isinstance(obj, dict) else {}


def _save_rule_golden_set_doc(doc: Dict[str, Any]) -> Path:
    path = _env_config_path("golden_set.json")
    path.parent.mkdir(parents=True, exist_ok=True)
    raw = json.dumps(doc, ensure_ascii=False, indent=2)
    path.write_text(raw, encoding="utf-8")
    _audit_config_change(config_name="golden_set.json", path=path, raw_text=raw)
    return path


def _extract_golden_samples_from_rulepack(*, form_code: str, rules: List[Dict[str, Any]], gates: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    gate_by_rule: Dict[str, str] = {}
    for gate in gates:
        if not isinstance(gate, dict):
            continue
        gid = str(gate.get("gate_id") or gate.get("id") or "").strip()
        for rid in _gate_rule_ids(gate):
            if rid and rid not in gate_by_rule:
                gate_by_rule[rid] = gid
    rows: List[Dict[str, Any]] = []
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        field_name = str(rule.get("field") or "").strip()
        rid = str(rule.get("rule_id") or rule.get("id") or "").strip()
        if not field_name or not rid:
            continue
        rows.append(
            {
                "form_code": form_code,
                "field_name": field_name,
                "expected_specir": str(rule.get("source_specir_id") or rule.get("specir_id") or "").strip(),
                "expected_rule": rid,
                "expected_gate": str(gate_by_rule.get(rid) or "").strip(),
                "expected_threshold": _rule_threshold_value(rule),
                "expected_operator": str(rule.get("operator") or "").strip(),
                "expected_unit": str(rule.get("unit") or "").strip(),
                "normRef": str(rule.get("norm_ref") or rule.get("normRef") or "").strip(),
                "source_clause": str(rule.get("source_clause") or rule.get("source_clause_id") or "").strip(),
                "source_text": str(rule.get("source_text") or "").strip(),
            }
        )
    rows.sort(key=lambda x: (str(x.get("field_name") or ""), str(x.get("expected_rule") or "")))
    return rows


def _next_golden_form_version(current: str, history_len: int) -> str:
    cur = str(current or "").strip()
    if not cur:
        cur = datetime.utcnow().strftime("%Y.%m")
    return f"{cur}+{history_len + 1}"


def _load_system_config() -> Dict[str, Any]:
    defaults: Dict[str, Any] = {
        "default_form_code": "bridge_shi_1",
        "bundle_id_by_form": {"*": "highway.bridge.pile@v1"},
        "bundle_version_by_form": {"*": "v1"},
        "norm_version_mapping": {},
        "gate_synthesis_policy": {
            "enabled_when_no_gates": True,
            "source_tag_on_filtered_rules": "autogen.rulepack_fallback",
            "source_tag_on_payload": "autogen.rulepack_payload_fallback",
        },
        "form_api_mapping": {"save_and_validate_form_code": "bridge_shi_1"},
        "specir_checklist_policy": {
            "enforce_before_approve": True,
            "items": [
                "semantic_correct",
                "slots_complete",
                "unit_correct",
                "threshold_correct",
                "gate_complete",
                "evidence_traceable",
            ],
            "required_fields": ["reviewer", "reviewed_at", "result", "comment"],
        },
        "runtime_performance_governance": {
            "thresholds": {
                "rulepack_load_time_ms": 200,
                "gate_execution_time_ms": 500,
                "proof_generation_time_ms": 200,
                "memory_usage_bytes": 67108864,
            },
            "large_rulepack_warning_bytes": 2097152,
            "runtime_timeout_ms": 800,
            "fallback_on_timeout": True,
            "alert_enabled": True,
        },
    }
    cfg = _load_env_config_json("system_config.json")
    if not isinstance(cfg, dict):
        cfg = {}
    out = dict(defaults)
    for k in [
        "default_form_code",
        "bundle_id_by_form",
        "bundle_version_by_form",
        "norm_version_mapping",
        "gate_synthesis_policy",
        "form_api_mapping",
        "specir_checklist_policy",
        "runtime_performance_governance",
    ]:
        if k in cfg:
            out[k] = cfg[k]
    return out


def _specir_checklist_policy() -> Dict[str, Any]:
    cfg = _load_system_config()
    raw = cfg.get("specir_checklist_policy", {}) if isinstance(cfg.get("specir_checklist_policy"), dict) else {}
    items_raw = raw.get("items", [])
    fields_raw = raw.get("required_fields", [])
    items = [str(x).strip() for x in items_raw if str(x).strip()] if isinstance(items_raw, list) else []
    required_fields = [str(x).strip() for x in fields_raw if str(x).strip()] if isinstance(fields_raw, list) else []
    if not items:
        items = [
            "semantic_correct",
            "slots_complete",
            "unit_correct",
            "threshold_correct",
            "gate_complete",
            "evidence_traceable",
        ]
    if not required_fields:
        required_fields = ["reviewer", "reviewed_at", "result", "comment"]
    return {
        "enforce_before_approve": bool(raw.get("enforce_before_approve", True)),
        "items": items,
        "required_fields": required_fields,
    }


def _as_non_empty_text(value: Any) -> str:
    text = str(value or "").strip()
    return text


def _validate_specir_checklist_for_approve(candidate: Dict[str, Any]) -> None:
    policy = _specir_checklist_policy()
    if not bool(policy.get("enforce_before_approve", True)):
        return

    required_items = [str(x).strip() for x in policy.get("items", []) if str(x).strip()]
    required_fields = [str(x).strip() for x in policy.get("required_fields", []) if str(x).strip()]

    checklist = candidate.get("specir_checklist")
    if not isinstance(checklist, dict):
        checklist = candidate.get("checklist")
    if not isinstance(checklist, dict):
        raise HTTPException(status_code=400, detail="未完成 SpecIR Checklist：缺少 checklist 数据，禁止 approve")

    missing_items: List[str] = []
    invalid_items: List[str] = []
    for item_key in required_items:
        row = checklist.get(item_key)
        if not isinstance(row, dict):
            missing_items.append(item_key)
            continue
        missing_fields = [f for f in required_fields if not _as_non_empty_text(row.get(f))]
        if missing_fields:
            invalid_items.append(f"{item_key}(missing: {', '.join(missing_fields)})")
            continue
        result = _as_non_empty_text(row.get("result")).lower()
        if result not in {"pass", "passed", "ok", "true", "1", "yes"}:
            invalid_items.append(f"{item_key}(result={_as_non_empty_text(row.get('result'))})")

    if missing_items or invalid_items:
        msgs: List[str] = []
        if missing_items:
            msgs.append(f"缺少项: {', '.join(missing_items)}")
        if invalid_items:
            msgs.append(f"未通过/字段缺失: {', '.join(invalid_items)}")
        raise HTTPException(status_code=400, detail=f"未完成 SpecIR Checklist，禁止 approve。{'; '.join(msgs)}")


def _build_candidate_specir_hash(candidate: Dict[str, Any]) -> str:
    # Build a stable, execution-focused snapshot for签字追溯。
    payload = {
        "candidate_id": str(candidate.get("candidate_id", "")).strip(),
        "rule_id": str(candidate.get("rule_id", "")).strip(),
        "clause_id": str(candidate.get("clause_id", "")).strip(),
        "clause_no": str(candidate.get("clause_no", "")).strip(),
        "norm_ref": str(candidate.get("norm_ref", "")).strip(),
        "field_key": str(candidate.get("field_key", "")).strip(),
        "operator": str(candidate.get("operator", "")).strip(),
        "threshold_value": candidate.get("threshold_value"),
        "unit": str(candidate.get("unit", "")).strip(),
        "source_specir_id": str(candidate.get("source_specir_id", "")).strip(),
        "specir_id": str(candidate.get("specir_id", "")).strip(),
    }
    return _stable_json_hash(payload)


def _build_candidate_checklist_hash(candidate: Dict[str, Any]) -> str:
    checklist = candidate.get("specir_checklist")
    if not isinstance(checklist, dict):
        checklist = candidate.get("checklist")
    if not isinstance(checklist, dict):
        checklist = {}
    return _stable_json_hash({"checklist": checklist})


def _append_candidate_transition_audit_and_version(
    *,
    candidate: Dict[str, Any],
    before: Dict[str, Any],
    after: Dict[str, Any],
    operator: str,
    role: str,
    operation_type: str,
    require_signature: bool = False,
) -> None:
    now = _utc_now()
    workflow = candidate.get("workflow") if isinstance(candidate.get("workflow"), dict) else {}

    signature_hash = ""
    specir_hash = _build_candidate_specir_hash(after)
    checklist_hash = _build_candidate_checklist_hash(after)
    if require_signature:
        signatures = workflow.get("signature_chain")
        if not isinstance(signatures, list):
            signatures = []
        prev_sig_hash = str(signatures[-1].get("signature_hash", "")).strip() if signatures and isinstance(signatures[-1], dict) else ""
        signature = {
            "signer": operator,
            "role": role,
            "timestamp": now,
            "specir_hash": specir_hash,
            "checklist_hash": checklist_hash,
            "prev_signature_hash": prev_sig_hash,
        }
        signature_hash = _stable_json_hash(signature)
        signature["signature_hash"] = signature_hash
        signatures.append(signature)
        workflow["signature_chain"] = signatures

    diff = _compute_candidate_diff(before, after)
    audit_logs = workflow.get("audit_log")
    if not isinstance(audit_logs, list):
        audit_logs = []
    audit_logs.append(
        {
            "before": before,
            "after": after,
            "diff": diff,
            "operator": operator,
            "operation_type": operation_type,
            "timestamp": now,
            "signature_hash": signature_hash,
        }
    )
    workflow["audit_log"] = audit_logs

    versions = workflow.get("version_chain")
    if not isinstance(versions, list):
        versions = []
    version_no = len(versions) + 1
    version_id = f"v{version_no}"
    versions.append(
        {
            "version_id": version_id,
            "created_at": now,
            "operation_type": operation_type,
            "operator": operator,
            "status": str(after.get("status", "")).strip(),
            "signature_hash": signature_hash,
            "specir_hash": specir_hash,
            "checklist_hash": checklist_hash,
            "snapshot": after,
        }
    )
    workflow["version_chain"] = versions
    workflow["current_version_id"] = version_id
    candidate["workflow"] = workflow


def _resolve_form_bundle(form_code: str) -> Tuple[str, str]:
    cfg = _load_system_config()
    f = str(form_code or "").strip()
    bid_map = cfg.get("bundle_id_by_form", {}) if isinstance(cfg.get("bundle_id_by_form"), dict) else {}
    bver_map = cfg.get("bundle_version_by_form", {}) if isinstance(cfg.get("bundle_version_by_form"), dict) else {}
    bundle_id = str(bid_map.get(f) or bid_map.get("*") or "highway.bridge.pile@v1").strip()
    bundle_ver = str(bver_map.get(f) or bver_map.get("*") or "v1").strip()
    return bundle_id, bundle_ver


def _resolve_norm_version(spec_code: str, spec_version: str) -> str:
    cfg = _load_system_config()
    mp = cfg.get("norm_version_mapping", {}) if isinstance(cfg.get("norm_version_mapping"), dict) else {}
    key = str(spec_code or "").strip()
    if key and key in mp and str(mp.get(key) or "").strip():
        return str(mp.get(key)).strip()
    return str(spec_version or "").strip()


def _gate_synthesis_policy() -> Dict[str, Any]:
    cfg = _load_system_config()
    p = cfg.get("gate_synthesis_policy", {}) if isinstance(cfg.get("gate_synthesis_policy"), dict) else {}
    return {
        "enabled_when_no_gates": bool(p.get("enabled_when_no_gates", True)),
        "source_tag_on_filtered_rules": str(p.get("source_tag_on_filtered_rules") or "autogen.rulepack_fallback").strip(),
        "source_tag_on_payload": str(p.get("source_tag_on_payload") or "autogen.rulepack_payload_fallback").strip(),
    }


def _rule_threshold_value(rule: Dict[str, Any]) -> Any:
    thr = rule.get("threshold")
    if isinstance(thr, dict):
        if thr.get("value") is not None:
            return thr.get("value")
        if thr.get("max") is not None and thr.get("min") is not None:
            return [thr.get("min"), thr.get("max")]
        if thr.get("max") is not None:
            return thr.get("max")
        if thr.get("min") is not None:
            return thr.get("min")
    for k in ("max", "min", "limit", "expected", "value"):
        if k in rule:
            return rule.get(k)
    return None


def _to_float_if_possible(val: Any) -> Any:
    if isinstance(val, (int, float)):
        return float(val)
    if isinstance(val, str):
        s = val.strip()
        if not s:
            return None
        try:
            return float(s)
        except Exception:
            return val
    return val


def _normalize_threshold_struct(rule_row: Dict[str, Any]) -> Tuple[Dict[str, Any], List[str]]:
    allowed_ops = {">=", "<=", "=", "between", "in", "exists"}
    raw_operator = str(rule_row.get("operator") or "").strip()
    operator = raw_operator
    if operator == "==":
        operator = "="
    if operator not in allowed_ops:
        if operator in {">", "<", "!="}:
            operator = ">=" if operator == ">" else "<=" if operator == "<" else "="
        elif operator:
            operator = operator
    raw_text = str(rule_row.get("source_text") or rule_row.get("condition") or "").strip()
    unit = str(rule_row.get("unit") or "").strip()

    value = _to_float_if_possible(rule_row.get("value"))
    min_v = _to_float_if_possible(rule_row.get("min"))
    max_v = _to_float_if_possible(rule_row.get("max"))
    if value is None:
        value = _to_float_if_possible(rule_row.get("expected"))
    if value is None:
        value = _to_float_if_possible(rule_row.get("limit"))

    existing_thr = rule_row.get("threshold")
    if isinstance(existing_thr, dict):
        if value is None:
            value = _to_float_if_possible(existing_thr.get("value"))
        if min_v is None:
            min_v = _to_float_if_possible(existing_thr.get("min"))
        if max_v is None:
            max_v = _to_float_if_possible(existing_thr.get("max"))
        if not unit:
            unit = str(existing_thr.get("unit") or "").strip()
        if not raw_text:
            raw_text = str(existing_thr.get("raw_text") or "").strip()
        if operator in {"", "=="}:
            operator = str(existing_thr.get("operator") or "").strip()

    errs: List[str] = []
    if not operator or operator not in allowed_ops:
        errs.append("invalid_operator")
    if not unit:
        errs.append("missing_unit")
    if operator == "between":
        if min_v is None or max_v is None:
            errs.append("missing_value_range")
    elif operator == "in":
        if value is None and not isinstance(existing_thr, dict):
            errs.append("missing_value_range")
    elif operator == "exists":
        pass
    else:
        if value is None and min_v is None and max_v is None:
            errs.append("missing_value_range")

    has_only_nl = bool(raw_text) and value is None and min_v is None and max_v is None and operator not in {"exists"}
    if has_only_nl:
        errs.append("natural_language_only_threshold")

    threshold_struct = {
        "value": value,
        "min": min_v,
        "max": max_v,
        "unit": unit,
        "operator": operator,
        "raw_text": raw_text,
    }
    return threshold_struct, errs


def _resolve_unresolved_type(reason_code: str, row: Dict[str, Any]) -> str:
    code = str(reason_code or "").strip().lower()
    txt = str(row.get("unresolved_reason") or "").strip().lower()
    if code == "missing_unit":
        return "missing_unit"
    if code == "missing_value_range":
        return "missing_threshold"
    if code == "invalid_operator" or code == "natural_language_only_threshold":
        return "semantic_ambiguity"
    if "formula" in txt or "unsupported_formula" in code:
        return "unsupported_formula"
    if "slot" in txt or "mapping" in txt:
        return "missing_slot_mapping"
    if "missing_gate" in txt or "gate_synthesis_failed" in txt:
        return "missing_gate"
    return "semantic_ambiguity"


def _unresolved_owner_for_type(utype: str) -> str:
    cfg = _load_system_config()
    mp = cfg.get("unresolved_owner_by_type", {}) if isinstance(cfg.get("unresolved_owner_by_type"), dict) else {}
    t = str(utype or "").strip()
    owner = str(mp.get(t) or "").strip()
    if owner:
        return owner
    return str(cfg.get("unresolved_default_owner") or "specir_owner").strip()


def _unresolved_priority_for_type(utype: str) -> str:
    t = str(utype or "").strip()
    if t in {"missing_gate", "unsupported_formula"}:
        return "P1"
    if t in {"missing_threshold", "missing_unit", "missing_slot_mapping"}:
        return "P2"
    return "P3"


def _build_unresolved_governance_fields(utype: str) -> Dict[str, Any]:
    priority = _unresolved_priority_for_type(utype)
    due_days = 1 if priority == "P1" else (3 if priority == "P2" else 7)
    due_dt = datetime.utcfromtimestamp(datetime.utcnow().timestamp() + due_days * 24 * 3600).date().isoformat()
    return {
        "priority": priority,
        "owner": _unresolved_owner_for_type(utype),
        "status": "open",
        "due_date": due_dt,
    }


def _empty_unresolved_type_counts() -> Dict[str, int]:
    return {k: 0 for k in sorted(UNRESOLVED_TYPES)}


def _build_normref_entry_map(normref_index_doc: Dict[str, Any]) -> Dict[str, Dict[str, Any]]:
    rows = normref_index_doc.get("entries", []) if isinstance(normref_index_doc, dict) else []
    out: Dict[str, Dict[str, Any]] = {}
    if not isinstance(rows, list):
        return out
    for row in rows:
        if not isinstance(row, dict):
            continue
        ref = str(row.get("normRef") or "").strip()
        if ref:
            out[ref] = row
    return out


def _extract_rule_anchor_fields(
    rule_row: Dict[str, Any],
    normref_entry: Optional[Dict[str, Any]],
) -> Dict[str, Any]:
    locator = normref_entry.get("locator", {}) if isinstance(normref_entry, dict) else {}
    source = locator.get("source", {}) if isinstance(locator, dict) else {}
    source_text = str(
        rule_row.get("source_text")
        or source.get("source_text")
        or ""
    ).strip()
    source_page = rule_row.get("source_page")
    if source_page is None:
        source_page = source.get("page_start")
    quote_start = rule_row.get("quote_start")
    quote_end = rule_row.get("quote_end")
    if quote_start is None and source_text:
        quote_start = 0
    if quote_end is None and source_text:
        quote_end = len(source_text)
    return {
        "normRef": str(rule_row.get("norm_ref") or "").strip(),
        "source_clause": str(rule_row.get("source_clause") or rule_row.get("source_clause_id") or "").strip(),
        "source_page": int(source_page) if isinstance(source_page, (int, float)) and int(source_page) >= 0 else None,
        "source_text": source_text,
        "quote_start": int(quote_start) if isinstance(quote_start, (int, float)) and int(quote_start) >= 0 else None,
        "quote_end": int(quote_end) if isinstance(quote_end, (int, float)) and int(quote_end) >= 0 else None,
    }


def _validate_rule_anchor_fields(anchor: Dict[str, Any]) -> List[str]:
    errs: List[str] = []
    if not str(anchor.get("normRef") or "").strip():
        errs.append("normRef missing")
    if not str(anchor.get("source_clause") or "").strip():
        errs.append("source_clause missing")
    if anchor.get("source_page") is None:
        errs.append("source_page missing")
    if not str(anchor.get("source_text") or "").strip():
        errs.append("source_text missing")
    if anchor.get("quote_start") is None:
        errs.append("quote_start missing")
    if anchor.get("quote_end") is None:
        errs.append("quote_end missing")
    qs = anchor.get("quote_start")
    qe = anchor.get("quote_end")
    if isinstance(qs, int) and isinstance(qe, int) and qe < qs:
        errs.append("quote_end < quote_start")
    return errs


def _compare_rulepack_with_golden(
    *,
    form_code: str,
    rules: List[Dict[str, Any]],
    gates: List[Dict[str, Any]],
) -> Dict[str, Any]:
    cases = [c for c in _load_rule_golden_cases() if str(c.get("form_code") or "").strip() == form_code]
    if not cases:
        return {"enabled": False, "form_code": form_code, "total_cases": 0, "passed": True, "diffs": []}

    gate_by_rule: Dict[str, Dict[str, Any]] = {}
    for gate in gates:
        if not isinstance(gate, dict):
            continue
        gid = str(gate.get("gate_id") or gate.get("id") or "").strip()
        for rid in _gate_rule_ids(gate):
            if rid and rid not in gate_by_rule:
                gate_by_rule[rid] = {"gate_id": gid, "gateRef": (gate.get("norm_refs") or [None])[0] if isinstance(gate.get("norm_refs"), list) and gate.get("norm_refs") else ""}

    actual_by_field: Dict[str, Dict[str, Any]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        field = str(rule.get("field") or "").strip()
        if not field:
            continue
        rid = str(rule.get("rule_id") or rule.get("id") or "").strip()
        g = gate_by_rule.get(rid, {})
        actual_by_field[field] = {
            "expected_specir": str(rule.get("source_specir_id") or rule.get("specir_id") or "").strip(),
            "expected_rule": rid,
            "expected_gate": str(g.get("gate_id") or "").strip(),
            "normRef": str(rule.get("norm_ref") or rule.get("normRef") or "").strip(),
            "source_clause": str(rule.get("source_clause") or rule.get("source_clause_id") or "").strip(),
            "source_text": str(rule.get("source_text") or "").strip(),
            "expected_unit": str(rule.get("unit") or "").strip(),
            "expected_operator": str(rule.get("operator") or "").strip(),
            "expected_threshold": _rule_threshold_value(rule),
        }

    diffs: List[Dict[str, Any]] = []
    mismatch_types = {
        "missing_rule",
        "threshold_changed",
        "operator_changed",
        "unit_changed",
        "gate_missing",
    }
    for case in cases:
        field = str(case.get("field_name") or "").strip()
        if not field:
            continue
        actual = actual_by_field.get(field)
        if not actual:
            diffs.append({"field_name": field, "type": "missing_rule", "expected": case, "actual": None})
            continue
        if case.get("expected_rule") != actual.get("expected_rule"):
            diffs.append(
                {
                    "field_name": field,
                    "type": "missing_rule",
                    "key": "expected_rule",
                    "expected": case.get("expected_rule"),
                    "actual": actual.get("expected_rule"),
                }
            )
        ev_gate = case.get("expected_gate")
        av_gate = actual.get("expected_gate")
        if ev_gate != av_gate:
            diffs.append(
                {
                    "field_name": field,
                    "type": "gate_missing",
                    "key": "expected_gate",
                    "expected": ev_gate,
                    "actual": av_gate,
                }
            )
        if case.get("expected_threshold") != actual.get("expected_threshold"):
            diffs.append(
                {
                    "field_name": field,
                    "type": "threshold_changed",
                    "key": "expected_threshold",
                    "expected": case.get("expected_threshold"),
                    "actual": actual.get("expected_threshold"),
                }
            )
        if case.get("expected_operator") != actual.get("expected_operator"):
            diffs.append(
                {
                    "field_name": field,
                    "type": "operator_changed",
                    "key": "expected_operator",
                    "expected": case.get("expected_operator"),
                    "actual": actual.get("expected_operator"),
                }
            )
        if case.get("expected_unit") != actual.get("expected_unit"):
            diffs.append(
                {
                    "field_name": field,
                    "type": "unit_changed",
                    "key": "expected_unit",
                    "expected": case.get("expected_unit"),
                    "actual": actual.get("expected_unit"),
                }
            )

    expected_fields = {str(c.get("field_name") or "").strip() for c in cases if str(c.get("field_name") or "").strip()}
    for field in actual_by_field.keys():
        if field not in expected_fields:
            diffs.append({"field_name": field, "type": "unexpected_field", "expected": None, "actual": actual_by_field[field]})

    classified = [d for d in diffs if str(d.get("type") or "").strip() in mismatch_types]
    type_counts: Dict[str, int] = {}
    for d in classified:
        dt = str(d.get("type") or "").strip()
        type_counts[dt] = int(type_counts.get(dt, 0) or 0) + 1

    return {
        "enabled": True,
        "form_code": form_code,
        "total_cases": len(cases),
        "passed": len(classified) == 0,
        "has_key_mismatch": len(classified) > 0,
        "type_counts": type_counts,
        "diffs": diffs,
        "key_mismatches": classified,
    }


@app.get("/normref/golden-set")
def get_rulepack_golden_set(form_code: str = "", version: str = "") -> Dict[str, Any]:
    rows = [x for x in _load_rule_golden_cases() if isinstance(x, dict)]
    f = str(form_code or "").strip()
    alias_map = {
        "bridge13": "bridge_shi_13",
        "bridge14": "bridge_shi_14",
        "bridge15": "bridge_shi_15",
    }
    f = alias_map.get(f, f)
    v = str(version or "").strip()
    if f:
        rows = [x for x in rows if str(x.get("form_code") or "").strip() == f]
    if v:
        rows = [x for x in rows if str(x.get("version") or "").strip() == v]
    # enforce normRef binding visibility
    bound_rows = [x for x in rows if str(x.get("normRef") or "").strip()]
    missing_normref = len(rows) - len(bound_rows)
    return {
        "status": "ok",
        "form_code": f,
        "version": v,
        "total": len(rows),
        "normref_bound": len(bound_rows),
        "normref_missing": missing_normref,
        "items": rows,
    }


@app.get("/normref/golden-set/history")
def get_rulepack_golden_set_history(form_code: str) -> Dict[str, Any]:
    f = str(form_code or "").strip()
    alias_map = {"bridge13": "bridge_shi_13", "bridge14": "bridge_shi_14", "bridge15": "bridge_shi_15"}
    f = alias_map.get(f, f)
    if not f:
        raise HTTPException(status_code=400, detail="form_code 不能为空")
    doc = _load_rule_golden_set_doc()
    forms = doc.get("forms", {}) if isinstance(doc.get("forms"), dict) else {}
    form_obj = forms.get(f, {}) if isinstance(forms.get(f), dict) else {}
    hist = form_obj.get("baseline_history", []) if isinstance(form_obj.get("baseline_history"), list) else []
    return {
        "status": "ok",
        "form_code": f,
        "current_version": str(form_obj.get("version") or "").strip(),
        "history_count": len(hist),
        "history": hist,
    }


@app.post("/normref/golden-set/review")
def review_rulepack_golden_set(request: GoldenSetReviewRequest) -> Dict[str, Any]:
    job_id = str(request.job_id or "").strip()
    form_code = str(request.form_code or "").strip()
    action = str(request.action or "").strip()
    operator = str(request.operator or "").strip()
    comment = str(request.comment or "").strip()
    signature = str(request.signature or "").strip()
    alias_map = {"bridge13": "bridge_shi_13", "bridge14": "bridge_shi_14", "bridge15": "bridge_shi_15"}
    form_code = alias_map.get(form_code, form_code)
    if not job_id or not form_code or not operator:
        raise HTTPException(status_code=400, detail="job_id/form_code/operator 不能为空")
    if action == "accept_new_baseline" and not signature:
        raise HTTPException(status_code=400, detail="baseline 更新必须签字（signature 不能为空）")

    rulepacks = _find_rulepacks_by_job(job_id)
    if not rulepacks:
        raise HTTPException(status_code=404, detail="未找到该 job 的 rulepack，无法进行 Golden Review")
    rp_path = rulepacks[0]
    try:
        rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"rulepack 非法 JSON：{rp_path.name}") from exc
    rules = rp_doc.get("rules", []) if isinstance(rp_doc.get("rules"), list) else []
    gates = rp_doc.get("gates", []) if isinstance(rp_doc.get("gates"), list) else []
    golden_compare = _compare_rulepack_with_golden(form_code=form_code, rules=rules, gates=gates)
    review_required = bool(golden_compare.get("enabled", False) and not bool(golden_compare.get("passed", True)))

    doc = _load_rule_golden_set_doc()
    forms = doc.get("forms", {}) if isinstance(doc.get("forms"), dict) else {}
    form_obj = forms.get(form_code, {}) if isinstance(forms.get(form_code), dict) else {}
    current_version = str(form_obj.get("version") or doc.get("golden_version") or "v1").strip()
    current_samples = form_obj.get("samples", []) if isinstance(form_obj.get("samples"), list) else []
    history = form_obj.get("baseline_history", []) if isinstance(form_obj.get("baseline_history"), list) else []

    review_row = {
        "at": _utc_now(),
        "job_id": job_id,
        "form_code": form_code,
        "action": action,
        "operator": operator,
        "comment": comment,
        "review_required": review_required,
        "golden_compare": golden_compare,
        "rulepack_name": rp_path.name,
    }

    if action == "accept_new_baseline":
        next_samples = _extract_golden_samples_from_rulepack(form_code=form_code, rules=[x for x in rules if isinstance(x, dict)], gates=[x for x in gates if isinstance(x, dict)])
        next_version = _next_golden_form_version(current_version, len(history))
        baseline_event = {
            "version": next_version,
            "from_version": current_version,
            "updated_at": _utc_now(),
            "updated_by": operator,
            "signature": signature,
            "comment": comment,
            "diff": {
                "golden_compare": golden_compare,
                "old_sample_count": len(current_samples),
                "new_sample_count": len(next_samples),
                "old_hash": _stable_json_hash({"samples": current_samples}),
                "new_hash": _stable_json_hash({"samples": next_samples}),
            },
        }
        history.append(baseline_event)
        form_obj["version"] = next_version
        form_obj["samples"] = next_samples
        form_obj["baseline_history"] = history[-300:]
        review_row["baseline_version"] = next_version
        review_row["signature"] = signature
    elif action == "reject_change":
        form_obj.setdefault("review_history", [])
        rh = form_obj.get("review_history", []) if isinstance(form_obj.get("review_history"), list) else []
        rh.append(review_row)
        form_obj["review_history"] = rh[-500:]
    elif action == "mark_expected_change":
        form_obj.setdefault("expected_changes", [])
        ex = form_obj.get("expected_changes", []) if isinstance(form_obj.get("expected_changes"), list) else []
        ex.append(review_row)
        form_obj["expected_changes"] = ex[-500:]
    else:
        raise HTTPException(status_code=400, detail=f"不支持的 action: {action}")

    forms[form_code] = form_obj
    doc["forms"] = forms
    doc["updated_at"] = _utc_now()
    save_path = _save_rule_golden_set_doc(doc)

    report = {
        "status": "ok",
        "review_required": review_required,
        "action": action,
        "form_code": form_code,
        "job_id": job_id,
        "golden_compare": golden_compare,
        "golden_set_path": str(save_path.resolve()),
    }
    _write_artifact_json(job_id, "golden_review_report.json", report)
    return report


def _load_quality_gate_thresholds() -> Dict[str, float]:
    defaults: Dict[str, float] = {
        "min_rule_correctness_rate": 0.99,
        "min_gate_executability_rate": 0.98,
        "min_traceability_rate": 1.0,
    }
    data = _load_env_config_json("quality_gate_thresholds.json", fallback_path=NORMREF_QUALITY_GATE_PATH)
    if not isinstance(data, dict):
        return defaults
    out = dict(defaults)
    for k in defaults.keys():
        try:
            if k in data:
                out[k] = float(data[k])
        except Exception:
            continue
    return out


