def _evaluate_gate_with_input(gate: Dict[str, Any], rules_by_id: Dict[str, Dict[str, Any]], values: Dict[str, Any]) -> Dict[str, Any]:
    gid = str(gate.get("gate_id") or gate.get("id") or "").strip() or "<unknown_gate>"
    rule_ids = _gate_rule_ids(gate)
    evaluated_rules: List[Dict[str, Any]] = []
    for rid in rule_ids:
        row = rules_by_id.get(rid, {})
        if not row:
            evaluated_rules.append({"rule_id": rid, "passed": False, "reason": "rule_missing"})
            continue
        ev = _evaluate_rule_with_input(row, values if isinstance(values, dict) else {})
        evaluated_rules.append(ev)
    passed = len(evaluated_rules) > 0 and all(bool(r.get("passed", False)) for r in evaluated_rules)
    return {"gate_id": gid, "passed": passed, "rule_ids": rule_ids, "rule_results": evaluated_rules}


def _run_gate_regression(form_code: str, payload: Dict[str, Any], critical_gates: List[str]) -> Dict[str, Any]:
    sample_cfg = _load_gate_regression_samples(form_code)
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gate_map: Dict[str, Dict[str, Any]] = {
        str(g.get("gate_id") or g.get("id") or "").strip(): g
        for g in gates
        if isinstance(g, dict) and str(g.get("gate_id") or g.get("id") or "").strip()
    }
    rules_by_id: Dict[str, Dict[str, Any]] = {
        str(r.get("rule_id") or r.get("ruleId") or r.get("id") or "").strip(): r
        for r in rules
        if isinstance(r, dict) and str(r.get("rule_id") or r.get("ruleId") or r.get("id") or "").strip()
    }
    sample_rows = sample_cfg.get("samples", []) if isinstance(sample_cfg.get("samples"), list) else []
    by_gate: Dict[str, List[Dict[str, Any]]] = {}
    for row in sample_rows:
        if not isinstance(row, dict):
            continue
        gid = str(row.get("gate_id") or "").strip()
        if not gid:
            continue
        by_gate.setdefault(gid, []).append(row)

    failures: List[Dict[str, Any]] = []
    warnings: List[str] = []
    total = 0
    passed = 0
    all_targets = list(dict.fromkeys([*(critical_gates or []), *list(by_gate.keys())]))
    for gid in all_targets:
        gate = gate_map.get(gid, {})
        if not gate:
            failures.append({"gate_id": gid, "reason": "gate_not_found_in_rulepack"})
            continue
        samples = by_gate.get(gid, [])
        if gid in critical_gates and len(samples) < 3:
            failures.append({"gate_id": gid, "reason": f"insufficient_samples:{len(samples)}(<3)"})
            continue
        if len(samples) == 0:
            warnings.append(f"{gid}: no regression samples configured")
            continue
        for idx, s in enumerate(samples, start=1):
            measured = s.get("measured", {})
            design = s.get("design", {})
            expected = str(s.get("expected_result", "FAIL")).strip().upper()
            values: Dict[str, Any] = {}
            if isinstance(design, dict):
                values.update(design)
            if isinstance(measured, dict):
                values.update(measured)
            ev = _evaluate_gate_with_input(gate, rules_by_id, values)
            actual = "PASS" if bool(ev.get("passed", False)) else "FAIL"
            total += 1
            ok = actual == expected
            if ok:
                passed += 1
            else:
                failures.append(
                    {
                        "gate_id": gid,
                        "sample_index": idx,
                        "expected_result": expected,
                        "actual_result": actual,
                        "measured": measured,
                        "design": design,
                    }
                )
    return {
        "enabled": True,
        "form_code": form_code,
        "critical_gates": critical_gates,
        "total_samples": total,
        "passed_samples": passed,
        "failed_samples": int(total - passed),
        "pass_rate": (float(passed) / float(total)) if total > 0 else 0.0,
        "passed": len(failures) == 0,
        "failures": failures,
        "warnings": warnings,
    }


def _run_runtime_regression(form_code: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    cfg = _load_runtime_regression_samples(form_code)
    samples = cfg.get("samples", []) if isinstance(cfg.get("samples"), list) else []
    if not samples:
        return {
            "enabled": False,
            "form_code": form_code,
            "passed": True,
            "reason": "runtime_samples_not_configured",
            "total_samples": 0,
            "passed_samples": 0,
            "failed_samples": 0,
            "rows": [],
        }
    rows: List[Dict[str, Any]] = []
    passed_samples = 0
    for idx, s in enumerate(samples, start=1):
        if not isinstance(s, dict):
            continue
        measured = s.get("measured", {})
        design = s.get("design", {})
        expected_result = str(s.get("expected_result", "FAIL")).strip().upper()
        expected_gates = s.get("expected_gates", {})
        expected_proof = s.get("expected_proof", {})
        values: Dict[str, Any] = {}
        if isinstance(design, dict):
            values.update(design)
        if isinstance(measured, dict):
            values.update(measured)

        runtime = _evaluate_rulepack_with_input(payload, values)
        actual_result = str(runtime.get("result", "")).strip().upper()
        gate_rows = runtime.get("gate_results", []) if isinstance(runtime.get("gate_results"), list) else []
        gate_map = {
            str((g or {}).get("gate_id") or "").strip(): ("PASS" if bool((g or {}).get("passed", False)) else "FAIL")
            for g in gate_rows
            if isinstance(g, dict) and str((g or {}).get("gate_id") or "").strip()
        }
        proof_payload = {
            "form_code": form_code,
            "sample_index": idx,
            "inputs": values,
            "runtime": runtime,
        }
        proof_hash = _stable_json_hash(proof_payload)
        actual_proof = {
            "proof_hash": proof_hash,
            "result": actual_result,
            "gate_count": len(gate_rows),
        }

        expected_obj = {
            "result": expected_result,
            "gates": expected_gates if isinstance(expected_gates, dict) else {},
            "proof": expected_proof if isinstance(expected_proof, dict) else {},
        }
        actual_obj = {
            "result": actual_result,
            "gates": gate_map,
            "proof": actual_proof,
        }
        diff_obj = _compute_simple_diff(expected_obj, actual_obj)
        diff_correct = len(diff_obj.keys()) == 0

        gate_correct = True
        if isinstance(expected_gates, dict):
            for gid, exp in expected_gates.items():
                if str(gate_map.get(str(gid).strip(), "")).upper() != str(exp or "").strip().upper():
                    gate_correct = False
                    break
        proof_correct = True
        if isinstance(expected_proof, dict):
            if str(expected_proof.get("result", "")).strip().upper():
                proof_correct = proof_correct and (
                    str(expected_proof.get("result", "")).strip().upper() == actual_result
                )
            if str(expected_proof.get("proof_hash", "")).strip():
                proof_correct = proof_correct and (
                    str(expected_proof.get("proof_hash", "")).strip() == str(actual_proof.get("proof_hash", "")).strip()
                )

        row_passed = (actual_result == expected_result) and gate_correct and proof_correct and diff_correct
        if row_passed:
            passed_samples += 1
        rows.append(
            {
                "sample_index": idx,
                "name": str(s.get("name") or f"sample_{idx}"),
                "expected": expected_obj,
                "actual": actual_obj,
                "diff": diff_obj,
                "checks": {
                    "diff_correct": diff_correct,
                    "gate_correct": gate_correct,
                    "proof_correct": proof_correct,
                },
                "passed": row_passed,
            }
        )
    total = len(rows)
    return {
        "enabled": True,
        "form_code": form_code,
        "passed": total > 0 and passed_samples == total,
        "total_samples": total,
        "passed_samples": passed_samples,
        "failed_samples": int(total - passed_samples),
        "rows": rows,
    }


def _evaluate_rulepack_with_input(payload: Dict[str, Any], values: Dict[str, Any]) -> Dict[str, Any]:
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    evaluated: Dict[str, Dict[str, Any]] = {}
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        rid = str(rule.get("rule_id") or rule.get("ruleId") or rule.get("id") or "").strip()
        if not rid:
            continue
        evaluated[rid] = _evaluate_rule_with_input(rule, values if isinstance(values, dict) else {})
    gate_results: List[Dict[str, Any]] = []
    for gate in gates:
        if not isinstance(gate, dict):
            continue
        gid = str(gate.get("gate_id") or gate.get("id") or "").strip() or "<unknown_gate>"
        rule_ids = _gate_rule_ids(gate)
        rows = [evaluated.get(rid, {"passed": False}) for rid in rule_ids]
        passed = len(rows) > 0 and all(bool(x.get("passed", False)) for x in rows)
        gate_results.append({"gate_id": gid, "passed": passed, "rule_ids": rule_ids})
    overall_pass = len(gate_results) > 0 and all(bool(x.get("passed", False)) for x in gate_results)
    return {"result": "PASS" if overall_pass else "FAIL", "gate_results": gate_results}


def _build_runtime_smoke_mock_values(payload: Dict[str, Any]) -> Dict[str, Any]:
    values: Dict[str, Any] = {}
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    for row in rules:
        if not isinstance(row, dict):
            continue
        field = str(row.get("field") or "").strip()
        if not field:
            continue
        min_v = row.get("min")
        max_v = row.get("max")
        op = _normalize_rule_operator(row.get("operator"))
        if isinstance(min_v, (int, float)) and isinstance(max_v, (int, float)):
            values[field] = (float(min_v) + float(max_v)) / 2.0
        elif isinstance(min_v, (int, float)):
            values[field] = float(min_v) if op in {">=", ">", "="} else float(min_v) + 1.0
        elif isinstance(max_v, (int, float)):
            values[field] = float(max_v) if op in {"<=", "<", "="} else float(max_v) - 1.0
        else:
            values[field] = 1
    return values


def _run_runtime_smoke_test(payload: Dict[str, Any], *, form_code: str, rulepack_name: str) -> Dict[str, Any]:
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    missing_rule_refs: List[Dict[str, Any]] = []
    runtime_crash = False
    proof_fail = False
    result_obj: Dict[str, Any] = {}
    errors: List[str] = []

    rule_ids = {
        str(r.get("rule_id") or r.get("ruleId") or r.get("id") or "").strip()
        for r in rules
        if isinstance(r, dict)
    }
    rule_ids.discard("")
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip() or "<unknown_gate>"
        for rid in _gate_rule_ids(g):
            if rid and rid not in rule_ids:
                missing_rule_refs.append({"gate_id": gid, "rule_id": rid})

    missing_rule = len(missing_rule_refs) > 0
    missing_gate = len([x for x in gates if isinstance(x, dict)]) == 0
    mock_values = _build_runtime_smoke_mock_values(payload if isinstance(payload, dict) else {})
    t0 = time.perf_counter()
    try:
        runtime = _evaluate_rulepack_with_input(payload if isinstance(payload, dict) else {}, mock_values)
        result_obj = runtime if isinstance(runtime, dict) else {}
    except Exception as exc:
        runtime_crash = True
        errors.append(f"runtime_exception: {exc}")
        result_obj = {}
    duration_ms = int((time.perf_counter() - t0) * 1000.0)

    proof_payload = {
        "form_code": form_code,
        "rulepack": rulepack_name,
        "inputs": mock_values,
        "runtime": result_obj,
    }
    proof_hash = ""
    try:
        proof_hash = _stable_json_hash(proof_payload)
        if not proof_hash:
            proof_fail = True
    except Exception as exc:
        proof_fail = True
        errors.append(f"proof_exception: {exc}")

    checks = {
        "runtime_crash": runtime_crash,
        "missing_rule": missing_rule,
        "missing_gate": missing_gate,
        "proof_fail": proof_fail,
    }
    passed = not any(bool(v) for v in checks.values())
    return {
        "rulepack": rulepack_name,
        "form_code": form_code,
        "passed": passed,
        "checks": checks,
        "duration_ms": duration_ms,
        "mock_measured_data": mock_values,
        "runtime_result": result_obj,
        "proof": {"proof_hash": proof_hash, "payload": proof_payload},
        "missing_rule_refs": missing_rule_refs,
        "errors": errors,
    }


def _runtime_performance_governance_config() -> Dict[str, Any]:
    cfg = _load_system_config()
    raw = cfg.get("runtime_performance_governance", {}) if isinstance(cfg.get("runtime_performance_governance"), dict) else {}
    out = {
        "thresholds": {
            "rulepack_load_time_ms": int(raw.get("rulepack_load_time_ms", 200) or 200),
            "gate_execution_time_ms": int(raw.get("gate_execution_time_ms", 500) or 500),
            "proof_generation_time_ms": int(raw.get("proof_generation_time_ms", 200) or 200),
            "memory_usage_bytes": int(raw.get("memory_usage_bytes", 64 * 1024 * 1024) or (64 * 1024 * 1024)),
        },
        "large_rulepack_warning_bytes": int(raw.get("large_rulepack_warning_bytes", 2 * 1024 * 1024) or (2 * 1024 * 1024)),
        "runtime_timeout_ms": int(raw.get("runtime_timeout_ms", 800) or 800),
        "fallback_on_timeout": bool(raw.get("fallback_on_timeout", True)),
        "alert_enabled": bool(raw.get("alert_enabled", True)),
    }
    return out


def _build_runtime_fallback_result(payload: Dict[str, Any], reason: str) -> Dict[str, Any]:
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    rows: List[Dict[str, Any]] = []
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip() or "<unknown_gate>"
        rows.append({"gate_id": gid, "passed": False, "rule_ids": _gate_rule_ids(g), "fallback": True})
    return {"result": "FAIL", "gate_results": rows, "fallback": True, "fallback_reason": reason}


def _emit_runtime_perf_alert(job_id: str, row: Dict[str, Any]) -> None:
    record = {
        "timestamp": _utc_now(),
        "type": "runtime_performance_alert",
        "job_id": job_id,
        "rulepack": str(row.get("rulepack") or "").strip(),
        "alerts": row.get("alerts", []),
        "metrics": row.get("performance_metrics", {}),
        "checks": row.get("checks", {}),
    }
    ADMIN_NOTIFY_PATH.parent.mkdir(parents=True, exist_ok=True)
    with ADMIN_NOTIFY_PATH.open("a", encoding="utf-8") as f:
        f.write(json.dumps(record, ensure_ascii=False) + "\n")


def _run_runtime_smoke_for_job(job_id: str) -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    perf_cfg = _runtime_performance_governance_config()
    thresholds = perf_cfg.get("thresholds", {}) if isinstance(perf_cfg.get("thresholds"), dict) else {}
    large_rulepack_warning_bytes = int(perf_cfg.get("large_rulepack_warning_bytes", 2 * 1024 * 1024) or (2 * 1024 * 1024))
    runtime_timeout_ms = int(perf_cfg.get("runtime_timeout_ms", 800) or 800)
    fallback_on_timeout = bool(perf_cfg.get("fallback_on_timeout", True))
    alert_enabled = bool(perf_cfg.get("alert_enabled", True))
    for rp in _find_rulepacks_by_job(job_id):
        t_load_start = time.perf_counter()
        file_size_bytes = int(rp.stat().st_size or 0) if rp.exists() else 0
        try:
            payload = json.loads(rp.read_text(encoding="utf-8"))
        except Exception as exc:
            rows.append(
                {
                    "rulepack": rp.name,
                    "form_code": "",
                    "passed": False,
                    "checks": {
                        "runtime_crash": True,
                        "missing_rule": False,
                        "missing_gate": False,
                        "proof_fail": True,
                    },
                    "errors": [f"rulepack_json_invalid: {exc}"],
                }
            )
            continue
        rulepack_load_time_ms = int((time.perf_counter() - t_load_start) * 1000.0)
        form_code = str(((payload.get("meta") if isinstance(payload.get("meta"), dict) else {}) or {}).get("form_code") or "").strip()
        mock_values = _build_runtime_smoke_mock_values(payload if isinstance(payload, dict) else {})
        runtime_crash = False
        errors: List[str] = []
        tracemalloc_started = False
        gate_execution_time_ms = 0
        proof_generation_time_ms = 0
        peak_memory_bytes = 0
        runtime_result: Dict[str, Any] = {}
        proof_hash = ""
        missing_rule_refs: List[Dict[str, Any]] = []

        rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
        gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
        rule_ids = {
            str(r.get("rule_id") or r.get("ruleId") or r.get("id") or "").strip()
            for r in rules
            if isinstance(r, dict)
        }
        rule_ids.discard("")
        for g in gates:
            if not isinstance(g, dict):
                continue
            gid = str(g.get("gate_id") or g.get("id") or "").strip() or "<unknown_gate>"
            for rid in _gate_rule_ids(g):
                if rid and rid not in rule_ids:
                    missing_rule_refs.append({"gate_id": gid, "rule_id": rid})

        try:
            tracemalloc.start()
            tracemalloc_started = True
            t_gate = time.perf_counter()
            runtime_result = _evaluate_rulepack_with_input(payload if isinstance(payload, dict) else {}, mock_values)
            gate_execution_time_ms = int((time.perf_counter() - t_gate) * 1000.0)
            if gate_execution_time_ms > runtime_timeout_ms and fallback_on_timeout:
                runtime_result = _build_runtime_fallback_result(payload if isinstance(payload, dict) else {}, reason=f"runtime_timeout>{runtime_timeout_ms}ms")
        except Exception as exc:
            runtime_crash = True
            errors.append(f"runtime_exception: {exc}")
            runtime_result = _build_runtime_fallback_result(payload if isinstance(payload, dict) else {}, reason="runtime_crash")
        try:
            t_proof = time.perf_counter()
            proof_payload = {
                "form_code": form_code,
                "rulepack": rp.name,
                "inputs": mock_values,
                "runtime": runtime_result,
            }
            proof_hash = _stable_json_hash(proof_payload)
            proof_generation_time_ms = int((time.perf_counter() - t_proof) * 1000.0)
        except Exception as exc:
            errors.append(f"proof_exception: {exc}")
            proof_generation_time_ms = int((time.perf_counter() - t_proof) * 1000.0) if "t_proof" in locals() else 0
        finally:
            if tracemalloc_started:
                try:
                    _, peak = tracemalloc.get_traced_memory()
                    peak_memory_bytes = int(peak or 0)
                except Exception:
                    peak_memory_bytes = 0
                tracemalloc.stop()

        missing_rule = len(missing_rule_refs) > 0
        missing_gate = len([x for x in gates if isinstance(x, dict)]) == 0
        proof_fail = not bool(proof_hash)
        checks = {
            "runtime_crash": runtime_crash,
            "missing_rule": missing_rule,
            "missing_gate": missing_gate,
            "proof_fail": proof_fail,
        }
        alerts: List[str] = []
        if rulepack_load_time_ms > int(thresholds.get("rulepack_load_time_ms", 200) or 200):
            alerts.append(f"rulepack_load_time_exceeded:{rulepack_load_time_ms}ms")
        if gate_execution_time_ms > int(thresholds.get("gate_execution_time_ms", 500) or 500):
            alerts.append(f"gate_execution_time_exceeded:{gate_execution_time_ms}ms")
        if proof_generation_time_ms > int(thresholds.get("proof_generation_time_ms", 200) or 200):
            alerts.append(f"proof_generation_time_exceeded:{proof_generation_time_ms}ms")
        if peak_memory_bytes > int(thresholds.get("memory_usage_bytes", 64 * 1024 * 1024) or (64 * 1024 * 1024)):
            alerts.append(f"memory_usage_exceeded:{peak_memory_bytes}bytes")
        warnings: List[str] = []
        if file_size_bytes >= large_rulepack_warning_bytes:
            warnings.append(f"large_rulepack_warning:size={file_size_bytes}bytes,threshold={large_rulepack_warning_bytes}bytes")
        if gate_execution_time_ms > runtime_timeout_ms and fallback_on_timeout:
            warnings.append(f"runtime_timeout_fallback_applied:timeout={runtime_timeout_ms}ms")

        row = {
            "rulepack": rp.name,
            "form_code": form_code,
            "passed": (not any(bool(v) for v in checks.values())) and len(alerts) == 0,
            "checks": checks,
            "warnings": warnings,
            "alerts": alerts,
            "performance_metrics": {
                "rulepack_load_time_ms": rulepack_load_time_ms,
                "gate_execution_time_ms": gate_execution_time_ms,
                "proof_generation_time_ms": proof_generation_time_ms,
                "memory_usage_bytes": peak_memory_bytes,
                "rulepack_size_bytes": file_size_bytes,
                "runtime_timeout_ms": runtime_timeout_ms,
            },
            "mock_measured_data": mock_values,
            "runtime_result": runtime_result,
            "proof": {"proof_hash": proof_hash},
            "missing_rule_refs": missing_rule_refs,
            "errors": errors,
        }
        rows.append(row)
        if alert_enabled and len(alerts) > 0:
            _emit_runtime_perf_alert(job_id, row)
        _append_trace(
            "runtime_smoke_perf",
            job_id=job_id,
            form_code=form_code,
            duration_ms=float(rulepack_load_time_ms + gate_execution_time_ms + proof_generation_time_ms),
            ok=bool(row.get("passed", False)),
            extra={"rulepack": rp.name, "alerts": alerts, "warnings": warnings},
        )
    total = len(rows)
    passed_count = len([x for x in rows if bool(x.get("passed", False))])
    failed_count = total - passed_count
    report = {
        "schema_version": "runtime_smoke_report.v1",
        "job_id": job_id,
        "generated_at": _utc_now(),
        "runtime_performance_governance": {
            "thresholds": thresholds,
            "large_rulepack_warning_bytes": large_rulepack_warning_bytes,
            "runtime_timeout_ms": runtime_timeout_ms,
            "fallback_on_timeout": fallback_on_timeout,
        },
        "passed": total > 0 and failed_count == 0,
        "total_rulepacks": total,
        "passed_rulepacks": passed_count,
        "failed_rulepacks": failed_count,
        "rows": rows,
    }
    _write_artifact_json(job_id, "runtime_smoke_report.json", report)
    return report


def _threshold_compare_key(rule: Dict[str, Any]) -> str:
    if not isinstance(rule, dict):
        return ""
    threshold_struct, _ = _normalize_threshold_struct(rule)
    obj = {
        "operator": str(threshold_struct.get("operator") or "").strip(),
        "value": threshold_struct.get("value"),
        "min": threshold_struct.get("min"),
        "max": threshold_struct.get("max"),
        "unit": str(threshold_struct.get("unit") or "").strip(),
    }
    return _stable_json_hash(obj)


def _semantic_compare_key(rule: Dict[str, Any]) -> str:
    if not isinstance(rule, dict):
        return ""
    obj = {
        "field": str(rule.get("field") or "").strip(),
        "condition": str(rule.get("condition") or "").strip(),
        "source_text": str(rule.get("source_text") or "").strip(),
    }
    return _stable_json_hash(obj)


def _build_cross_norm_conflict_report(job_id: str) -> Dict[str, Any]:
    packs = _find_rulepacks_by_job(job_id)
    if not packs:
        report = {
            "schema_version": "cross_norm_conflict_report.v1",
            "job_id": job_id,
            "generated_at": _utc_now(),
            "status": "no_rulepack",
            "summary": {"total_conflicts": 0, "critical_count": 0},
            "conflicts": [],
        }
        _write_artifact_json(job_id, "conflict_report.json", report)
        return report

    target_doc = json.loads(packs[0].read_text(encoding="utf-8"))
    target_meta = target_doc.get("meta", {}) if isinstance(target_doc.get("meta"), dict) else {}
    target_form = str(target_meta.get("form_code") or "").strip()
    target_norm_id = str(target_meta.get("norm_id") or target_meta.get("spec_code") or "").strip()
    target_norm_ver = str(target_meta.get("norm_version") or target_meta.get("spec_version") or "").strip()

    candidates: List[Tuple[Path, Dict[str, Any]]] = []
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        fc = str(meta.get("form_code") or "").strip()
        nid = str(meta.get("norm_id") or meta.get("spec_code") or "").strip()
        nver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        if fc != target_form or nid != target_norm_id or not nver or nver == target_norm_ver:
            continue
        candidates.append((p.resolve(), doc))

    current_rules = [x for x in (target_doc.get("rules", []) if isinstance(target_doc.get("rules"), list) else []) if isinstance(x, dict)]
    current_gates = [x for x in (target_doc.get("gates", []) if isinstance(target_doc.get("gates"), list) else []) if isinstance(x, dict)]
    current_rule_by_field: Dict[str, Dict[str, Any]] = {}
    current_rule_by_clause: Dict[str, Dict[str, Any]] = {}
    for r in current_rules:
        field = str(r.get("field") or "").strip()
        clause = str(r.get("source_clause_id") or r.get("source_clause") or "").strip()
        if field and field not in current_rule_by_field:
            current_rule_by_field[field] = r
        if clause and clause not in current_rule_by_clause:
            current_rule_by_clause[clause] = r
    current_gate_operator_by_id = {
        str(g.get("gate_id") or g.get("id") or "").strip(): str(g.get("operator") or g.get("decision_logic") or "").strip()
        for g in current_gates
        if isinstance(g, dict) and str(g.get("gate_id") or g.get("id") or "").strip()
    }

    conflicts: List[Dict[str, Any]] = []
    for p, base_doc in candidates:
        base_meta = base_doc.get("meta", {}) if isinstance(base_doc.get("meta"), dict) else {}
        base_ver = str(base_meta.get("norm_version") or base_meta.get("spec_version") or "").strip()
        base_rules = [x for x in (base_doc.get("rules", []) if isinstance(base_doc.get("rules"), list) else []) if isinstance(x, dict)]
        base_gates = [x for x in (base_doc.get("gates", []) if isinstance(base_doc.get("gates"), list) else []) if isinstance(x, dict)]
        base_rule_by_field: Dict[str, Dict[str, Any]] = {}
        base_rule_by_clause: Dict[str, Dict[str, Any]] = {}
        for r in base_rules:
            field = str(r.get("field") or "").strip()
            clause = str(r.get("source_clause_id") or r.get("source_clause") or "").strip()
            if field and field not in base_rule_by_field:
                base_rule_by_field[field] = r
            if clause and clause not in base_rule_by_clause:
                base_rule_by_clause[clause] = r
        base_gate_operator_by_id = {
            str(g.get("gate_id") or g.get("id") or "").strip(): str(g.get("operator") or g.get("decision_logic") or "").strip()
            for g in base_gates
            if isinstance(g, dict) and str(g.get("gate_id") or g.get("id") or "").strip()
        }

        for field, cur_rule in current_rule_by_field.items():
            base_rule = base_rule_by_field.get(field)
            if not isinstance(base_rule, dict):
                continue
            if _threshold_compare_key(cur_rule) != _threshold_compare_key(base_rule):
                conflicts.append(
                    {
                        "type": "same_field_different_threshold",
                        "severity": "medium",
                        "field": field,
                        "source_clause": str(cur_rule.get("source_clause_id") or cur_rule.get("source_clause") or "").strip(),
                        "current_norm_version": target_norm_ver,
                        "base_norm_version": base_ver,
                        "current_threshold": cur_rule.get("threshold"),
                        "base_threshold": base_rule.get("threshold"),
                        "rulepack_base": p.name,
                    }
                )

        for gate_id, cur_op in current_gate_operator_by_id.items():
            base_op = base_gate_operator_by_id.get(gate_id)
            if base_op is None:
                continue
            if str(cur_op).strip().lower() != str(base_op).strip().lower():
                conflicts.append(
                    {
                        "type": "same_gate_different_operator",
                        "severity": "high",
                        "gate_id": gate_id,
                        "current_norm_version": target_norm_ver,
                        "base_norm_version": base_ver,
                        "current_operator": cur_op,
                        "base_operator": base_op,
                        "rulepack_base": p.name,
                    }
                )

        for clause, cur_rule in current_rule_by_clause.items():
            base_rule = base_rule_by_clause.get(clause)
            if not isinstance(base_rule, dict):
                continue
            if _semantic_compare_key(cur_rule) != _semantic_compare_key(base_rule):
                conflicts.append(
                    {
                        "type": "same_clause_different_semantic",
                        "severity": "critical",
                        "clause": clause,
                        "current_norm_version": target_norm_ver,
                        "base_norm_version": base_ver,
                        "current_semantic": {
                            "field": cur_rule.get("field"),
                            "condition": cur_rule.get("condition"),
                            "source_text": cur_rule.get("source_text"),
                        },
                        "base_semantic": {
                            "field": base_rule.get("field"),
                            "condition": base_rule.get("condition"),
                            "source_text": base_rule.get("source_text"),
                        },
                        "rulepack_base": p.name,
                    }
                )

    sev_counts: Dict[str, int] = {"low": 0, "medium": 0, "high": 0, "critical": 0}
    for row in conflicts:
        sev = str(row.get("severity") or "low").strip().lower()
        if sev not in sev_counts:
            sev = "low"
        sev_counts[sev] += 1
    report = {
        "schema_version": "cross_norm_conflict_report.v1",
        "job_id": job_id,
        "generated_at": _utc_now(),
        "current": {
            "form_code": target_form,
            "norm_id": target_norm_id,
            "norm_version": target_norm_ver,
            "rulepack": packs[0].name,
        },
        "summary": {
            "total_conflicts": len(conflicts),
            "severity_counts": sev_counts,
            "critical_count": int(sev_counts.get("critical", 0) or 0),
            "block_auto_publish": int(sev_counts.get("critical", 0) or 0) > 0,
        },
        "conflicts": conflicts,
    }
    _write_artifact_json(job_id, "conflict_report.json", report)
    return report


def _semantic_slot_token(raw: Any) -> str:
    text = str(raw or "").strip().lower()
    text = re.sub(r"[^a-z0-9]+", "_", text).strip("_")
    return text


def _run_semantic_consistency_engine(
    *,
    job_id: str,
    form_code: str,
    payload: Dict[str, Any],
) -> Dict[str, Any]:
    slots = payload.get("slots", []) if isinstance(payload.get("slots"), list) else []
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    semantic_tree = payload.get("semantic_tree", {}) if isinstance(payload.get("semantic_tree"), dict) else {}
    issues: List[Dict[str, Any]] = []

    # 1) slot 命名一致性
    slot_norm_map: Dict[str, set[str]] = {}
    for s in slots:
        if not isinstance(s, dict):
            continue
        slot_key = str(s.get("slotKey") or "").strip()
        slot = str(s.get("slot") or "").strip()
        if slot_key and slot and slot_key != slot:
            issues.append(
                {
                    "type": "slot_naming_inconsistency",
                    "severity": "medium",
                    "slotKey": slot_key,
                    "slot": slot,
                    "message": "slotKey 与 slot 命名不一致",
                }
            )
        for raw in [slot_key, slot]:
            token = _semantic_slot_token(raw)
            if token and raw:
                slot_norm_map.setdefault(token, set()).add(raw)
    for token, raws in slot_norm_map.items():
        if len(raws) > 1:
            issues.append(
                {
                    "type": "slot_naming_alias_collision",
                    "severity": "low",
                    "token": token,
                    "variants": sorted(list(raws)),
                    "message": "同一语义 slot 存在多种命名写法",
                }
            )

    # 2) unit 一致性（同 field）
    field_units: Dict[str, set[str]] = {}
    for r in rules:
        if not isinstance(r, dict):
            continue
        field = str(r.get("field") or "").strip()
        if not field:
            continue
        threshold_struct, _ = _normalize_threshold_struct(r)
        unit = str(threshold_struct.get("unit") or r.get("unit") or "").strip()
        if unit:
            field_units.setdefault(field, set()).add(unit)
    for field, units in field_units.items():
        if len(units) > 1:
            issues.append(
                {
                    "type": "unit_inconsistency",
                    "severity": "high",
                    "field": field,
                    "units": sorted(list(units)),
                    "message": "同一 field 存在多个单位",
                }
            )

    # 3) operator 一致性（同 field + gate）
    field_ops: Dict[str, set[str]] = {}
    for r in rules:
        if not isinstance(r, dict):
            continue
        field = str(r.get("field") or "").strip()
        if not field:
            continue
        op = _normalize_rule_operator(r.get("operator"))
        if op:
            field_ops.setdefault(field, set()).add(op)
    for field, ops in field_ops.items():
        if len(ops) > 1:
            issues.append(
                {
                    "type": "operator_inconsistency",
                    "severity": "medium",
                    "field": field,
                    "operators": sorted(list(ops)),
                    "message": "同一 field 存在多个 operator",
                }
            )
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip()
        op1 = str(g.get("operator") or "").strip().lower()
        op2 = str(g.get("decision_logic") or "").strip().lower()
        if gid and op1 and op2 and op1 != op2:
            issues.append(
                {
                    "type": "gate_operator_inconsistency",
                    "severity": "medium",
                    "gate_id": gid,
                    "operator": op1,
                    "decision_logic": op2,
                    "message": "gate operator 与 decision_logic 不一致",
                }
            )

    # 4) semantic tree 一致性
    st_ok, st_errs = _validate_semantic_tree_for_form(form_code, semantic_tree if isinstance(semantic_tree, dict) else {})
    if not st_ok:
        for err in st_errs[:50]:
            issues.append({"type": "semantic_tree_inconsistency", "severity": "high", "message": str(err)})
    field_nodes = semantic_tree.get("field_nodes", []) if isinstance(semantic_tree.get("field_nodes"), list) else []
    field_node_keys = {
        str(x.get("field_key") or x.get("field") or "").strip()
        for x in field_nodes
        if isinstance(x, dict) and str(x.get("field_key") or x.get("field") or "").strip()
    }
    gate_refs = _build_gate_ref_lookup_from_semantic_tree(semantic_tree if isinstance(semantic_tree, dict) else {})
    gate_id_set = {
        str(g.get("gate_id") or g.get("id") or "").strip()
        for g in gates
        if isinstance(g, dict) and str(g.get("gate_id") or g.get("id") or "").strip()
    }
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip()
        field = str(r.get("field") or "").strip()
        if field and field_node_keys and field not in field_node_keys:
            issues.append(
                {
                    "type": "semantic_tree_field_missing",
                    "severity": "high",
                    "rule_id": rid,
                    "field": field,
                    "message": "rule.field 在 semantic_tree.field_nodes 中不存在",
                }
            )
    for field_key, gate_ref in gate_refs.items():
        if gate_ref and gate_ref not in gate_id_set:
            issues.append(
                {
                    "type": "semantic_tree_gate_missing",
                    "severity": "high",
                    "field": field_key,
                    "gate_ref": gate_ref,
                    "message": "semantic_tree.gate_refs 指向不存在的 gate",
                }
            )

    severity_counts = {"low": 0, "medium": 0, "high": 0, "critical": 0}
    for row in issues:
        sev = str(row.get("severity") or "low").strip().lower()
        if sev not in severity_counts:
            sev = "low"
        severity_counts[sev] += 1
    passed = len(issues) == 0
    report = {
        "schema_version": "semantic_consistency_report.v1",
        "generated_at": _utc_now(),
        "job_id": job_id,
        "form_code": form_code,
        "passed": passed,
        "summary": {
            "total_issues": len(issues),
            "severity_counts": severity_counts,
            "slot_count": len([x for x in slots if isinstance(x, dict)]),
            "rule_count": len([x for x in rules if isinstance(x, dict)]),
            "gate_count": len([x for x in gates if isinstance(x, dict)]),
        },
        "checks": {
            "slot_naming_consistency": not any(str(x.get("type") or "").startswith("slot_") for x in issues),
            "unit_consistency": not any(str(x.get("type") or "") == "unit_inconsistency" for x in issues),
            "operator_consistency": not any("operator" in str(x.get("type") or "") for x in issues),
            "semantic_tree_consistency": not any(str(x.get("type") or "").startswith("semantic_tree") for x in issues),
        },
        "issues": issues,
    }
    _write_artifact_json(job_id, "semantic_consistency_report.json", report)
    return report


def _run_rulepack_e2e_validation(form_code: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    sample = _load_rulepack_e2e_sample(form_code)
    if not sample:
        return {"enabled": False, "form_code": form_code, "passed": True, "reason": "sample_not_configured"}
    pass_input = sample.get("pass_input", {})
    fail_input = sample.get("fail_input", {})
    expected_pass = str(sample.get("expected_pass", "PASS")).strip().upper() or "PASS"
    expected_fail = str(sample.get("expected_fail", "FAIL")).strip().upper() or "FAIL"
    pass_eval = _evaluate_rulepack_with_input(payload, pass_input if isinstance(pass_input, dict) else {})
    fail_eval = _evaluate_rulepack_with_input(payload, fail_input if isinstance(fail_input, dict) else {})
    actual_pass = str(pass_eval.get("result", "")).strip().upper()
    actual_fail = str(fail_eval.get("result", "")).strip().upper()
    passed = actual_pass == expected_pass and actual_fail == expected_fail
    return {
        "enabled": True,
        "form_code": form_code,
        "passed": passed,
        "expected": {"pass_case": expected_pass, "fail_case": expected_fail},
        "actual": {"pass_case": actual_pass, "fail_case": actual_fail},
        "pass_case": pass_eval,
        "fail_case": fail_eval,
    }


def _load_publish_guardrails() -> Dict[str, Any]:
    defaults: Dict[str, Any] = {
        "max_size_growth_ratio": 3.0,
        "max_size_growth_bytes": 1048576,
        "critical_gates": {},
    }
    obj = _load_env_config_json("publish_guardrails.json", fallback_path=PUBLISH_GUARDRAIL_PATH)
    if not isinstance(obj, dict):
        return defaults
    out = dict(defaults)
    if "max_size_growth_ratio" in obj:
        try:
            out["max_size_growth_ratio"] = float(obj["max_size_growth_ratio"])
        except Exception:
            pass
    if "max_size_growth_bytes" in obj:
        try:
            out["max_size_growth_bytes"] = int(obj["max_size_growth_bytes"])
        except Exception:
            pass
    if isinstance(obj.get("critical_gates"), dict):
        out["critical_gates"] = obj["critical_gates"]
    return out


def _compute_rulepack_quality_metrics(
    *,
    rules: List[Dict[str, Any]],
    gates: List[Dict[str, Any]],
    traceability: List[Dict[str, Any]],
    components: List[Dict[str, Any]],
) -> Dict[str, Any]:
    rules_count = len([r for r in rules if isinstance(r, dict)])
    gates_count = len([g for g in gates if isinstance(g, dict)])
    components_count = len([c for c in components if isinstance(c, dict)])
    trace_rows = [t for t in traceability if isinstance(t, dict)]

    rule_trace_ok = 0
    unresolved_count = 0
    for row in trace_rows:
        clause_ok = bool(str(row.get("source_clause_id") or "").strip() or str(row.get("source_clause") or "").strip())
        spec_ok = bool(str(row.get("source_spec_code") or "").strip() and str(row.get("source_spec_version") or "").strip())
        text_ok = bool(str(row.get("source_text") or "").strip())
        unresolved = bool(row.get("unresolved", False))
        if unresolved:
            unresolved_count += 1
        if clause_ok and spec_ok and text_ok and not unresolved:
            rule_trace_ok += 1

    rule_correctness_rate = (rule_trace_ok / rules_count) if rules_count > 0 else 0.0
    traceability_rate = (len(trace_rows) / rules_count) if rules_count > 0 else 0.0

    known_rule_ids = {
        str(r.get("rule_id") or r.get("ruleId") or "").strip()
        for r in rules
        if isinstance(r, dict) and str(r.get("rule_id") or r.get("ruleId") or "").strip()
    }
    executable_gates = 0
    for gate in gates:
        if not isinstance(gate, dict):
            continue
        gate_rules = _gate_rule_ids(gate)
        gate_refs = gate.get("norm_refs", [])
        rule_ok = bool(gate_rules) and all((rid in known_rule_ids) for rid in gate_rules)
        ref_ok = isinstance(gate_refs, list) and len([x for x in gate_refs if str(x).strip()]) > 0
        if rule_ok and ref_ok:
            executable_gates += 1
    gate_executability_rate = (executable_gates / gates_count) if gates_count > 0 else 0.0

    return {
        "rules_count": rules_count,
        "gates_count": gates_count,
        "components_count": components_count,
        "traceability_count": len(trace_rows),
        "unresolved_rule_count": unresolved_count,
        "rule_correctness_rate": rule_correctness_rate,
        "gate_executability_rate": gate_executability_rate,
        "traceability_rate": traceability_rate,
    }


def _record_publish_metric(event: Dict[str, Any]) -> None:
    NORMREF_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    rows: List[Dict[str, Any]] = []
    if NORMREF_PUBLISH_METRICS_PATH.exists():
        try:
            doc = json.loads(NORMREF_PUBLISH_METRICS_PATH.read_text(encoding="utf-8"))
            if isinstance(doc, dict) and isinstance(doc.get("events"), list):
                rows = [x for x in doc["events"] if isinstance(x, dict)]
        except Exception:
            rows = []
    rows.append(event)
    payload = {"events": rows[-5000:]}
    NORMREF_PUBLISH_METRICS_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _load_rulepack_release_registry() -> Dict[str, Any]:
    if not RULEPACK_RELEASE_REGISTRY_PATH.exists():
        return {"forms": {}}
    try:
        doc = json.loads(RULEPACK_RELEASE_REGISTRY_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {"forms": {}}
    if not isinstance(doc, dict):
        return {"forms": {}}
    forms = doc.get("forms", {})
    if not isinstance(forms, dict):
        forms = {}
    return {"forms": forms}


def _save_rulepack_release_registry(doc: Dict[str, Any]) -> None:
    NORMREF_UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    forms = doc.get("forms", {}) if isinstance(doc, dict) else {}
    payload = {"forms": forms if isinstance(forms, dict) else {}}
    RULEPACK_RELEASE_REGISTRY_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _load_norm_version_registry() -> Dict[str, Any]:
    if not NORM_VERSION_REGISTRY_PATH.exists():
        return {"norms": {}}
    try:
        doc = json.loads(NORM_VERSION_REGISTRY_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {"norms": {}}
    if not isinstance(doc, dict):
        return {"norms": {}}
    norms = doc.get("norms", {})
    if not isinstance(norms, dict):
        norms = {}
    return {"norms": norms}


def _save_norm_version_registry(doc: Dict[str, Any]) -> None:
    norms = doc.get("norms", {}) if isinstance(doc, dict) else {}
    if not isinstance(norms, dict):
        norms = {}
    NORM_VERSION_REGISTRY_PATH.parent.mkdir(parents=True, exist_ok=True)
    NORM_VERSION_REGISTRY_PATH.write_text(json.dumps({"norms": norms}, ensure_ascii=False, indent=2), encoding="utf-8")


def _scan_rulepack_norm_version_index() -> Dict[str, Dict[str, Dict[str, Any]]]:
    # index[norm_id][norm_version] -> aggregate info from rulepacks
    index: Dict[str, Dict[str, Dict[str, Any]]] = {}
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        norm_id = str(meta.get("spec_code") or meta.get("norm_id") or "").strip()
        norm_ver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        form_code = str(meta.get("form_code") or "").strip()
        if not norm_id or not norm_ver:
            continue
        by_ver = index.setdefault(norm_id, {})
        row = by_ver.setdefault(
            norm_ver,
            {
                "norm_id": norm_id,
                "version": norm_ver,
                "rulepack_count": 0,
                "form_codes": [],
                "rulepacks": [],
                "latest_updated_at": "",
            },
        )
        row["rulepack_count"] = int(row.get("rulepack_count", 0) or 0) + 1
        fcs = row.get("form_codes", []) if isinstance(row.get("form_codes"), list) else []
        if form_code and form_code not in fcs:
            fcs.append(form_code)
        row["form_codes"] = sorted([str(x).strip() for x in fcs if str(x).strip()])
        packs = row.get("rulepacks", []) if isinstance(row.get("rulepacks"), list) else []
        packs.append(p.name)
        row["rulepacks"] = sorted([str(x).strip() for x in packs if str(x).strip()])
        updated = str(meta.get("updated_at") or meta.get("created_at") or "").strip()
        if updated and updated > str(row.get("latest_updated_at") or ""):
            row["latest_updated_at"] = updated
    return index


def _reconcile_norm_version_registry(
    *,
    operator: str,
    dry_run: bool = True,
    prune_missing: bool = False,
    norm_id: str = "",
) -> Dict[str, Any]:
    nid_filter = str(norm_id or "").strip()
    reg = _load_norm_version_registry()
    norms = reg.get("norms", {}) if isinstance(reg.get("norms"), dict) else {}
    index = _scan_rulepack_norm_version_index()

    changed_norm_ids: List[str] = []
    added_rows: List[Dict[str, Any]] = []
    marked_missing_rows: List[Dict[str, Any]] = []
    pruned_rows: List[Dict[str, Any]] = []
    touched_norms: Dict[str, List[Dict[str, Any]]] = {}

    target_norm_ids = sorted(set(list(norms.keys()) + list(index.keys())))
    for nid in target_norm_ids:
        if nid_filter and nid != nid_filter:
            continue
        existing_rows = norms.get(nid, []) if isinstance(norms.get(nid), list) else []
        existing_map: Dict[str, Dict[str, Any]] = {}
        for row in existing_rows:
            if not isinstance(row, dict):
                continue
            ver = str(row.get("version") or "").strip()
            if ver and ver not in existing_map:
                existing_map[ver] = dict(row)
        idx_rows = index.get(nid, {}) if isinstance(index.get(nid), dict) else {}

        # mark or prune versions registered but no supporting rulepacks
        for ver, row in list(existing_map.items()):
            if ver in idx_rows:
                if str(row.get("status") or "").strip() == "missing_rulepack":
                    row["status"] = "active"
                    row["updated_at"] = _utc_now()
                    row["updated_by"] = operator
                    existing_map[ver] = row
                    changed_norm_ids.append(nid)
                continue
            if prune_missing:
                pruned_rows.append({"norm_id": nid, "version": ver})
                existing_map.pop(ver, None)
                changed_norm_ids.append(nid)
                continue
            if str(row.get("status") or "").strip() != "missing_rulepack":
                row["status"] = "missing_rulepack"
                row["updated_at"] = _utc_now()
                row["updated_by"] = operator
                existing_map[ver] = row
                marked_missing_rows.append({"norm_id": nid, "version": ver})
                changed_norm_ids.append(nid)

        # auto-add versions discovered from rulepacks but absent in registry
        for ver, idx_row in idx_rows.items():
            if ver in existing_map:
                continue
            auto_row = {
                "norm_id": nid,
                "norm_name": nid,
                "version": ver,
                "effective_date": "",
                "source_hash": "",
                "source_file_hash": "",
                "parent_version": "",
                "status": "active",
                "created_by": operator,
                "approved_by": "",
                "auto_discovered": True,
                "rulepack_count": int(idx_row.get("rulepack_count", 0) or 0),
                "form_codes": idx_row.get("form_codes", []),
                "rulepacks": idx_row.get("rulepacks", []),
                "latest_rulepack_updated_at": str(idx_row.get("latest_updated_at") or ""),
                "created_at": _utc_now(),
                "updated_at": _utc_now(),
            }
            existing_map[ver] = auto_row
            added_rows.append({"norm_id": nid, "version": ver, "rulepack_count": auto_row["rulepack_count"]})
            changed_norm_ids.append(nid)

        ordered = sorted(
            existing_map.values(),
            key=lambda x: (str(x.get("effective_date") or ""), str(x.get("version") or "")),
            reverse=True,
        )
        if ordered:
            touched_norms[nid] = ordered

    if changed_norm_ids and (not dry_run):
        for nid, rows in touched_norms.items():
            norms[nid] = rows
        reg["norms"] = norms
        _save_norm_version_registry(reg)

    report = {
        "schema_version": "norm_version_registry_consistency_report.v1",
        "generated_at": _utc_now(),
        "operator": operator,
        "dry_run": bool(dry_run),
        "prune_missing": bool(prune_missing),
        "norm_id_filter": nid_filter,
        "summary": {
            "changed_norm_count": len(sorted(set(changed_norm_ids))),
            "added_row_count": len(added_rows),
            "marked_missing_count": len(marked_missing_rows),
            "pruned_row_count": len(pruned_rows),
        },
        "added_rows": added_rows,
        "marked_missing_rows": marked_missing_rows,
        "pruned_rows": pruned_rows,
    }
    NORMREF_REPORT_DIR.mkdir(parents=True, exist_ok=True)
    report_path = NORMREF_REPORT_DIR / "norm_version_registry_consistency_report.json"
    report_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    report["report_path"] = str(report_path.resolve())
    return report


