def _build_specir_snapshot_doc(form_code: str, version: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    trace = payload.get("traceability", []) if isinstance(payload.get("traceability"), list) else []
    specir_ids = sorted(
        list(
            {
                str(t.get("specir_id") or t.get("source_specir_id") or "").strip()
                for t in trace
                if isinstance(t, dict) and str(t.get("specir_id") or t.get("source_specir_id") or "").strip()
            }
        )
    )
    return {
        "schema_version": "specir_snapshot.v1",
        "generated_at": _utc_now(),
        "form_code": form_code,
        "version": version,
        "specir_count": len(specir_ids),
        "specir_ids": specir_ids,
        "traceability_count": len([x for x in trace if isinstance(x, dict)]),
        "semantic_tree": payload.get("semantic_tree", {}) if isinstance(payload.get("semantic_tree"), dict) else {},
        "canonical_hash": _stable_json_hash({"specir_ids": specir_ids, "traceability": trace}),
    }


def _write_runtime_cache_refresh(affected_forms: List[str], operator: str, reason: str) -> str:
    path = NORMREF_UPLOAD_DIR / "runtime_cache_state.json"
    row = {
        "refreshed_at": _utc_now(),
        "operator": str(operator or "").strip(),
        "reason": str(reason or "").strip(),
        "affected_forms": [str(x).strip() for x in affected_forms if str(x).strip()],
    }
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(row, ensure_ascii=False, indent=2), encoding="utf-8")
    return str(path.resolve())


def _resolve_forms_for_project(project_id: str, release_forms: Dict[str, Any]) -> List[str]:
    pid = str(project_id or "").strip()
    if not pid:
        return []
    cfg = _load_system_config()
    mapping = cfg.get("project_form_mapping", {}) if isinstance(cfg.get("project_form_mapping"), dict) else {}
    rows = mapping.get(pid, []) if isinstance(mapping.get(pid, []), list) else []
    forms = [str(x).strip() for x in rows if str(x).strip()]
    if forms:
        return sorted(list(set(forms)))
    # fallback: prefix match; if no match, treat project rollback as workspace rollback
    pref = [k for k in release_forms.keys() if str(k).strip().startswith(pid)]
    if pref:
        return sorted(list(set([str(x).strip() for x in pref if str(x).strip()])))
    return sorted(list(set([str(k).strip() for k in release_forms.keys() if str(k).strip()])))


def _validate_rollback_forms(affected_forms: List[str]) -> Dict[str, Any]:
    details: List[Dict[str, Any]] = []
    blockers: List[str] = []
    for fc in [str(x).strip() for x in affected_forms if str(x).strip()]:
        row: Dict[str, Any] = {"form_code": fc, "checks": {}, "ok": True}
        try:
            resolved = _resolve_runtime_rulepack_version(fc, subject="rollback_validation")
            selected = str(resolved.get("selected_version") or "").strip()
            row["selected_version"] = selected
            row["checks"]["runtime_load_ok"] = True
            rp_path = _ensure_rulepack_exists(selected)
            rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
            if not isinstance(rp_doc, dict):
                raise ValueError("rulepack_not_object")
            rules = rp_doc.get("rules", []) if isinstance(rp_doc.get("rules"), list) else []
            gates = rp_doc.get("gates", []) if isinstance(rp_doc.get("gates"), list) else []
            row["checks"]["rule_count_ok"] = len(rules) > 0
            row["checks"]["gate_count_ok"] = len(gates) > 0
            golden = rp_doc.get("golden_compare", {}) if isinstance(rp_doc.get("golden_compare"), dict) else {}
            row["checks"]["golden_set_pass"] = bool(golden.get("passed", True)) if golden else True
            gate_reg = rp_doc.get("gate_regression", {}) if isinstance(rp_doc.get("gate_regression"), dict) else {}
            runtime_reg = rp_doc.get("runtime_regression", {}) if isinstance(rp_doc.get("runtime_regression"), dict) else {}
            row["checks"]["regression_pass"] = bool(gate_reg.get("passed", False)) and bool(runtime_reg.get("passed", False))
            row["ok"] = bool(
                row["checks"]["runtime_load_ok"]
                and row["checks"]["rule_count_ok"]
                and row["checks"]["gate_count_ok"]
                and row["checks"]["golden_set_pass"]
                and row["checks"]["regression_pass"]
            )
            if not row["ok"]:
                blockers.append(f"{fc}: rollback validation failed")
        except Exception as exc:
            row["checks"]["runtime_load_ok"] = False
            row["ok"] = False
            row["error"] = str(exc)
            blockers.append(f"{fc}: runtime load failed ({exc})")
        details.append(row)
    return {"ok": len(blockers) == 0, "details": details, "blockers": blockers}


def _generate_rulepack_snapshot(form_code: str, version: str) -> Dict[str, Any]:
    p = _rulepack_name_to_path(version)
    try:
        doc = json.loads(p.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"rulepack 读取失败：{version}") from exc
    if not isinstance(doc, dict):
        raise HTTPException(status_code=400, detail=f"rulepack 顶层结构非法：{version}")
    snap = _build_rulepack_snapshot_doc(name=version, payload=doc)
    out = _snapshot_file_path(form_code, version)
    out.write_text(json.dumps(snap, ensure_ascii=False, indent=2), encoding="utf-8")
    return {"snapshot_path": str(out.resolve()), "snapshot": snap}


def _diff_snapshot_maps(cur: Dict[str, str], base: Dict[str, str]) -> Dict[str, List[str]]:
    added = sorted([k for k in cur.keys() if k not in base])
    removed = sorted([k for k in base.keys() if k not in cur])
    changed = sorted([k for k in cur.keys() if k in base and cur[k] != base[k]])
    return {"added": added, "removed": removed, "changed": changed}


def _compare_rulepack_snapshots(cur: Dict[str, Any], base: Dict[str, Any]) -> Dict[str, Any]:
    c = cur.get("canonical", {}) if isinstance(cur.get("canonical"), dict) else {}
    b = base.get("canonical", {}) if isinstance(base.get("canonical"), dict) else {}
    rules_diff = _diff_snapshot_maps(
        c.get("rules", {}) if isinstance(c.get("rules"), dict) else {},
        b.get("rules", {}) if isinstance(b.get("rules"), dict) else {},
    )
    gates_diff = _diff_snapshot_maps(
        c.get("gates", {}) if isinstance(c.get("gates"), dict) else {},
        b.get("gates", {}) if isinstance(b.get("gates"), dict) else {},
    )
    comps_diff = _diff_snapshot_maps(
        c.get("components", {}) if isinstance(c.get("components"), dict) else {},
        b.get("components", {}) if isinstance(b.get("components"), dict) else {},
    )
    has_diff = any(
        len(x.get(y, [])) > 0
        for x in [rules_diff, gates_diff, comps_diff]
        for y in ["added", "removed", "changed"]
    )
    return {
        "has_diff": has_diff,
        "rules": rules_diff,
        "gates": gates_diff,
        "components": comps_diff,
    }


def _build_rulepack_regression_snapshot(*, payload: Dict[str, Any]) -> Dict[str, Any]:
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    comps = payload.get("components", []) if isinstance(payload.get("components"), list) else []
    unresolved = payload.get("unresolved", {}) if isinstance(payload.get("unresolved"), dict) else {}

    rule_ids = sorted(
        {
            str((r or {}).get("rule_id") or (r or {}).get("id") or "").strip()
            for r in rules
            if isinstance(r, dict) and str((r or {}).get("rule_id") or (r or {}).get("id") or "").strip()
        }
    )
    gate_ids = sorted(
        {
            str((g or {}).get("gate_id") or (g or {}).get("id") or "").strip()
            for g in gates
            if isinstance(g, dict) and str((g or {}).get("gate_id") or (g or {}).get("id") or "").strip()
        }
    )
    component_ids = sorted(
        {
            str((c or {}).get("component_id") or (c or {}).get("id") or "").strip()
            for c in comps
            if isinstance(c, dict) and str((c or {}).get("component_id") or (c or {}).get("id") or "").strip()
        }
    )

    return {
        "timestamp": _utc_now(),
        "rule_count": len(rules),
        "gate_count": len(gates),
        "component_count": len(comps),
        "unresolved_count": int(unresolved.get("count", 0) or 0),
        "rule_ids": rule_ids,
        "gate_ids": gate_ids,
        "component_ids": component_ids,
        "rule_map": _snapshot_asset_map([x for x in rules if isinstance(x, dict)], ["rule_id", "ruleId", "id"]),
        "gate_map": _snapshot_asset_map([x for x in gates if isinstance(x, dict)], ["gate_id", "id"]),
        "component_map": _snapshot_asset_map([x for x in comps if isinstance(x, dict)], ["component_id", "id"]),
    }


def _snapshot_regression_diff(cur: Dict[str, Any], prev: Dict[str, Any]) -> Dict[str, Any]:
    def _mk(cur_map: Dict[str, str], prev_map: Dict[str, str]) -> Dict[str, List[str]]:
        cur_keys = set(cur_map.keys())
        prev_keys = set(prev_map.keys())
        added = sorted(cur_keys - prev_keys)
        removed = sorted(prev_keys - cur_keys)
        modified = sorted([k for k in (cur_keys & prev_keys) if cur_map.get(k) != prev_map.get(k)])
        return {"added": added, "removed": removed, "modified": modified}

    rules = _mk(
        cur.get("rule_map", {}) if isinstance(cur.get("rule_map"), dict) else {},
        prev.get("rule_map", {}) if isinstance(prev.get("rule_map"), dict) else {},
    )
    gates = _mk(
        cur.get("gate_map", {}) if isinstance(cur.get("gate_map"), dict) else {},
        prev.get("gate_map", {}) if isinstance(prev.get("gate_map"), dict) else {},
    )
    components = _mk(
        cur.get("component_map", {}) if isinstance(cur.get("component_map"), dict) else {},
        prev.get("component_map", {}) if isinstance(prev.get("component_map"), dict) else {},
    )
    has_diff = any(
        [
            bool(rules["added"] or rules["removed"] or rules["modified"]),
            bool(gates["added"] or gates["removed"] or gates["modified"]),
            bool(components["added"] or components["removed"] or components["modified"]),
            int(cur.get("unresolved_count", 0) or 0) != int(prev.get("unresolved_count", 0) or 0),
            int(cur.get("rule_count", 0) or 0) != int(prev.get("rule_count", 0) or 0),
            int(cur.get("gate_count", 0) or 0) != int(prev.get("gate_count", 0) or 0),
            int(cur.get("component_count", 0) or 0) != int(prev.get("component_count", 0) or 0),
        ]
    )
    return {
        "has_diff": has_diff,
        "rules": rules,
        "gates": gates,
        "components": components,
        "counts": {
            "current": {
                "rule_count": int(cur.get("rule_count", 0) or 0),
                "gate_count": int(cur.get("gate_count", 0) or 0),
                "component_count": int(cur.get("component_count", 0) or 0),
                "unresolved_count": int(cur.get("unresolved_count", 0) or 0),
            },
            "previous": {
                "rule_count": int(prev.get("rule_count", 0) or 0),
                "gate_count": int(prev.get("gate_count", 0) or 0),
                "component_count": int(prev.get("component_count", 0) or 0),
                "unresolved_count": int(prev.get("unresolved_count", 0) or 0),
            },
        },
    }


def _is_snapshot_diff_approved(form_code: str, version: str, candidate_hash: str) -> bool:
    rows = _load_rulepack_snapshot_approvals().get("approvals", {})
    if not isinstance(rows, dict):
        return False
    key = f"{form_code}::{version}"
    row = rows.get(key, {}) if isinstance(rows.get(key, {}), dict) else {}
    return bool(
        row.get("approved") is True
        and str(row.get("candidate_hash") or "").strip() == str(candidate_hash or "").strip()
    )


def _ensure_rulepack_exists(version: str) -> Path:
    name = str(version or "").strip()
    if not name:
        raise HTTPException(status_code=400, detail="version 不能为空")
    target = (NORMREF_RULEPACK_DIR / name).resolve()
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=404, detail=f"未找到 rulepack 版本：{name}")
    return target


def _hash_percent(seed: str) -> float:
    h = hashlib.sha256(seed.encode("utf-8")).hexdigest()
    n = int(h[:8], 16)
    return (n % 10000) / 10000.0


def _resolve_runtime_rulepack_version(form_code: str, subject: str = "") -> Dict[str, Any]:
    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
    row = forms.get(str(form_code).strip(), {}) if isinstance(forms, dict) else {}
    if not isinstance(row, dict) or not row:
        raise HTTPException(status_code=404, detail=f"未配置 form_code={form_code} 的发布版本")
    active = str(row.get("active_version") or "").strip()
    stable = str(row.get("stable_version") or "").strip()
    canary = str(row.get("canary_version") or "").strip()
    ratio = float(row.get("gray_ratio", 0.0) or 0.0)
    chosen = active or stable
    route = "active"
    if canary and ratio > 0:
        seed = f"{form_code}:{subject or 'anonymous'}"
        pct = _hash_percent(seed)
        if pct < ratio:
            chosen = canary
            route = "canary"
        else:
            chosen = stable or active
            route = "stable"
    if not chosen:
        raise HTTPException(status_code=400, detail=f"form_code={form_code} 缺少可用版本")
    _ensure_rulepack_exists(chosen)
    return {
        "form_code": form_code,
        "selected_version": chosen,
        "route": route,
        "gray_ratio": ratio,
        "stable_version": stable,
        "canary_version": canary,
        "active_version": active,
    }


def _compute_publish_slo_4w() -> Dict[str, Any]:
    rows: List[Dict[str, Any]] = []
    if NORMREF_PUBLISH_METRICS_PATH.exists():
        try:
            doc = json.loads(NORMREF_PUBLISH_METRICS_PATH.read_text(encoding="utf-8"))
            if isinstance(doc, dict) and isinstance(doc.get("events"), list):
                rows = [x for x in doc["events"] if isinstance(x, dict)]
        except Exception:
            rows = []
    now = datetime.utcnow()
    window_start = now.timestamp() - 28 * 24 * 3600
    scoped: List[Dict[str, Any]] = []
    for item in rows:
        ts = str(item.get("timestamp") or "").strip()
        try:
            dt = datetime.fromisoformat(ts.replace("Z", "+00:00"))
            if dt.timestamp() >= window_start:
                scoped.append(item)
        except Exception:
            continue
    total = len(scoped)
    success = len([x for x in scoped if str(x.get("status") or "").strip() == "success"])
    rate = (success / total) if total > 0 else 1.0
    return {
        "window_days": 28,
        "total_publish_attempts": total,
        "successful_publishes": success,
        "success_rate": rate,
        "target_rate": 0.99,
        "passed": rate >= 0.99,
    }


def _parse_utc_ts(ts: str) -> Optional[datetime]:
    text = str(ts or "").strip()
    if not text:
        return None


def _classify_sla_priority(reason: str) -> Tuple[str, int, str]:
    txt = str(reason or "").strip().lower()
    if ("关键字段误判" in reason) or ("misjudge" in txt) or ("发布失败" in reason) or ("发布门禁失败" in reason) or ("gateref" in txt and ("缺失" in reason or "missing" in txt)):
        return "P1", 24, "P1_REDLINE"
    if ("覆盖率下降" in reason) or ("coverage_drop" in txt) or ("unresolved" in txt):
        return "P2", 72, "P2_QUALITY"
    # default to P2 for unknown non-critical reasons
    return "P2", 72, "P2_OTHER"


def _compute_sla_status(occurred_at: datetime, sla_hours: int) -> Dict[str, Any]:
    due = occurred_at.timestamp() + int(sla_hours) * 3600
    now_ts = datetime.utcnow().timestamp()
    overdue = now_ts > due
    return {
        "occurred_at": datetime.utcfromtimestamp(occurred_at.timestamp()).isoformat() + "Z",
        "due_at": datetime.utcfromtimestamp(due).isoformat() + "Z",
        "sla_hours": int(sla_hours),
        "status": "overdue" if overdue else "on_track",
        "remaining_hours": max(0.0, (due - now_ts) / 3600.0),
    }


def _collect_sla_issues(*, form_code: str, date_from: date, date_to: date, trends: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    fc = str(form_code or "").strip()
    issues: List[Dict[str, Any]] = []
    day_set = set(_iter_days(date_from, date_to))

    # 1) from quality gate result blockers/alerts
    for p in NORMREF_ARTIFACTS_DIR.glob("*/quality_gate_result.json"):
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        mtime = datetime.utcfromtimestamp(p.stat().st_mtime)
        day = mtime.date().isoformat()
        if day not in day_set:
            continue
        checked = doc.get("checked", []) if isinstance(doc.get("checked"), list) else []
        forms = {
            str((x or {}).get("form_code") or "").strip()
            for x in checked
            if isinstance(x, dict) and str((x or {}).get("form_code") or "").strip()
        }
        if fc and forms and fc not in forms:
            continue
        for src, rows in [("blocker", doc.get("blockers", [])), ("alert", doc.get("alerts", []))]:
            if not isinstance(rows, list):
                continue
            for r in rows:
                reason = str(r or "").strip()
                if not reason:
                    continue
                pcode, sla_h, category = _classify_sla_priority(reason)
                if pcode == "P2" and "unresolved_count" in reason:
                    # unresolved_count can include key/non-key; keep as P2 per requested SLA bucket.
                    category = "P2_UNRESOLVED"
                if pcode == "P1" and "gateref" in reason.lower():
                    category = "P1_GATEREF_MISSING"
                if pcode == "P1" and ("发布失败" in reason or "发布门禁失败" in reason):
                    category = "P1_PUBLISH_FAIL"
                if pcode == "P1" and ("关键字段误判" in reason):
                    category = "P1_KEYFIELD_MISJUDGE"
                sla = _compute_sla_status(mtime, sla_h)
                issues.append(
                    {
                        "priority": pcode,
                        "category": category,
                        "reason": reason,
                        "form_code": next(iter(forms), fc),
                        "source": f"quality_gate_{src}",
                        **sla,
                    }
                )

    # 2) from coverage decline (P2)
    sorted_tr = sorted([x for x in trends if isinstance(x, dict)], key=lambda x: str(x.get("date") or ""))
    for i in range(1, len(sorted_tr)):
        prev = sorted_tr[i - 1]
        cur = sorted_tr[i]
        if float(cur.get("rule_coverage", 0.0) or 0.0) < float(prev.get("rule_coverage", 0.0) or 0.0):
            dt = datetime.fromisoformat(str(cur.get("date")) + "T00:00:00")
            sla = _compute_sla_status(dt, 72)
            issues.append(
                {
                    "priority": "P2",
                    "category": "P2_COVERAGE_DROP",
                    "reason": f"coverage_drop: rule_coverage {prev.get('rule_coverage')} -> {cur.get('rule_coverage')}",
                    "form_code": fc,
                    "source": "dashboard_trend",
                    **sla,
                }
            )
        if float(cur.get("gate_coverage", 0.0) or 0.0) < float(prev.get("gate_coverage", 0.0) or 0.0):
            dt = datetime.fromisoformat(str(cur.get("date")) + "T00:00:00")
            sla = _compute_sla_status(dt, 72)
            issues.append(
                {
                    "priority": "P2",
                    "category": "P2_COVERAGE_DROP",
                    "reason": f"coverage_drop: gate_coverage {prev.get('gate_coverage')} -> {cur.get('gate_coverage')}",
                    "form_code": fc,
                    "source": "dashboard_trend",
                    **sla,
                }
            )

    # deduplicate by priority+reason+occurred day
    seen: set[str] = set()
    out: List[Dict[str, Any]] = []
    for it in issues:
        key = f"{it.get('priority')}|{it.get('reason')}|{str(it.get('occurred_at') or '')[:10]}|{it.get('form_code')}"
        if key in seen:
            continue
        seen.add(key)
        out.append(it)
    out.sort(key=lambda x: (0 if str(x.get("priority")) == "P1" else 1, str(x.get("due_at") or "")))
    return out
    try:
        return datetime.fromisoformat(text.replace("Z", "+00:00"))
    except Exception:
        return None


def _iter_days(date_from: date, date_to: date) -> List[str]:
    out: List[str] = []
    cur = date_from
    while cur <= date_to:
        out.append(cur.isoformat())
        cur = cur.fromordinal(cur.toordinal() + 1)
    return out


def _bucket_key_by_granularity(day_iso: str, granularity: str) -> str:
    g = str(granularity or "day").strip().lower()
    try:
        d = date.fromisoformat(day_iso)
    except Exception:
        return day_iso
    if g == "month":
        return f"{d.year:04d}-{d.month:02d}"
    if g == "week":
        y, w, _ = d.isocalendar()
        return f"{y:04d}-W{int(w):02d}"
    return d.isoformat()


def _collect_quality_trend_analytics(
    *,
    form_code: str = "",
    norm_version: str = "",
    compare_norm_version: str = "",
    date_from: str = "",
    date_to: str = "",
    granularity: str = "day",
) -> Dict[str, Any]:
    fc = str(form_code or "").strip()
    nv = str(norm_version or "").strip()
    nv_cmp = str(compare_norm_version or "").strip()
    g = str(granularity or "day").strip().lower()
    if g not in {"day", "week", "month"}:
        g = "day"
    d_to = date.today()
    d_from = d_to.fromordinal(max(1, d_to.toordinal() - 29))
    if str(date_from or "").strip():
        try:
            d_from = date.fromisoformat(str(date_from).strip())
        except Exception:
            pass
    if str(date_to or "").strip():
        try:
            d_to = date.fromisoformat(str(date_to).strip())
        except Exception:
            pass
    if d_from > d_to:
        d_from, d_to = d_to, d_from
    day_set = set(_iter_days(d_from, d_to))

    def _collect_for_norm(target_nv: str) -> List[Dict[str, Any]]:
        bucket: Dict[str, Dict[str, Any]] = {}
        # rulepack-based metrics
        for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
            if not p.is_file():
                continue
            try:
                doc = json.loads(p.read_text(encoding="utf-8"))
            except Exception:
                continue
            if not isinstance(doc, dict):
                continue
            meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
            f = str(meta.get("form_code") or "").strip()
            if fc and f != fc:
                continue
            nver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
            if target_nv and nver != target_nv:
                continue
            day = datetime.utcfromtimestamp(p.stat().st_mtime).date().isoformat()
            if day not in day_set:
                continue
            b = _bucket_key_by_granularity(day, g)
            if b not in bucket:
                bucket[b] = {
                    "bucket": b,
                    "rule_count": 0,
                    "gate_coverage_sum": 0.0,
                    "gate_coverage_n": 0,
                    "unresolved_count": 0,
                    "publish_total": 0,
                    "publish_success": 0,
                    "rollback_count": 0,
                }
            row = bucket[b]
            rules = doc.get("rules", []) if isinstance(doc.get("rules"), list) else []
            cov = doc.get("docpeg_coverage", {}) if isinstance(doc.get("docpeg_coverage"), dict) else {}
            unresolved = doc.get("unresolved", {}) if isinstance(doc.get("unresolved"), dict) else {}
            row["rule_count"] += len(rules)
            row["gate_coverage_sum"] += float(cov.get("gate_coverage_rate", 0.0) or 0.0)
            row["gate_coverage_n"] += 1
            row["unresolved_count"] += int(unresolved.get("count", 0) or 0)

        # publish success trend
        events: List[Dict[str, Any]] = []
        if NORMREF_PUBLISH_METRICS_PATH.exists():
            try:
                doc = json.loads(NORMREF_PUBLISH_METRICS_PATH.read_text(encoding="utf-8"))
                if isinstance(doc, dict) and isinstance(doc.get("events"), list):
                    events = [x for x in doc.get("events", []) if isinstance(x, dict)]
            except Exception:
                events = []
        for ev in events:
            ts = _parse_utc_ts(str(ev.get("timestamp") or ""))
            if ts is None:
                continue
            day = ts.date().isoformat()
            if day not in day_set:
                continue
            ev_fc = str(ev.get("form_code") or "").strip()
            if fc and ev_fc and ev_fc != fc:
                continue
            b = _bucket_key_by_granularity(day, g)
            if b not in bucket:
                bucket[b] = {
                    "bucket": b,
                    "rule_count": 0,
                    "gate_coverage_sum": 0.0,
                    "gate_coverage_n": 0,
                    "unresolved_count": 0,
                    "publish_total": 0,
                    "publish_success": 0,
                    "rollback_count": 0,
                }
            bucket[b]["publish_total"] += 1
            if str(ev.get("status") or "").strip() == "success":
                bucket[b]["publish_success"] += 1

        # rollback trend from release history
        reg = _load_rulepack_release_registry()
        forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
        if isinstance(forms, dict):
            for form, fr in forms.items():
                if fc and str(form).strip() != fc:
                    continue
                hist = fr.get("history", []) if isinstance(fr, dict) and isinstance(fr.get("history"), list) else []
                for h in hist:
                    if not isinstance(h, dict):
                        continue
                    if str(h.get("action") or "").strip().lower() != "rollback":
                        continue
                    ts = _parse_utc_ts(str(h.get("time") or ""))
                    if ts is None:
                        continue
                    day = ts.date().isoformat()
                    if day not in day_set:
                        continue
                    ver = str(h.get("to_version") or h.get("version") or "").strip()
                    if target_nv and ver:
                        try:
                            rp_doc = json.loads(_rulepack_name_to_path(ver).read_text(encoding="utf-8"))
                            meta = rp_doc.get("meta", {}) if isinstance(rp_doc.get("meta"), dict) else {}
                            rv = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
                            if rv != target_nv:
                                continue
                        except Exception:
                            continue
                    b = _bucket_key_by_granularity(day, g)
                    if b not in bucket:
                        bucket[b] = {
                            "bucket": b,
                            "rule_count": 0,
                            "gate_coverage_sum": 0.0,
                            "gate_coverage_n": 0,
                            "unresolved_count": 0,
                            "publish_total": 0,
                            "publish_success": 0,
                            "rollback_count": 0,
                        }
                    bucket[b]["rollback_count"] += 1

        out_rows: List[Dict[str, Any]] = []
        for b in sorted(bucket.keys()):
            row = bucket[b]
            n = int(row.get("gate_coverage_n", 0) or 0)
            publish_total = int(row.get("publish_total", 0) or 0)
            out_rows.append(
                {
                    "bucket": b,
                    "rule_count": int(row.get("rule_count", 0) or 0),
                    "gate_coverage": (float(row.get("gate_coverage_sum", 0.0) or 0.0) / float(n)) if n > 0 else 0.0,
                    "unresolved_count": int(row.get("unresolved_count", 0) or 0),
                    "publish_success_rate": (float(row.get("publish_success", 0) or 0) / float(publish_total)) if publish_total > 0 else 0.0,
                    "rollback_count": int(row.get("rollback_count", 0) or 0),
                }
            )
        return out_rows

    primary = _collect_for_norm(nv)
    compare = _collect_for_norm(nv_cmp) if nv_cmp else []
    report = {
        "schema_version": "quality_trend_report.v1",
        "generated_at": _utc_now(),
        "filters": {
            "form_code": fc,
            "norm_version": nv,
            "compare_norm_version": nv_cmp,
            "date_from": d_from.isoformat(),
            "date_to": d_to.isoformat(),
            "granularity": g,
        },
        "trends": primary,
        "compare_trends": compare,
    }
    NORMREF_REPORT_DIR.mkdir(parents=True, exist_ok=True)
    report_path = NORMREF_REPORT_DIR / "quality_trend_report.json"
    report_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    report["quality_report_path"] = str(report_path.resolve())
    return report


def _load_health_check_state() -> Dict[str, Any]:
    if not RULEPACK_HEALTH_STATE_PATH.exists():
        return {"last_run_date": "", "last_status": "", "last_report_path": ""}
    try:
        obj = json.loads(RULEPACK_HEALTH_STATE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {"last_run_date": "", "last_status": "", "last_report_path": ""}
    if not isinstance(obj, dict):
        return {"last_run_date": "", "last_status": "", "last_report_path": ""}
    return {
        "last_run_date": str(obj.get("last_run_date") or "").strip(),
        "last_status": str(obj.get("last_status") or "").strip(),
        "last_report_path": str(obj.get("last_report_path") or "").strip(),
    }


def _save_health_check_state(state: Dict[str, Any]) -> None:
    RULEPACK_HEALTH_STATE_PATH.parent.mkdir(parents=True, exist_ok=True)
    RULEPACK_HEALTH_STATE_PATH.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")


def _notify_admin_critical_health(report: Dict[str, Any], operator: str) -> None:
    row = {
        "timestamp": _utc_now(),
        "type": "rulepack_health_critical",
        "operator": str(operator or "system").strip(),
        "status": str(report.get("status") or "").strip(),
        "summary": report.get("summary", {}),
        "report_path": str(report.get("report_path") or "").strip(),
    }
    ADMIN_NOTIFY_PATH.parent.mkdir(parents=True, exist_ok=True)
    with ADMIN_NOTIFY_PATH.open("a", encoding="utf-8") as f:
        f.write(json.dumps(row, ensure_ascii=False) + "\n")
    _audit_security_event(
        action="rulepack_health_check_critical",
        actor=str(operator or "system").strip(),
        result="critical",
        target="rulepack_health",
        required_role="admin",
        reason="critical health status",
    )


def _run_rulepack_auto_health_check(*, operator: str = "system", force: bool = False) -> Dict[str, Any]:
    today = date.today().isoformat()
    state = _load_health_check_state()
    if (not force) and str(state.get("last_run_date") or "").strip() == today and RULEPACK_HEALTH_REPORT_PATH.exists():
        try:
            obj = json.loads(RULEPACK_HEALTH_REPORT_PATH.read_text(encoding="utf-8"))
            if isinstance(obj, dict):
                obj["auto_skipped"] = True
                return obj
        except Exception:
            pass

    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
    if not isinstance(forms, dict):
        forms = {}
    checks: List[Dict[str, Any]] = []
    schema_fail = 0
    trace_fail = 0
    runtime_fail = 0
    gate_fail = 0
    regression_fail = 0
    for fc, row in forms.items():
        if not isinstance(row, dict):
            continue
        form_code = str(fc).strip()
        if not form_code:
            continue
        item: Dict[str, Any] = {"form_code": form_code, "checks": {}}
        # 1) schema validation
        try:
            resolved = _resolve_runtime_rulepack_version(form_code, subject="health_check")
            version = str(resolved.get("selected_version") or "").strip()
            rp_path = _ensure_rulepack_exists(version)
            rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
            ok_schema, _, _, _ = _validate_rulepack_schema_with_compat(rp_doc if isinstance(rp_doc, dict) else {})
            item["checks"]["schema_validation"] = bool(ok_schema)
            item["selected_version"] = version
            # 2) traceability validation
            trace_rows = rp_doc.get("traceability", []) if isinstance(rp_doc.get("traceability"), list) else []
            trace_ok = len(trace_rows) > 0
            if trace_ok:
                for t in trace_rows:
                    if not isinstance(t, dict):
                        trace_ok = False
                        break
                    if not str(t.get("norm_ref") or "").strip():
                        trace_ok = False
                        break
            item["checks"]["traceability_validation"] = bool(trace_ok)
            # 3) runtime smoke test
            smoke = _evaluate_rulepack_with_input(rp_doc if isinstance(rp_doc, dict) else {}, {})
            item["checks"]["runtime_smoke_test"] = isinstance(smoke, dict) and isinstance(smoke.get("gate_results"), list)
            # 4) gate execution test
            gate_rows = rp_doc.get("gates", []) if isinstance(rp_doc.get("gates"), list) else []
            gate_exec_ok = len(gate_rows) > 0 and all(len(_gate_rule_ids(g)) > 0 for g in gate_rows if isinstance(g, dict))
            item["checks"]["gate_execution_test"] = bool(gate_exec_ok)
            # 5) regression quick test
            gate_reg = rp_doc.get("gate_regression", {}) if isinstance(rp_doc.get("gate_regression"), dict) else {}
            runtime_reg = rp_doc.get("runtime_regression", {}) if isinstance(rp_doc.get("runtime_regression"), dict) else {}
            reg_ok = bool(gate_reg.get("passed", False)) and bool(runtime_reg.get("passed", False))
            item["checks"]["regression_quick_test"] = bool(reg_ok)
        except Exception as exc:
            item["checks"]["schema_validation"] = False
            item["checks"]["traceability_validation"] = False
            item["checks"]["runtime_smoke_test"] = False
            item["checks"]["gate_execution_test"] = False
            item["checks"]["regression_quick_test"] = False
            item["error"] = str(exc)
        if not bool(item["checks"].get("schema_validation", False)):
            schema_fail += 1
        if not bool(item["checks"].get("traceability_validation", False)):
            trace_fail += 1
        if not bool(item["checks"].get("runtime_smoke_test", False)):
            runtime_fail += 1
        if not bool(item["checks"].get("gate_execution_test", False)):
            gate_fail += 1
        if not bool(item["checks"].get("regression_quick_test", False)):
            regression_fail += 1
        checks.append(item)

    critical_count = schema_fail + runtime_fail + gate_fail + regression_fail
    warning_count = trace_fail
    status = "healthy"
    if critical_count > 0:
        status = "critical"
    elif warning_count > 0:
        status = "warning"

    report = {
        "schema_version": "rulepack_health_check_report.v1",
        "generated_at": _utc_now(),
        "status": status,
        "summary": {
            "form_count": len(checks),
            "critical_count": critical_count,
            "warning_count": warning_count,
            "schema_fail_count": schema_fail,
            "traceability_fail_count": trace_fail,
            "runtime_fail_count": runtime_fail,
            "gate_fail_count": gate_fail,
            "regression_fail_count": regression_fail,
        },
        "checks": checks,
    }
    RULEPACK_HEALTH_REPORT_PATH.parent.mkdir(parents=True, exist_ok=True)
    RULEPACK_HEALTH_REPORT_PATH.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    report["report_path"] = str(RULEPACK_HEALTH_REPORT_PATH.resolve())
    _save_health_check_state({"last_run_date": today, "last_status": status, "last_report_path": report["report_path"]})
    if status == "critical":
        _notify_admin_critical_health(report, operator)
    return report


def _maybe_run_daily_health_check() -> Dict[str, Any]:
    return _run_rulepack_auto_health_check(operator="system", force=False)


def _load_auto_regression_state() -> Dict[str, Any]:
    if not AUTO_REGRESSION_STATE_PATH.exists():
        return {"forms": {}}
    try:
        obj = json.loads(AUTO_REGRESSION_STATE_PATH.read_text(encoding="utf-8"))
    except Exception:
        return {"forms": {}}
    if not isinstance(obj, dict):
        return {"forms": {}}
    forms = obj.get("forms", {})
    if not isinstance(forms, dict):
        forms = {}
    return {"forms": forms}


def _save_auto_regression_state(doc: Dict[str, Any]) -> None:
    forms = doc.get("forms", {}) if isinstance(doc, dict) else {}
    if not isinstance(forms, dict):
        forms = {}
    AUTO_REGRESSION_STATE_PATH.parent.mkdir(parents=True, exist_ok=True)
    AUTO_REGRESSION_STATE_PATH.write_text(json.dumps({"forms": forms}, ensure_ascii=False, indent=2), encoding="utf-8")


def _run_auto_regression_for_rulepack_doc(
    *,
    form_code: str,
    payload: Dict[str, Any],
    reason: str,
    norm_version: str = "",
    job_id: str = "",
) -> Dict[str, Any]:
    checks: Dict[str, Any] = {}
    blockers: List[str] = []
    # 1) snapshot diff
    current_snap = _build_rulepack_regression_snapshot(payload=payload if isinstance(payload, dict) else {})
    prev_path = _find_latest_rulepack_for_form(form_code, exclude_job_id=job_id)
    prev_doc: Dict[str, Any] = {}
    if prev_path is not None:
        try:
            obj = json.loads(prev_path.read_text(encoding="utf-8"))
            if isinstance(obj, dict):
                prev_doc = _build_rulepack_regression_snapshot(payload=obj)
        except Exception:
            prev_doc = {}
    snap_diff = _snapshot_regression_diff(current_snap, prev_doc) if prev_doc else {"has_diff": False}
    checks["snapshot_diff"] = {"passed": True, "diff": snap_diff}

    # 2) golden set compare
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    golden = payload.get("golden_compare", {}) if isinstance(payload.get("golden_compare"), dict) else _compare_rulepack_with_golden(form_code=form_code, rules=rules, gates=gates)
    checks["golden_set_compare"] = {"passed": bool(golden.get("passed", True)), "summary": golden}
    if not bool(golden.get("passed", True)):
        blockers.append("golden_set_compare_failed")

    # 3) gate regression
    gate_reg = payload.get("gate_regression", {}) if isinstance(payload.get("gate_regression"), dict) else {}
    if not gate_reg:
        guard_cfg = _load_publish_guardrails()
        critical_map = guard_cfg.get("critical_gates", {}) if isinstance(guard_cfg.get("critical_gates"), dict) else {}
        critical = [str(x).strip() for x in (critical_map.get(form_code, []) if isinstance(critical_map.get(form_code, []), list) else []) if str(x).strip()]
        gate_reg = _run_gate_regression(form_code, payload, critical)
    checks["gate_regression"] = {"passed": bool(gate_reg.get("passed", False)), "summary": gate_reg}
    if not bool(gate_reg.get("passed", False)):
        blockers.append("gate_regression_failed")

    # 4) runtime regression
    runtime_reg = payload.get("runtime_regression", {}) if isinstance(payload.get("runtime_regression"), dict) else _run_runtime_regression(form_code, payload)
    checks["runtime_regression"] = {"passed": bool(runtime_reg.get("passed", False)), "summary": runtime_reg}
    if not bool(runtime_reg.get("passed", False)):
        blockers.append("runtime_regression_failed")

    passed = len(blockers) == 0
    report = {
        "schema_version": "auto_regression_report.v1",
        "generated_at": _utc_now(),
        "form_code": form_code,
        "norm_version": norm_version,
        "job_id": job_id,
        "reason": reason,
        "passed": passed,
        "checks": checks,
        "blockers": blockers,
    }
    return report


def _trigger_auto_regression_for_job(job_id: str, reason: str) -> Dict[str, Any]:
    reports: List[Dict[str, Any]] = []
    state = _load_auto_regression_state()
    forms_state = state.get("forms", {}) if isinstance(state.get("forms"), dict) else {}
    packs = _find_rulepack_paths_by_job(job_id)
    for p in packs:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        form_code = str(meta.get("form_code") or "").strip()
        norm_ver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        if not form_code:
            continue
        rep = _run_auto_regression_for_rulepack_doc(form_code=form_code, payload=doc, reason=reason, norm_version=norm_ver, job_id=job_id)
        reports.append(rep)
        forms_state[form_code] = {
            "passed": bool(rep.get("passed", False)),
            "updated_at": _utc_now(),
            "reason": reason,
            "norm_version": norm_ver,
            "job_id": job_id,
            "report": rep,
        }
    state["forms"] = forms_state
    _save_auto_regression_state(state)
    out = {
        "status": "ok",
        "job_id": job_id,
        "reason": reason,
        "reports": reports,
        "passed": all(bool(x.get("passed", False)) for x in reports) if reports else False,
    }
    out_path = _artifact_dir_for_job(job_id) / "auto_regression_report.json"
    out_path.parent.mkdir(parents=True, exist_ok=True)
    out_path.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    out["report_path"] = str(out_path.resolve())
    return out


def _trigger_auto_regression_for_norm_version(norm_id: str, norm_version: str, reason: str) -> Dict[str, Any]:
    reports: List[Dict[str, Any]] = []
    state = _load_auto_regression_state()
    forms_state = state.get("forms", {}) if isinstance(state.get("forms"), dict) else {}
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        nid = str(meta.get("spec_code") or meta.get("norm_id") or "").strip()
        nver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        form_code = str(meta.get("form_code") or "").strip()
        if not form_code:
            continue
        if norm_id and nid != norm_id:
            continue
        if norm_version and nver != norm_version:
            continue
        rep = _run_auto_regression_for_rulepack_doc(form_code=form_code, payload=doc, reason=reason, norm_version=nver, job_id=str(meta.get("job_id") or "").strip())
        reports.append(rep)
        forms_state[form_code] = {
            "passed": bool(rep.get("passed", False)),
            "updated_at": _utc_now(),
            "reason": reason,
            "norm_version": nver,
            "job_id": str(meta.get("job_id") or "").strip(),
            "report": rep,
        }
    state["forms"] = forms_state
    _save_auto_regression_state(state)
    return {"status": "ok", "reason": reason, "reports": reports, "passed": all(bool(x.get("passed", False)) for x in reports) if reports else False}


def _assert_auto_regression_pass_for_forms(form_codes: List[str]) -> None:
    state = _load_auto_regression_state()
    forms = state.get("forms", {}) if isinstance(state.get("forms"), dict) else {}
    for fc in [str(x).strip() for x in form_codes if str(x).strip()]:
        row = forms.get(fc, {}) if isinstance(forms.get(fc, {}), dict) else {}
        if not row or not bool(row.get("passed", False)):
            raise HTTPException(status_code=400, detail=f"auto_regression 未通过，禁止 merge/publish: form_code={fc}")


def _collect_quality_dashboard(*, form_code: str = "", norm_version: str = "", date_from: str = "", date_to: str = "") -> Dict[str, Any]:
    fc = str(form_code or "").strip()
    nv_filter = str(norm_version or "").strip()
    d_to = date.today()
    d_from = d_to.fromordinal(max(1, d_to.toordinal() - 13))
    if str(date_from or "").strip():
        try:
            d_from = date.fromisoformat(str(date_from).strip())
        except Exception:
            pass
    if str(date_to or "").strip():
        try:
            d_to = date.fromisoformat(str(date_to).strip())
        except Exception:
            pass
    if d_from > d_to:
        d_from, d_to = d_to, d_from
    day_keys = _iter_days(d_from, d_to)
    day_set = set(day_keys)

    publish_metrics: List[Dict[str, Any]] = []
    if NORMREF_PUBLISH_METRICS_PATH.exists():
        try:
            doc = json.loads(NORMREF_PUBLISH_METRICS_PATH.read_text(encoding="utf-8"))
            if isinstance(doc, dict) and isinstance(doc.get("events"), list):
                publish_metrics = [x for x in doc["events"] if isinstance(x, dict)]
        except Exception:
            publish_metrics = []

    # Build quality from latest rulepack per form (or filtered form only).
    latest_by_form: Dict[str, Tuple[float, Dict[str, Any], Path]] = {}
    selected_rulepacks: List[Tuple[Path, Dict[str, Any]]] = []
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        f = str(meta.get("form_code") or "").strip()
        if not f:
            continue
        if fc and f != fc:
            continue
        nver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        if nv_filter and nver != nv_filter:
            continue
        day = datetime.utcfromtimestamp(p.stat().st_mtime).date().isoformat()
        if day not in day_set:
            continue
        selected_rulepacks.append((p, doc))
        mt = p.stat().st_mtime
        if f not in latest_by_form or mt > latest_by_form[f][0]:
            latest_by_form[f] = (mt, doc, p)

    publishable_form_count = 0
    unresolved_total = 0
    rule_cov_vals: List[float] = []
    gate_cov_vals: List[float] = []
    rule_count_total = 0
    gate_count_total = 0
    missing_gate_total = 0
    unresolved_item_counter: Dict[str, int] = {}
    missing_gate_counter: Dict[str, int] = {}
    regression_fail_counter: Dict[str, int] = {}
    auto_gate_sum = 0
    field_total_sum = 0
    for f, (_, rp, _) in latest_by_form.items():
        unresolved = rp.get("unresolved", {}) if isinstance(rp.get("unresolved"), dict) else {}
        unresolved_total += int(unresolved.get("count", 0) or 0)
        for it in (unresolved.get("items", []) if isinstance(unresolved.get("items"), list) else []):
            if not isinstance(it, dict):
                continue
            key = str(it.get("reason") or it.get("type") or it.get("rule_id") or "unknown").strip() or "unknown"
            unresolved_item_counter[key] = unresolved_item_counter.get(key, 0) + 1
        rule_count_total += len(rp.get("rules", []) if isinstance(rp.get("rules"), list) else [])
        gate_count_total += len(rp.get("gates", []) if isinstance(rp.get("gates"), list) else [])
        cov = rp.get("docpeg_coverage", {}) if isinstance(rp.get("docpeg_coverage"), dict) else {}
        rule_cov_vals.append(float(cov.get("executable_rate", 0.0) or 0.0))
        gate_cov_vals.append(float(cov.get("gate_coverage_rate", 0.0) or 0.0))
        auto_gate_sum += int(cov.get("auto_gate_count", 0) or 0)
        field_total_sum += int(cov.get("field_total", 0) or 0)
        missing_gate_total += int(cov.get("missing_gateRef_count", 0) or 0)
        mg = rp.get("missing_gate_governance", {}) if isinstance(rp.get("missing_gate_governance"), dict) else {}
        for it in (mg.get("warnings", []) if isinstance(mg.get("warnings"), list) else []):
            if not isinstance(it, dict):
                continue
            key = str(it.get("field") or it.get("rule_id") or "unknown").strip() or "unknown"
            missing_gate_counter[key] = missing_gate_counter.get(key, 0) + 1
        gate_reg = rp.get("gate_regression", {}) if isinstance(rp.get("gate_regression"), dict) else {}
        for it in (gate_reg.get("failures", []) if isinstance(gate_reg.get("failures"), list) else []):
            if not isinstance(it, dict):
                continue
            key = str(it.get("gate_id") or it.get("reason") or "unknown").strip() or "unknown"
            regression_fail_counter[key] = regression_fail_counter.get(key, 0) + 1
        runtime_reg = rp.get("runtime_regression", {}) if isinstance(rp.get("runtime_regression"), dict) else {}
        if not bool(runtime_reg.get("passed", True)):
            key = f"runtime:{f}"
            regression_fail_counter[key] = regression_fail_counter.get(key, 0) + int(runtime_reg.get("failed_samples", 0) or 0)
        schema_ok = bool((rp.get("schema_validation", {}) if isinstance(rp.get("schema_validation"), dict) else {}).get("valid", False))
        has_rules = len(rp.get("rules", []) if isinstance(rp.get("rules"), list) else []) > 0
        has_gates = len(rp.get("gates", []) if isinstance(rp.get("gates"), list) else []) > 0
        if schema_ok and has_rules and has_gates and int(unresolved.get("count", 0) or 0) == 0:
            publishable_form_count += 1

    # Build failure rate from pipeline audits.
    build_total = 0
    build_fail = 0
    today_key = date.today().isoformat()
    today_build_total = 0
    today_build_success = 0
    today_build_failed = 0
    # map form_code filter by job ids seen in rulepack filenames
    allowed_job_ids: set[str] = set()
    if fc:
        for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
            try:
                doc = json.loads(p.read_text(encoding="utf-8"))
            except Exception:
                continue
            if not isinstance(doc, dict):
                continue
            meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
            if str(meta.get("form_code") or "").strip() != fc:
                continue
            jid = str(meta.get("job_id") or "").strip()
            if jid:
                allowed_job_ids.add(jid)
    for audit_path in NORMREF_ARTIFACTS_DIR.glob("*/12_pipeline_audit.json"):
        try:
            job_id = audit_path.parent.name
            if fc and allowed_job_ids and job_id not in allowed_job_ids:
                continue
            mt_day = datetime.utcfromtimestamp(audit_path.stat().st_mtime).date().isoformat()
            if mt_day not in day_set:
                continue
            doc = json.loads(audit_path.read_text(encoding="utf-8-sig"))
            if not isinstance(doc, dict):
                continue
            build_total += 1
            if not bool(doc.get("valid", False)):
                build_fail += 1
                if mt_day == today_key:
                    today_build_total += 1
                    today_build_failed += 1
            else:
                if mt_day == today_key:
                    today_build_total += 1
                    today_build_success += 1
        except Exception:
            continue
    build_failure_rate = (build_fail / build_total) if build_total > 0 else 0.0

    # Publish success rate and top failure reasons from publish metrics.
    pub_total = 0
    pub_success = 0
    fail_reason_count: Dict[str, int] = {}
    trend_map: Dict[str, Dict[str, Any]] = {
        d: {
            "date": d,
            "build_total": 0,
            "build_fail": 0,
            "publish_total": 0,
            "publish_success": 0,
            "unresolved_total": 0,
            "rule_coverage": 0.0,
            "gate_coverage": 0.0,
            "publishable_forms": 0,
        }
        for d in day_keys
    }

    # rulepack daily trends
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        f = str(meta.get("form_code") or "").strip()
        if fc and f != fc:
            continue
        day = datetime.utcfromtimestamp(p.stat().st_mtime).date().isoformat()
        if day not in trend_map:
            continue
        cov = doc.get("docpeg_coverage", {}) if isinstance(doc.get("docpeg_coverage"), dict) else {}
        unresolved = doc.get("unresolved", {}) if isinstance(doc.get("unresolved"), dict) else {}
        tr = trend_map[day]
        tr["unresolved_total"] += int(unresolved.get("count", 0) or 0)
        tr["rule_coverage"] += float(cov.get("executable_rate", 0.0) or 0.0)
        tr["gate_coverage"] += float(cov.get("gate_coverage_rate", 0.0) or 0.0)
        tr["publishable_forms"] += 1

    for audit_path in NORMREF_ARTIFACTS_DIR.glob("*/12_pipeline_audit.json"):
        try:
            job_id = audit_path.parent.name
            if fc and allowed_job_ids and job_id not in allowed_job_ids:
                continue
            day = datetime.utcfromtimestamp(audit_path.stat().st_mtime).date().isoformat()
            if day not in trend_map:
                continue
            doc = json.loads(audit_path.read_text(encoding="utf-8-sig"))
            if not isinstance(doc, dict):
                continue
            tr = trend_map[day]
            tr["build_total"] += 1
            if not bool(doc.get("valid", False)):
                tr["build_fail"] += 1
        except Exception:
            continue

    for ev in publish_metrics:
        ts = _parse_utc_ts(str(ev.get("timestamp") or ""))
        if ts is None:
            continue
        day = ts.date().isoformat()
        if day not in trend_map:
            continue
        ef = str(ev.get("form_code") or "").strip()
        if fc and ef and ef != fc:
            continue
        ok = bool(ev.get("success", False))
        pub_total += 1
        if ok:
            pub_success += 1
        else:
            reason = str(ev.get("error") or ev.get("reason") or "unknown").strip() or "unknown"
            fail_reason_count[reason] = fail_reason_count.get(reason, 0) + 1
        tr = trend_map[day]
        tr["publish_total"] += 1
        if ok:
            tr["publish_success"] += 1

    publish_success_rate = (pub_success / pub_total) if pub_total > 0 else 0.0
    top_fail_reasons = [
        {"reason": k, "count": v}
        for k, v in sorted(fail_reason_count.items(), key=lambda x: x[1], reverse=True)[:10]
    ]

    # normalize daily avg coverage
    trends: List[Dict[str, Any]] = []
    for d in day_keys:
        tr = trend_map[d]
        n = int(tr["publishable_forms"] or 0)
        if n > 0:
            tr["rule_coverage"] = float(tr["rule_coverage"]) / float(n)
            tr["gate_coverage"] = float(tr["gate_coverage"]) / float(n)
        tr["build_failure_rate"] = (float(tr["build_fail"]) / float(tr["build_total"])) if int(tr["build_total"]) > 0 else 0.0
        tr["publish_success_rate"] = (float(tr["publish_success"]) / float(tr["publish_total"])) if int(tr["publish_total"]) > 0 else 0.0
        trends.append(tr)

    sla_issues = _collect_sla_issues(form_code=fc, date_from=d_from, date_to=d_to, trends=trends)
    p1_total = len([x for x in sla_issues if str(x.get("priority") or "") == "P1"])
    p2_total = len([x for x in sla_issues if str(x.get("priority") or "") == "P2"])
    overdue_total = len([x for x in sla_issues if str(x.get("status") or "") == "overdue"])

    rollback_count = 0
    gray_release_count = 0
    reg = _load_rulepack_release_registry()
    forms_doc = reg.get("forms", {}) if isinstance(reg, dict) else {}
    if isinstance(forms_doc, dict):
        for fcode, row in forms_doc.items():
            if fc and str(fcode).strip() != fc:
                continue
            hist = row.get("history", []) if isinstance(row, dict) and isinstance(row.get("history"), list) else []
            for h in hist:
                if not isinstance(h, dict):
                    continue
                ts = _parse_utc_ts(str(h.get("time") or ""))
                if ts is None or ts.date().isoformat() not in day_set:
                    continue
                ver = str(h.get("to_version") or h.get("version") or "").strip()
                if nv_filter and ver:
                    try:
                        rp_doc = json.loads(_rulepack_name_to_path(ver).read_text(encoding="utf-8"))
                        meta = rp_doc.get("meta", {}) if isinstance(rp_doc.get("meta"), dict) else {}
                        nv = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
                        if nv != nv_filter:
                            continue
                    except Exception:
                        continue
                action = str(h.get("action") or "").strip().lower()
                if action == "rollback":
                    rollback_count += 1
                if action == "release" and float(h.get("gray_ratio", 0.0) or 0.0) > 0.0:
                    gray_release_count += 1

    total_forms_for_cov = 0
    cfg = _load_system_config()
    mapping = cfg.get("form_api_mapping", {}) if isinstance(cfg.get("form_api_mapping"), dict) else {}
    total_forms_for_cov = len([k for k in mapping.keys() if str(k).strip() and str(k).strip() != "save_and_validate_form_code"])
    if fc:
        total_forms_for_cov = 1
    form_coverage_rate = (len(latest_by_form) / total_forms_for_cov) if total_forms_for_cov > 0 else 1.0
    auto_gate_rate = (auto_gate_sum / field_total_sum) if field_total_sum > 0 else 0.0
    manual_review_rate = (unresolved_total / rule_count_total) if rule_count_total > 0 else 0.0

    def _top_rows(counter: Dict[str, int], topn: int = 10, label: str = "item") -> List[Dict[str, Any]]:
        return [{label: k, "count": v} for k, v in sorted(counter.items(), key=lambda x: x[1], reverse=True)[:topn]]

    return {
        "form_code": fc,
        "norm_version": nv_filter,
        "date_from": d_from.isoformat(),
        "date_to": d_to.isoformat(),
        "filters": {
            "form_code": fc,
            "norm_version": nv_filter,
            "date_from": d_from.isoformat(),
            "date_to": d_to.isoformat(),
        },
        "today_build": {
            "build_count": today_build_total,
            "success_count": today_build_success,
            "failed_count": today_build_failed,
        },
        "rule_quality": {
            "rule_count": rule_count_total,
            "gate_count": gate_count_total,
            "missing_gate_count": missing_gate_total,
            "unresolved_count": unresolved_total,
        },
        "publish_quality": {
            "publish_success_rate": publish_success_rate,
            "rollback_count": rollback_count,
            "gray_release_count": gray_release_count,
        },
        "form_quality": {
            "form_coverage_rate": form_coverage_rate,
            "auto_gate_rate": auto_gate_rate,
            "manual_review_rate": manual_review_rate,
        },
        "top_issues": {
            "top_unresolved": _top_rows(unresolved_item_counter, 10, "reason"),
            "top_missing_gate": _top_rows(missing_gate_counter, 10, "field"),
            "top_regression_failures": _top_rows(regression_fail_counter, 10, "target"),
        },
        "overview": {
            "publishable_form_count": publishable_form_count,
            "unresolved_total": unresolved_total,
            "rule_coverage_rate": (sum(rule_cov_vals) / len(rule_cov_vals)) if rule_cov_vals else 0.0,
            "gate_coverage_rate": (sum(gate_cov_vals) / len(gate_cov_vals)) if gate_cov_vals else 0.0,
            "build_failure_rate": build_failure_rate,
            "publish_success_rate": publish_success_rate,
            "top_fail_reasons": top_fail_reasons,
            "sla": {
                "p1_total": p1_total,
                "p2_total": p2_total,
                "overdue_total": overdue_total,
            },
        },
        "sla_issues": sla_issues,
        "trends": trends,
    }


def _load_rulepack_v1_schema() -> Dict[str, Any]:
    if not RULEPACK_V1_SCHEMA_PATH.exists():
        raise HTTPException(status_code=500, detail=f"缺少 rulepack v1 schema: {RULEPACK_V1_SCHEMA_PATH}")
    try:
        obj = json.loads(RULEPACK_V1_SCHEMA_PATH.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"rulepack v1 schema 非法: {RULEPACK_V1_SCHEMA_PATH}") from exc
    if not isinstance(obj, dict):
        raise HTTPException(status_code=500, detail="rulepack v1 schema 根节点必须是对象")
    return obj


def _load_rulepack_v2_schema() -> Dict[str, Any]:
    if not RULEPACK_V2_SCHEMA_PATH.exists():
        raise HTTPException(status_code=500, detail=f"缺少 rulepack v2 schema: {RULEPACK_V2_SCHEMA_PATH}")
    try:
        obj = json.loads(RULEPACK_V2_SCHEMA_PATH.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=500, detail=f"rulepack v2 schema 非法: {RULEPACK_V2_SCHEMA_PATH}") from exc
    if not isinstance(obj, dict):
        raise HTTPException(status_code=500, detail="rulepack v2 schema 根节点必须是对象")
    return obj


def _gate_type_to_decision_logic(gate_type: str) -> str:
    t = str(gate_type or "").strip().upper()
    if t == "ALL_PASS":
        return "all_pass"
    if t == "ANY_PASS":
        return "any_pass"
    if t in {"RANGE", "RANGE_CHECK"}:
        return "range_check"
    if t in {"THRESHOLD", "COMPARE"}:
        return "threshold_compare"
    return "custom_expr"


def _to_rulepack_v1_payload(payload: Dict[str, Any]) -> Dict[str, Any]:
    meta = payload.get("meta", {}) if isinstance(payload.get("meta"), dict) else {}
    components = payload.get("components", []) if isinstance(payload.get("components"), list) else []
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    out: Dict[str, Any] = {
        "meta": {
            "schema_version": "v1",
            "form_code": str(meta.get("form_code") or "").strip(),
            "norm_id": str(meta.get("spec_code") or meta.get("norm_id") or "").strip(),
            "norm_version": str(meta.get("spec_version") or meta.get("norm_version") or "").strip(),
            "rulepack_version": str(meta.get("package_version") or meta.get("rulepack_version") or "v1").strip(),
            "selection_mode": str(meta.get("selection_mode") or "unknown").strip(),
            "generated_at": str(meta.get("generated_at") or "").strip(),
            "counts": {
                "components": len([x for x in components if isinstance(x, dict)]),
                "rules": len([x for x in rules if isinstance(x, dict)]),
                "gates": len([x for x in gates if isinstance(x, dict)]),
            },
        },
        "components": [],
        "rules": [],
        "gates": [],
    }
    for comp in components:
        if not isinstance(comp, dict):
            continue
        out["components"].append(
            {
                "id": str(comp.get("component_id") or comp.get("id") or "").strip(),
                "title": str(comp.get("title") or comp.get("name") or comp.get("component_id") or comp.get("id") or "").strip(),
                "normRef": str(comp.get("norm_ref") or comp.get("normRef") or "").strip(),
                "source_clause": str(comp.get("source_clause") or comp.get("source_clause_id") or "").strip(),
                "type": str(comp.get("type") or "measurement").strip(),
            }
        )
    for rule in rules:
        if not isinstance(rule, dict):
            continue
        threshold_struct, _ = _normalize_threshold_struct(rule)
        existing_lineage = rule.get("lineage", {}) if isinstance(rule.get("lineage"), dict) else {}
        rule_row: Dict[str, Any] = {
            "id": str(rule.get("rule_id") or rule.get("id") or "").strip(),
            "component_id": str(rule.get("component_id") or "").strip(),
            "source_clause": str(rule.get("source_clause") or rule.get("source_clause_id") or "").strip(),
            "field": str(rule.get("field") or "").strip(),
            "operator": str(threshold_struct.get("operator") or "").strip(),
            "unit": str(threshold_struct.get("unit") or "").strip(),
            "condition": str(rule.get("condition") or "").strip(),
            "normRef": str(rule.get("norm_ref") or rule.get("normRef") or "").strip(),
            "threshold": threshold_struct,
            "lineage": _build_rule_lineage_payload(
                norm_id=str(meta.get("spec_code") or meta.get("norm_id") or "").strip(),
                norm_version=str(meta.get("norm_version") or meta.get("spec_version") or "").strip(),
                norm_ref=str(rule.get("norm_ref") or rule.get("normRef") or "").strip(),
                source_text=str(rule.get("source_text") or "").strip(),
                source_file_hash=str(existing_lineage.get("source_file_hash") or meta.get("source_doc_hash") or "").strip(),
                created_by=str(existing_lineage.get("created_by") or ""),
                reviewed_by=str(existing_lineage.get("reviewed_by") or ""),
                published_by=str(existing_lineage.get("published_by") or ""),
                published_at=str(existing_lineage.get("published_at") or ""),
            ),
        }
        out["rules"].append(rule_row)
    for gate in gates:
        if not isinstance(gate, dict):
            continue
        existing_lineage = gate.get("lineage", {}) if isinstance(gate.get("lineage"), dict) else {}
        rule_ids = _gate_rule_ids(gate)
        norm_refs = gate.get("norm_refs", [])
        gate_ref = ""
        if isinstance(norm_refs, list) and norm_refs:
            gate_ref = str(norm_refs[0] or "").strip()
        out["gates"].append(
            {
                "id": str(gate.get("gate_id") or gate.get("id") or "").strip(),
                "gateRef": gate_ref,
                "ruleRef": str(rule_ids[0] if rule_ids else "").strip(),
                "decision_logic": _gate_type_to_decision_logic(str(gate.get("type") or "").strip()),
                "on_pass": str(gate.get("on_pass") or "pass").strip(),
                "on_fail": str(gate.get("on_fail") or "fail").strip(),
                "lineage": _build_rule_lineage_payload(
                    norm_id=str(meta.get("spec_code") or meta.get("norm_id") or "").strip(),
                    norm_version=str(meta.get("norm_version") or meta.get("spec_version") or "").strip(),
                    norm_ref=gate_ref,
                    source_text="",
                    source_file_hash=str(existing_lineage.get("source_file_hash") or meta.get("source_doc_hash") or "").strip(),
                    created_by=str(existing_lineage.get("created_by") or ""),
                    reviewed_by=str(existing_lineage.get("reviewed_by") or ""),
                    published_by=str(existing_lineage.get("published_by") or ""),
                    published_at=str(existing_lineage.get("published_at") or ""),
                ),
            }
        )
    return out


def _migrate_rulepack_v1_to_v2_in_memory(v1_payload: Dict[str, Any]) -> Dict[str, Any]:
    out = dict(v1_payload)
    meta = out.get("meta") if isinstance(out.get("meta"), dict) else {}
    meta = dict(meta)
    meta["schema_version"] = "v2"
    meta["rulepack_version"] = "v2"
    meta["source_schema_version"] = "v1"
    meta["migration"] = {"from": "v1", "at": _utc_now()}
    out["meta"] = meta
    gates = out.get("gates") if isinstance(out.get("gates"), list) else []
    new_gates: List[Dict[str, Any]] = []
    for gate in gates:
        if not isinstance(gate, dict):
            continue
        g = dict(gate)
        rule_ref = str(g.pop("ruleRef", "")).strip()
        g["ruleRefs"] = [rule_ref] if rule_ref else []
        new_gates.append(g)
    out["gates"] = new_gates
    return out


def _detect_rulepack_schema_version(payload: Dict[str, Any]) -> str:
    meta = payload.get("meta") if isinstance(payload.get("meta"), dict) else {}
    sv = str(meta.get("schema_version") or "").strip().lower()
    if sv in {"v1", "v2"}:
        return sv
    if sv:
        return f"unsupported:{sv}"
    return "legacy"


def _format_validation_error_path(error: Any) -> str:
    parts: List[str] = []
    for p in list(error.absolute_path):
        if isinstance(p, int):
            if len(parts) == 0:
                parts.append(f"[{p}]")
            else:
                parts[-1] = f"{parts[-1]}[{p}]"
        else:
            parts.append(str(p))
    base_path = ".".join(parts) if parts else ""
    if getattr(error, "validator", "") == "required":
        m = re.search(r"'([^']+)' is a required property", str(error.message))
        if m:
            missing = m.group(1)
            if base_path:
                return f"{base_path}.{missing} missing"
            return f"{missing} missing"
    if base_path:
        return f"{base_path} {error.message}"
    return str(error.message)


def _validate_rulepack_v1_schema(payload: Dict[str, Any]) -> Tuple[bool, List[str], Dict[str, Any]]:
    schema = _load_rulepack_v1_schema()
    canonical = _to_rulepack_v1_payload(payload)
    validator = Draft202012Validator(schema, format_checker=FormatChecker())
    errors = sorted(validator.iter_errors(canonical), key=lambda e: list(e.absolute_path))
    messages = [_format_validation_error_path(err) for err in errors]
    return (len(messages) == 0, messages, canonical)


def _validate_rulepack_v2_schema(payload: Dict[str, Any]) -> Tuple[bool, List[str], Dict[str, Any]]:
    schema = _load_rulepack_v2_schema()
    validator = Draft202012Validator(schema, format_checker=FormatChecker())
    errors = sorted(validator.iter_errors(payload), key=lambda e: list(e.absolute_path))
    messages = [_format_validation_error_path(err) for err in errors]
    return (len(messages) == 0, messages, payload)


def _validate_rulepack_schema_with_compat(payload: Dict[str, Any]) -> Tuple[bool, List[str], Dict[str, Any], str]:
    version = _detect_rulepack_schema_version(payload if isinstance(payload, dict) else {})
    if version == "legacy":
        ok, errs, canonical_v1 = _validate_rulepack_v1_schema(payload if isinstance(payload, dict) else {})
        return ok, errs, canonical_v1, "legacy->v1"
    if version == "v1":
        ok, errs, canonical_v1 = _validate_rulepack_v1_schema(payload if isinstance(payload, dict) else {})
        return ok, errs, canonical_v1, "v1"
    if version == "v2":
        ok, errs, canonical_v2 = _validate_rulepack_v2_schema(payload if isinstance(payload, dict) else {})
        return ok, errs, canonical_v2, "v2"
    return False, [f"不支持的 rulepack schema_version: {version.split(':', 1)[-1]}"], {}, version


def _assert_rulepack_version_compatible(payload: Dict[str, Any], *, stage: str) -> None:
    # Compatibility policy:
    # - build output supports v1 only (v2 produced by migration script)
    # - publish/runtime can read legacy/v1/v2
    version = _detect_rulepack_schema_version(payload if isinstance(payload, dict) else {})
    if stage == "build_output":
        if version != "v1":
            raise HTTPException(status_code=400, detail=f"构建失败：build 仅支持输出 schema_version=v1，当前为 {version}")
        return
    if stage in {"publish_input", "runtime_input"}:
        if version in {"legacy", "v1", "v2"}:
            return
        raise HTTPException(status_code=400, detail=f"版本不兼容：{stage} 不支持 {version}")
    raise HTTPException(status_code=500, detail=f"未知兼容性检查阶段: {stage}")


def _find_rulepacks_by_job(job_id: str) -> List[Path]:
    if not NORMREF_RULEPACK_DIR.exists():
        return []
    token = f"-{str(job_id).strip()}.rulepack.json"
    rows = [
        p.resolve()
        for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json")
        if p.is_file() and p.name.endswith(token)
    ]
    rows.sort(key=lambda x: x.stat().st_mtime, reverse=True)
    return rows


def _collect_rulepack_anchor_audit_for_job(job_id: str) -> Dict[str, Any]:
    packs = _find_rulepacks_by_job(job_id)
    total_rules = 0
    invalid_rules = 0
    invalid_items: List[Dict[str, Any]] = []
    for p in packs:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        audit = doc.get("anchor_audit") if isinstance(doc, dict) else None
        if isinstance(audit, dict):
            total_rules += int(audit.get("total_rules", 0) or 0)
            invalid_rules += int(audit.get("invalid_rules", 0) or 0)
            rows = audit.get("rows", [])
            if isinstance(rows, list):
                for row in rows:
                    if isinstance(row, dict) and not bool(row.get("valid")):
                        invalid_items.append(
                            {
                                "rule_id": str(row.get("rule_id") or "").strip(),
                                "errors": row.get("errors", []),
                                "rulepack": p.name,
                            }
                        )
    return {
        "rulepack_count": len(packs),
        "total_rules": total_rules,
        "invalid_rules": invalid_rules,
        "valid": invalid_rules == 0,
        "invalid_items": invalid_items[:100],
    }


def _collect_rulepack_unresolved_summary_for_job(job_id: str) -> Dict[str, Any]:
    packs = _find_rulepacks_by_job(job_id)
    type_counts = _empty_unresolved_type_counts()
    total = 0
    items: List[Dict[str, Any]] = []
    overdue_count = 0
    now_day = date.today().isoformat()
    for p in packs:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        unresolved = doc.get("unresolved") if isinstance(doc, dict) else None
        if not isinstance(unresolved, dict):
            continue
        total += int(unresolved.get("count", 0) or 0)
        tc = unresolved.get("type_counts", {})
        if isinstance(tc, dict):
            for k, v in tc.items():
                kk = str(k).strip()
                if kk in type_counts:
                    type_counts[kk] = type_counts.get(kk, 0) + int(v or 0)
        rows = unresolved.get("items", [])
        if isinstance(rows, list):
            for row in rows:
                if not isinstance(row, dict):
                    continue
                items.append(
                    {
                        "rulepack": p.name,
                        "rule_id": str(row.get("rule_id") or "").strip(),
                        "type": str(row.get("type") or "").strip(),
                        "reason": str(row.get("reason") or "").strip(),
                        "normRef": str(row.get("normRef") or "").strip(),
                        "source_clause": str(row.get("source_clause") or "").strip(),
                        "priority": str(row.get("priority") or "").strip() or "P3",
                        "owner": str(row.get("owner") or "").strip() or _unresolved_owner_for_type(str(row.get("type") or "").strip()),
                        "status": str(row.get("status") or "").strip() or "open",
                        "due_date": str(row.get("due_date") or "").strip(),
                    }
                )
                status = str(row.get("status") or "").strip().lower() or "open"
                due_date = str(row.get("due_date") or "").strip()
                if status not in {"resolved", "verified"} and due_date and due_date < now_day:
                    overdue_count += 1
    threshold = int((_load_system_config().get("unresolved_block_threshold", 0) if isinstance(_load_system_config(), dict) else 0) or 0)
    return {
        "rulepack_count": len(packs),
        "unresolved_count": total,
        "type_counts": type_counts,
        "items": items[:200],
        "overdue_count": overdue_count,
        "alerts": [f"unresolved_overdue={overdue_count}"] if overdue_count > 0 else [],
        "threshold": threshold,
        "blocked": total > threshold,
    }


def _collect_measurement_gate_mapping_summary_for_job(job_id: str) -> Dict[str, Any]:
    packs = _find_rulepacks_by_job(job_id)
    total_pairs = 0
    missing_count = 0
    missing_items: List[Dict[str, Any]] = []
    for p in packs:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        mg = doc.get("measurement_gate_mapping") if isinstance(doc, dict) else None
        if not isinstance(mg, dict):
            continue
        total_pairs += int(mg.get("measurement_pair_count", 0) or 0)
        mcnt = int(mg.get("missing_count", 0) or 0)
        missing_count += mcnt
        rows = mg.get("missing_items", [])
        if isinstance(rows, list):
            for row in rows:
                if not isinstance(row, dict):
                    continue
                missing_items.append(
                    {
                        "rulepack": p.name,
                        "field_key": str(row.get("field_key") or "").strip(),
                        "reason": str(row.get("reason") or "").strip(),
                        "gateRef": str(row.get("gateRef") or "").strip(),
                    }
                )
    return {
        "rulepack_count": len(packs),
        "measurement_pair_count": total_pairs,
        "missing_count": missing_count,
        "blocked": missing_count > 0,
        "missing_items": missing_items[:200],
    }


def _compute_docpeg_coverage_from_semantic_tree_only(form_code: str, semantic_tree: Dict[str, Any]) -> Dict[str, Any]:
    pairs = semantic_tree.get("measurement_pairs", []) if isinstance(semantic_tree, dict) else []
    pair_rows = [x for x in pairs if isinstance(x, dict)]
    field_nodes = semantic_tree.get("field_nodes", []) if isinstance(semantic_tree, dict) else []
    field_total = len([x for x in field_nodes if isinstance(x, dict)]) or len(pair_rows)
    gate_ref_map = _build_gate_ref_lookup_from_semantic_tree(semantic_tree if isinstance(semantic_tree, dict) else {})
    missing = 0
    for pair in pair_rows:
        fk = str(pair.get("field_key") or pair.get("field") or "").strip()
        gr = str(pair.get("gateRef") or pair.get("gate_ref") or gate_ref_map.get(fk, "")).strip()
        if not gr:
            missing += 1
    auto = max(len(pair_rows) - missing, 0)
    manual = max(field_total - auto, 0)
    exe_rate = (auto / field_total) if field_total > 0 else 0.0
    cov_rate = ((field_total - missing) / field_total) if field_total > 0 else 0.0
    return {
        "form_code": form_code,
        "field_total": field_total,
        "auto_gate_count": auto,
        "manual_fallback_count": manual,
        "missing_gateRef_count": missing,
        "executable_rate": exe_rate,
        "gate_coverage_rate": cov_rate,
    }


def _specbundle_has_form_mapping(form_code: str) -> bool:
    bid, bver = _resolve_form_bundle(form_code)
    bundle = _load_specbundle(bid, bver, form_code)
    rules = [x for x in bundle.get("rules", []) if isinstance(x, dict)]
    frm = [x for x in bundle.get("fieldRuleMap", []) if isinstance(x, dict)]
    return bool(rules or frm)


def _derive_rule_ids_from_form_code(form_code: str, rules_rows: List[Dict[str, Any]]) -> set[str]:
    """
    Derive a rule-id subset from conventional form code suffixes, e.g.
    bridge_shi_13 -> <spec>.13_* rules.
    """
    m = re.search(r"(\d+)$", str(form_code or "").strip())
    if not m:
        return set()
    chapter_no = m.group(1)
    out: set[str] = set()
    patt = re.compile(rf"\.{re.escape(chapter_no)}_\d+_\d+\.rule$")
    for row in rules_rows:
        rid = str(row.get("rule_id") or row.get("ruleId") or "").strip()
        cid = str(row.get("source_clause_id") or row.get("clause_id") or "").strip()
        if rid and patt.search(rid):
            out.add(rid)
            continue
        if cid.startswith(f"{chapter_no}."):
            if rid:
                out.add(rid)
    return out


def _upsert_specbundle_rule_mapping(
    form_code: str,
    rule_ids: set[str],
    *,
    source: str,
) -> None:
    bid, bver = _resolve_form_bundle(form_code)
    bundle = _load_specbundle(bid, bver, form_code)
    merged = sorted(
        {
            str(x.get("ruleId") or x.get("rule_id") or "").strip()
            for x in bundle.get("rules", [])
            if isinstance(x, dict) and str(x.get("ruleId") or x.get("rule_id") or "").strip()
        }
        | {str(x).strip() for x in rule_ids if str(x).strip()}
    )
    payload = dict(bundle)
    payload["rules"] = [{"ruleId": rid, "fieldKeys": ["measured_value"]} for rid in merged]
    payload["fieldRuleMap"] = [
        {
            "fieldKey": "measured_value",
            "fieldName": "实测值",
            "gateRequired": True,
            "ruleIds": merged,
            "valueSource": "manual",
        }
    ]
    meta = payload.get("metadata")
    if not isinstance(meta, dict):
        meta = {}
    meta["source"] = source
    meta["updatedAt"] = _utc_now()
    payload["metadata"] = meta
    bid, bver = _resolve_form_bundle(form_code)
    path = _bundle_file_path(bid, bver, form_code)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _rule_row_matches_form(rule: Dict[str, Any], form_code: str, target_rule_ids: set[str]) -> bool:
    rid = str(rule.get("rule_id") or rule.get("ruleId") or "").strip()
    if rid and rid in target_rule_ids:
        return True
    if not form_code:
        return False
    token = str(form_code).strip().lower()
    for key in ("rule_id", "ruleId", "component_id", "componentId", "norm_ref", "source_ref", "source_clause_id"):
        val = str(rule.get(key, "")).strip().lower()
        if token and val and token in val:
            return True
    return False


def _gate_rule_ids(gate: Dict[str, Any]) -> List[str]:
    rows = gate.get("rule_ids")
    if isinstance(rows, list):
        return [str(x).strip() for x in rows if str(x).strip()]
    rows = gate.get("ruleIds")
    if isinstance(rows, list):
        return [str(x).strip() for x in rows if str(x).strip()]
    return []


def _synthesize_gates_from_rules(rows: List[Dict[str, Any]], source_tag: str = "autogen.rulepack_fallback") -> List[Dict[str, Any]]:
    out: List[Dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        rid = str(row.get("rule_id") or row.get("ruleId") or "").strip()
        if not rid:
            continue
        comp_id = str(row.get("component_id") or row.get("componentId") or "").strip()
        norm_ref_val = str(row.get("norm_ref") or "").strip()
        out.append(
            {
                "gate_id": f"gate.{comp_id or rid}",
                "name": f"Auto gate for {rid}",
                "type": "ALL_PASS",
                "rule_ids": [rid],
                "norm_refs": [norm_ref_val] if norm_ref_val else [],
                "component_id": comp_id,
                "source": source_tag,
            }
        )
    return out


def _build_norm_layer(job_id: str, index: Dict[str, Any], review_pkg: Dict[str, Any]) -> Dict[str, Any]:
    art_dir = _artifact_dir_for_job(job_id)
    rules_doc = json.loads((art_dir / "07_rules.json").read_text(encoding="utf-8")) if (art_dir / "07_rules.json").exists() else {}
    gates_doc = json.loads((art_dir / "08_gates.json").read_text(encoding="utf-8")) if (art_dir / "08_gates.json").exists() else {}
    comps_doc = json.loads((art_dir / "05_components.json").read_text(encoding="utf-8")) if (art_dir / "05_components.json").exists() else {}
    proof_doc = json.loads((art_dir / "10_proof_templates.json").read_text(encoding="utf-8")) if (art_dir / "10_proof_templates.json").exists() else {}
    specir_doc = json.loads((art_dir / "13_specir.json").read_text(encoding="utf-8")) if (art_dir / "13_specir.json").exists() else {}
    normref_index_doc = json.loads((art_dir / "norm_ref_index.json").read_text(encoding="utf-8")) if (art_dir / "norm_ref_index.json").exists() else {}

    source_art = review_pkg.get("source_artifacts") if isinstance(review_pkg.get("source_artifacts"), dict) else {}
    spec_code = str(index.get("spec_code") or index.get("std_code") or review_pkg.get("std_code") or "").strip()
    spec_version = str(index.get("spec_version") or index.get("version") or review_pkg.get("standard_version") or "").strip() or "v1"
    source_doc_hash = str(index.get("source_doc_hash") or review_pkg.get("source_doc_hash") or source_art.get("source_doc_hash") or "").strip()
    if not source_doc_hash:
        source_file = str(source_art.get("input_file") or "").strip()
        if source_file:
            src_path = Path(source_file).expanduser()
            if src_path.exists() and src_path.is_file():
                try:
                    source_doc_hash = _sha256_file(src_path)
                except Exception:
                    source_doc_hash = ""
    norm_ref = str(index.get("normRef") or review_pkg.get("normRef") or "").strip()

    rules_rows = [x for x in (rules_doc.get("rules", []) if isinstance(rules_doc, dict) else []) if isinstance(x, dict)]
    gates_rows = [x for x in (gates_doc.get("gates", []) if isinstance(gates_doc, dict) else []) if isinstance(x, dict)]
    comp_rows = [x for x in (comps_doc.get("components", []) if isinstance(comps_doc, dict) else []) if isinstance(x, dict)]
    proof_rows = [x for x in (proof_doc.get("proof_templates", []) if isinstance(proof_doc, dict) else []) if isinstance(x, dict)]

    return {
        "art_dir": art_dir,
        "spec_code": spec_code,
        "spec_version": spec_version,
        "source_doc_hash": source_doc_hash,
        "normRef": norm_ref,
        "rules_rows": rules_rows,
        "gates_rows": gates_rows,
        "comp_rows": comp_rows,
        "proof_rows": proof_rows,
        "specir_doc": specir_doc,
        "normref_index_doc": normref_index_doc,
        "counts": {
            "rules": len(rules_rows),
            "gates": len(gates_rows),
            "components": len(comp_rows),
            "proof_templates": len(proof_rows),
        },
    }


def _build_doc_layer(form_code: str) -> Dict[str, Any]:
    bid, bver = _resolve_form_bundle(form_code)
    bundle = _load_specbundle(bid, bver, form_code)
    semantic_tree = bundle.get("semanticTree", {}) if isinstance(bundle, dict) else {}
    ok, errs = _validate_semantic_tree_for_form(form_code, semantic_tree if isinstance(semantic_tree, dict) else {})
    if not ok:
        raise HTTPException(status_code=400, detail=f"Doc层 semantic_tree 非法：{'; '.join(errs[:10])}")
    asset_whitelist = _load_form_asset_whitelist(form_code)
    # Strict policy: Rulepack must be selected from form-level whitelist.
    if len(asset_whitelist.get("allowed_rules", set())) == 0:
        raise HTTPException(status_code=400, detail=f"Doc层缺少 allowed_rules 白名单：{form_code}")
    return {
        "form_code": form_code,
        "semantic_tree": semantic_tree,
        "field_rule_map": [x for x in bundle.get("fieldRuleMap", []) if isinstance(x, dict)] if isinstance(bundle.get("fieldRuleMap"), list) else [],
        "asset_whitelist": asset_whitelist,
        "rule_overrides": _load_form_rule_overrides(form_code),
    }


def _build_rulepack_asset_slice_from_layers(
    norm_layer: Dict[str, Any],
    doc_layer: Dict[str, Any],
    *,
    selected_slot_keys: List[str] | None = None,
    selected_specir_ids: List[str] | None = None,
) -> Dict[str, Any]:
    rules_rows = list(norm_layer.get("rules_rows", []))
    gates_rows = list(norm_layer.get("gates_rows", []))
    comp_rows = list(norm_layer.get("comp_rows", []))
    proof_rows = list(norm_layer.get("proof_rows", []))
    wl = doc_layer.get("asset_whitelist", {}) if isinstance(doc_layer.get("asset_whitelist"), dict) else {}
    allowed_specir_ids = {str(x).strip() for x in wl.get("allowed_specir_ids", set()) if str(x).strip()}
    allowed_rules = {str(x).strip() for x in wl.get("allowed_rules", set()) if str(x).strip()}
    allowed_components = {str(x).strip() for x in wl.get("allowed_components", set()) if str(x).strip()}
    allowed_gates = {str(x).strip() for x in wl.get("allowed_gates", set()) if str(x).strip()}
    allowed_normrefs = {str(x).strip() for x in wl.get("allowed_normRefs", set()) if str(x).strip()}

    selected_slot_key_set = {str(x).strip() for x in (selected_slot_keys or []) if str(x).strip()}
    selected_slot_key_norm_set = {x.lower() for x in selected_slot_key_set}
    selected_specir_id_set = {str(x).strip() for x in (selected_specir_ids or []) if str(x).strip()}

    removed_reason: Dict[str, int] = {}

    def _mark(reason: str) -> None:
        removed_reason[reason] = int(removed_reason.get(reason, 0) or 0) + 1

    filtered_rules: List[Dict[str, Any]] = []
    for r in rules_rows:
        if not isinstance(r, dict):
            continue
        rule_id = str(r.get("rule_id") or r.get("ruleId") or "").strip()
        component_id = str(r.get("component_id") or r.get("componentId") or "").strip()
        specir_id = str(r.get("specir_id") or r.get("source_specir_id") or "").strip()
        norm_ref = str(r.get("norm_ref") or r.get("normRef") or "").strip()
        field = str(r.get("field") or r.get("slotKey") or r.get("slot_key") or "").strip()
        field_norm = field.lower()
        component_norm = component_id.lower()
        if allowed_rules and rule_id not in allowed_rules:
            _mark("rule_not_in_allowed_rules")
            continue
        if allowed_normrefs and norm_ref and norm_ref not in allowed_normrefs:
            _mark("unrelated_clause_normref_not_allowed")
            continue
        if allowed_components and component_id and component_id not in allowed_components:
            _mark("component_not_in_allowed_components")
            continue
        if selected_slot_key_norm_set and field_norm and field_norm not in selected_slot_key_norm_set and component_norm not in selected_slot_key_norm_set:
            _mark("rule_not_in_selected_slotKeys")
            continue
        if selected_slot_key_norm_set and not field_norm and component_norm not in selected_slot_key_norm_set:
            _mark("unrelated_slot")
            continue
        if selected_specir_id_set and specir_id and specir_id not in selected_specir_id_set:
            _mark("rule_not_in_selected_specir_ids")
            continue
        if allowed_specir_ids and specir_id and specir_id not in allowed_specir_ids:
            _mark("specir_not_in_allowed_specir_ids")
            continue
        filtered_rules.append(r)

    selected_rule_ids = {
        str(r.get("rule_id") or r.get("ruleId") or "").strip()
        for r in filtered_rules
        if str(r.get("rule_id") or r.get("ruleId") or "").strip()
    }
    filtered_gates: List[Dict[str, Any]] = []
    for g in gates_rows:
        if not isinstance(g, dict):
            continue
        gate_id = str(g.get("gate_id") or g.get("id") or "").strip()
        gate_rule_ids = _gate_rule_ids(g)
        if not any(rid in selected_rule_ids for rid in gate_rule_ids):
            _mark("gate_without_selected_rules")
            continue
        if any(rid not in selected_rule_ids for rid in gate_rule_ids):
            _mark("gate_partially_outside_selected_rules")
            continue
        if allowed_gates and gate_id and gate_id not in allowed_gates:
            _mark("gate_not_in_allowed_gates")
            continue
        filtered_gates.append(g)

    gate_linked_rule_ids = set()
    for g in filtered_gates:
        gate_linked_rule_ids.update([rid for rid in _gate_rule_ids(g) if rid in selected_rule_ids])
    filtered_rules = [
        r for r in filtered_rules
        if str(r.get("rule_id") or r.get("ruleId") or "").strip() in gate_linked_rule_ids
    ]

    selected_component_ids = {
        str(r.get("component_id") or r.get("componentId") or "").strip()
        for r in filtered_rules
        if str(r.get("component_id") or r.get("componentId") or "").strip()
    }
    filtered_components: List[Dict[str, Any]] = []
    for c in comp_rows:
        if not isinstance(c, dict):
            continue
        component_id = str(c.get("component_id") or c.get("id") or "").strip()
        comp_specir_id = str(c.get("specir_id") or "").strip()
        if component_id not in selected_component_ids:
            _mark("component_not_referenced_by_gate_chain")
            continue
        if allowed_components and component_id and component_id not in allowed_components:
            _mark("component_not_in_allowed_components")
            continue
        if selected_specir_id_set and comp_specir_id and comp_specir_id not in selected_specir_id_set:
            _mark("component_not_in_selected_specir_ids")
            continue
        if allowed_specir_ids and comp_specir_id and comp_specir_id not in allowed_specir_ids:
            _mark("component_specir_not_allowed")
            continue
        filtered_components.append(c)

    selected_component_ids = {
        str(c.get("component_id") or c.get("id") or "").strip()
        for c in filtered_components
        if str(c.get("component_id") or c.get("id") or "").strip()
    }
    filtered_rules = [
        r for r in filtered_rules
        if str(r.get("component_id") or r.get("componentId") or "").strip() in selected_component_ids
    ]
    selected_rule_ids = {
        str(r.get("rule_id") or r.get("ruleId") or "").strip()
        for r in filtered_rules
        if str(r.get("rule_id") or r.get("ruleId") or "").strip()
    }
    filtered_gates = [
        g for g in filtered_gates
        if all(rid in selected_rule_ids for rid in _gate_rule_ids(g))
    ]

    def _proof_ref_ids(row: Dict[str, Any]) -> set[str]:
        refs: set[str] = set()
        for key in ("proof_template_id", "proof_id", "template_id"):
            val = str(row.get(key) or "").strip()
            if val:
                refs.add(val)
        raw_refs = row.get("proof_template_refs") or row.get("proof_refs")
        if isinstance(raw_refs, list):
            for item in raw_refs:
                val = str(item).strip()
                if val:
                    refs.add(val)
        return refs

    referenced_proof_ids: set[str] = set()
    for row in filtered_rules:
        referenced_proof_ids.update(_proof_ref_ids(row))
    for row in filtered_gates:
        referenced_proof_ids.update(_proof_ref_ids(row))
    for row in filtered_components:
        referenced_proof_ids.update(_proof_ref_ids(row))

    filtered_proof_templates: List[Dict[str, Any]] = []
    for p in proof_rows:
        if not isinstance(p, dict):
            continue
        pid = str(p.get("proof_id") or p.get("proof_template_id") or p.get("id") or "").strip()
        if referenced_proof_ids and pid and pid not in referenced_proof_ids:
            _mark("proof_template_not_referenced_by_component_rule_gate")
            continue
        if selected_specir_id_set:
            psid = str(p.get("specir_id") or "").strip()
            if psid and psid not in selected_specir_id_set:
                _mark("proof_template_not_in_selected_specir_ids")
                continue
        filtered_proof_templates.append(p)

    selected_specir_from_rules = {
        str(r.get("specir_id") or r.get("source_specir_id") or "").strip()
        for r in filtered_rules
        if str(r.get("specir_id") or r.get("source_specir_id") or "").strip()
    }
    selected_slots_from_rules = {
        str(r.get("field") or r.get("slotKey") or r.get("slot_key") or "").strip()
        for r in filtered_rules
        if str(r.get("field") or r.get("slotKey") or r.get("slot_key") or "").strip()
    }
    removed_specir_noise = 0
    if selected_specir_id_set:
        removed_specir_noise = len([sid for sid in selected_specir_id_set if sid and sid not in selected_specir_from_rules])
        if removed_specir_noise > 0:
            removed_reason["selected_specir_without_rule_reference"] = removed_specir_noise
    pre_rules = int((norm_layer.get("counts", {}) if isinstance(norm_layer.get("counts", {}), dict) else {}).get("rules", 0) or 0)
    pre_gates = int((norm_layer.get("counts", {}) if isinstance(norm_layer.get("counts", {}), dict) else {}).get("gates", 0) or 0)
    pre_components = int((norm_layer.get("counts", {}) if isinstance(norm_layer.get("counts", {}), dict) else {}).get("components", 0) or 0)
    pre_proofs = int((norm_layer.get("counts", {}) if isinstance(norm_layer.get("counts", {}), dict) else {}).get("proof_templates", 0) or 0)
    post_rules = len(filtered_rules)
    post_gates = len(filtered_gates)
    post_components = len(filtered_components)
    post_proofs = len(filtered_proof_templates)
    filtered_out_counts = {
        "rules": max(pre_rules - post_rules, 0),
        "gates": max(pre_gates - post_gates, 0),
        "components": max(pre_components - post_components, 0),
        "proof_templates": max(pre_proofs - post_proofs, 0),
        "specir": removed_specir_noise,
    }
    filtered_out_counts["total"] = int(
        filtered_out_counts["rules"]
        + filtered_out_counts["gates"]
        + filtered_out_counts["components"]
        + filtered_out_counts["proof_templates"]
        + filtered_out_counts["specir"]
    )
    return {
        "rules": filtered_rules,
        "gates": filtered_gates,
        "components": filtered_components,
        "proof_templates": filtered_proof_templates,
        "selected_rule_ids": selected_rule_ids,
        "selected_component_ids": selected_component_ids,
        "pre_counts": norm_layer.get("counts", {}),
        "post_counts": {
            "rules": post_rules,
            "gates": post_gates,
            "components": post_components,
            "proof_templates": post_proofs,
            "specir": len(selected_specir_from_rules),
            "slots": len(selected_slots_from_rules),
        },
        "filtered_out_counts": filtered_out_counts,
        "removed_reason": removed_reason,
    }


def _stable_rule_fingerprint(rule: Dict[str, Any]) -> str:
    base = {
        "rule_id": str(rule.get("rule_id") or rule.get("id") or "").strip(),
        "component_id": str(rule.get("component_id") or "").strip(),
        "field": str(rule.get("field") or "").strip(),
        "operator": str(rule.get("operator") or "").strip(),
        "threshold": rule.get("threshold"),
        "unit": str(rule.get("unit") or "").strip(),
        "condition": str(rule.get("condition") or "").strip(),
        "norm_ref": str(rule.get("norm_ref") or rule.get("normRef") or "").strip(),
        "source_clause": str(rule.get("source_clause") or rule.get("source_clause_id") or "").strip(),
    }
    return _stable_json_hash(base)


def _build_traceability_payload(
    *,
    job_id: str,
    form_code: str,
    spec_version: str,
    normalized_rules: List[Dict[str, Any]],
    gates_payload: List[Dict[str, Any]],
    specir_items: List[Dict[str, Any]],
    rulepack_name: str,
) -> Dict[str, Any]:
    specir_by_id: Dict[str, Dict[str, Any]] = {}
    for row in specir_items:
        if not isinstance(row, dict):
            continue
        sid = str(row.get("specir_id") or row.get("component_id") or "").strip()
        if sid:
            specir_by_id[sid] = row

    rules_by_id: Dict[str, Dict[str, Any]] = {}
    for r in normalized_rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("ruleId") or r.get("id") or "").strip()
        if rid:
            rules_by_id[rid] = r

    gate_rows: List[Dict[str, Any]] = []
    for g in gates_payload:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip()
        if not gid:
            continue
        rule_refs = [str(x).strip() for x in _gate_rule_ids(g) if str(x).strip()]
        specir_refs = sorted(
            list(
                set(
                    [
                        str((rules_by_id.get(rid, {}) if isinstance(rules_by_id.get(rid, {}), dict) else {}).get("source_specir_id")
                            or (rules_by_id.get(rid, {}) if isinstance(rules_by_id.get(rid, {}), dict) else {}).get("specir_id")
                            or "").strip()
                        for rid in rule_refs
                    ]
                )
            )
        )
        specir_refs = [x for x in specir_refs if x]
        slot_keys = sorted(
            list(
                set(
                    [
                        str((rules_by_id.get(rid, {}) if isinstance(rules_by_id.get(rid, {}), dict) else {}).get("slotKey")
                            or (rules_by_id.get(rid, {}) if isinstance(rules_by_id.get(rid, {}), dict) else {}).get("field")
                            or "").strip()
                        for rid in rule_refs
                    ]
                )
            )
        )
        slot_keys = [x for x in slot_keys if x]
        gate_rows.append(
            {
                "gate_id": gid,
                "rule_refs": rule_refs,
                "specir_refs": specir_refs,
                "slotKeys": slot_keys,
            }
        )

    rule_rows: List[Dict[str, Any]] = []
    for rid, r in rules_by_id.items():
        sid = str(r.get("source_specir_id") or r.get("specir_id") or "").strip()
        hit = specir_by_id.get(sid, {}) if sid else {}
        evidence = hit.get("evidence", {}) if isinstance(hit, dict) and isinstance(hit.get("evidence"), dict) else {}
        rule_rows.append(
            {
                "rule_id": rid,
                "specir_id": sid,
                "normRef": str(r.get("norm_ref") or r.get("normRef") or hit.get("normRef") or "").strip(),
                "source_text": str(r.get("source_text") or evidence.get("original_text") or "").strip(),
                "page": r.get("source_page"),
                "standard_version": str(r.get("source_spec_version") or spec_version or "").strip(),
                "slotKey": str(r.get("slotKey") or r.get("field") or "").strip(),
            }
        )

    specir_rule_ids: Dict[str, List[str]] = {}
    specir_gate_ids: Dict[str, List[str]] = {}
    for rr in rule_rows:
        sid = str(rr.get("specir_id") or "").strip()
        rid = str(rr.get("rule_id") or "").strip()
        if sid and rid:
            specir_rule_ids.setdefault(sid, []).append(rid)
    for gg in gate_rows:
        gid = str(gg.get("gate_id") or "").strip()
        for sid in gg.get("specir_refs", []) if isinstance(gg.get("specir_refs"), list) else []:
            ss = str(sid).strip()
            if ss and gid:
                specir_gate_ids.setdefault(ss, []).append(gid)

    specir_rows: List[Dict[str, Any]] = []
    for sid, item in specir_by_id.items():
        specir_rows.append(
            {
                "specir_id": sid,
                "derived_rules": sorted(list(set(specir_rule_ids.get(sid, [])))),
                "derived_gates": sorted(list(set(specir_gate_ids.get(sid, [])))),
                "used_forms": [form_code] if form_code else [],
                "published_rulepacks": [rulepack_name] if rulepack_name else [],
            }
        )

    timeline: List[Dict[str, Any]] = []
    for rr in rule_rows:
        timeline.append({"type": "rule_trace", "id": str(rr.get("rule_id") or ""), "at": _utc_now(), "data": rr})
    for gg in gate_rows:
        timeline.append({"type": "gate_trace", "id": str(gg.get("gate_id") or ""), "at": _utc_now(), "data": gg})
    for ss in specir_rows:
        timeline.append({"type": "specir_trace", "id": str(ss.get("specir_id") or ""), "at": _utc_now(), "data": ss})

    return {
        "schema_version": "traceability.v1",
        "generated_at": _utc_now(),
        "job_id": job_id,
        "form_code": form_code,
        "rulepack_name": rulepack_name,
        "rules": rule_rows,
        "gates": gate_rows,
        "specir": specir_rows,
        "timeline": timeline,
    }


def _find_latest_rulepack_for_form(form_code: str, *, exclude_job_id: str = "") -> Optional[Path]:
    if not NORMREF_RULEPACK_DIR.exists():
        return None
    rows: List[Tuple[float, Path]] = []
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {})
        if not isinstance(meta, dict):
            continue
        if str(meta.get("form_code") or "").strip() != str(form_code).strip():
            continue
        if exclude_job_id and str(meta.get("job_id") or "").strip() == str(exclude_job_id).strip():
            continue
        rows.append((p.stat().st_mtime, p.resolve()))
    if not rows:
        return None
    rows.sort(key=lambda x: x[0], reverse=True)
    return rows[0][1]


def _find_rulepack_paths_by_job(job_id: str) -> List[Path]:
    if not NORMREF_RULEPACK_DIR.exists():
        return []
    token = f"-{str(job_id).strip()}.rulepack.json"
    rows = [p.resolve() for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json") if p.is_file() and p.name.endswith(token)]
    rows.sort(key=lambda x: x.stat().st_mtime, reverse=True)
    return rows


def _build_rulepack_audit_report(
    *,
    job_id: str,
    form_code: str,
    norm_version: str,
    pre_counts: Dict[str, Any],
    selected_components_count: int,
    selected_rules: List[Dict[str, Any]],
    selected_gates_count: int,
    unresolved_count: int,
) -> Dict[str, Any]:
    selected_rules_count = len([x for x in selected_rules if isinstance(x, dict)])
    current_rule_map: Dict[str, str] = {}
    for r in selected_rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip()
        if rid:
            current_rule_map[rid] = _stable_rule_fingerprint(r)

    previous = _find_latest_rulepack_for_form(form_code, exclude_job_id=job_id)
    prev_rule_map: Dict[str, str] = {}
    if previous is not None:
        try:
            prev_doc = json.loads(previous.read_text(encoding="utf-8"))
            prev_rules = prev_doc.get("rules", []) if isinstance(prev_doc, dict) else []
            if isinstance(prev_rules, list):
                for r in prev_rules:
                    if not isinstance(r, dict):
                        continue
                    rid = str(r.get("rule_id") or r.get("id") or "").strip()
                    if rid:
                        prev_rule_map[rid] = _stable_rule_fingerprint(r)
        except Exception:
            prev_rule_map = {}

    added = sorted([rid for rid in current_rule_map.keys() if rid not in prev_rule_map])
    removed = sorted([rid for rid in prev_rule_map.keys() if rid not in current_rule_map])
    changed = sorted([rid for rid in current_rule_map.keys() if rid in prev_rule_map and current_rule_map[rid] != prev_rule_map[rid]])

    pre_rules = int(pre_counts.get("rules", 0) or 0)
    pre_gates = int(pre_counts.get("gates", 0) or 0)
    pre_components = int(pre_counts.get("components", 0) or 0)
    filtered_out_detail = {
        "rules": max(pre_rules - selected_rules_count, 0),
        "gates": max(pre_gates - int(selected_gates_count or 0), 0),
        "components": max(pre_components - int(selected_components_count or 0), 0),
    }
    filtered_out_count = int(filtered_out_detail["rules"] + filtered_out_detail["gates"] + filtered_out_detail["components"])
    return {
        "job_id": job_id,
        "form_code": form_code,
        "norm_version": norm_version,
        "selected_components_count": selected_components_count,
        "selected_rules_count": selected_rules_count,
        "selected_gates_count": selected_gates_count,
        "filtered_out_count": filtered_out_count,
        "filtered_out_detail": filtered_out_detail,
        "added_rules": added,
        "removed_rules": removed,
        "changed_rules": changed,
        "unresolved_count": int(unresolved_count or 0),
        "baseline_rulepack": str(previous) if previous else "",
        "generated_at": _utc_now(),
    }


def _build_rulepack_size_governance_report(*, form_code: str, job_id: str, current_path: Path) -> Dict[str, Any]:
    current_size_bytes = int(current_path.stat().st_size) if current_path.exists() else 0
    current_doc: Dict[str, Any] = {}
    try:
        obj = json.loads(current_path.read_text(encoding="utf-8"))
        current_doc = obj if isinstance(obj, dict) else {}
    except Exception:
        current_doc = {}
    current_components = current_doc.get("components", []) if isinstance(current_doc.get("components"), list) else []
    current_rules = current_doc.get("rules", []) if isinstance(current_doc.get("rules"), list) else []
    current_gates = current_doc.get("gates", []) if isinstance(current_doc.get("gates"), list) else []
    current_metrics = {
        "component_count": len(current_components),
        "rule_count": len(current_rules),
        "gate_count": len(current_gates),
        "file_size_kb": round(float(current_size_bytes) / 1024.0, 3),
        "file_size_bytes": current_size_bytes,
    }

    previous = _find_latest_rulepack_for_form(form_code, exclude_job_id=job_id)
    previous_path = str(previous.resolve()) if previous is not None else ""
    previous_metrics: Dict[str, Any] = {}
    growth: Dict[str, Any] = {}
    if previous is not None and previous.exists():
        prev_doc: Dict[str, Any] = {}
        try:
            pobj = json.loads(previous.read_text(encoding="utf-8"))
            prev_doc = pobj if isinstance(pobj, dict) else {}
        except Exception:
            prev_doc = {}
        prev_components = prev_doc.get("components", []) if isinstance(prev_doc.get("components"), list) else []
        prev_rules = prev_doc.get("rules", []) if isinstance(prev_doc.get("rules"), list) else []
        prev_gates = prev_doc.get("gates", []) if isinstance(prev_doc.get("gates"), list) else []
        prev_size_bytes = int(previous.stat().st_size)
        previous_metrics = {
            "component_count": len(prev_components),
            "rule_count": len(prev_rules),
            "gate_count": len(prev_gates),
            "file_size_kb": round(float(prev_size_bytes) / 1024.0, 3),
            "file_size_bytes": prev_size_bytes,
        }
        for key in ("component_count", "rule_count", "gate_count", "file_size_bytes"):
            cur = float(current_metrics.get(key, 0) or 0)
            prev = float(previous_metrics.get(key, 0) or 0)
            if prev > 0:
                ratio = (cur - prev) / prev
                growth[key] = {"delta": cur - prev, "growth_ratio": ratio, "growth_percent": round(ratio * 100.0, 4)}
            else:
                growth[key] = {"delta": cur, "growth_ratio": None, "growth_percent": None}
    else:
        growth = {
            "component_count": {"delta": current_metrics["component_count"], "growth_ratio": None, "growth_percent": None},
            "rule_count": {"delta": current_metrics["rule_count"], "growth_ratio": None, "growth_percent": None},
            "gate_count": {"delta": current_metrics["gate_count"], "growth_ratio": None, "growth_percent": None},
            "file_size_bytes": {"delta": current_metrics["file_size_bytes"], "growth_ratio": None, "growth_percent": None},
        }

    over_30: List[str] = []
    for key in ("component_count", "rule_count", "gate_count", "file_size_bytes"):
        ratio = growth.get(key, {}).get("growth_ratio")
        if isinstance(ratio, (int, float)) and float(ratio) > 0.30:
            over_30.append(key)
    warning = len(over_30) > 0
    block = len(over_30) > 0
    return {
        "schema_version": "rulepack_size_report.v1",
        "generated_at": _utc_now(),
        "job_id": job_id,
        "form_code": form_code,
        "growth_threshold": 0.30,
        "warning": warning,
        "block": block,
        "over_growth_metrics": over_30,
        "current": current_metrics,
        "previous": previous_metrics,
        "growth": growth,
        "previous_rulepack_path": previous_path,
        "current_rulepack_path": str(current_path.resolve()),
    }


def _publish_gate_check_rulepacks(job_id: str) -> Dict[str, Any]:
    blockers: List[str] = []
    alerts: List[str] = []
    checked: List[Dict[str, Any]] = []
    rollback_forms: List[str] = []
    paths = _find_rulepack_paths_by_job(job_id)
    if not paths:
        blockers.append("未找到该 job 的 rulepack 产物")
        out = {"ok": False, "blockers": blockers, "alerts": alerts, "checked": checked, "rollback_required": False, "rollback_forms": []}
        qg_path = _artifact_dir_for_job(job_id) / "quality_gate_result.json"
        qg_path.parent.mkdir(parents=True, exist_ok=True)
        qg_path.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
        return out
    guard = _load_publish_guardrails()
    # Quality redline: rulepack abnormal growth > 30% blocks publish.
    max_ratio = 1.3
    max_growth = int(guard.get("max_size_growth_bytes", 1048576) or 1048576)
    critical_map = guard.get("critical_gates", {}) if isinstance(guard.get("critical_gates"), dict) else {}
    unresolved_threshold = int((_load_system_config().get("unresolved_block_threshold", 0) if isinstance(_load_system_config(), dict) else 0) or 0)

    for p in paths:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            blockers.append(f"{p.name}: 非法 JSON")
            continue
        if not isinstance(doc, dict):
            blockers.append(f"{p.name}: 顶层结构非法")
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        form_code = str(meta.get("form_code") or "").strip()
        rules = doc.get("rules", []) if isinstance(doc.get("rules"), list) else []
        gates = doc.get("gates", []) if isinstance(doc.get("gates"), list) else []
        unresolved = doc.get("unresolved", {}) if isinstance(doc.get("unresolved"), dict) else {}
        mg = doc.get("measurement_gate_mapping", {}) if isinstance(doc.get("measurement_gate_mapping"), dict) else {}
        cov = doc.get("docpeg_coverage", {}) if isinstance(doc.get("docpeg_coverage"), dict) else {}
        schema_validation = doc.get("schema_validation", {}) if isinstance(doc.get("schema_validation"), dict) else {}
        e2e_validation = doc.get("e2e_validation", {}) if isinstance(doc.get("e2e_validation"), dict) else {}
        golden_compare = doc.get("golden_compare", {}) if isinstance(doc.get("golden_compare"), dict) else {}
        gate_regression = doc.get("gate_regression", {}) if isinstance(doc.get("gate_regression"), dict) else {}
        runtime_regression = doc.get("runtime_regression", {}) if isinstance(doc.get("runtime_regression"), dict) else {}
        missing_gate_report = doc.get("missing_gate_governance", {}) if isinstance(doc.get("missing_gate_governance"), dict) else {}

        # 1. schema
        if not bool(schema_validation.get("valid", False)):
            blockers.append(f"{p.name}: Schema 校验未通过")
        # 2/3 counts
        if len(rules) <= 0:
            blockers.append(f"{p.name}: rule_count <= 0")
        if len(gates) <= 0:
            blockers.append(f"{p.name}: gate_count <= 0")
        # 4 unresolved
        unresolved_count = int(unresolved.get("count", 0) or 0)
        if unresolved_count > unresolved_threshold:
            blockers.append(f"{p.name}: unresolved_count={unresolved_count} (阈值={unresolved_threshold})")
        # 5 missing gate ref (redline: rate > 0 blocks)
        missing_count = int(mg.get("missing_count", 0) or 0)
        missing_rate = float(cov.get("missing_gateRef_rate", 0.0) or 0.0)
        if missing_rate > 0.0 or missing_count != 0:
            blockers.append(
                f"{p.name}: gateRef 缺失率={missing_rate:.6f} (redline > 0), missing_gateRef_count={missing_count}"
            )
        governance_missing_rate = float(missing_gate_report.get("missing_gate_rate", 0.0) or 0.0)
        if governance_missing_rate > 0.0:
            blockers.append(
                f"{p.name}: missing_gate_rate={governance_missing_rate:.6f} (>0, 阻断发布)"
            )

        # 6 size anomaly
        prev = _find_latest_rulepack_for_form(form_code, exclude_job_id=job_id)
        cur_size = p.stat().st_size
        if prev is not None:
            try:
                prev_size = prev.stat().st_size
                growth = cur_size - prev_size
                ratio = (cur_size / prev_size) if prev_size > 0 else 9999.0
                if ratio > max_ratio:
                    alerts.append(
                        f"{p.name}: rulepack size 增长异常 ratio={ratio:.4f} (>1.3), growth={growth}, cur={cur_size}, prev={prev_size}"
                    )
                    blockers.append(
                        f"{p.name}: rulepack 大小异常增长 >30% (cur={cur_size}, prev={prev_size}, growth={growth}, ratio={ratio:.4f})"
                    )
            except Exception:
                pass

        # 7 critical gate smoke
        required_gates = critical_map.get(form_code, [])
        if isinstance(required_gates, list) and required_gates:
            gate_ids = {
                str(g.get("gate_id") or g.get("id") or "").strip()
                for g in gates
                if isinstance(g, dict)
            }
            miss = [str(x).strip() for x in required_gates if str(x).strip() and str(x).strip() not in gate_ids]
            if miss:
                blockers.append(f"{p.name}: 关键 Gate 冒烟失败，缺失 {', '.join(miss)}")
        # 8 e2e validation
        sample_cfg = _load_rulepack_e2e_sample(form_code)
        if sample_cfg:
            if not e2e_validation:
                blockers.append(f"{p.name}: 缺少 e2e_validation 结果")
            elif not bool(e2e_validation.get("passed", False)):
                blockers.append(
                    f"{p.name}: E2E 校验失败 (expected={e2e_validation.get('expected')}, actual={e2e_validation.get('actual')})"
                )
            # Redline: key-field misjudgment rate > 1% triggers rollback.
            expected = e2e_validation.get("expected", {}) if isinstance(e2e_validation.get("expected"), dict) else {}
            actual = e2e_validation.get("actual", {}) if isinstance(e2e_validation.get("actual"), dict) else {}
            total_cases = 0
            mismatch = 0
            for k in ("pass_case", "fail_case"):
                if str(expected.get(k) or "").strip():
                    total_cases += 1
                    if str(expected.get(k) or "").strip().upper() != str(actual.get(k) or "").strip().upper():
                        mismatch += 1
            misjudge_rate = (float(mismatch) / float(total_cases)) if total_cases > 0 else 0.0
            if misjudge_rate > 0.01:
                if form_code and form_code not in rollback_forms:
                    rollback_forms.append(form_code)
                alerts.append(
                    f"{p.name}: 关键字段误判率={misjudge_rate:.6f} (>0.01), mismatch={mismatch}/{total_cases}，触发回滚"
                )
        # 9 golden set mismatch (key fields) blocks publish
        if bool(golden_compare.get("enabled", False)) and bool(golden_compare.get("has_key_mismatch", False)):
            rows = golden_compare.get("key_mismatches", []) if isinstance(golden_compare.get("key_mismatches"), list) else []
            sample = ", ".join(
                [
                    f"{str(x.get('field_name') or '-')}/{str(x.get('type') or '-')}"
                    for x in rows[:8]
                    if isinstance(x, dict)
                ]
            )
            blockers.append(f"{p.name}: golden_key_mismatch={len(rows)} ({sample})")
        # 10 gate regression
        if gate_regression:
            if not bool(gate_regression.get("passed", False)):
                fail_rows = gate_regression.get("failures", []) if isinstance(gate_regression.get("failures"), list) else []
                sample = ", ".join(
                    [f"{str(x.get('gate_id') or '-')}" for x in fail_rows[:8] if isinstance(x, dict)]
                )
                blockers.append(f"{p.name}: gate_regression_failed={len(fail_rows)} ({sample})")
        # 11 runtime regression
        if runtime_regression:
            if not bool(runtime_regression.get("passed", False)):
                blockers.append(
                    f"{p.name}: runtime_regression_failed="
                    f"{int(runtime_regression.get('failed_samples', 0) or 0)}/"
                    f"{int(runtime_regression.get('total_samples', 0) or 0)}"
                )

        checked.append(
            {
                "rulepack": p.name,
                "form_code": form_code,
                "rule_count": len(rules),
                "gate_count": len(gates),
                "unresolved_count": unresolved_count,
                "missing_gateRef_count": missing_count,
                "missing_gateRef_rate": missing_rate,
                "schema_valid": bool(schema_validation.get("valid", False)),
                "e2e_passed": bool(e2e_validation.get("passed", False)) if e2e_validation else None,
                "golden_compare_passed": bool(golden_compare.get("passed", True)) if golden_compare else None,
                "gate_regression_passed": bool(gate_regression.get("passed", False)) if gate_regression else None,
                "runtime_regression_passed": bool(runtime_regression.get("passed", False)) if runtime_regression else None,
                "missing_gate_rate": governance_missing_rate,
                "size_bytes": cur_size,
            }
        )
    integrity_report = _build_asset_integrity_report(job_id)
    if str(integrity_report.get("publish_status") or "").strip() == "blocked":
        blockers.append("Asset integrity check failed")
        summary = integrity_report.get("summary", {}) if isinstance(integrity_report.get("summary"), dict) else {}
        blockers.append(
            "integrity: "
            f"dangling_specir_refs={int(summary.get('dangling_specir_refs', 0) or 0)}, "
            f"dangling_rule_refs={int(summary.get('dangling_rule_refs', 0) or 0)}, "
            f"dangling_gate_refs={int(summary.get('dangling_gate_refs', 0) or 0)}, "
            f"dangling_slot_refs={int(summary.get('dangling_slot_refs', 0) or 0)}, "
            f"unused_components={int(summary.get('unused_components', 0) or 0)}, "
            f"duplicate_rules={int(summary.get('duplicate_rules', 0) or 0)}, "
            f"duplicate_gates={int(summary.get('duplicate_gates', 0) or 0)}"
        )
    out = {
        "ok": len(blockers) == 0,
        "blockers": blockers,
        "alerts": alerts,
        "checked": checked,
        "rollback_required": len(rollback_forms) > 0,
        "rollback_forms": rollback_forms,
        "asset_integrity": integrity_report,
    }
    qg_path = _artifact_dir_for_job(job_id) / "quality_gate_result.json"
    qg_path.parent.mkdir(parents=True, exist_ok=True)
    qg_path.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    out["quality_gate_result_path"] = str(qg_path.resolve())
    return out


def _production_publish_gate_check(job_id: str) -> Dict[str, Any]:
    blockers: List[str] = []
    checks: Dict[str, Any] = {}
    checked: List[Dict[str, Any]] = []
    paths = _find_rulepack_paths_by_job(job_id)
    unresolved_threshold = int((_load_system_config().get("unresolved_block_threshold", 0) if isinstance(_load_system_config(), dict) else 0) or 0)
    if not paths:
        blockers.append("未找到该 job 的 rulepack 产物")
    key_total = 0
    key_match = 0
    for p in paths:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            blockers.append(f"{p.name}: 非法 JSON")
            continue
        if not isinstance(doc, dict):
            blockers.append(f"{p.name}: 顶层结构非法")
            continue
        schema_validation = doc.get("schema_validation", {}) if isinstance(doc.get("schema_validation"), dict) else {}
        unresolved = doc.get("unresolved", {}) if isinstance(doc.get("unresolved"), dict) else {}
        cov = doc.get("docpeg_coverage", {}) if isinstance(doc.get("docpeg_coverage"), dict) else {}
        mg = doc.get("measurement_gate_mapping", {}) if isinstance(doc.get("measurement_gate_mapping"), dict) else {}
        golden_compare = doc.get("golden_compare", {}) if isinstance(doc.get("golden_compare"), dict) else {}
        gate_regression = doc.get("gate_regression", {}) if isinstance(doc.get("gate_regression"), dict) else {}
        runtime_regression = doc.get("runtime_regression", {}) if isinstance(doc.get("runtime_regression"), dict) else {}
        e2e = doc.get("e2e_validation", {}) if isinstance(doc.get("e2e_validation"), dict) else {}

        schema_valid = bool(schema_validation.get("valid", False))
        unresolved_count = int(unresolved.get("count", 0) or 0)
        missing_gate_ref_count = int(mg.get("missing_count", 0) or 0)
        gate_coverage_rate = float(cov.get("gate_coverage_rate", 0.0) or 0.0)
        golden_set_pass = bool(golden_compare.get("passed", True)) if golden_compare else True
        gate_regression_pass = bool(gate_regression.get("passed", False)) if gate_regression else False
        runtime_regression_pass = bool(runtime_regression.get("passed", False)) if runtime_regression else False
        regression_pass = bool(gate_regression_pass and runtime_regression_pass)

        expected = e2e.get("expected", {}) if isinstance(e2e.get("expected"), dict) else {}
        actual = e2e.get("actual", {}) if isinstance(e2e.get("actual"), dict) else {}
        local_total = 0
        local_match = 0
        for k in ("pass_case", "fail_case"):
            if str(expected.get(k) or "").strip():
                local_total += 1
                if str(expected.get(k) or "").strip().upper() == str(actual.get(k) or "").strip().upper():
                    local_match += 1
        key_total += local_total
        key_match += local_match

        checked.append(
            {
                "rulepack": p.name,
                "schema_valid": schema_valid,
                "unresolved_count": unresolved_count,
                "missing_gateRef_count": missing_gate_ref_count,
                "gate_coverage_rate": gate_coverage_rate,
                "golden_set_pass": golden_set_pass,
                "gate_regression_pass": gate_regression_pass,
                "runtime_regression_pass": runtime_regression_pass,
                "regression_pass": regression_pass,
                "key_field_total": local_total,
                "key_field_match": local_match,
                "key_field_accuracy": (float(local_match) / float(local_total)) if local_total > 0 else 1.0,
            }
        )

    schema_valid_all = bool(paths) and (all(bool(x.get("schema_valid", False)) for x in checked) if checked else False)
    unresolved_zero_all = all(int(x.get("unresolved_count", 0) or 0) <= unresolved_threshold for x in checked) if checked else False
    missing_gate_ref_zero_all = all(int(x.get("missing_gateRef_count", 0) or 0) == 0 for x in checked) if checked else False
    min_gate_coverage = min([float(x.get("gate_coverage_rate", 0.0) or 0.0) for x in checked], default=0.0)
    gate_coverage_ok = min_gate_coverage >= 0.98
    key_field_accuracy = (float(key_match) / float(key_total)) if key_total > 0 else 1.0
    key_field_accuracy_ok = key_field_accuracy >= 0.99
    golden_set_pass_all = all(bool(x.get("golden_set_pass", False)) for x in checked) if checked else False
    regression_pass_all = all(bool(x.get("regression_pass", False)) for x in checked) if checked else False

    checks["schema_valid"] = schema_valid_all
    checks["unresolved_count_threshold_ok"] = unresolved_zero_all
    checks["missing_gateRef_count_zero"] = missing_gate_ref_zero_all
    checks["gate_coverage_rate_gte_98pct"] = gate_coverage_ok
    checks["key_field_accuracy_gte_99pct"] = key_field_accuracy_ok
    checks["golden_set_pass"] = golden_set_pass_all
    checks["regression_pass"] = regression_pass_all

    if not schema_valid_all:
        blockers.append("Schema valid 检查失败")
    if not unresolved_zero_all:
        blockers.append(f"unresolved_count > threshold({unresolved_threshold})")
    if not missing_gate_ref_zero_all:
        blockers.append("missing_gateRef_count != 0")
    if not gate_coverage_ok:
        blockers.append(f"gate_coverage_rate < 98% (min={min_gate_coverage:.4f})")
    if not key_field_accuracy_ok:
        blockers.append(f"key_field_accuracy < 99% (actual={key_field_accuracy:.4f})")
    if not golden_set_pass_all:
        blockers.append("golden_set_pass != true")
    if not regression_pass_all:
        blockers.append("regression_pass != true")

    out = {
        "ok": len(blockers) == 0,
        "publish_status": "ready" if len(blockers) == 0 else "blocked",
        "job_id": job_id,
        "checks": checks,
        "blockers": blockers,
        "summary": {
            "rulepack_count": len(checked),
            "min_gate_coverage_rate": min_gate_coverage,
            "key_field_accuracy": key_field_accuracy,
            "key_field_total": key_total,
            "key_field_match": key_match,
        },
        "checked": checked,
        "generated_at": _utc_now(),
    }
    report_path = _artifact_dir_for_job(job_id) / "publish_gate_report.json"
    report_path.parent.mkdir(parents=True, exist_ok=True)
    report_path.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    out["publish_gate_report_path"] = str(report_path.resolve())
    return out


def _check_candidate_signature_exists(candidate: Dict[str, Any]) -> bool:
    workflow = candidate.get("workflow") if isinstance(candidate.get("workflow"), dict) else {}
    chain = workflow.get("signature_chain", []) if isinstance(workflow.get("signature_chain"), list) else []
    if not chain:
        return False
    last = chain[-1] if isinstance(chain[-1], dict) else {}
    required = ["signer", "role", "timestamp", "specir_hash", "checklist_hash"]
    return all(str(last.get(k, "")).strip() for k in required)


def _final_publish_gate_check(job_id: str, req_signature: str) -> Dict[str, Any]:
    blockers: List[str] = []
    checks: Dict[str, Any] = {}

    # 1) Document IR validation pass
    index_path = _artifact_dir_for_job(job_id) / "00_pipeline_index.json"
    index_obj: Dict[str, Any] = {}
    if index_path.exists():
        try:
            index_obj = json.loads(index_path.read_text(encoding="utf-8-sig"))
        except Exception:
            blockers.append("Document IR validation fail: 00_pipeline_index.json 非法")
    else:
        blockers.append("Document IR validation fail: 缺少 00_pipeline_index.json")
    validations = index_obj.get("validations", {}) if isinstance(index_obj.get("validations"), dict) else {}
    doc_ir_keys = ["01_spec.json", "02_catalog.json", "03_clause_tree.json"]
    doc_ir_ok = True
    for key in doc_ir_keys:
        row = validations.get(key, {}) if isinstance(validations.get(key), dict) else {}
        if not bool(row.get("schema_valid", False)) or not bool(row.get("business_valid", False)):
            doc_ir_ok = False
            blockers.append(f"Document IR validation fail: {key} 未通过")
    checks["document_ir_validation_pass"] = doc_ir_ok

    # 2) SpecIR quality gate pass
    qg = _publish_gate_check_rulepacks(job_id)
    checks["specir_quality_gate_pass"] = bool(qg.get("ok", False))
    if not checks["specir_quality_gate_pass"]:
        for b in (qg.get("blockers", []) if isinstance(qg.get("blockers"), list) else []):
            blockers.append(f"SpecIR quality gate fail: {b}")

    # Candidate-level checks: 3/4/5
    package = _load_review_package(job_id)
    candidates = [c for c in package.get("candidates", []) if isinstance(c, dict)]
    approved = [c for c in candidates if _normalize_candidate_status(str(c.get("status", ""))) == "approved"]

    # 3) all SpecIR approved
    all_approved = len(candidates) > 0 and len(approved) == len(candidates)
    checks["all_specir_approved"] = all_approved
    if not all_approved:
        blockers.append(f"SpecIR approved fail: approved={len(approved)}, total={len(candidates)}")

    # 4) checklist completed
    checklist_ok = True
    for c in approved:
        try:
            _validate_specir_checklist_for_approve(c)
        except Exception:
            checklist_ok = False
            cid = str(c.get("candidate_id") or c.get("rule_id") or "-").strip()
            blockers.append(f"Checklist fail: candidate={cid}")
    checks["checklist_complete"] = checklist_ok

    # 5) signature exists
    sig_ok = bool(str(req_signature or "").strip())
    if not sig_ok:
        blockers.append("Signature fail: publish request signature 不能为空")
    for c in approved:
        if not _check_candidate_signature_exists(c):
            sig_ok = False
            cid = str(c.get("candidate_id") or c.get("rule_id") or "-").strip()
            blockers.append(f"Signature fail: candidate={cid} 缺少签字链")
    checks["signature_exists"] = sig_ok

    # 6) Rulepack schema valid
    schema_ok = True
    job_rulepacks = _find_rulepacks_by_job(job_id)
    if not job_rulepacks:
        schema_ok = False
        blockers.append("Rulepack schema fail: 未找到 rulepack 产物")
    for rp_path in job_rulepacks:
        try:
            rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
        except Exception:
            schema_ok = False
            blockers.append(f"Rulepack schema fail: 非法 JSON {rp_path.name}")
            continue
        ok, errs, _, resolved = _validate_rulepack_schema_with_compat(rp_doc if isinstance(rp_doc, dict) else {})
        if not ok:
            schema_ok = False
            preview = "; ".join(errs[:5])
            blockers.append(f"Rulepack schema fail: {rp_path.name} ({resolved}) {preview}")
    checks["rulepack_schema_valid"] = schema_ok

    # 7) traceability complete
    trace_ok = True
    for rp_path in job_rulepacks:
        try:
            rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
        except Exception:
            trace_ok = False
            continue
        trace = rp_doc.get("traceability", []) if isinstance(rp_doc.get("traceability"), list) else []
        if not trace:
            trace_ok = False
            blockers.append(f"Traceability fail: {rp_path.name} traceability 为空")
            continue
        bad = 0
        for row in trace:
            if not isinstance(row, dict):
                bad += 1
                continue
            clause_ok = str(row.get("source_clause_id") or row.get("clause_id") or "").strip()
            spec_ok = str(row.get("specir_id") or row.get("source_specir_id") or "").strip()
            unresolved = bool(row.get("unresolved", False))
            if (not clause_ok) or (not spec_ok) or unresolved:
                bad += 1
        if bad > 0:
            trace_ok = False
            blockers.append(f"Traceability fail: {rp_path.name} incomplete_rows={bad}")
    checks["traceability_complete"] = trace_ok

    # 8) unresolved_count = 0
    unresolved_summary = _collect_rulepack_unresolved_summary_for_job(job_id)
    unresolved_count = int(unresolved_summary.get("unresolved_count", 0) or 0)
    unresolved_threshold = int(unresolved_summary.get("threshold", 0) or 0)
    unresolved_ok = unresolved_count <= unresolved_threshold
    checks["unresolved_count_threshold_ok"] = unresolved_ok
    if not unresolved_ok:
        blockers.append(f"Unresolved fail: unresolved_count={unresolved_count}, threshold={unresolved_threshold}")

    ok = len(blockers) == 0
    return {
        "ok": ok,
        "publish_status": "ready" if ok else "blocked",
        "checks": checks,
        "blockers": blockers,
        "unresolved_count": unresolved_count,
        "quality_gate_result": qg,
    }


def _validate_rulepack_contract(payload: Dict[str, Any]) -> Dict[str, Any]:
    """
    Contract checks:
    1) rulepack JSON schema valid
    2) all gate rule refs can find Rule
    3) all measurement_pair gateRefs can find Gate or Rule-linked gate
    4) all normRef can find source anchor
    5) all component_id unique
    """
    blockers: List[str] = []

    schema_ok, schema_errs, _, resolved = _validate_rulepack_schema_with_compat(payload if isinstance(payload, dict) else {})
    if not schema_ok:
        blockers.append(f"schema_invalid({resolved}): " + "; ".join(schema_errs[:10]))
    meta_obj = payload.get("meta", {}) if isinstance(payload, dict) and isinstance(payload.get("meta"), dict) else {}
    norm_ver = str(meta_obj.get("norm_version") or meta_obj.get("spec_version") or "").strip()
    if not norm_ver:
        blockers.append("norm_version_missing: rulepack meta 必须绑定 norm_version")

    rules = payload.get("rules", []) if isinstance(payload, dict) and isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload, dict) and isinstance(payload.get("gates"), list) else []
    components = payload.get("components", []) if isinstance(payload, dict) and isinstance(payload.get("components"), list) else []
    semantic_tree = payload.get("semantic_tree", {}) if isinstance(payload, dict) and isinstance(payload.get("semantic_tree"), dict) else {}

    rule_ids = {
        str(r.get("rule_id") or r.get("id") or "").strip()
        for r in rules
        if isinstance(r, dict) and str(r.get("rule_id") or r.get("id") or "").strip()
    }
    gate_ids = {
        str(g.get("gate_id") or g.get("id") or "").strip()
        for g in gates
        if isinstance(g, dict) and str(g.get("gate_id") or g.get("id") or "").strip()
    }

    # 2) gate->rule refs
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip() or "<unknown_gate>"
        for rid in _gate_rule_ids(g):
            if rid and rid not in rule_ids:
                blockers.append(f"gate_rule_ref_missing: gate={gid}, ruleRef={rid}")

    # 3) measurement pair gate refs
    mg = _validate_measurement_pair_gate_mapping(
        form_code=str((payload.get("meta", {}) if isinstance(payload.get("meta"), dict) else {}).get("form_code") or "").strip(),
        semantic_tree=semantic_tree,
        gates_rows=gates,
    )
    if not bool(mg.get("passed", False)):
        miss = mg.get("missing_items", []) if isinstance(mg.get("missing_items"), list) else []
        for item in miss[:50]:
            blockers.append(
                f"measurement_gate_ref_missing: field={str(item.get('field_key') or '-')}, reason={str(item.get('reason') or '')}, gateRef={str(item.get('gateRef') or '')}"
            )

    # 4) normRef -> anchor
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip() or "<unknown_rule>"
        anchor = _extract_rule_anchor_fields(r, None)
        errs = _validate_rule_anchor_fields(anchor)
        if errs:
            blockers.append(f"normref_anchor_missing: rule={rid}, errors={','.join(errs)}")

    # 5) unique component_id
    seen: set[str] = set()
    dup: set[str] = set()
    for c in components:
        if not isinstance(c, dict):
            continue
        cid = str(c.get("component_id") or c.get("id") or "").strip()
        if not cid:
            continue
        if cid in seen:
            dup.add(cid)
        else:
            seen.add(cid)
    for cid in sorted(dup):
        blockers.append(f"duplicate_component_id: {cid}")

    return {
        "ok": len(blockers) == 0,
        "blockers": blockers,
        "summary": {
            "rules": len(rules),
            "gates": len(gates),
            "components": len(components),
            "unique_components": len(seen),
            "duplicate_components": len(dup),
        },
    }


def _build_asset_integrity_report(job_id: str) -> Dict[str, Any]:
    paths = _find_rulepack_paths_by_job(job_id)
    report_items: List[Dict[str, Any]] = []
    blockers: List[str] = []
    total_counts = {
        "dangling_specir_refs": 0,
        "dangling_rule_refs": 0,
        "dangling_gate_refs": 0,
        "dangling_slot_refs": 0,
        "unused_components": 0,
        "duplicate_rules": 0,
        "duplicate_gates": 0,
    }
    for p in paths:
        try:
            doc = json.loads(p.read_text(encoding="utf-8-sig"))
        except Exception:
            blockers.append(f"{p.name}: invalid_json")
            continue
        if not isinstance(doc, dict):
            blockers.append(f"{p.name}: invalid_root")
            continue
        rules = [x for x in (doc.get("rules", []) if isinstance(doc.get("rules"), list) else []) if isinstance(x, dict)]
        gates = [x for x in (doc.get("gates", []) if isinstance(doc.get("gates"), list) else []) if isinstance(x, dict)]
        components = [x for x in (doc.get("components", []) if isinstance(doc.get("components"), list) else []) if isinstance(x, dict)]
        slots = [x for x in (doc.get("slots", []) if isinstance(doc.get("slots"), list) else []) if isinstance(x, dict)]
        semantic_tree = doc.get("semantic_tree", {}) if isinstance(doc.get("semantic_tree"), dict) else {}

        specir_doc = _read_artifact_payload(job_id, "13_specir.json")
        specir_items = specir_doc.get("items", []) if isinstance(specir_doc.get("items"), list) else []
        specir_ids = {
            str(x.get("specir_id") or x.get("component_id") or "").strip()
            for x in specir_items
            if isinstance(x, dict) and str(x.get("specir_id") or x.get("component_id") or "").strip()
        }
        rule_ids: List[str] = [str(x.get("rule_id") or x.get("ruleId") or x.get("id") or "").strip() for x in rules if str(x.get("rule_id") or x.get("ruleId") or x.get("id") or "").strip()]
        gate_ids: List[str] = [str(x.get("gate_id") or x.get("id") or "").strip() for x in gates if str(x.get("gate_id") or x.get("id") or "").strip()]
        component_ids = {str(x.get("component_id") or x.get("id") or "").strip() for x in components if str(x.get("component_id") or x.get("id") or "").strip()}
        slot_keys = {
            str(x.get("slotKey") or x.get("slot") or "").strip()
            for x in slots
            if str(x.get("slotKey") or x.get("slot") or "").strip()
        }

        dup_rules = len(rule_ids) - len(set(rule_ids))
        dup_gates = len(gate_ids) - len(set(gate_ids))

        dangling_specir = 0
        dangling_slot = 0
        used_components: set[str] = set()
        for r in rules:
            sid = str(r.get("source_specir_id") or r.get("specir_id") or "").strip()
            if sid and sid not in specir_ids:
                dangling_specir += 1
            sk = str(r.get("slotKey") or r.get("field") or "").strip()
            if sk and sk not in slot_keys:
                dangling_slot += 1
            cid = str(r.get("component_id") or r.get("componentId") or "").strip()
            if cid:
                used_components.add(cid)

        dangling_rule = 0
        rule_id_set = set(rule_ids)
        for g in gates:
            for rid in _gate_rule_ids(g):
                if rid and rid not in rule_id_set:
                    dangling_rule += 1

        dangling_gate = 0
        gate_id_set = set(gate_ids)
        gate_refs = semantic_tree.get("gate_refs", []) if isinstance(semantic_tree.get("gate_refs"), list) else []
        for row in gate_refs:
            if not isinstance(row, dict):
                continue
            gref = str(row.get("gate_ref") or row.get("gateRef") or "").strip()
            if gref and gref not in gate_id_set and gref not in rule_id_set:
                dangling_gate += 1

        unused_components = len([cid for cid in component_ids if cid not in used_components])

        total_counts["dangling_specir_refs"] += dangling_specir
        total_counts["dangling_rule_refs"] += dangling_rule
        total_counts["dangling_gate_refs"] += dangling_gate
        total_counts["dangling_slot_refs"] += dangling_slot
        total_counts["unused_components"] += unused_components
        total_counts["duplicate_rules"] += dup_rules
        total_counts["duplicate_gates"] += dup_gates

        report_items.append(
            {
                "rulepack": p.name,
                "form_code": str((doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}).get("form_code") or "").strip(),
                "dangling_specir_refs": dangling_specir,
                "dangling_rule_refs": dangling_rule,
                "dangling_gate_refs": dangling_gate,
                "dangling_slot_refs": dangling_slot,
                "unused_components": unused_components,
                "duplicate_rules": dup_rules,
                "duplicate_gates": dup_gates,
                "ok": (dangling_specir + dangling_rule + dangling_gate + dangling_slot + unused_components + dup_rules + dup_gates) == 0,
            }
        )
    failed = [
        x for x in report_items
        if isinstance(x, dict) and not bool(x.get("ok", False))
    ]
    out = {
        "schema_version": "asset_integrity_report.v1",
        "generated_at": _utc_now(),
        "job_id": job_id,
        "publish_status": "blocked" if (len(failed) > 0 or len(blockers) > 0) else "ready",
        "summary": {
            **total_counts,
            "failed_rulepacks": len(failed),
            "checked_rulepacks": len(report_items),
        },
        "items": report_items,
        "blockers": blockers,
    }
    path = _artifact_dir_for_job(job_id) / "integrity_report.json"
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    out["integrity_report_path"] = str(path.resolve())
    return out


def _runtime_schema_capabilities() -> Dict[str, Any]:
    return {
        "supported_gate_operators": {"all_pass"},
        "supported_rule_operators": {"between", ">=", ">", "<=", "<", "=", "exists"},
        "supported_formula_runtimes": set(),
    }


def _validate_runtime_compatibility(payload: Dict[str, Any]) -> Dict[str, Any]:
    caps = _runtime_schema_capabilities()
    blockers: List[str] = []
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    slots = payload.get("slots", []) if isinstance(payload.get("slots"), list) else []
    components = payload.get("components", []) if isinstance(payload.get("components"), list) else []
    semantic_tree = payload.get("semantic_tree", {}) if isinstance(payload.get("semantic_tree"), dict) else {}
    formulas = payload.get("formulas", []) if isinstance(payload.get("formulas"), list) else []

    field_id_set: set[str] = set()
    for row in (semantic_tree.get("field_nodes", []) if isinstance(semantic_tree.get("field_nodes"), list) else []):
        if not isinstance(row, dict):
            continue
        fid = str(row.get("field_id") or row.get("id") or "").strip()
        if fid:
            field_id_set.add(fid)
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip() or "<unknown_rule>"
        field_id = str(r.get("field_id") or "").strip()
        field = str(r.get("field") or "").strip()
        if field_id and field_id not in field_id_set:
            blockers.append(f"field_id_not_exists: rule={rid}, field_id={field_id}")
        if not field:
            blockers.append(f"field_missing: rule={rid}")

    slot_set: set[str] = set()
    for s in slots:
        if not isinstance(s, dict):
            continue
        k1 = str(s.get("slotKey") or "").strip()
        k2 = str(s.get("slot") or "").strip()
        if k1:
            slot_set.add(k1)
        if k2:
            slot_set.add(k2)
    for c in components:
        if isinstance(c, dict):
            cid = str(c.get("component_id") or c.get("id") or "").strip()
            if cid:
                slot_set.add(cid)
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip() or "<unknown_rule>"
        slot = str(r.get("component_id") or r.get("slot") or "").strip()
        if slot and slot not in slot_set:
            blockers.append(f"slot_not_exists: rule={rid}, slot={slot}")

    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip() or "<unknown_gate>"
        gate_op = str(g.get("operator") or g.get("decision_logic") or "all_pass").strip().lower()
        if gate_op not in caps["supported_gate_operators"]:
            blockers.append(f"gate_operator_unsupported: gate={gid}, operator={gate_op}")

    supported_rule_ops: set[str] = caps["supported_rule_operators"]
    for r in rules:
        if not isinstance(r, dict):
            continue
        rid = str(r.get("rule_id") or r.get("id") or "").strip() or "<unknown_rule>"
        op = _normalize_rule_operator(r.get("operator"))
        if op not in supported_rule_ops:
            blockers.append(f"rule_operator_unsupported: rule={rid}, operator={op}")
        threshold = r.get("threshold")
        if isinstance(threshold, dict) and threshold.get("formula") is not None:
            f_runtime = str(threshold.get("formula_runtime") or threshold.get("formula_engine") or "inline").strip().lower()
            if f_runtime not in caps["supported_formula_runtimes"]:
                blockers.append(f"formula_runtime_unsupported: rule={rid}, runtime={f_runtime}")
    for f in formulas:
        if not isinstance(f, dict):
            continue
        fid = str(f.get("id") or f.get("formula_id") or "<unknown_formula>").strip()
        f_runtime = str(f.get("runtime") or f.get("engine") or "inline").strip().lower()
        if f_runtime not in caps["supported_formula_runtimes"]:
            blockers.append(f"formula_runtime_unsupported: formula={fid}, runtime={f_runtime}")

    compatibility_status = "passed" if len(blockers) == 0 else "failed"
    return {
        "ok": len(blockers) == 0,
        "compatibility_status": compatibility_status,
        "blockers": blockers,
        "summary": {
            "rules": len([x for x in rules if isinstance(x, dict)]),
            "gates": len([x for x in gates if isinstance(x, dict)]),
            "slots": len(slot_set),
            "field_ids": len(field_id_set),
        },
    }


@app.post("/normref/rulepack/build")
def build_rulepack(request: BuildRulePackRequest) -> Dict[str, Any]:
    t_build_start = time.perf_counter()
    _update_obs_metrics(build_total_inc=1)
    job_id = str(request.job_id or "").strip()
    if not job_id:
        raise HTTPException(status_code=400, detail="job_id 不能为空")
    sys_cfg = _load_system_config()
    form_code = str(request.form_code or "").strip() or str(sys_cfg.get("default_form_code") or "bridge_shi_1").strip()
    form_name = str(request.form_name or "").strip()
    package_version = str(request.package_version or "").strip() or "v1"
    schema_version = str(request.schema_version or "").strip() or "v1"
    conflict_policy = str(request.conflict_policy or "").strip() or "primary_first"
    if schema_version != "v1":
        raise HTTPException(
            status_code=400,
            detail=(
                f"构建失败：当前构建器仅支持 schema_version=v1；收到 {schema_version}。"
                "如需 v2，请先构建 v1 再使用迁移脚本 v1->v2。"
            ),
        )

    index_path = _artifact_dir_for_job(job_id) / "00_pipeline_index.json"
    if not index_path.exists():
        raise HTTPException(status_code=404, detail=f"未找到任务 {job_id} 的 artifacts 索引")
    try:
        index = json.loads(index_path.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"00_pipeline_index.json 非法：{job_id}") from exc

    review_pkg = _load_review_package(job_id)
    t_norm = time.perf_counter()
    norm_layer = _build_norm_layer(job_id, index, review_pkg)
    _append_trace("norm_parse", job_id=job_id, form_code=form_code, duration_ms=(time.perf_counter() - t_norm) * 1000.0, ok=True)
    t_doc = time.perf_counter()
    doc_layer = _build_doc_layer(form_code)
    _append_trace("doc_mapping", job_id=job_id, form_code=form_code, duration_ms=(time.perf_counter() - t_doc) * 1000.0, ok=True)
    spec_code = str(norm_layer.get("spec_code") or "").strip()
    spec_version = str(norm_layer.get("spec_version") or "").strip() or "v1"
    norm_version = _resolve_norm_version(spec_code=str(norm_layer.get("spec_code") or "").strip(), spec_version=spec_version)
    source_doc_hash = str(norm_layer.get("source_doc_hash") or "").strip()
    norm_ref = str(norm_layer.get("normRef") or "").strip()
    if not spec_code:
        raise HTTPException(status_code=400, detail="缺少 spec_code，无法生成 rulepack")
    if not source_doc_hash:
        raise HTTPException(status_code=400, detail="缺少 source_doc_hash，无法生成 rulepack")
    if not str(norm_version or "").strip():
        raise HTTPException(status_code=400, detail="缺少 norm_version，rulepack 必须绑定 norm_version")
    semantic_tree = doc_layer.get("semantic_tree", {}) if isinstance(doc_layer.get("semantic_tree"), dict) else {}
    layer_slice = _build_rulepack_asset_slice_from_layers(
        norm_layer,
        doc_layer,
        selected_slot_keys=request.selected_slotKeys,
        selected_specir_ids=request.selected_specir_ids,
    )
    filtered_rules_rows = [x for x in layer_slice.get("rules", []) if isinstance(x, dict)]
    gates_rows = [x for x in layer_slice.get("gates", []) if isinstance(x, dict)]
    comp_rows = [x for x in layer_slice.get("components", []) if isinstance(x, dict)]
    proof_template_rows = [x for x in layer_slice.get("proof_templates", []) if isinstance(x, dict)]
    pre_counts = layer_slice.get("pre_counts", {}) if isinstance(layer_slice.get("pre_counts"), dict) else {}
    selection_mode = "whitelist"
    selected_rule_ids = set(layer_slice.get("selected_rule_ids", set()))
    selected_component_ids = set(layer_slice.get("selected_component_ids", set()))
    if not filtered_rules_rows:
        _raise_policy_http_error(
            ERROR_RULE_MISSING,
            user_message=f"Rulepack构建失败：form_code={form_code} 白名单未匹配到任何规则。",
            detail=f"form_code={form_code}",
        )
    gate_synthesis_applied = False
    synth_policy = _gate_synthesis_policy()
    if bool(synth_policy.get("enabled_when_no_gates", True)) and selected_rule_ids and len(gates_rows) == 0:
        # Fallback: synthesize minimal gates so downstream DocPeg execution can
        # still perform pass/fail per selected measurement-linked rule.
        gates_rows = _synthesize_gates_from_rules(filtered_rules_rows, source_tag=str(synth_policy.get("source_tag_on_filtered_rules") or "autogen.rulepack_fallback"))
        gate_synthesis_applied = True
    asset_whitelist = doc_layer.get("asset_whitelist", {}) if isinstance(doc_layer.get("asset_whitelist"), dict) else {}
    allowed_components = set(asset_whitelist.get("allowed_components", set()))
    allowed_rules = set(asset_whitelist.get("allowed_rules", set()))
    allowed_gates = set(asset_whitelist.get("allowed_gates", set()))
    allowed_normrefs = set(asset_whitelist.get("allowed_normRefs", set()))
    allowed_specir_ids = set(asset_whitelist.get("allowed_specir_ids", set()))
    specir_doc = norm_layer.get("specir_doc", {}) if isinstance(norm_layer.get("specir_doc"), dict) else {}
    normref_index_doc = norm_layer.get("normref_index_doc", {}) if isinstance(norm_layer.get("normref_index_doc"), dict) else {}
    # Keep slots/layout aligned to selected components to avoid full-form leakage.
    if isinstance(specir_doc, dict):
        raw_slots = specir_doc.get("slots")
        if isinstance(raw_slots, list):
            specir_doc["slots"] = [
                s
                for s in raw_slots
                if str((s or {}).get("slotKey") or "").strip() in selected_component_ids
                or str((s or {}).get("slot") or "").strip() in selected_component_ids
            ]
        raw_layout = specir_doc.get("layout")
        if isinstance(raw_layout, dict):
            sections = raw_layout.get("sections")
            if isinstance(sections, dict):
                body = sections.get("body")
                if isinstance(body, list):
                    sections["body"] = [
                        row
                        for row in body
                        if str((row or {}).get("slot") or "").strip() in selected_component_ids
                    ]
                raw_layout["sections"] = sections
            specir_doc["layout"] = raw_layout
    rule_overrides = _load_form_rule_overrides(form_code)
    source_map: Dict[Tuple[str, str], Dict[str, Any]] = {}
    normalized_rules: List[Dict[str, Any]] = []
    traceability: List[Dict[str, Any]] = []
    normref_entry_map = _build_normref_entry_map(normref_index_doc if isinstance(normref_index_doc, dict) else {})
    anchor_audit_rows: List[Dict[str, Any]] = []
    unresolved_items: List[Dict[str, Any]] = []
    unresolved_type_counts = _empty_unresolved_type_counts()
    unresolved_threshold_stats: Dict[str, int] = {
        "missing_value_range": 0,
        "missing_unit": 0,
        "invalid_operator": 0,
        "natural_language_only_threshold": 0,
    }
    for r in filtered_rules_rows:
        if not isinstance(r, dict):
            continue
        rule_id = str(r.get("rule_id", "")).strip()
        if not rule_id:
            continue
        row = dict(r)
        norm_ref_val = str(r.get("norm_ref", "")).strip()
        source_spec_code = spec_code
        source_spec_version = spec_version
        source_clause_id = ""
        if norm_ref_val:
            try:
                parsed = _parse_normref_uri(norm_ref_val)
                spec_from_ref = _format_std_code_display(str(parsed.get("spec", "")).strip())
                if spec_from_ref:
                    source_spec_code = spec_from_ref
                source_clause_id = str(parsed.get("clause", "")).strip()
            except Exception:
                source_clause_id = ""
        row["source_spec_code"] = source_spec_code
        row["source_spec_version"] = source_spec_version
        row["source_clause_id"] = source_clause_id or str(r.get("source_clause", "")).strip()
        patch = rule_overrides.get(rule_id)
        if isinstance(patch, dict):
            for k, v in patch.items():
                row[k] = v
        slot_key = str(
            row.get("slotKey")
            or row.get("slot_key")
            or row.get("field")
            or ""
        ).strip()
        if slot_key == "measured_value":
            slot_key = ""
        row["slotKey"] = slot_key
        # Formal rule field must be slotKey; measured_value only allowed as debug fallback.
        row["field"] = slot_key
        debug_field = str(r.get("field") or row.get("debug_field") or "").strip()
        if debug_field:
            row["debug_field"] = debug_field
        if not slot_key:
            unresolved_type_counts["missing_slot_mapping"] = unresolved_type_counts.get("missing_slot_mapping", 0) + 1
            unresolved_items.append(
                {
                    "rule_id": rule_id,
                    "field": "",
                    "type": "missing_slot_mapping",
                    "reason": "formal_rule_requires_slotKey",
                    "normRef": str(row.get("norm_ref") or "").strip() or "UNKNOWN",
                    "source_clause": str(row.get("source_clause") or row.get("source_clause_id") or "").strip() or "UNKNOWN",
                    **_build_unresolved_governance_fields("missing_slot_mapping"),
                }
            )
            continue
        threshold_struct, threshold_errs = _normalize_threshold_struct(row)
        row["threshold"] = threshold_struct
        row["operator"] = threshold_struct.get("operator")
        row["unit"] = threshold_struct.get("unit")
        unresolved_now = bool(row.get("unresolved", False))
        for code in threshold_errs:
            unresolved_threshold_stats[code] = unresolved_threshold_stats.get(code, 0) + 1
            unresolved_now = True
            utype = _resolve_unresolved_type(code, row)
            unresolved_type_counts[utype] = unresolved_type_counts.get(utype, 0) + 1
            unresolved_items.append(
                {
                    "rule_id": rule_id,
                    "field": str(row.get("field") or "").strip(),
                    "type": utype,
                    "reason": code,
                    "normRef": str(row.get("norm_ref") or "").strip() or "UNKNOWN",
                    "source_clause": str(row.get("source_clause") or row.get("source_clause_id") or "").strip() or "UNKNOWN",
                    **_build_unresolved_governance_fields(utype),
                }
            )
        if threshold_errs:
            reasons = [str(row.get("unresolved_reason") or "").strip(), *threshold_errs]
            row["unresolved_reason"] = ",".join(sorted(set([x for x in reasons if x])))
        row["unresolved"] = unresolved_now
        anchor = _extract_rule_anchor_fields(row, normref_entry_map.get(norm_ref_val))
        row["source_page"] = anchor.get("source_page")
        row["quote_start"] = anchor.get("quote_start")
        row["quote_end"] = anchor.get("quote_end")
        row["source_anchor_url"] = (
            f"/normref/rules/source-locate?job_id={job_id}&rule_id={rule_id}"
        )
        anchor_errors = _validate_rule_anchor_fields(anchor)
        if anchor_errors:
            unresolved_now = True
            row["unresolved"] = True
            prev_reason = str(row.get("unresolved_reason") or "").strip()
            row["unresolved_reason"] = ",".join([x for x in [prev_reason, "missing_source"] if x])
            unresolved_type_counts["missing_slot_mapping"] = unresolved_type_counts.get("missing_slot_mapping", 0) + 1
            utype_anchor = "missing_slot_mapping"
            unresolved_items.append(
                {
                    "rule_id": rule_id,
                    "field": str(row.get("field") or "").strip(),
                    "type": utype_anchor,
                    "reason": ",".join(anchor_errors),
                    "normRef": anchor.get("normRef") or str(row.get("norm_ref") or "").strip() or "UNKNOWN",
                    "source_clause": anchor.get("source_clause") or str(row.get("source_clause") or row.get("source_clause_id") or "").strip() or "UNKNOWN",
                    **_build_unresolved_governance_fields(utype_anchor),
                }
            )
        anchor_audit_rows.append(
            {
                "rule_id": rule_id,
                "anchor": anchor,
                "errors": anchor_errors,
                "valid": len(anchor_errors) == 0,
            }
        )
        normalized_rules.append(row)
        source_key = (source_spec_code, source_spec_version)
        if source_key not in source_map:
            source_map[source_key] = {
                "spec_code": source_spec_code,
                "spec_version": source_spec_version,
                "source_doc_hash": source_doc_hash if source_spec_code == spec_code else "",
                "job_id": job_id if source_spec_code == spec_code else "",
                "priority": 1 if source_spec_code == spec_code else 2,
            }
        traceability.append(
            {
                "rule_id": rule_id,
                "norm_ref": norm_ref_val,
                "source_spec_code": source_spec_code,
                "source_spec_version": source_spec_version,
                "source_clause_id": row["source_clause_id"],
                "source_clause": str(r.get("source_clause", "")).strip(),
                "source_text": str(r.get("source_text", "")).strip(),
                "unresolved": bool(r.get("unresolved", False)),
            }
        )
    existing_unresolved_rule_ids = {
        str(item.get("rule_id") or "").strip()
        for item in unresolved_items
        if isinstance(item, dict) and str(item.get("rule_id") or "").strip()
    }
    for row in normalized_rules:
        if not isinstance(row, dict):
            continue
        if not bool(row.get("unresolved", False)):
            continue
        rid = str(row.get("rule_id") or row.get("id") or "").strip()
        if rid in existing_unresolved_rule_ids:
            continue
        reason = str(row.get("unresolved_reason") or "").strip() or "unresolved_without_reason"
        utype = _resolve_unresolved_type(reason, row)
        unresolved_type_counts[utype] = unresolved_type_counts.get(utype, 0) + 1
        unresolved_items.append(
            {
                "rule_id": rid,
                "field": str(row.get("field") or "").strip(),
                "type": utype,
                "reason": reason,
                "normRef": str(row.get("norm_ref") or "").strip() or "UNKNOWN",
                "source_clause": str(row.get("source_clause") or row.get("source_clause_id") or "").strip() or "UNKNOWN",
                **_build_unresolved_governance_fields(utype),
            }
        )
    sources = sorted(list(source_map.values()), key=lambda x: int(x.get("priority", 99)))

    if selected_rule_ids and len(gates_payload := list(gates_rows)) == 0:
        unresolved_type_counts["missing_gate"] = unresolved_type_counts.get("missing_gate", 0) + 1
        utype_gate = "missing_gate"
        unresolved_items.append(
            {
                "rule_id": "",
                "field": "",
                "type": utype_gate,
                "reason": "no gates available for selected rules and synthesis produced none",
                "normRef": "UNKNOWN",
                "source_clause": "UNKNOWN",
                **_build_unresolved_governance_fields(utype_gate),
            }
        )

    specir_layout = (specir_doc.get("layout") if isinstance(specir_doc, dict) else {}) or {}
    specir_slots = (specir_doc.get("slots") if isinstance(specir_doc, dict) else []) or []

    # Fallback: if specir doesn't provide slots/layout, derive a minimal usable set
    # from component/rule/gate assets so downstream integration won't receive empty bindings.
    if not isinstance(specir_slots, list) or len(specir_slots) == 0:
        derived_slots: List[Dict[str, Any]] = []
        seen_slots: set[str] = set()
        for comp in comp_rows:
            slot_key = str(comp.get("component_id") or comp.get("id") or "").strip()
            if not slot_key or slot_key in seen_slots:
                continue
            seen_slots.add(slot_key)
            derived_slots.append(
                {
                    "slotKey": slot_key,
                    "label": str(comp.get("title") or comp.get("name") or slot_key),
                    "type": "component",
                    "editable": bool(comp.get("editable", True)),
                    "source_clause": str(comp.get("source_clause") or "").strip(),
                }
            )
        for rule in filtered_rules_rows:
            slot_key = str(rule.get("field") or "").strip()
            if not slot_key or slot_key in seen_slots:
                continue
            seen_slots.add(slot_key)
            derived_slots.append(
                {
                    "slotKey": slot_key,
                    "label": slot_key,
                    "type": "rule_field",
                    "editable": False,
                    "norm_ref": str(rule.get("norm_ref") or "").strip(),
                }
            )
        for gate in gates_rows:
            slot_key = str(gate.get("gate_id") or gate.get("id") or "").strip()
            if not slot_key or slot_key in seen_slots:
                continue
            seen_slots.add(slot_key)
            derived_slots.append(
                {
                    "slotKey": slot_key,
                    "label": slot_key,
                    "type": "gate",
                    "editable": False,
                }
            )
        specir_slots = derived_slots

    if not isinstance(specir_layout, dict) or len(specir_layout.keys()) == 0:
        # Minimal fallback layout: keep sections explicit for consumers.
        specir_layout = {
            "paper": {"size": "A4", "orientation": "portrait"},
            "sections": {
                "headerFree": [],
                "headerGrid": [],
                "body": [
                    {
                        "key": str(slot.get("slotKey") or f"slot_{idx}"),
                        "type": "cell",
                        "slot": str(slot.get("slotKey") or ""),
                        "label": str(slot.get("label") or slot.get("slotKey") or ""),
                    }
                    for idx, slot in enumerate(specir_slots)
                    if isinstance(slot, dict)
                ],
                "footer": [],
            },
            "fallback": True,
        }
    # Normalize body cells to component slots only for rulepack consumers.
    sections = specir_layout.get("sections") if isinstance(specir_layout, dict) else None
    if isinstance(sections, dict):
        body = sections.get("body")
        if isinstance(body, list):
            sections["body"] = [
                row
                for row in body
                if isinstance(row, dict)
                and str(row.get("slot") or "").strip() in selected_component_ids
            ]
        specir_layout["sections"] = sections

    gates_payload = list(gates_rows)
    if bool(synth_policy.get("enabled_when_no_gates", True)) and len(gates_payload) == 0 and len(normalized_rules) > 0:
        gates_payload = _synthesize_gates_from_rules(normalized_rules, source_tag=str(synth_policy.get("source_tag_on_payload") or "autogen.rulepack_payload_fallback"))
    gates_payload = [
        g for g in gates_payload
        if isinstance(g, dict) and len(_gate_rule_ids(g)) > 0
    ]

    slot_manifest_items: List[Dict[str, Any]] = []
    seen_slot_manifest: set[str] = set()
    for rule in normalized_rules:
        if not isinstance(rule, dict):
            continue
        slot_key = str(rule.get("slotKey") or rule.get("field") or "").strip()
        if (not slot_key) or slot_key == "measured_value" or slot_key in seen_slot_manifest:
            continue
        seen_slot_manifest.add(slot_key)
        segs = slot_key.split(".")
        slot_manifest_items.append(
            {
                "slotKey": slot_key,
                "domain": segs[0] if len(segs) > 0 else "",
                "object": segs[1] if len(segs) > 1 else "",
                "property": segs[2] if len(segs) > 2 else "",
                "measure": segs[3] if len(segs) > 3 else "",
                "aliases": [str(rule.get("debug_field") or "").strip()] if str(rule.get("debug_field") or "").strip() else [],
                "unit": str(rule.get("unit") or "").strip(),
                "semantic_type": str(rule.get("rule_type") or "").strip(),
                "supported_forms": [form_code],
            }
        )
    slot_manifest_payload = {
        "schema_version": "slot_manifest.v1",
        "generated_at": _utc_now(),
        "form_code": form_code,
        "count": len(slot_manifest_items),
        "items": slot_manifest_items,
    }
    rulepack_manifest_payload = {
        "schema_version": "rulepack_manifest.v1",
        "generated_at": _utc_now(),
        "job_id": job_id,
        "form_code": form_code,
        "specir_count": int((layer_slice.get("post_counts", {}) if isinstance(layer_slice.get("post_counts", {}), dict) else {}).get("specir", 0) or 0),
        "rule_count": len(normalized_rules),
        "gate_count": len(gates_payload),
        "slot_count": len(slot_manifest_items),
        "removed_noise_count": int((layer_slice.get("filtered_out_counts", {}) or {}).get("total", 0) or 0),
    }

    payload = {
        "meta": {
            "kind": "normref.rulepack",
            "schema_version": "v1",
            "package_version": package_version,
            "conflict_policy": conflict_policy,
            "form_code": form_code,
            "form_name": form_name or form_code,
            "spec_code": spec_code,
            "spec_version": spec_version,
            "norm_version": norm_version,
            "job_id": job_id,
            "source_doc_hash": source_doc_hash,
            "normRef": norm_ref,
            "sources": sources,
            "selection_mode": selection_mode or "unknown",
            "selected_rule_count": len(selected_rule_ids),
            "generated_at": _utc_now(),
        },
        "layer_io": {
            "norm": {
                "inputs": ["00_pipeline_index.json", "05_components.json", "07_rules.json", "08_gates.json", "10_proof_templates.json", "norm_ref_index.json"],
                "outputs": {
                    "rules": len(filtered_rules_rows),
                    "gates": len(gates_payload),
                    "components": len(comp_rows),
                    "proof_templates": len(proof_template_rows),
                },
            },
            "doc": {
                "inputs": ["specbundle.semanticTree", "form_asset_whitelists.json", "form_rule_overrides.json"],
                "outputs": {
                    "form_code": form_code,
                    "semantic_tree_fields": len((semantic_tree.get("field_nodes", []) if isinstance(semantic_tree, dict) else [])),
                    "whitelist": {
                        "allowed_components": len(allowed_components),
                        "allowed_rules": len(allowed_rules),
                        "allowed_gates": len(allowed_gates),
                        "allowed_normRefs": len(allowed_normrefs),
                    },
                },
            },
            "rulepack": {
                "inputs": ["norm_layer.filtered_assets", "doc_layer.semantic_tree", "doc_layer.whitelist"],
                "outputs": ["meta", "rules", "gates", "components", "proof_templates", "semantic_tree"],
            },
        },
        "layout": specir_layout,
        "slots": specir_slots,
        "rules": normalized_rules,
        "gates": gates_payload,
        "components": comp_rows,
        "proof_templates": proof_template_rows,
        "traceability": traceability,
        "semantic_tree": semantic_tree,
        "anchor_audit": {
            "total_rules": len(anchor_audit_rows),
            "valid_rules": len([x for x in anchor_audit_rows if bool(x.get("valid"))]),
            "invalid_rules": len([x for x in anchor_audit_rows if not bool(x.get("valid"))]),
            "rows": anchor_audit_rows,
        },
        "unresolved": {
            "count": len(unresolved_items),
            "type_counts": unresolved_type_counts,
            "items": unresolved_items,
            "gate_synthesis_applied": gate_synthesis_applied,
        },
        "unresolved_stats": {
            "threshold": {
                **unresolved_threshold_stats,
                "total_unresolved_threshold_rules": sum(int(v) for v in unresolved_threshold_stats.values()),
            }
        },
        "whitelist_filtering": {
            "form_code": form_code,
            "pre_filter_counts": pre_counts,
            "post_filter_counts": {
                "components": len(comp_rows),
                "rules": len(normalized_rules),
                "gates": len(gates_payload),
                "proof_templates": len(proof_template_rows),
            },
            "filtered_out_counts": layer_slice.get("filtered_out_counts", {}),
            "before_count": pre_counts,
            "after_count": layer_slice.get("post_counts", {}),
            "removed_noise_count": int((layer_slice.get("filtered_out_counts", {}) or {}).get("total", 0) or 0),
            "removed_reason": layer_slice.get("removed_reason", {}),
            "applied": {
                "allowed_specir_ids_count": len(allowed_specir_ids),
                "allowed_components_count": len(allowed_components),
                "allowed_rules_count": len(allowed_rules),
                "allowed_gates_count": len(allowed_gates),
                "allowed_normRefs_count": len(allowed_normrefs),
                "selected_slotKeys_count": len([x for x in request.selected_slotKeys if str(x).strip()]),
                "selected_specir_ids_count": len([x for x in request.selected_specir_ids if str(x).strip()]),
            },
        },
    }
    lineage_actors = _derive_review_lineage_actors(review_pkg if isinstance(review_pkg, dict) else {})
    payload = _upsert_rulepack_lineage(
        payload=payload,
        norm_id=spec_code,
        norm_version=norm_version,
        source_file_hash=source_doc_hash,
        created_by=str(lineage_actors.get("created_by") or ""),
        reviewed_by=str(lineage_actors.get("reviewed_by") or ""),
        published_by="",
        published_at="",
    )
    unresolved_count = int((payload.get("unresolved", {}) or {}).get("count", 0) if isinstance(payload.get("unresolved", {}), dict) else 0)
    audit_report = _build_rulepack_audit_report(
        job_id=job_id,
        form_code=form_code,
        norm_version=spec_version,
        pre_counts=pre_counts if isinstance(pre_counts, dict) else {},
        selected_components_count=len(comp_rows),
        selected_rules=normalized_rules,
        selected_gates_count=len(gates_payload),
        unresolved_count=unresolved_count,
    )
    payload["audit_report"] = audit_report
    measurement_gate_mapping = _validate_measurement_pair_gate_mapping(
        form_code=form_code,
        semantic_tree=semantic_tree if isinstance(semantic_tree, dict) else {},
        gates_rows=gates_payload,
    )
    docpeg_coverage = _compute_docpeg_coverage_report(
        form_code=form_code,
        semantic_tree=semantic_tree if isinstance(semantic_tree, dict) else {},
        measurement_gate_mapping=measurement_gate_mapping,
    )
    payload["measurement_gate_mapping"] = measurement_gate_mapping
    payload["docpeg_coverage"] = docpeg_coverage
    semantic_consistency = _run_semantic_consistency_engine(
        job_id=job_id,
        form_code=form_code,
        payload=payload,
    )
    payload["semantic_consistency"] = semantic_consistency
    payload["missing_gate_governance"] = _build_missing_gate_governance_report(
        form_code=form_code,
        payload=payload,
    )
    payload["e2e_validation"] = _run_rulepack_e2e_validation(form_code, payload)
    guard_cfg = _load_publish_guardrails()
    critical_gates_cfg = guard_cfg.get("critical_gates", {}) if isinstance(guard_cfg.get("critical_gates"), dict) else {}
    critical_gates = [str(x).strip() for x in (critical_gates_cfg.get(form_code, []) if isinstance(critical_gates_cfg.get(form_code, []), list) else []) if str(x).strip()]
    payload["gate_regression"] = _run_gate_regression(form_code, payload, critical_gates)
    payload["runtime_regression"] = _run_runtime_regression(form_code, payload)
    _assert_rulepack_version_compatible(payload, stage="build_output")
    schema_ok, schema_errors, canonical_doc, schema_resolved = _validate_rulepack_schema_with_compat(payload)
    payload["schema_validation"] = {
        "schema_id": f"rulepack-{schema_resolved}",
        "valid": schema_ok,
        "errors": schema_errors,
        "validated_at": _utc_now(),
    }
    if not schema_ok:
        preview = "; ".join(schema_errors[:10])
        raise HTTPException(
            status_code=400,
            detail=f"rulepack schema 校验失败: {preview}",
        )
    quality_metrics = _compute_rulepack_quality_metrics(
        rules=normalized_rules,
        gates=gates_payload,
        traceability=traceability,
        components=comp_rows,
    )
    golden_compare = _compare_rulepack_with_golden(
        form_code=form_code,
        rules=normalized_rules,
        gates=gates_payload,
    )
    thresholds = _load_quality_gate_thresholds()
    quality_gate = {
        "thresholds": thresholds,
        "metrics": quality_metrics,
        "passed": (
            quality_metrics["rule_correctness_rate"] >= thresholds["min_rule_correctness_rate"]
            and quality_metrics["gate_executability_rate"] >= thresholds["min_gate_executability_rate"]
            and quality_metrics["traceability_rate"] >= thresholds["min_traceability_rate"]
        ),
    }
    payload["quality_gate"] = quality_gate
    payload["golden_compare"] = golden_compare
    payload["golden_review"] = {
        "status": "review_required" if (bool(golden_compare.get("enabled", False)) and not bool(golden_compare.get("passed", True))) else "not_required",
        "required": bool(golden_compare.get("enabled", False)) and not bool(golden_compare.get("passed", True)),
    }
    golden_diff_report = {
        "schema_version": "golden_diff_report.v1",
        "generated_at": _utc_now(),
        "job_id": job_id,
        "form_code": form_code,
        "rulepack_name": file_name if "file_name" in locals() else "",
        "golden_compare": golden_compare,
        "diffs": golden_compare.get("diffs", []) if isinstance(golden_compare, dict) else [],
        "type_counts": golden_compare.get("type_counts", {}) if isinstance(golden_compare, dict) else {},
        "key_mismatches": golden_compare.get("key_mismatches", []) if isinstance(golden_compare, dict) else [],
        "has_key_mismatch": bool(golden_compare.get("has_key_mismatch", False)) if isinstance(golden_compare, dict) else False,
    }
    if request.enforce_quality_gate and not bool(quality_gate["passed"]):
        raise HTTPException(
            status_code=400,
            detail=(
                "rulepack 质量门禁未通过："
                f"rule_correctness_rate={quality_metrics['rule_correctness_rate']:.4f}, "
                f"gate_executability_rate={quality_metrics['gate_executability_rate']:.4f}, "
                f"traceability_rate={quality_metrics['traceability_rate']:.4f}"
            ),
        )
    if not bool(measurement_gate_mapping.get("passed", False)):
        missing_preview = "; ".join(
            [
                f"{str(x.get('field_key') or '-')}: {str(x.get('reason') or '')}"
                for x in (measurement_gate_mapping.get("missing_items", []) if isinstance(measurement_gate_mapping.get("missing_items"), list) else [])[:20]
            ]
        )
        raise HTTPException(
            status_code=400,
            detail=(
                "MeasurementPair -> gateRef 映射校验失败："
                f"missing_count={measurement_gate_mapping.get('missing_count', 0)}; {missing_preview}"
            ),
        )
    payload["build_log"] = {
        "docpeg_coverage": docpeg_coverage,
        "message": (
            f"DocPeg coverage form={form_code}, field_total={docpeg_coverage['field_total']}, "
            f"auto_gate_count={docpeg_coverage['auto_gate_count']}, "
            f"manual_fallback_count={docpeg_coverage['manual_fallback_count']}, "
            f"missing_gateRef_count={docpeg_coverage['missing_gateRef_count']}, "
            f"executable_rate={docpeg_coverage['executable_rate']:.4f}, "
            f"gate_coverage_rate={docpeg_coverage['gate_coverage_rate']:.4f}"
        ),
    }
    # Final guard: keep layout.body strictly aligned with exported components.
    final_comp_ids = {
        str(c.get("component_id") or c.get("id") or "").strip()
        for c in payload.get("components", [])
        if isinstance(c, dict) and str(c.get("component_id") or c.get("id") or "").strip()
    }
    layout_obj = payload.get("layout")
    if isinstance(layout_obj, dict):
        sections_obj = layout_obj.get("sections")
        if isinstance(sections_obj, dict):
            body_obj = sections_obj.get("body")
            if isinstance(body_obj, list):
                sections_obj["body"] = [
                    row
                    for row in body_obj
                    if isinstance(row, dict)
                    and str(row.get("slot") or "").strip() in final_comp_ids
                ]
            layout_obj["sections"] = sections_obj
        payload["layout"] = layout_obj
    token = _safe_upload_name(f"{spec_code}-{spec_version}-{form_code}-{job_id}").strip("-") or job_id
    file_name = f"{token}.rulepack.json"
    specir_items_for_trace = [x for x in (specir_doc.get("items", []) if isinstance(specir_doc.get("items"), list) else []) if isinstance(x, dict)]
    traceability_payload = _build_traceability_payload(
        job_id=job_id,
        form_code=form_code,
        spec_version=spec_version,
        normalized_rules=normalized_rules,
        gates_payload=gates_payload,
        specir_items=specir_items_for_trace,
        rulepack_name=file_name,
    )
    shared_clusters = _build_shared_rule_clusters(
        norm_id=spec_code,
        current_rulepack_name=file_name,
        current_payload=payload,
    )
    current_shared_refs = shared_clusters.get("current_rule_references", {}) if isinstance(shared_clusters.get("current_rule_references"), dict) else {}
    meta_obj = payload.get("meta", {}) if isinstance(payload.get("meta"), dict) else {}
    meta_obj["shared_reference_enabled"] = True
    meta_obj["shared_cluster_count"] = int(shared_clusters.get("cluster_count", 0) or 0)
    payload["meta"] = meta_obj
    payload["shared_references"] = current_shared_refs
    for rr in payload.get("rules", []) if isinstance(payload.get("rules"), list) else []:
        if not isinstance(rr, dict):
            continue
        rid = str(rr.get("rule_id") or rr.get("id") or "").strip()
        rr["shared_reference"] = sorted(
            list(
                set(
                    [
                        str(x).strip()
                        for x in (current_shared_refs.get(rid, []) if isinstance(current_shared_refs.get(rid, []), list) else [])
                        if str(x).strip()
                    ]
                )
            )
        )
    NORMREF_RULEPACK_DIR.mkdir(parents=True, exist_ok=True)
    out_path = (NORMREF_RULEPACK_DIR / file_name).resolve()
    out_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    slot_manifest_path = (_artifact_dir_for_job(job_id) / "slot_manifest.json").resolve()
    slot_manifest_path.write_text(json.dumps(slot_manifest_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    rulepack_manifest_path = (_artifact_dir_for_job(job_id) / "rulepack_manifest.json").resolve()
    rulepack_manifest_path.write_text(json.dumps(rulepack_manifest_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    traceability_path = (_artifact_dir_for_job(job_id) / "traceability.json").resolve()
    traceability_path.write_text(json.dumps(traceability_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    _upsert_slot_registry_rows(
        slot_manifest_payload.get("items", []) if isinstance(slot_manifest_payload.get("items"), list) else []
    )
    golden_diff_report["rulepack_name"] = file_name
    # Persist per-job audit artifact.
    audit_path = _artifact_dir_for_job(job_id) / "rulepack_audit.json"
    audit_path.parent.mkdir(parents=True, exist_ok=True)
    audit_path.write_text(json.dumps(audit_report, ensure_ascii=False, indent=2), encoding="utf-8")
    golden_diff_path = _artifact_dir_for_job(job_id) / "golden_diff_report.json"
    golden_diff_path.write_text(json.dumps(golden_diff_report, ensure_ascii=False, indent=2), encoding="utf-8")
    gate_regression_path = _artifact_dir_for_job(job_id) / "gate_regression_report.json"
    gate_regression_path.write_text(
        json.dumps(payload.get("gate_regression", {}), ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    runtime_regression_path = _artifact_dir_for_job(job_id) / "runtime_regression_report.json"
    runtime_regression_path.write_text(
        json.dumps(payload.get("runtime_regression", {}), ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    missing_gate_report_path = _artifact_dir_for_job(job_id) / "missing_gate_report.json"
    missing_gate_report_path.write_text(
        json.dumps(payload.get("missing_gate_governance", {}), ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    semantic_consistency_report_path = _artifact_dir_for_job(job_id) / "semantic_consistency_report.json"
    shared_rule_clusters_path = _artifact_dir_for_job(job_id) / "shared_rule_clusters.json"
    shared_rule_clusters_path.write_text(json.dumps(shared_clusters, ensure_ascii=False, indent=2), encoding="utf-8")
    rulepack_size_report = _build_rulepack_size_governance_report(
        form_code=form_code,
        job_id=job_id,
        current_path=out_path,
    )
    rulepack_size_report_path = _artifact_dir_for_job(job_id) / "rulepack_size_report.json"
    rulepack_size_report_path.write_text(
        json.dumps(rulepack_size_report, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    # Rulepack snapshot regression (per job artifacts)
    snapshot_now = _build_rulepack_regression_snapshot(payload=payload)
    snapshot_ts = datetime.utcnow().strftime("%Y%m%dT%H%M%SZ")
    snapshot_dir = _artifact_dir_for_job(job_id)
    previous_paths = sorted(
        [p for p in snapshot_dir.glob("snapshot_*.json") if p.is_file()],
        key=lambda p: p.stat().st_mtime,
        reverse=True,
    )
    previous_snapshot: Dict[str, Any] = {}
    previous_snapshot_path = ""
    if previous_paths:
        previous_snapshot_path = str(previous_paths[0].resolve())
        try:
            obj = json.loads(previous_paths[0].read_text(encoding="utf-8-sig"))
            previous_snapshot = obj if isinstance(obj, dict) else {}
        except Exception:
            previous_snapshot = {}
    snapshot_file = snapshot_dir / f"snapshot_{snapshot_ts}.json"
    snapshot_file.write_text(json.dumps(snapshot_now, ensure_ascii=False, indent=2), encoding="utf-8")
    snapshot_diff = (
        _snapshot_regression_diff(snapshot_now, previous_snapshot)
        if previous_snapshot
        else {
            "has_diff": False,
            "rules": {"added": [], "removed": [], "modified": []},
            "gates": {"added": [], "removed": [], "modified": []},
            "components": {"added": [], "removed": [], "modified": []},
            "counts": {"current": {
                "rule_count": int(snapshot_now.get("rule_count", 0) or 0),
                "gate_count": int(snapshot_now.get("gate_count", 0) or 0),
                "component_count": int(snapshot_now.get("component_count", 0) or 0),
                "unresolved_count": int(snapshot_now.get("unresolved_count", 0) or 0),
            }, "previous": {}},
        }
    )
    snapshot_diff_doc = {
        "generated_at": _utc_now(),
        "job_id": job_id,
        "current_snapshot": str(snapshot_file.resolve()),
        "previous_snapshot": previous_snapshot_path,
        "diff": snapshot_diff,
    }
    snapshot_diff_path = snapshot_dir / "snapshot_diff.json"
    snapshot_diff_path.write_text(json.dumps(snapshot_diff_doc, ensure_ascii=False, indent=2), encoding="utf-8")
    integrity_report = _build_asset_integrity_report(job_id)
    out = {
        "status": "ok",
        "rulepack_name": file_name,
        "rulepack_path": str(out_path),
        "download_url": f"/normref/rulepack/download/{file_name}",
        "meta": payload["meta"],
        "quality_gate": quality_gate,
        "golden_compare": golden_compare,
        "golden_diff_report": golden_diff_report,
        "golden_diff_report_path": str(golden_diff_path.resolve()),
        "gate_regression": payload.get("gate_regression", {}),
        "gate_regression_report_path": str(gate_regression_path.resolve()),
        "runtime_regression": payload.get("runtime_regression", {}),
        "runtime_regression_report_path": str(runtime_regression_path.resolve()),
        "semantic_consistency": semantic_consistency,
        "semantic_consistency_report_path": str(semantic_consistency_report_path.resolve()),
        "shared_rule_clusters": shared_clusters,
        "shared_rule_clusters_path": str(shared_rule_clusters_path.resolve()),
        "missing_gate_report": payload.get("missing_gate_governance", {}),
        "missing_gate_report_path": str(missing_gate_report_path.resolve()),
        "rulepack_size_report": rulepack_size_report,
        "rulepack_size_report_path": str(rulepack_size_report_path.resolve()),
        "snapshot_path": str(snapshot_file.resolve()),
        "snapshot_diff": snapshot_diff_doc,
        "snapshot_diff_path": str(snapshot_diff_path.resolve()),
        "measurement_gate_mapping": measurement_gate_mapping,
        "docpeg_coverage": docpeg_coverage,
        "schema_validation": payload["schema_validation"],
        "unresolved_stats": payload.get("unresolved_stats", {}),
        "whitelist_filtering": payload.get("whitelist_filtering", {}),
        "build_log": payload.get("build_log", {}),
        "slot_manifest": {
            "count": int(slot_manifest_payload.get("count", 0) or 0),
            "path": str(slot_manifest_path),
        },
        "traceability_export": {
            "count": int(len(traceability_payload.get("timeline", []) if isinstance(traceability_payload.get("timeline"), list) else [])),
            "path": str(traceability_path),
        },
        "asset_integrity_report": integrity_report,
        "rulepack_manifest": {
            **rulepack_manifest_payload,
            "path": str(rulepack_manifest_path),
        },
        "audit_report": audit_report,
        "audit_report_path": str(audit_path.resolve()),
        "canonical_preview": canonical_doc,
        "counts": {
            "components": len(comp_rows),
            "rules": len(normalized_rules),
            "gates": len(gates_payload),
            "proof_templates": len(proof_template_rows),
            "traceability": len(traceability),
        },
    }
    _append_trace("rulepack_build", job_id=job_id, form_code=form_code, duration_ms=(time.perf_counter() - t_build_start) * 1000.0, ok=True)
    _update_obs_metrics(
        build_success_inc=1,
        rule_count=len(normalized_rules),
        gate_count=len(gates_payload),
        unresolved_count=int((payload.get("unresolved", {}) if isinstance(payload.get("unresolved"), dict) else {}).get("count", 0) or 0),
    )
    return out


@app.get("/normref/rulepack/download/{rulepack_name}")
def download_rulepack(rulepack_name: str) -> FileResponse:
    safe_name = str(rulepack_name or "").strip()
    if not safe_name or "/" in safe_name or "\\" in safe_name:
        raise HTTPException(status_code=400, detail="非法 rulepack_name")
    target = (NORMREF_RULEPACK_DIR / safe_name).resolve()
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=404, detail=f"未找到 rulepack：{safe_name}")
    return FileResponse(path=target, filename=safe_name, media_type="application/json")


@app.get("/normref/rulepack/quality/{rulepack_name}")
def get_rulepack_quality(rulepack_name: str) -> Dict[str, Any]:
    safe_name = str(rulepack_name or "").strip()
    if not safe_name or "/" in safe_name or "\\" in safe_name:
        raise HTTPException(status_code=400, detail="非法 rulepack_name")
    target = (NORMREF_RULEPACK_DIR / safe_name).resolve()
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=404, detail=f"未找到 rulepack：{safe_name}")
    try:
        payload = json.loads(target.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail="rulepack JSON 非法") from exc
    _assert_rulepack_version_compatible(payload if isinstance(payload, dict) else {}, stage="runtime_input")
    schema_ok, schema_errs, _, resolved = _validate_rulepack_schema_with_compat(payload if isinstance(payload, dict) else {})
    if not schema_ok:
        preview = "; ".join(schema_errs[:10])
        raise HTTPException(status_code=400, detail=f"rulepack schema({resolved}) 校验失败：{preview}")
    quality = payload.get("quality_gate") if isinstance(payload, dict) else None
    if not isinstance(quality, dict):
        raise HTTPException(status_code=404, detail="该 rulepack 不包含 quality_gate 信息")
    unresolved = payload.get("unresolved") if isinstance(payload, dict) else {}
    return {
        "status": "ok",
        "rulepack_name": safe_name,
        "schema_version": _detect_rulepack_schema_version(payload if isinstance(payload, dict) else {}),
        "quality_gate": quality,
        "unresolved": unresolved if isinstance(unresolved, dict) else {},
    }


