@app.get("/normref/audit/production/timeline")
def get_production_audit_timeline(
    date_from: str = "",
    date_to: str = "",
    actor: str = "",
    event_type: str = "",
    limit: int = 500,
) -> Dict[str, Any]:
    lim = max(1, min(int(limit or 500), 5000))
    df = str(date_from or "").strip()
    dt = str(date_to or "").strip()
    actor_q = str(actor or "").strip()
    type_q = str(event_type or "").strip()
    rows = _load_production_audit_events(limit=0)
    out: List[Dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        if actor_q and str(row.get("actor") or "").strip() != actor_q:
            continue
        if type_q and str(row.get("event_type") or "").strip() != type_q:
            continue
        ts = str(row.get("time") or "").strip()
        day = ts[:10] if len(ts) >= 10 else ""
        if df and day and day < df:
            continue
        if dt and day and day > dt:
            continue
        out.append(row)
    chain = _verify_production_audit_chain(rows)
    return {"status": "ok", "immutable": True, "chain_valid": bool(chain.get("valid")), "chain": chain, "items": out[-lim:]}


