@app.get("/normref/unresolved/trends")
def get_unresolved_trends(form_code: str = "", norm_version: str = "", date_from: str = "", date_to: str = "") -> Dict[str, Any]:
    fc = str(form_code or "").strip()
    nv = str(norm_version or "").strip()
    d_to = date.today()
    d_from = d_to.fromordinal(max(1, d_to.toordinal() - 13))
    if str(date_from or "").strip():
        try:
            d_from = date.fromisoformat(str(date_from).strip())
        except Exception:
            pass
    if str(date_to or "").strip():
        try:
            d_to = date.fromisoformat(str(date_to).strip())
        except Exception:
            pass
    if d_from > d_to:
        d_from, d_to = d_to, d_from
    days = _iter_days(d_from, d_to)
    trend: Dict[str, Dict[str, Any]] = {d: {"date": d, "unresolved_count": 0, "overdue_count": 0} for d in days}
    for p in NORMREF_RULEPACK_DIR.glob("*.rulepack.json"):
        if not p.is_file():
            continue
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        meta = doc.get("meta", {}) if isinstance(doc.get("meta"), dict) else {}
        f = str(meta.get("form_code") or "").strip()
        nver = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
        if fc and f != fc:
            continue
        if nv and nver != nv:
            continue
        day = datetime.utcfromtimestamp(p.stat().st_mtime).date().isoformat()
        if day not in trend:
            continue
        unresolved = doc.get("unresolved", {}) if isinstance(doc.get("unresolved"), dict) else {}
        rows = unresolved.get("items", []) if isinstance(unresolved.get("items"), list) else []
        cnt = len([x for x in rows if isinstance(x, dict)])
        overdue = 0
        today_str = date.today().isoformat()
        for row in rows:
            if not isinstance(row, dict):
                continue
            st = str(row.get("status") or "").strip().lower() or "open"
            due = str(row.get("due_date") or "").strip()
            if st not in {"resolved", "verified"} and due and due < today_str:
                overdue += 1
        trend[day]["unresolved_count"] += cnt
        trend[day]["overdue_count"] += overdue
    return {
        "status": "ok",
        "filters": {"form_code": fc, "norm_version": nv, "date_from": d_from.isoformat(), "date_to": d_to.isoformat()},
        "items": [trend[d] for d in days],
    }


@app.post("/normref/unresolved/status")
def update_unresolved_status(request: UnresolvedStatusUpdateRequest) -> Dict[str, Any]:
    jid = str(request.job_id or "").strip()
    rid = str(request.rule_id or "").strip()
    utype = str(request.unresolved_type or "").strip()
    from_status = str(request.from_status or "").strip().lower()
    to_status = str(request.to_status or "").strip().lower()
    operator = str(request.operator or "").strip() or "system"
    if not jid:
        raise HTTPException(status_code=400, detail="job_id 不能为空")
    transitions = {"open": ["processing"], "processing": ["resolved"], "resolved": ["verified"], "verified": []}
    packs = _find_rulepacks_by_job(jid)
    updated = 0
    for p in packs:
        try:
            doc = json.loads(p.read_text(encoding="utf-8"))
        except Exception:
            continue
        if not isinstance(doc, dict):
            continue
        unresolved = doc.get("unresolved", {}) if isinstance(doc.get("unresolved"), dict) else {}
        rows = unresolved.get("items", []) if isinstance(unresolved.get("items"), list) else []
        changed = False
        for row in rows:
            if not isinstance(row, dict):
                continue
            if rid and str(row.get("rule_id") or "").strip() != rid:
                continue
            if utype and str(row.get("type") or "").strip() != utype:
                continue
            cur = str(row.get("status") or "open").strip().lower()
            if from_status and cur != from_status:
                continue
            if to_status != cur and to_status not in transitions.get(cur, []):
                raise HTTPException(status_code=400, detail=f"非法状态流转: {cur} -> {to_status}")
            row["status"] = to_status
            row["updated_by"] = operator
            row["updated_at"] = _utc_now()
            if to_status in {"resolved", "verified"} and not str(row.get("resolved_at") or "").strip():
                row["resolved_at"] = _utc_now()
            updated += 1
            changed = True
        if changed:
            unresolved["items"] = rows
            doc["unresolved"] = unresolved
            p.write_text(json.dumps(doc, ensure_ascii=False, indent=2), encoding="utf-8")
    return {"status": "ok", "job_id": jid, "updated": updated, "to_status": to_status}


@app.get("/normref/measurement-gate-mapping/stats")
def get_measurement_gate_mapping_stats(job_id: str) -> Dict[str, Any]:
    jid = str(job_id or "").strip()
    if not jid:
        raise HTTPException(status_code=400, detail="job_id 不能为空")
    return {
        "status": "ok",
        "job_id": jid,
        "measurement_gate_mapping": _collect_measurement_gate_mapping_summary_for_job(jid),
    }


@app.get("/normref/docpeg/coverage")
def get_docpeg_coverage(form_code: str = "", job_id: str = "") -> Dict[str, Any]:
    fcode = str(form_code or "").strip()
    jid = str(job_id or "").strip()
    # Priority 1: job-level runtime coverage from built rulepack(s)
    if jid:
        packs = _find_rulepacks_by_job(jid)
        items: List[Dict[str, Any]] = []
        for p in packs:
            try:
                doc = json.loads(p.read_text(encoding="utf-8"))
            except Exception:
                continue
            cov = doc.get("docpeg_coverage") if isinstance(doc, dict) else None
            if isinstance(cov, dict):
                items.append(cov)
        if fcode:
            items = [x for x in items if str(x.get("form_code") or "").strip() == fcode]
        return {"status": "ok", "source": "rulepack", "job_id": jid, "items": items}

    # Priority 2: form-level coverage from semantic_tree in specbundle storage
    bundles = list(SPECBUNDLE_REPO_DIR.glob("*.json")) if SPECBUNDLE_REPO_DIR.exists() else []
    items: List[Dict[str, Any]] = []
    for p in bundles:
        try:
            b = json.loads(p.read_text(encoding="utf-8-sig"))
        except Exception:
            continue
        if not isinstance(b, dict):
            continue
        form = str(b.get("formCode") or "").strip()
        if fcode and form != fcode:
            continue
        st = b.get("semanticTree", {})
        if not isinstance(st, dict):
            continue
        ok, _ = _validate_semantic_tree_for_form(form, st)
        if not ok:
            continue
        items.append(_compute_docpeg_coverage_from_semantic_tree_only(form, st))
    return {"status": "ok", "source": "specbundle.semantic_tree", "items": items}


@app.post("/normref/rulepack/release")
def release_rulepack_by_form(request: RulepackReleaseRequest) -> Dict[str, Any]:
    form_code = str(request.form_code or "").strip()
    operator = str(request.operator or "").strip()
    version = str(request.version or "").strip()
    canary_version = str(request.canary_version or "").strip()
    gray_ratio = float(request.gray_ratio or 0.0)
    if not form_code:
        raise HTTPException(status_code=400, detail="form_code 不能为空")
    if not operator:
        raise HTTPException(status_code=400, detail="operator 不能为空")
    _require_role(operator, "publisher", action="rulepack_rollback", target=form_code or norm_version or project_id or "global")
    _require_role(operator, "publisher", action="rulepack_release", target=form_code)
    if gray_ratio < 0 or gray_ratio > 1:
        raise HTTPException(status_code=400, detail="gray_ratio 必须在 [0,1]")
    _assert_auto_regression_pass_for_forms([form_code])
    _ensure_rulepack_exists(version)
    if canary_version:
        _ensure_rulepack_exists(canary_version)
    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
    if not isinstance(forms, dict):
        forms = {}
    cur = forms.get(form_code, {}) if isinstance(forms.get(form_code, {}), dict) else {}
    # Snapshot regression gate:
    # 1) generate candidate snapshot
    # 2) compare with current stable baseline snapshot
    # 3) if diff exists and not approved, block release
    candidate_snapshot = _generate_rulepack_snapshot(form_code, version)
    candidate_doc = candidate_snapshot.get("snapshot", {}) if isinstance(candidate_snapshot.get("snapshot"), dict) else {}
    candidate_hash = str(candidate_doc.get("canonical_hash") or "").strip()
    baseline_version = str(cur.get("stable_version") or cur.get("active_version") or "").strip()
    snapshot_diff: Dict[str, Any] = {"has_diff": False, "rules": {"added": [], "removed": [], "changed": []}, "gates": {"added": [], "removed": [], "changed": []}, "components": {"added": [], "removed": [], "changed": []}}
    baseline_snapshot_path = ""
    if baseline_version and baseline_version != version:
        baseline_snapshot = _generate_rulepack_snapshot(form_code, baseline_version)
        baseline_doc = baseline_snapshot.get("snapshot", {}) if isinstance(baseline_snapshot.get("snapshot"), dict) else {}
        baseline_snapshot_path = str(baseline_snapshot.get("snapshot_path") or "")
        snapshot_diff = _compare_rulepack_snapshots(candidate_doc, baseline_doc)
        diff_path = _snapshot_file_path(form_code, f"{version}.diff")
        diff_payload = {
            "form_code": form_code,
            "candidate_version": version,
            "baseline_version": baseline_version,
            "generated_at": _utc_now(),
            "snapshot_diff": snapshot_diff,
            "candidate_snapshot_path": str(candidate_snapshot.get("snapshot_path") or ""),
            "baseline_snapshot_path": baseline_snapshot_path,
        }
        diff_path.write_text(json.dumps(diff_payload, ensure_ascii=False, indent=2), encoding="utf-8")
        if bool(snapshot_diff.get("has_diff", False)) and not _is_snapshot_diff_approved(form_code, version, candidate_hash):
            raise HTTPException(
                status_code=400,
                detail=(
                    "发布阻断：检测到 rulepack snapshot 差异且未经确认。"
                    f" form_code={form_code}, candidate={version}, baseline={baseline_version}, "
                    f"diff_file={str(diff_path.resolve())}"
                ),
            )
    history = cur.get("history", []) if isinstance(cur.get("history", []), list) else []
    now = _utc_now()
    prev_active = str(cur.get("active_version") or "").strip()
    row = {
        "form_code": form_code,
        "active_version": version,
        "stable_version": version,
        "canary_version": canary_version,
        "gray_ratio": gray_ratio,
        "updated_by": operator,
        "updated_at": now,
        "history": history,
    }
    history.append(
        {
            "action": "release",
            "version": version,
            "form_code": form_code,
            "operator": operator,
            "time": now,
            "from_version": prev_active,
            "to_version": version,
            "gray_ratio": gray_ratio,
            "canary_version": canary_version,
        }
    )
    row["history"] = history[-200:]
    forms[form_code] = row
    reg["forms"] = forms
    _save_rulepack_release_registry(reg)
    specir_snapshot_path = ""
    publish_meta_path = ""
    try:
        rp_path = _rulepack_name_to_path(version)
        rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
        if isinstance(rp_doc, dict):
            meta_obj = rp_doc.get("meta", {}) if isinstance(rp_doc.get("meta"), dict) else {}
            rp_doc = _upsert_rulepack_lineage(
                payload=rp_doc,
                norm_id=str(meta_obj.get("spec_code") or meta_obj.get("norm_id") or "").strip(),
                norm_version=str(meta_obj.get("norm_version") or meta_obj.get("spec_version") or "").strip(),
                source_file_hash=str(meta_obj.get("source_doc_hash") or "").strip(),
                created_by="",
                reviewed_by="",
                published_by=operator,
                published_at=now,
            )
            rp_path.write_text(json.dumps(rp_doc, ensure_ascii=False, indent=2), encoding="utf-8")
            specir_snapshot = _build_specir_snapshot_doc(form_code, version, rp_doc)
            specir_path = _specir_snapshot_file_path(form_code, version)
            specir_path.write_text(json.dumps(specir_snapshot, ensure_ascii=False, indent=2), encoding="utf-8")
            specir_snapshot_path = str(specir_path.resolve())
            publish_meta = {
                "schema_version": "publish_meta.v1",
                "generated_at": now,
                "form_code": form_code,
                "version": version,
                "from_version": prev_active,
                "operator": operator,
                "gray_ratio": gray_ratio,
                "canary_version": canary_version,
                "norm_version": str(meta_obj.get("norm_version") or meta_obj.get("spec_version") or "").strip(),
                "rulepack_snapshot_path": str(candidate_snapshot.get("snapshot_path") or ""),
                "specir_snapshot_path": specir_snapshot_path,
            }
            pub_path = _publish_meta_file_path(form_code, version)
            pub_path.write_text(json.dumps(publish_meta, ensure_ascii=False, indent=2), encoding="utf-8")
            publish_meta_path = str(pub_path.resolve())
            latest_hist = row.get("history", []) if isinstance(row.get("history"), list) else []
            if latest_hist:
                latest_hist[-1]["rulepack_snapshot"] = str(candidate_snapshot.get("snapshot_path") or "")
                latest_hist[-1]["specir_snapshot"] = specir_snapshot_path
                latest_hist[-1]["publish_meta"] = publish_meta_path
                row["history"] = latest_hist
                forms[form_code] = row
                reg["forms"] = forms
                _save_rulepack_release_registry(reg)
    except Exception:
        # keep release successful for legacy/bad historical packs
        pass
    _audit_security_event(action="rulepack_release", actor=operator, result="success", target=f"{form_code}:{version}", required_role="publisher")
    _append_production_audit_event(
        event_type="rulepack_published",
        actor=operator,
        target=f"{form_code}:{version}",
        action="publish_rulepack",
        before={"active_version": prev_active},
        after={"active_version": version},
        extra={"form_code": form_code, "version": version, "gray_ratio": gray_ratio, "canary_version": canary_version},
    )
    return {
        "status": "ok",
        "release": {"version": version, "form_code": form_code, "operator": operator, "time": now},
        "current": row,
        "snapshot_regression": {
            "candidate_snapshot_path": str(candidate_snapshot.get("snapshot_path") or ""),
            "baseline_snapshot_path": baseline_snapshot_path,
            "diff": snapshot_diff,
            "approved": bool(not snapshot_diff.get("has_diff", False) or _is_snapshot_diff_approved(form_code, version, candidate_hash)),
        },
        "snapshots": {
            "rulepack_snapshot": str(candidate_snapshot.get("snapshot_path") or ""),
            "specir_snapshot": specir_snapshot_path,
            "publish_meta": publish_meta_path,
        },
    }


@app.post("/normref/rulepack/snapshot/approve")
def approve_rulepack_snapshot_diff(request: RulepackSnapshotApproveRequest) -> Dict[str, Any]:
    form_code = str(request.form_code or "").strip()
    version = str(request.version or "").strip()
    operator = str(request.operator or "").strip()
    reason = str(request.reason or "").strip()
    if not form_code or not version or not operator:
        raise HTTPException(status_code=400, detail="form_code/version/operator 不能为空")
    snap = _generate_rulepack_snapshot(form_code, version)
    snap_doc = snap.get("snapshot", {}) if isinstance(snap.get("snapshot"), dict) else {}
    candidate_hash = str(snap_doc.get("canonical_hash") or "").strip()
    rows_doc = _load_rulepack_snapshot_approvals()
    rows = rows_doc.get("approvals", {}) if isinstance(rows_doc.get("approvals"), dict) else {}
    key = f"{form_code}::{version}"
    rows[key] = {
        "approved": True,
        "form_code": form_code,
        "version": version,
        "candidate_hash": candidate_hash,
        "operator": operator,
        "reason": reason,
        "approved_at": _utc_now(),
    }
    rows_doc["approvals"] = rows
    _save_rulepack_snapshot_approvals(rows_doc)
    return {"status": "ok", "approval": rows[key], "snapshot_path": str(snap.get("snapshot_path") or "")}


@app.post("/normref/rulepack/rollback")
def rollback_rulepack_by_form(request: RulepackRollbackRequest) -> Dict[str, Any]:
    form_code = str(request.form_code or "").strip()
    norm_version = str(request.norm_version or "").strip()
    project_id = str(request.project_id or "").strip()
    target = str(request.target or "form_code").strip().lower() or "form_code"
    operator = str(request.operator or "").strip()
    rollback_reason = str(request.rollback_reason or "").strip() or "manual rollback"
    dry_run = bool(request.dry_run)
    force_rollback = bool(request.force_rollback)
    if not operator:
        raise HTTPException(status_code=400, detail="operator 不能为空")
    if target not in {"form_code", "norm_version", "project"}:
        raise HTTPException(status_code=400, detail="target 必须是 form_code|norm_version|project")
    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
    target_forms: List[str] = []
    if target == "form_code":
        if not form_code:
            raise HTTPException(status_code=400, detail="form_code 不能为空")
        target_forms = [form_code]
    elif target == "norm_version":
        if not norm_version:
            raise HTTPException(status_code=400, detail="norm_version 不能为空")
        for fc, row in forms.items():
            if not isinstance(row, dict):
                continue
            active = str(row.get("active_version") or "").strip()
            if not active:
                continue
            try:
                rp_doc = json.loads(_rulepack_name_to_path(active).read_text(encoding="utf-8"))
            except Exception:
                continue
            meta = rp_doc.get("meta", {}) if isinstance(rp_doc.get("meta"), dict) else {}
            nv = str(meta.get("norm_version") or meta.get("spec_version") or "").strip()
            if nv == norm_version:
                target_forms.append(str(fc).strip())
    else:
        if not project_id:
            raise HTTPException(status_code=400, detail="project_id 不能为空")
        target_forms = _resolve_forms_for_project(project_id, forms if isinstance(forms, dict) else {})
    target_forms = sorted(list(set([x for x in target_forms if x])))
    if not target_forms:
        raise HTTPException(status_code=404, detail="未找到可回滚的目标表单")

    plans: List[Dict[str, Any]] = []
    errors: List[str] = []
    for fc in target_forms:
        cur = forms.get(fc, {}) if isinstance(forms.get(fc, {}), dict) else {}
        if not cur:
            if force_rollback:
                plans.append({"form_code": fc, "skipped": True, "reason": "no_release_record"})
                continue
            errors.append(f"form_code={fc} 不存在发布记录")
            continue
        history = cur.get("history", []) if isinstance(cur.get("history", []), list) else []
        current_active = str(cur.get("active_version") or "").strip()
        prev = ""
        for item in reversed(history):
            if not isinstance(item, dict):
                continue
            to_ver = str(item.get("to_version") or item.get("version") or "").strip()
            if to_ver and to_ver != current_active:
                prev = to_ver
                break
        if not prev and force_rollback:
            plans.append({"form_code": fc, "from_version": current_active, "to_version": current_active, "skipped": True, "reason": "no_previous_version"})
            continue
        if not prev:
            errors.append(f"form_code={fc} 没有可回滚的上一版本")
            continue
        try:
            _ensure_rulepack_exists(prev)
        except Exception:
            if force_rollback:
                plans.append({"form_code": fc, "from_version": current_active, "to_version": prev, "skipped": True, "reason": "target_rulepack_missing"})
                continue
            errors.append(f"form_code={fc} 目标版本不存在: {prev}")
            continue
        plans.append({"form_code": fc, "from_version": current_active, "to_version": prev, "skipped": False})
    if errors and not force_rollback:
        raise HTTPException(status_code=400, detail="; ".join(errors[:20]))

    now = _utc_now()
    affected_forms = [str(x.get("form_code") or "").strip() for x in plans if not bool(x.get("skipped", False))]
    report = {
        "schema_version": "rollback_report.v1",
        "generated_at": now,
        "target": target,
        "operator": operator,
        "rollback_reason": rollback_reason,
        "dry_run": dry_run,
        "force_rollback": force_rollback,
        "from_version": {str(x.get("form_code") or ""): str(x.get("from_version") or "") for x in plans if str(x.get("form_code") or "")},
        "to_version": {str(x.get("form_code") or ""): str(x.get("to_version") or "") for x in plans if str(x.get("form_code") or "")},
        "affected_forms": affected_forms,
        "plans": plans,
    }
    NORMREF_REPORT_DIR.mkdir(parents=True, exist_ok=True)
    report_path = NORMREF_REPORT_DIR / "rollback_report.json"
    report_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    report["report_path"] = str(report_path.resolve())
    if dry_run:
        report["rollback_status"] = "dry_run"
        return {"status": "ok", "dry_run": True, "report": report}

    for plan in plans:
        if bool(plan.get("skipped", False)):
            continue
        fc = str(plan.get("form_code") or "").strip()
        cur = forms.get(fc, {}) if isinstance(forms.get(fc, {}), dict) else {}
        if not cur:
            continue
        history = cur.get("history", []) if isinstance(cur.get("history", []), list) else []
        from_ver = str(plan.get("from_version") or "").strip()
        to_ver = str(plan.get("to_version") or "").strip()
        cur["active_version"] = to_ver
        cur["stable_version"] = to_ver
        cur["canary_version"] = ""
        cur["gray_ratio"] = 0.0
        cur["updated_by"] = operator
        cur["updated_at"] = now
        history.append(
            {
                "action": "rollback",
                "version": to_ver,
                "form_code": fc,
                "operator": operator,
                "time": now,
                "from_version": from_ver,
                "to_version": to_ver,
                "rollback_reason": rollback_reason,
            }
        )
        cur["history"] = history[-200:]
        forms[fc] = cur
    reg["forms"] = forms
    _save_rulepack_release_registry(reg)
    cache_path = _write_runtime_cache_refresh(affected_forms, operator, rollback_reason)
    for plan in plans:
        if bool(plan.get("skipped", False)):
            continue
        _append_production_audit_event(
            event_type="rulepack_rollback",
            actor=operator,
            target=f"{str(plan.get('form_code') or '').strip()}:{str(plan.get('to_version') or '').strip()}",
            action="rollback_rulepack",
            before={"active_version": str(plan.get("from_version") or "").strip()},
            after={"active_version": str(plan.get("to_version") or "").strip()},
            extra={"rollback_reason": rollback_reason, "target": target, "dry_run": dry_run, "force_rollback": force_rollback},
        )
    validation = _validate_rollback_forms(affected_forms)
    report["cache_refresh_state_path"] = cache_path
    report["validation"] = validation
    if not bool(validation.get("ok", False)):
        # auto restore pre-rollback versions
        restore_now = _utc_now()
        for plan in plans:
            if bool(plan.get("skipped", False)):
                continue
            fc = str(plan.get("form_code") or "").strip()
            from_ver = str(plan.get("from_version") or "").strip()
            if not fc or not from_ver:
                continue
            cur = forms.get(fc, {}) if isinstance(forms.get(fc, {}), dict) else {}
            if not cur:
                continue
            hist = cur.get("history", []) if isinstance(cur.get("history", []), list) else []
            cur["active_version"] = from_ver
            cur["stable_version"] = from_ver
            cur["canary_version"] = ""
            cur["gray_ratio"] = 0.0
            cur["updated_by"] = operator
            cur["updated_at"] = restore_now
            hist.append(
                {
                    "action": "rollback_restore",
                    "version": from_ver,
                    "form_code": fc,
                    "operator": operator,
                    "time": restore_now,
                    "from_version": str(plan.get("to_version") or "").strip(),
                    "to_version": from_ver,
                    "rollback_reason": f"auto_restore_after_validation_failed:{rollback_reason}",
                }
            )
            cur["history"] = hist[-200:]
            forms[fc] = cur
        reg["forms"] = forms
        _save_rulepack_release_registry(reg)
        report["rollback_status"] = "failed"
        report["auto_restored"] = True
        report_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
        return {"status": "failed", "dry_run": False, "report": report, "updated_forms": affected_forms}
    report["rollback_status"] = "success"
    report["auto_restored"] = False
    report_path.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    _update_obs_metrics(rollback_inc=max(1, len(affected_forms)))
    return {"status": "ok", "dry_run": False, "report": report, "updated_forms": affected_forms}


@app.post("/normref/rulepack/patch/auto-generate")
def auto_generate_rulepack_patch(request: AutoPatchGenerateRequest) -> Dict[str, Any]:
    form_code = str(request.form_code or "").strip()
    operator = str(request.operator or "").strip() or "system"
    base_v, target_v = _resolve_patch_versions(form_code, str(request.base_version or "").strip(), str(request.target_version or "").strip())
    if not form_code:
        # fallback from target rulepack meta
        try:
            t_doc = json.loads(_rulepack_name_to_path(target_v).read_text(encoding="utf-8"))
            t_meta = t_doc.get("meta", {}) if isinstance(t_doc.get("meta"), dict) else {}
            form_code = str(t_meta.get("form_code") or "").strip()
        except Exception:
            form_code = ""
    patch = _generate_rulepack_patch(form_code=form_code, base_version=base_v, target_version=target_v)
    preview_doc = {
        "schema_version": "rulepack_patch_preview.v1",
        "generated_at": _utc_now(),
        "form_code": form_code,
        "base_version": base_v,
        "target_version": target_v,
        **patch,
    }
    preview_path = NORMREF_REPORT_DIR / "rulepack_patch_preview.json"
    preview_path.parent.mkdir(parents=True, exist_ok=True)
    preview_path.write_text(json.dumps(preview_doc, ensure_ascii=False, indent=2), encoding="utf-8")

    if bool(request.rollback):
        rb = rollback_rulepack_by_form(
            RulepackRollbackRequest(
                form_code=form_code,
                operator=operator,
                rollback_reason=str(request.rollback_reason or "auto patch rollback").strip(),
                dry_run=bool(request.dry_run),
            )
        )
        return {"status": "ok", "mode": "rollback", "dry_run": bool(request.dry_run), "preview": bool(request.preview), **patch, "preview_path": str(preview_path.resolve()), "rollback_result": rb}

    return {"status": "ok", "mode": "dry_run" if bool(request.dry_run) else "apply_plan", "dry_run": bool(request.dry_run), "preview": bool(request.preview), **patch, "preview_path": str(preview_path.resolve())}


@app.get("/normref/rulepack/release/current")
def get_current_rulepack_release(form_code: str) -> Dict[str, Any]:
    f = str(form_code or "").strip()
    if not f:
        raise HTTPException(status_code=400, detail="form_code 不能为空")
    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
    cur = forms.get(f, {}) if isinstance(forms.get(f, {}), dict) else {}
    if not cur:
        raise HTTPException(status_code=404, detail=f"form_code={f} 无发布记录")
    return {"status": "ok", "form_code": f, "current": cur}


@app.get("/normref/rulepack/release/history")
def get_rulepack_release_history(form_code: str = "") -> Dict[str, Any]:
    reg = _load_rulepack_release_registry()
    forms = reg.get("forms", {}) if isinstance(reg, dict) else {}
    if not isinstance(forms, dict):
        forms = {}
    fc = str(form_code or "").strip()
    if fc:
        cur = forms.get(fc, {}) if isinstance(forms.get(fc, {}), dict) else {}
        if not cur:
            raise HTTPException(status_code=404, detail=f"form_code={fc} 无发布记录")
        return {
            "status": "ok",
            "form_code": fc,
            "active_version": str(cur.get("active_version") or "").strip(),
            "history": cur.get("history", []) if isinstance(cur.get("history"), list) else [],
            "current": cur,
        }
    items = []
    for k, row in forms.items():
        if not isinstance(row, dict):
            continue
        items.append(
            {
                "form_code": str(k).strip(),
                "active_version": str(row.get("active_version") or "").strip(),
                "updated_at": str(row.get("updated_at") or "").strip(),
                "updated_by": str(row.get("updated_by") or "").strip(),
                "history_count": len(row.get("history", [])) if isinstance(row.get("history"), list) else 0,
            }
        )
    items = sorted(items, key=lambda x: (str(x.get("updated_at") or ""), str(x.get("form_code") or "")), reverse=True)
    return {"status": "ok", "items": items}


@app.get("/normref/runtime/rulepack/resolve")
def resolve_runtime_rulepack(form_code: str, subject: str = "") -> Dict[str, Any]:
    resolved = _resolve_runtime_rulepack_version(str(form_code or "").strip(), subject=subject)
    return {"status": "ok", **resolved}


@app.get("/normref/rules/source-locate")
def locate_rule_source(job_id: str, rule_id: str) -> Dict[str, Any]:
    jid = str(job_id or "").strip()
    rid = str(rule_id or "").strip()
    if not jid or not rid:
        raise HTTPException(status_code=400, detail="job_id 与 rule_id 不能为空")
    art_dir = _artifact_dir_for_job(jid)
    rules_path = art_dir / "07_rules.json"
    normref_path = art_dir / "norm_ref_index.json"
    if not rules_path.exists() or not normref_path.exists():
        raise HTTPException(status_code=404, detail="缺少规则或 norm_ref_index 产物")
    try:
        rules_doc = json.loads(rules_path.read_text(encoding="utf-8"))
        normref_doc = json.loads(normref_path.read_text(encoding="utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=400, detail="产物 JSON 非法") from exc
    rows = rules_doc.get("rules", []) if isinstance(rules_doc, dict) else []
    if not isinstance(rows, list):
        rows = []
    rule = None
    for row in rows:
        if not isinstance(row, dict):
            continue
        if str(row.get("rule_id") or "").strip() == rid:
            rule = row
            break
    if not isinstance(rule, dict):
        raise HTTPException(status_code=404, detail=f"未找到 rule: {rid}")
    ref_map = _build_normref_entry_map(normref_doc if isinstance(normref_doc, dict) else {})
    norm_ref = str(rule.get("norm_ref") or "").strip()
    anchor = _extract_rule_anchor_fields(rule, ref_map.get(norm_ref))
    errs = _validate_rule_anchor_fields(anchor)
    return {
        "status": "ok",
        "job_id": jid,
        "rule_id": rid,
        "anchor": anchor,
        "valid": len(errs) == 0,
        "errors": errs,
        "click_url": f"/normref/rules/source-locate?job_id={jid}&rule_id={rid}",
    }


@app.post("/normref/publish-workflow")
def publish_normdoc_workflow(request: PublishNormDocWorkflowRequest) -> Dict[str, Any]:
    t_publish_start = time.perf_counter()
    parsed_normref = _parse_normref_uri(request.normRef)
    job_id = str(request.job_id or "").strip()
    standard_code = str(request.standard_code or "").strip()
    version = _normalize_bundle_version(request.version)
    published_by = str(request.published_by or request.publisher or "").strip()
    req_normdoc_id = str(request.normdoc_id or "").strip()
    req_bundle_hash = str(request.bundle_hash or "").strip()
    req_signature = str(request.signature or "").strip()
    publish_executable_package = bool(request.publish_executable_package)
    _update_obs_metrics(publish_total_inc=1)
    try:
        if not published_by:
            raise HTTPException(status_code=400, detail="published_by 不能为空")
        _require_role(published_by, "publisher", action="normdoc_publish", target=job_id)
        if not job_id:
            raise HTTPException(status_code=400, detail="job_id 不能为空（用于发布前 artifacts 校验）")
        final_gate = _final_publish_gate_check(job_id, req_signature=req_signature)
        if not bool(final_gate.get("ok", False)):
            _record_publish_metric(
                {
                    "timestamp": _utc_now(),
                    "status": "blocked",
                    "job_id": job_id,
                    "published_by": published_by,
                    "reason": "final_publish_gate_blocked",
                    "final_gate": final_gate,
                }
            )
            return {
                "status": "blocked",
                "publish_status": "blocked",
                "job_id": job_id,
                "blockers": final_gate.get("blockers", []),
                "checks": final_gate.get("checks", {}),
                "unresolved_count": int(final_gate.get("unresolved_count", 0) or 0),
            }
        try:
            job_form_codes: List[str] = []
            for p in _find_rulepack_paths_by_job(job_id):
                try:
                    obj = json.loads(p.read_text(encoding="utf-8"))
                except Exception:
                    continue
                if not isinstance(obj, dict):
                    continue
                meta = obj.get("meta", {}) if isinstance(obj.get("meta"), dict) else {}
                fc = str(meta.get("form_code") or "").strip()
                if fc:
                    job_form_codes.append(fc)
            _assert_auto_regression_pass_for_forms(sorted(list(set(job_form_codes))))
        except HTTPException as exc:
            _record_publish_metric(
                {
                    "timestamp": _utc_now(),
                    "status": "blocked",
                    "job_id": job_id,
                    "published_by": published_by,
                    "reason": "auto_regression_blocked",
                    "detail": _http_exception_detail_text(exc),
                }
            )
            return {
                "status": "blocked",
                "publish_status": "blocked",
                "job_id": job_id,
                "blockers": [_http_exception_detail_text(exc)],
                "checks": {"auto_regression_pass": False},
            }
        production_gate = _production_publish_gate_check(job_id)
        if not bool(production_gate.get("ok", False)):
            _record_publish_metric(
                {
                    "timestamp": _utc_now(),
                    "status": "blocked",
                    "job_id": job_id,
                    "published_by": published_by,
                    "reason": "production_publish_gate_blocked",
                    "production_gate": production_gate,
                }
            )
            return {
                "status": "blocked",
                "publish_status": "blocked",
                "job_id": job_id,
                "blockers": production_gate.get("blockers", []),
                "checks": production_gate.get("checks", {}),
                "publish_gate_report_path": production_gate.get("publish_gate_report_path", ""),
            }
        try:
            pkg = _load_review_package(job_id)
            cands = pkg.get("candidates", []) if isinstance(pkg.get("candidates"), list) else []
            extractors = {
                str(((c.get("workflow") or {}) if isinstance(c, dict) else {}).get("extractor_id") or "").strip()
                for c in cands
                if isinstance(c, dict)
            }
            reviewers = {
                str(((c.get("workflow") or {}) if isinstance(c, dict) else {}).get("reviewer_id") or "").strip()
                for c in cands
                if isinstance(c, dict)
            }
            extractors.discard("")
            reviewers.discard("")
            if published_by in extractors or published_by in reviewers:
                raise HTTPException(status_code=400, detail="流程分离校验失败：publisher 不能是 editor/reviewer")
        except HTTPException:
            raise
        except Exception:
            # For legacy jobs without review package, keep backward compatibility.
            pass
        _assert_pipeline_ready_for_publish(job_id, require_runtime_derived=publish_executable_package)
        publish_gate = _publish_gate_check_rulepacks(job_id)
        if not bool(publish_gate.get("ok", False)):
            if bool(publish_gate.get("rollback_required", False)):
                rb_forms = [
                    str(x).strip()
                    for x in (publish_gate.get("rollback_forms", []) if isinstance(publish_gate.get("rollback_forms"), list) else [])
                    if str(x).strip()
                ]
                rollback_results: List[Dict[str, Any]] = []
                for fc in rb_forms:
                    try:
                        rb = rollback_rulepack_by_form(
                            RulepackRollbackRequest(
                                form_code=fc,
                                operator=published_by or "quality_gate_auto_rollback",
                            )
                        )
                        rollback_results.append({"form_code": fc, "status": "ok", "result": rb})
                    except Exception as exc:
                        rollback_results.append({"form_code": fc, "status": "failed", "error": str(exc)})
                publish_gate["rollback_results"] = rollback_results
            reasons = publish_gate.get("blockers", []) if isinstance(publish_gate.get("blockers"), list) else []
            detail = "发布门禁失败：\n" + "\n".join([f"- {str(x)}" for x in reasons[:50]])
            _raise_policy_http_error(ERROR_PUBLISH_FAILED, user_message="发布门禁失败，请先修复阻断项。", detail=detail)
        # If the job already produced rulepack files, all of them must pass v1 schema validation.
        job_rulepacks = _find_rulepacks_by_job(job_id)
        compatibility_rows: List[Dict[str, Any]] = []
        for rp_path in job_rulepacks:
            try:
                rp_doc = json.loads(rp_path.read_text(encoding="utf-8"))
            except Exception:
                raise HTTPException(status_code=400, detail=f"发布失败：rulepack 非法 JSON：{rp_path.name}")
            _assert_rulepack_version_compatible(rp_doc if isinstance(rp_doc, dict) else {}, stage="publish_input")
            ok, errs, _, resolved = _validate_rulepack_schema_with_compat(rp_doc if isinstance(rp_doc, dict) else {})
            if not ok:
                preview = "; ".join(errs[:10])
                raise HTTPException(status_code=400, detail=f"发布失败：rulepack schema({resolved}) 校验失败（{rp_path.name}）：{preview}")
            runtime_compat = _validate_runtime_compatibility(rp_doc if isinstance(rp_doc, dict) else {})
            compatibility_rows.append(
                {
                    "rulepack": rp_path.name,
                    "compatibility_status": runtime_compat.get("compatibility_status", "failed"),
                    "ok": bool(runtime_compat.get("ok", False)),
                    "summary": runtime_compat.get("summary", {}),
                    "blockers": runtime_compat.get("blockers", []),
                }
            )
        compatibility_failed = [x for x in compatibility_rows if not bool(x.get("ok", False))]
        compatibility_report = {
            "schema_version": "runtime_compatibility_report.v1",
            "job_id": job_id,
            "generated_at": _utc_now(),
            "compatibility_status": "failed" if compatibility_failed else "passed",
            "rulepacks": compatibility_rows,
        }
        _write_artifact_json(job_id, "runtime_compatibility_report.json", compatibility_report)
        if compatibility_failed:
            _record_publish_metric(
                {
                    "timestamp": _utc_now(),
                    "status": "blocked",
                    "job_id": job_id,
                    "published_by": published_by,
                    "reason": "runtime_compatibility_failed",
                    "compatibility_status": "failed",
                    "runtime_compatibility_report": compatibility_report,
                }
            )
            return {
                "status": "blocked",
                "publish_status": "blocked",
                "job_id": job_id,
                "compatibility_status": "failed",
                "blockers": [
                    str(msg)
                    for row in compatibility_failed
                    for msg in (row.get("blockers", []) if isinstance(row.get("blockers"), list) else [])
                ][:100],
                "runtime_compatibility_report_path": str((_artifact_dir_for_job(job_id) / "runtime_compatibility_report.json").resolve()),
            }
        conflict_report = _build_cross_norm_conflict_report(job_id)
        conflict_summary = conflict_report.get("summary", {}) if isinstance(conflict_report.get("summary"), dict) else {}
        if bool(conflict_summary.get("block_auto_publish", False)):
            _record_publish_metric(
                {
                    "timestamp": _utc_now(),
                    "status": "blocked",
                    "job_id": job_id,
                    "published_by": published_by,
                    "reason": "cross_norm_conflict_critical",
                    "conflict_report": conflict_report,
                }
            )
            return {
                "status": "blocked",
                "publish_status": "blocked",
                "job_id": job_id,
                "conflict_level": "critical",
                "blockers": ["cross_norm_conflict_critical: 禁止自动发布"],
                "conflict_report_path": str((_artifact_dir_for_job(job_id) / "conflict_report.json").resolve()),
            }
        unresolved_summary = _collect_rulepack_unresolved_summary_for_job(job_id)
        if int(unresolved_summary.get("unresolved_count", 0) or 0) > 0:
            raise HTTPException(
                status_code=400,
                detail=(
                    "发布失败：存在 unresolved 规则。"
                    f" unresolved_count={unresolved_summary.get('unresolved_count', 0)}"
                ),
            )
        mapping_summary = _collect_measurement_gate_mapping_summary_for_job(job_id)
        pair_total = int(mapping_summary.get("measurement_pair_count", 0) or 0)
        missing_count = int(mapping_summary.get("missing_count", 0) or 0)
        missing_rate = (missing_count / pair_total) if pair_total > 0 else 0.0
        if missing_rate > 0:
            preview = "; ".join(
                [
                    f"{str(x.get('field_key') or '-')}: {str(x.get('reason') or '')}"
                    for x in (mapping_summary.get("missing_items", []) if isinstance(mapping_summary.get("missing_items"), list) else [])[:20]
                ]
            )
            raise HTTPException(
                status_code=400,
                detail=(
                    "发布失败：MeasurementPair -> gateRef 映射不完整。"
                    f" missing_count={missing_count}, missing_rate={missing_rate:.4f}; {preview}"
                ),
            )
        anchor_audit_summary = _collect_rulepack_anchor_audit_for_job(job_id)
        if not bool(anchor_audit_summary.get("valid")):
            raise HTTPException(
                status_code=400,
                detail=(
                    "发布失败：存在缺少原文锚点的 Rule。"
                    f" invalid_rules={anchor_audit_summary.get('invalid_rules', 0)}"
                ),
            )
        normdoc_artifact_path = _artifact_dir_for_job(job_id) / "11_normdoc.json"
        if not normdoc_artifact_path.exists():
            raise HTTPException(status_code=400, detail=f"任务 {job_id} 缺少 11_normdoc.json，禁止发布。")
        try:
            normdoc_artifact = json.loads(normdoc_artifact_path.read_text(encoding="utf-8-sig"))
        except json.JSONDecodeError as exc:
            raise HTTPException(status_code=400, detail="11_normdoc.json 非法，禁止发布。") from exc
        artifact_status = str((normdoc_artifact or {}).get("status", "")).strip()
        artifact_source_model = str((normdoc_artifact or {}).get("source_model", "")).strip().lower()
        artifact_normdoc_id = str((normdoc_artifact or {}).get("normdoc_id", "")).strip()
        artifact_bundle_hash = str((normdoc_artifact or {}).get("bundle_hash", "")).strip()
        artifact_standard_code = str((normdoc_artifact or {}).get("spec_code") or (normdoc_artifact or {}).get("standard_code") or "").strip()
        artifact_normref = str((normdoc_artifact or {}).get("normRef") or "").strip()
        artifact_version = str((normdoc_artifact or {}).get("version", "")).strip()
        layerpeg_doc = (normdoc_artifact or {}).get("layerpeg")
        rules_count = 0
        gates_count = 0
        if isinstance(normdoc_artifact, dict):
            rules_val = normdoc_artifact.get("rules")
            gates_val = normdoc_artifact.get("gates")
            if isinstance(rules_val, list):
                rules_count = len(rules_val)
            if isinstance(gates_val, list):
                gates_count = len(gates_val)
            validations_obj = normdoc_artifact.get("validations")
            if isinstance(validations_obj, dict):
                if rules_count <= 0:
                    rules_count = int(validations_obj.get("rules_count", 0) or 0)
                if gates_count <= 0:
                    gates_count = int(validations_obj.get("gates_count", 0) or 0)
        if artifact_status == "draft_invalid":
            raise HTTPException(status_code=400, detail="当前 NormDoc 为 draft_invalid，禁止发布到规则库。")
        if artifact_source_model and artifact_source_model != "normref_only":
            raise HTTPException(status_code=400, detail="发布失败：仅允许 normRef 来源模型（source_model=normref_only）。")
        if artifact_status and artifact_status != "ready_to_publish":
            raise HTTPException(status_code=400, detail=f"当前 NormDoc 状态为 {artifact_status}，仅 ready_to_publish 可发布。")
        layerpeg_ok, layerpeg_reason = _validate_layerpeg_publishable(layerpeg_doc if isinstance(layerpeg_doc, dict) else {})
        if not layerpeg_ok:
            raise HTTPException(status_code=400, detail=f"发布失败：LayerPeg 校验未通过（{layerpeg_reason}）。")
        if rules_count <= 0:
            _raise_policy_http_error(
                ERROR_RULE_MISSING,
                user_message="发布失败：无规则（rules_count <= 0）。",
                detail=f"job_id={job_id}",
            )
        if gates_count <= 0:
            _raise_policy_http_error(
                ERROR_GATE_MISSING,
                user_message="发布失败：无 gate（gates_count <= 0）。",
                detail=f"job_id={job_id}",
            )
        if not artifact_normref:
            raise HTTPException(status_code=400, detail="发布失败：当前 NormDoc 缺少 normRef，禁止发布。")
        if artifact_normref != parsed_normref["normRef"]:
            raise HTTPException(status_code=400, detail="发布失败：请求 normRef 与 artifacts 不一致。")
        if req_normdoc_id and artifact_normdoc_id and req_normdoc_id != artifact_normdoc_id:
            raise HTTPException(status_code=400, detail="normdoc_id 与当前 job artifacts 不一致。")
        if req_bundle_hash and artifact_bundle_hash and req_bundle_hash != artifact_bundle_hash:
            raise HTTPException(status_code=400, detail="bundle_hash 与当前 job artifacts 不一致。")
        if not req_signature:
            raise HTTPException(status_code=400, detail="signature 不能为空。")
        standard_code = standard_code or artifact_standard_code
        version = artifact_version or version
        if not standard_code:
            raise HTTPException(status_code=400, detail="standard_code 不能为空")

        build_result = build_specbundle(
            BuildSpecBundleRequest(
                standard_code=standard_code,
                version=version,
                job_id=job_id,
                spec_md_path=request.spec_md_path,
                spec_json_path=request.spec_json_path,
                specir_yaml_path=request.specir_yaml_path,
                hash_manifest_path=request.hash_manifest_path,
            )
        )
        bundle_path = Path(str(build_result.get("bundle_path", "")).strip()).resolve()
        _verify_specbundle_completeness(bundle_path)

        normdoc_id = str(build_result.get("normdoc_id", "")).strip()
        if not normdoc_id:
            raise HTTPException(status_code=500, detail="发布流程错误：缺少 normdoc_id")
        try:
            published = normdoc_repository.publish(normdoc_id, published_by)
        except ValueError as exc:
            raise HTTPException(status_code=400, detail=str(exc)) from exc
        except Exception as exc:
            if _is_rule_store_unavailable_error(exc):
                _raise_policy_http_error(
                    ERROR_RULE_STORE_UNAVAILABLE,
                    user_message="发布失败：Rule Store 不可用，请稍后重试。",
                    detail=str(exc),
                )
            _raise_policy_http_error(
                ERROR_PUBLISH_FAILED,
                user_message="发布失败：写入 Rule Store 过程中发生异常。",
                detail=str(exc),
            )
        _record_publish_metric(
            {
                "timestamp": _utc_now(),
                "status": "success",
                "job_id": job_id,
                "normdoc_id": normdoc_id,
                "published_by": published_by,
                "rule_anchor_audit": _collect_rulepack_anchor_audit_for_job(job_id),
                "unresolved_summary": _collect_rulepack_unresolved_summary_for_job(job_id),
                "measurement_gate_mapping_summary": _collect_measurement_gate_mapping_summary_for_job(job_id),
            }
        )
        _audit_security_event(action="normdoc_publish", actor=published_by, result="success", target=job_id, required_role="publisher")
        _append_trace(
            "publish",
            job_id=job_id,
            form_code="",
            duration_ms=(time.perf_counter() - t_publish_start) * 1000.0,
            ok=True,
            extra={"normdoc_id": normdoc_id},
        )
        _update_obs_metrics(publish_success_inc=1)
        publish_report = {
            "status": "ok",
            "job_id": job_id,
            "compatibility_status": "passed",
            "publish_executable_package": publish_executable_package,
            "published_by": published_by,
            "bundle_hash": str(build_result.get("bundle_hash", "")).strip(),
            "package_id": normdoc_id,
            "bundle_path": str(bundle_path),
            "published_at": _utc_now(),
            "normdoc": published.model_dump(),
        }
        runtime_smoke_report = _run_runtime_smoke_for_job(job_id)
        conflict_report = _build_cross_norm_conflict_report(job_id)
        publish_report["runtime_smoke"] = {
            "passed": bool(runtime_smoke_report.get("passed", False)),
            "total_rulepacks": int(runtime_smoke_report.get("total_rulepacks", 0) or 0),
            "failed_rulepacks": int(runtime_smoke_report.get("failed_rulepacks", 0) or 0),
            "report_path": str((_artifact_dir_for_job(job_id) / "runtime_smoke_report.json").resolve()),
        }
        publish_report["cross_norm_conflict"] = {
            "summary": conflict_report.get("summary", {}),
            "report_path": str((_artifact_dir_for_job(job_id) / "conflict_report.json").resolve()),
        }
        _write_artifact_json(job_id, "publish_report.json", publish_report)
        _register_required_artifact(job_id, "publish_report.json", created_by=published_by)
        return {
            "status": "ok",
            "job_id": job_id,
            "compatibility_status": "passed",
            "runtime_smoke": publish_report.get("runtime_smoke", {}),
            "cross_norm_conflict": publish_report.get("cross_norm_conflict", {}),
            "publish_executable_package": publish_executable_package,
            "normdoc": published.model_dump(),
            "bundle_hash": str(build_result.get("bundle_hash", "")).strip(),
            "package_id": normdoc_id,
            "bundle_path": str(bundle_path),
            "publish_slo_4w": _compute_publish_slo_4w(),
        }
    except HTTPException as exc:
        _audit_security_event(action="normdoc_publish", actor=published_by, result="failed", target=job_id, required_role="publisher", reason=_http_exception_detail_text(exc))
        _append_trace(
            "publish",
            job_id=job_id,
            form_code="",
            duration_ms=(time.perf_counter() - t_publish_start) * 1000.0,
            ok=False,
            extra={"error": str(exc.detail)},
        )
        _record_publish_metric(
            {
                "timestamp": _utc_now(),
                "status": "failed",
                "job_id": job_id,
                "normdoc_id": req_normdoc_id,
                "published_by": published_by,
                "reason": _http_exception_detail_text(exc),
                "rule_anchor_audit": _collect_rulepack_anchor_audit_for_job(job_id) if job_id else {},
                "unresolved_summary": _collect_rulepack_unresolved_summary_for_job(job_id) if job_id else {},
                "measurement_gate_mapping_summary": _collect_measurement_gate_mapping_summary_for_job(job_id) if job_id else {},
            }
        )
        raise
    except Exception as exc:
        _audit_security_event(action="normdoc_publish", actor=published_by, result="failed", target=job_id, required_role="publisher", reason=str(exc))
        _append_trace(
            "publish",
            job_id=job_id,
            form_code="",
            duration_ms=(time.perf_counter() - t_publish_start) * 1000.0,
            ok=False,
            extra={"error": str(exc)},
        )
        _record_publish_metric(
            {
                "timestamp": _utc_now(),
                "status": "failed",
                "job_id": job_id,
                "normdoc_id": req_normdoc_id,
                "published_by": published_by,
                "reason": str(exc),
            }
        )
        _raise_policy_http_error(
            ERROR_PUBLISH_FAILED,
            user_message="发布失败：发生未预期异常，请检查日志。",
            detail=str(exc),
        )


