@app.post("/normref/norm-versions/change/transition")
def transition_norm_change(request: NormChangeTransitionRequest) -> Dict[str, Any]:
    norm_id = str(request.norm_id or "").strip()
    old_ver = str(request.old_norm_version or "").strip()
    new_ver = str(request.new_norm_version or "").strip()
    target = str(request.target_state or "").strip()
    operator = str(request.operator or "").strip()
    note = str(request.note or "").strip()
    if not norm_id or not old_ver or not new_ver or not target or not operator:
        raise HTTPException(status_code=400, detail="norm_id/old_norm_version/new_norm_version/target_state/operator 不能为空")
    allowed_states = ["proposal", "reviewed", "gray_release", "full_release", "archived"]
    if target not in allowed_states:
        raise HTTPException(status_code=400, detail=f"非法状态: {target}")

    wf = _load_norm_change_workflows()
    rows = wf.get("changes", []) if isinstance(wf.get("changes"), list) else []
    key = f"{norm_id}:{old_ver}->{new_ver}"
    found: Optional[Dict[str, Any]] = None
    for row in rows:
        if not isinstance(row, dict):
            continue
        if str(row.get("change_key") or "").strip() == key:
            found = row
            break
    if found is None:
        found = {
            "change_id": f"chg_{uuid.uuid4().hex[:12]}",
            "change_key": key,
            "norm_id": norm_id,
            "old_norm_version": old_ver,
            "new_norm_version": new_ver,
            "state": "proposal",
            "created_at": _utc_now(),
            "history": [],
        }
        rows.append(found)

    current = str(found.get("state") or "proposal").strip()
    allowed_from: Dict[str, List[str]] = {
        "proposal": ["reviewed"],
        "reviewed": ["gray_release"],
        "gray_release": ["full_release", "reviewed"],
        "full_release": ["archived"],
        "archived": [],
    }
    if target != current and target not in allowed_from.get(current, []):
        raise HTTPException(status_code=400, detail=f"非法流转: {current} -> {target}")

    impact = _compute_norm_version_diff(norm_id=norm_id, old_ver=old_ver, new_ver=new_ver, mark_review=True)
    impact_analysis = {
        "generated_at": _utc_now(),
        "changed_clause_count": len(impact.get("changed_clauses", [])),
        "affected_rule_count": len(impact.get("affected_rules", [])),
        "affected_gate_count": len(impact.get("affected_gates", [])),
        "affected_form_count": len(impact.get("affected_form_codes", [])),
        "detail": impact,
    }
    found["impact_analysis"] = impact_analysis
    found["state"] = target
    found["updated_at"] = _utc_now()
    hist = found.get("history", []) if isinstance(found.get("history"), list) else []
    hist.append({"time": _utc_now(), "operator": operator, "from_state": current, "to_state": target, "note": note})
    found["history"] = hist[-200:]

    # Full release: old version enters compatibility period.
    if target == "full_release":
        reg = _load_norm_version_registry()
        norms = reg.get("norms", {}) if isinstance(reg.get("norms"), dict) else {}
        vers = norms.get(norm_id, []) if isinstance(norms.get(norm_id), list) else []
        for row in vers:
            if not isinstance(row, dict):
                continue
            ver = str(row.get("version") or "").strip()
            if ver == old_ver:
                row["status"] = "compatibility"
                row["compatibility_from"] = _utc_now()
                row["compatibility_until"] = datetime.utcfromtimestamp(datetime.utcnow().timestamp() + 30 * 24 * 3600).isoformat() + "Z"
            elif ver == new_ver:
                row["status"] = "active"
        norms[norm_id] = vers
        reg["norms"] = norms
        _save_norm_version_registry(reg)

    wf["changes"] = rows
    _save_norm_change_workflows(wf)
    auto_reg = _trigger_auto_regression_for_norm_version(
        norm_id=norm_id,
        norm_version=new_ver,
        reason="norm_version_transition",
    )
    return {"status": "ok", "change": found, "auto_regression": auto_reg}


@app.post("/normref/norm-versions/change/rollback")
def rollback_norm_change(request: NormChangeRollbackRequest) -> Dict[str, Any]:
    cid = str(request.change_id or "").strip()
    operator = str(request.operator or "").strip()
    reason = str(request.reason or "").strip()
    if not cid or not operator:
        raise HTTPException(status_code=400, detail="change_id/operator 不能为空")
    wf = _load_norm_change_workflows()
    rows = wf.get("changes", []) if isinstance(wf.get("changes"), list) else []
    found: Optional[Dict[str, Any]] = None
    for row in rows:
        if isinstance(row, dict) and str(row.get("change_id") or "").strip() == cid:
            found = row
            break
    if found is None:
        raise HTTPException(status_code=404, detail=f"未找到 change_id={cid}")
    cur = str(found.get("state") or "").strip()
    if cur != "gray_release":
        raise HTTPException(status_code=400, detail=f"仅 gray_release 可回滚，当前 {cur}")
    found["state"] = "reviewed"
    found["updated_at"] = _utc_now()
    hist = found.get("history", []) if isinstance(found.get("history"), list) else []
    hist.append({"time": _utc_now(), "operator": operator, "from_state": "gray_release", "to_state": "reviewed", "note": reason or "gray rollback"})
    found["history"] = hist[-200:]
    wf["changes"] = rows
    _save_norm_change_workflows(wf)
    return {"status": "ok", "change": found}


@app.post("/normref/normdocs")
def register_normdoc(request: RegisterNormDocRequest) -> Dict[str, Any]:
    specbundle_path = Path(request.specbundle_path).expanduser()
    specir_path = Path(request.specir_path).expanduser()
    spec_md_path = Path(request.spec_md_path).expanduser()
    spec_json_path = Path(request.spec_json_path).expanduser()
    if not specbundle_path.is_absolute():
        specbundle_path = (REPO_ROOT / specbundle_path).resolve()
    else:
        specbundle_path = specbundle_path.resolve()
    if not specir_path.is_absolute():
        specir_path = (REPO_ROOT / specir_path).resolve()
    else:
        specir_path = specir_path.resolve()
    if not spec_md_path.is_absolute():
        spec_md_path = (REPO_ROOT / spec_md_path).resolve()
    else:
        spec_md_path = spec_md_path.resolve()
    if not spec_json_path.is_absolute():
        spec_json_path = (REPO_ROOT / spec_json_path).resolve()
    else:
        spec_json_path = spec_json_path.resolve()

    _ensure_bundle_bound_paths(
        specbundle_path=specbundle_path,
        specir_path=specir_path,
        spec_md_path=spec_md_path,
        spec_json_path=spec_json_path,
    )
    existing = normdoc_repository.get(request.normdoc_id)
    if existing and existing.status == "published":
        raise HTTPException(status_code=400, detail=f"NormDoc 已发布且不可直接修改：{request.normdoc_id}，请创建新版本。")
    rule_count, component_count = _compute_spec_counts(spec_json_path)
    model = normdoc_repository.upsert(
        NormDocCreatePayload(
            normdoc_id=request.normdoc_id,
            standard_code=request.standard_code,
            standard_name=request.standard_name,
            version=request.version,
            status=request.status,
            specbundle_path=str(specbundle_path),
            bundle_hash=request.bundle_hash,
            specir_path=str(specir_path),
            spec_md_path=str(spec_md_path),
            spec_json_path=str(spec_json_path),
            created_by=request.created_by,
            published_by=request.published_by,
            published_at=request.published_at,
            rule_count=rule_count,
            component_count=component_count,
        )
    )
    return {"status": "ok", "item": model.model_dump()}


