def rule_store_normdoc_detail(normdoc_id: str) -> Dict[str, Any]:
    row = normdoc_repository.get(normdoc_id)
    if not row or row.status != "published":
        raise HTTPException(status_code=404, detail=f"published normdoc 不存在：{normdoc_id}")
    return {"status": "ok", "source": "Rule Store", "item": row.model_dump()}


