def _bundle_storage_key(bundle_id: str, bundle_version: str, form_code: str) -> str:
    norm_id = _safe_upload_name(bundle_id.replace("@", "-at-").replace("/", "-")).strip("-")
    norm_ver = _safe_upload_name(bundle_version).strip("-") or "v1"
    norm_form = _safe_upload_name(form_code).strip("-") or "unknown_form"
    return f"{norm_id}__{norm_ver}__{norm_form}.json"


def _bundle_file_path(bundle_id: str, bundle_version: str, form_code: str) -> Path:
    SPECBUNDLE_REPO_DIR.mkdir(parents=True, exist_ok=True)
    return SPECBUNDLE_REPO_DIR / _bundle_storage_key(bundle_id, bundle_version, form_code)


def _default_bundle_payload(bundle_id: str, bundle_version: str, form_code: str) -> Dict[str, Any]:
    def _build_semantic_tree(fc: str, frm: List[Dict[str, Any]]) -> Dict[str, Any]:
        field_nodes = []
        measurement_pairs = []
        gate_refs = []
        for row in frm:
            if not isinstance(row, dict):
                continue
            field_key = str(row.get("fieldKey") or "").strip()
            field_name = str(row.get("fieldName") or field_key).strip()
            if not field_key:
                continue
            field_nodes.append({"field_key": field_key, "field_name": field_name})
            measurement_pairs.append({"field_key": field_key, "pair_type": "single_field"})
            refs: List[str] = []
            rid = str(row.get("ruleId") or "").strip()
            if rid:
                refs.append(rid)
            rids = row.get("ruleIds")
            if isinstance(rids, list):
                refs.extend([str(x).strip() for x in rids if str(x).strip()])
            if refs:
                gate_refs.append({"field_key": field_key, "gate_ref": refs[0]})
        return {
            "form_code": fc,
            "field_nodes": field_nodes,
            "measurement_pairs": measurement_pairs,
            "gate_refs": gate_refs,
        }

    seed_form_code = str((_load_system_config().get("form_api_mapping", {}) if isinstance(_load_system_config().get("form_api_mapping", {}), dict) else {}).get("save_and_validate_form_code") or "bridge_shi_1").strip()
    if form_code != seed_form_code:
        default_frm: List[Dict[str, Any]] = []
        return {
            "bundleId": bundle_id,
            "bundleVersion": bundle_version,
            "formCode": form_code,
            "formName": form_code,
            "dtoType": "pile",
            "stage": "autogen_pending_refine",
            "rules": [],
            "fieldRuleMap": default_frm,
            "semanticTree": _build_semantic_tree(form_code, default_frm),
            "metadata": {"source": "bootstrap.empty", "createdAt": _utc_now()},
        }
    frm = _bridge_shi_1_field_rule_map()
    return {
        "bundleId": bundle_id,
        "bundleVersion": bundle_version,
        "formCode": form_code,
        "formName": "钻（挖）孔桩护筒（壁）桩位检查表",
        "dtoType": "pile",
        "stage": "casing_position_check",
        "rules": _bridge_shi_1_rules_payload(bundle_id),
        "fieldRuleMap": frm,
        "semanticTree": _build_semantic_tree(form_code, frm),
        "metadata": {"source": "bootstrap.default", "createdAt": _utc_now()},
    }


def _validate_semantic_tree_for_form(form_code: str, semantic_tree: Dict[str, Any]) -> Tuple[bool, List[str]]:
    errs: List[str] = []
    if not isinstance(semantic_tree, dict):
        return False, ["semantic_tree must be object"]
    required = ["form_code", "field_nodes", "measurement_pairs", "gate_refs"]
    for key in required:
        if key not in semantic_tree:
            errs.append(f"semantic_tree.{key} missing")
    tree_form = str(semantic_tree.get("form_code") or "").strip()
    if tree_form != str(form_code).strip():
        errs.append(f"semantic_tree.form_code mismatch: expected {form_code}, got {tree_form or '<empty>'}")
    for key in ("field_nodes", "measurement_pairs", "gate_refs"):
        if key in semantic_tree and not isinstance(semantic_tree.get(key), list):
            errs.append(f"semantic_tree.{key} must be array")
    return len(errs) == 0, errs


def _build_gate_ref_lookup_from_semantic_tree(semantic_tree: Dict[str, Any]) -> Dict[str, str]:
    rows = semantic_tree.get("gate_refs", []) if isinstance(semantic_tree, dict) else []
    out: Dict[str, str] = {}
    if not isinstance(rows, list):
        return out
    for row in rows:
        if not isinstance(row, dict):
            continue
        fk = str(row.get("field_key") or row.get("field") or "").strip()
        gr = str(row.get("gate_ref") or row.get("gateRef") or "").strip()
        if fk:
            out[fk] = gr
    return out


def _validate_measurement_pair_gate_mapping(
    *,
    form_code: str,
    semantic_tree: Dict[str, Any],
    gates_rows: List[Dict[str, Any]],
) -> Dict[str, Any]:
    pairs = semantic_tree.get("measurement_pairs", []) if isinstance(semantic_tree, dict) else []
    if not isinstance(pairs, list):
        pairs = []
    gate_ref_map = _build_gate_ref_lookup_from_semantic_tree(semantic_tree if isinstance(semantic_tree, dict) else {})
    gate_ids = {
        str(g.get("gate_id") or g.get("id") or "").strip()
        for g in gates_rows
        if isinstance(g, dict) and str(g.get("gate_id") or g.get("id") or "").strip()
    }
    gate_rule_ids: set[str] = set()
    for g in gates_rows:
        if not isinstance(g, dict):
            continue
        for rid in _gate_rule_ids(g):
            if rid:
                gate_rule_ids.add(rid)
    missing: List[Dict[str, Any]] = []
    for idx, pair in enumerate(pairs):
        if not isinstance(pair, dict):
            missing.append(
                {
                    "index": idx,
                    "field_key": "",
                    "reason": "measurement_pair_not_object",
                    "gateRef": "",
                }
            )
            continue
        field_key = str(pair.get("field_key") or pair.get("field") or "").strip()
        gate_ref = str(pair.get("gateRef") or pair.get("gate_ref") or gate_ref_map.get(field_key, "")).strip()
        if not gate_ref:
            missing.append(
                {
                    "index": idx,
                    "field_key": field_key,
                    "reason": "missing_gateRef",
                    "gateRef": "",
                }
            )
            continue
        in_gates = (gate_ref in gate_ids) or (gate_ref in gate_rule_ids)
        if not in_gates:
            missing.append(
                {
                    "index": idx,
                    "field_key": field_key,
                    "reason": "gateRef_not_found_in_gates",
                    "gateRef": gate_ref,
                }
            )
    return {
        "form_code": form_code,
        "measurement_pair_count": len(pairs),
        "missing_count": len(missing),
        "passed": len(missing) == 0,
        "missing_items": missing,
    }


def _compute_docpeg_coverage_report(
    *,
    form_code: str,
    semantic_tree: Dict[str, Any],
    measurement_gate_mapping: Dict[str, Any],
) -> Dict[str, Any]:
    field_nodes = semantic_tree.get("field_nodes", []) if isinstance(semantic_tree, dict) else []
    pairs = semantic_tree.get("measurement_pairs", []) if isinstance(semantic_tree, dict) else []
    field_total = len([x for x in field_nodes if isinstance(x, dict)]) or len([x for x in pairs if isinstance(x, dict)])
    pair_total = len([x for x in pairs if isinstance(x, dict)])
    missing_gate_ref_count = int(measurement_gate_mapping.get("missing_count", 0) or 0)
    auto_gate_count = max(pair_total - missing_gate_ref_count, 0)
    manual_fallback_count = max(field_total - auto_gate_count, 0)
    executable_rate = (auto_gate_count / field_total) if field_total > 0 else 0.0
    gate_coverage_rate = ((field_total - missing_gate_ref_count) / field_total) if field_total > 0 else 0.0
    missing_gate_ref_rate = (missing_gate_ref_count / field_total) if field_total > 0 else 0.0
    return {
        "form_code": form_code,
        "field_total": field_total,
        "auto_gate_count": auto_gate_count,
        "manual_fallback_count": manual_fallback_count,
        "missing_gateRef_count": missing_gate_ref_count,
        "missing_gateRef_rate": missing_gate_ref_rate,
        "executable_rate": executable_rate,
        "gate_coverage_rate": gate_coverage_rate,
    }


def _is_judgement_rule(rule: Dict[str, Any]) -> bool:
    if not isinstance(rule, dict):
        return False
    if str(rule.get("expression") or "").strip():
        return True
    if str(rule.get("operator") or "").strip():
        return True
    if rule.get("threshold") is not None:
        return True
    if str(rule.get("condition") or "").strip():
        return True
    return False


def _build_missing_gate_governance_report(*, form_code: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    rules = payload.get("rules", []) if isinstance(payload.get("rules"), list) else []
    gates = payload.get("gates", []) if isinstance(payload.get("gates"), list) else []
    gate_by_rule: Dict[str, List[str]] = {}
    for g in gates:
        if not isinstance(g, dict):
            continue
        gid = str(g.get("gate_id") or g.get("id") or "").strip()
        if not gid:
            continue
        for rid in _gate_rule_ids(g):
            if rid:
                gate_by_rule.setdefault(rid, []).append(gid)

    warnings: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    considered = 0
    missing = 0
    for row in rules:
        if not isinstance(row, dict):
            continue
        rid = str(row.get("rule_id") or row.get("ruleId") or row.get("id") or "").strip()
        if not rid:
            continue
        considered += 1
        mapped = gate_by_rule.get(rid, [])
        if mapped:
            continue
        missing += 1
        item = {
            "rule_id": rid,
            "field": str(row.get("field") or row.get("field_key") or "").strip(),
            "norm_ref": str(row.get("norm_ref") or row.get("normRef") or "").strip(),
            "reason": "rule_exists_but_gate_missing",
        }
        warnings.append(item)
        if _is_judgement_rule(row):
            err = dict(item)
            err["reason"] = "judgement_specir_missing_gate"
            errors.append(err)

    missing_gate_rate = (float(missing) / float(considered)) if considered > 0 else 0.0
    block_publish = missing_gate_rate > 0.0
    return {
        "schema_version": "missing_gate_report.v1",
        "generated_at": _utc_now(),
        "form_code": form_code,
        "rule_count": considered,
        "missing_gate_count": missing,
        "missing_gate_rate": missing_gate_rate,
        "warning_count": len(warnings),
        "error_count": len(errors),
        "warnings": warnings,
        "errors": errors,
        "block_publish": block_publish,
        "rules": {
            "rule_exists_gate_missing_warning": len(warnings) > 0,
            "judgement_specir_missing_gate_error": len(errors) > 0,
            "missing_gate_rate_gt_zero_block": block_publish,
        },
    }


def _load_specbundle(bundle_id: str, bundle_version: str = "v1", form_code: str = "") -> Dict[str, Any]:
    if not str(form_code or "").strip():
        form_code = str(_load_system_config().get("default_form_code") or "bridge_shi_1").strip()
    path = _bundle_file_path(bundle_id, bundle_version, form_code)
    if path.exists():
        try:
            payload = json.loads(path.read_text(encoding="utf-8-sig"))
            if isinstance(payload, dict):
                st = payload.get("semanticTree")
                if not isinstance(st, dict):
                    # Backfill a per-form semantic tree if legacy payload misses it.
                    frm = [x for x in payload.get("fieldRuleMap", []) if isinstance(x, dict)] if isinstance(payload.get("fieldRuleMap"), list) else []
                    payload["semanticTree"] = {
                        "form_code": form_code,
                        "field_nodes": [{"field_key": str(x.get("fieldKey") or "").strip(), "field_name": str(x.get("fieldName") or x.get("fieldKey") or "").strip()} for x in frm if str(x.get("fieldKey") or "").strip()],
                        "measurement_pairs": [{"field_key": str(x.get("fieldKey") or "").strip(), "pair_type": "single_field"} for x in frm if str(x.get("fieldKey") or "").strip()],
                        "gate_refs": [
                            {
                                "field_key": str(x.get("fieldKey") or "").strip(),
                                "gate_ref": (
                                    str(x.get("ruleId") or "").strip()
                                    or (
                                        str((x.get("ruleIds") or [""])[0]).strip()
                                        if isinstance(x.get("ruleIds"), list) and len(x.get("ruleIds", [])) > 0
                                        else ""
                                    )
                                ),
                            }
                            for x in frm
                            if str(x.get("fieldKey") or "").strip()
                        ],
                    }
                ok, errs = _validate_semantic_tree_for_form(form_code, payload.get("semanticTree", {}))
                if not ok:
                    raise HTTPException(status_code=400, detail=f"semantic_tree 非法（{form_code}）：{'; '.join(errs[:10])}")
                return payload
        except json.JSONDecodeError:
            pass
    payload = _default_bundle_payload(bundle_id, bundle_version, form_code)
    ok, errs = _validate_semantic_tree_for_form(form_code, payload.get("semanticTree", {}))
    if not ok:
        raise HTTPException(status_code=500, detail=f"默认 semantic_tree 非法（{form_code}）：{'; '.join(errs[:10])}")
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return payload


@app.get("/normref/ingest/jobs/{job_id}/artifact-registry")
def get_artifact_registry(job_id: str) -> Dict[str, Any]:
    _register_required_artifacts_for_job(job_id, created_by="system.registry_refresh")
    reg = _load_artifact_registry()
    artifacts = reg.get("artifacts", {}) if isinstance(reg.get("artifacts"), dict) else {}
    rows: Dict[str, List[Dict[str, Any]]] = {}
    for name in _artifact_required_names():
        key = f"{job_id}:{name}"
        versions = artifacts.get(key, [])
        rows[name] = [x for x in versions if isinstance(x, dict)] if isinstance(versions, list) else []
    return {"status": "ok", "job_id": job_id, "artifacts": rows}


@app.get("/normref/ingest/jobs/{job_id}/artifact-registry/diff")
def artifact_registry_diff(job_id: str, artifact_name: str, artifact_id_a: str, artifact_id_b: str) -> Dict[str, Any]:
    safe_name = _safe_upload_name(artifact_name)
    reg = _load_artifact_registry()
    versions = (reg.get("artifacts", {}) or {}).get(f"{job_id}:{safe_name}", [])
    if not isinstance(versions, list):
        versions = []
    a = next((x for x in versions if isinstance(x, dict) and str(x.get("artifact_id", "")).strip() == str(artifact_id_a or "").strip()), None)
    b = next((x for x in versions if isinstance(x, dict) and str(x.get("artifact_id", "")).strip() == str(artifact_id_b or "").strip()), None)
    if not isinstance(a, dict) or not isinstance(b, dict):
        raise HTTPException(status_code=404, detail="artifact diff 版本不存在")
    pa = Path(str(a.get("path", "")).strip())
    pb = Path(str(b.get("path", "")).strip())
    if not pa.exists() or not pb.exists():
        raise HTTPException(status_code=404, detail="artifact diff 文件不存在")
    aa = pa.read_text(encoding="utf-8-sig").splitlines()
    bb = pb.read_text(encoding="utf-8-sig").splitlines()
    diff = list(difflib.unified_diff(aa, bb, fromfile=str(a.get("version", "a")), tofile=str(b.get("version", "b")), lineterm=""))
    return {"status": "ok", "job_id": job_id, "artifact_name": safe_name, "from": a, "to": b, "diff": diff}


@app.get("/normref/ingest/jobs/{job_id}/artifact-registry/download/{artifact_id}")
def artifact_registry_download(job_id: str, artifact_id: str) -> FileResponse:
    reg = _load_artifact_registry()
    artifacts = reg.get("artifacts", {}) if isinstance(reg.get("artifacts"), dict) else {}
    target: Optional[Dict[str, Any]] = None
    for key, versions in artifacts.items():
        if not str(key).startswith(f"{job_id}:") or not isinstance(versions, list):
            continue
        for row in versions:
            if isinstance(row, dict) and str(row.get("artifact_id", "")).strip() == str(artifact_id or "").strip():
                target = row
                break
        if target:
            break
    if not isinstance(target, dict):
        raise HTTPException(status_code=404, detail="artifact_id 不存在")
    path = Path(str(target.get("path", "")).strip())
    if not path.exists():
        raise HTTPException(status_code=404, detail="artifact 文件不存在")
    return FileResponse(path=path, media_type="application/json", filename=path.name)


@app.post("/normref/ingest/jobs/{job_id}/artifact-registry/rollback")
def artifact_registry_rollback(job_id: str, request: ArtifactRollbackRequest) -> Dict[str, Any]:
    safe_name = _safe_upload_name(request.artifact_name)
    reg = _load_artifact_registry()
    artifacts = reg.get("artifacts", {}) if isinstance(reg.get("artifacts"), dict) else {}
    key = f"{job_id}:{safe_name}"
    versions = artifacts.get(key, [])
    if not isinstance(versions, list):
        versions = []
    src = next((x for x in versions if isinstance(x, dict) and str(x.get("artifact_id", "")).strip() == str(request.artifact_id or "").strip()), None)
    if not isinstance(src, dict):
        raise HTTPException(status_code=404, detail="rollback 目标版本不存在")
    src_path = Path(str(src.get("path", "")).strip())
    if not src_path.exists():
        raise HTTPException(status_code=404, detail="rollback 目标文件不存在")
    payload = json.loads(src_path.read_text(encoding="utf-8-sig"))
    _write_artifact_json(job_id, safe_name, payload)
    created = _register_required_artifact(job_id, safe_name, created_by=str(request.created_by or "").strip() or "system.rollback")
    if not isinstance(created, dict):
        raise HTTPException(status_code=500, detail="rollback 后注册失败")
    return {"status": "ok", "job_id": job_id, "artifact_name": safe_name, "rolled_back_from": src, "current": created}


