@app.get("/normref/ingest/jobs/{job_id}/norm-knowledge-graph/conflicts")
def norm_knowledge_graph_conflicts(job_id: str) -> Dict[str, Any]:
    _build_norm_knowledge_graph(job_id)
    spec = _read_artifact_payload(job_id, "01_spec.json")
    slot_mapping = _read_artifact_payload(job_id, "slot_mapping_recommendations.json")
    if (not slot_mapping) or (not isinstance(slot_mapping.get("recommended_slot_keys"), list)):
        slot_mapping = normref_ingest_slot_mapping(job_id=job_id, rebuild=True)
    slot_conflict = _build_slot_conflict_report(
        job_id=job_id,
        spec_code=str(spec.get("spec_code") or spec.get("spec_id") or "").strip() if isinstance(spec, dict) else "",
        recommendations=slot_mapping if isinstance(slot_mapping, dict) else {},
    )
    cross_conflict = _build_cross_norm_conflict_report(job_id)
    out = {
        "status": "ok",
        "job_id": job_id,
        "slot_conflict_summary": slot_conflict.get("summary", {}),
        "slot_conflicts": slot_conflict.get("conflicts", []),
        "cross_norm_conflict_summary": cross_conflict.get("summary", {}),
        "cross_norm_conflicts": cross_conflict.get("conflicts", []),
    }
    _write_artifact_json(job_id, "norm_knowledge_graph_conflicts.json", out)
    out["conflict_report_path"] = str((_artifact_dir_for_job(job_id) / "norm_knowledge_graph_conflicts.json").resolve())
    return out


@app.post("/normref/ingest/jobs/{job_id}/norm-knowledge-graph/propagate")
def norm_knowledge_graph_propagate(job_id: str, request: NormKnowledgeGraphPropagationRequest) -> Dict[str, Any]:
    graph = _build_norm_knowledge_graph(job_id)
    seeds = [str(x).strip() for x in request.seed_node_ids if str(x).strip()]
    if not seeds:
        fallback = graph.get("nodes", []) if isinstance(graph.get("nodes"), list) else []
        if fallback and isinstance(fallback[0], dict):
            nid = str(fallback[0].get("id") or "").strip()
            if nid:
                seeds = [nid]
    if not seeds:
        raise HTTPException(status_code=400, detail="seed_node_ids 不能为空")
    out = _auto_propagate_on_form_impact_graph(
        graph,
        seed_node_ids=seeds,
        max_depth=int(request.max_depth or 2),
        min_confidence=float(request.min_confidence or 0.35),
    )
    out["job_id"] = job_id
    return out


