@app.post("/normref/ingest/jobs/{job_id}/specir-graph/impact-query")
def specir_knowledge_graph_impact_query(job_id: str, request: SpecIRImpactQueryRequest) -> Dict[str, Any]:
    graph = _build_specir_knowledge_graph(job_id)
    norm_ref = str(request.normRef or "").strip()
    slot_key = str(request.slotKey or "").strip()
    specir_id = str(request.specir_id or "").strip()
    seed_node_ids: List[str] = []
    if norm_ref:
        seed_node_ids.append(f"normRef:{norm_ref}")
    if slot_key:
        seed_node_ids.append(f"slot:{slot_key}")
    if specir_id:
        exact = f"specir:{specir_id}"
        seed_node_ids.append(exact)
        nodes = graph.get("nodes", []) if isinstance(graph.get("nodes"), list) else []
        for n in nodes:
            if not isinstance(n, dict):
                continue
            nid = str(n.get("id") or "").strip()
            if nid.endswith(f":{specir_id}") and nid not in seed_node_ids:
                seed_node_ids.append(nid)
    if not seed_node_ids:
        raise HTTPException(status_code=400, detail="normRef / slotKey / specir_id 至少填写一个")
    out = _impact_analysis_specir_graph(graph, seed_node_ids, max_depth=int(request.max_depth or 2))
    out["job_id"] = job_id
    out["query"] = {"normRef": norm_ref, "slotKey": slot_key, "specir_id": specir_id}
    return out


