@app.get("/normref/ingest/jobs/{job_id}/specir/{specir_id}/trace")
def normref_ingest_specir_trace(job_id: str, specir_id: str) -> Dict[str, Any]:
    sid = str(specir_id or "").strip()
    if not sid:
        raise HTTPException(status_code=400, detail="specir_id 不能为空")
    specir = normref_ingest_specir(job_id, rebuild=False)
    items = specir.get("items", []) if isinstance(specir.get("items"), list) else []
    hit: Dict[str, Any] = {}
    for row in items:
        if not isinstance(row, dict):
            continue
        rid = str(row.get("specir_id") or row.get("component_id") or "").strip()
        if rid == sid:
            hit = row
            break
    if not hit:
        raise HTTPException(status_code=404, detail=f"未找到 specir_id={sid}")
    rules_doc = _read_artifact_payload(job_id, "07_rules.json")
    gates_doc = _read_artifact_payload(job_id, "08_gates.json")
    rules = [x for x in (rules_doc.get("rules", []) if isinstance(rules_doc.get("rules"), list) else []) if isinstance(x, dict)]
    gates = [x for x in (gates_doc.get("gates", []) if isinstance(gates_doc.get("gates"), list) else []) if isinstance(x, dict)]
    derived_rules = [
        r for r in rules
        if str(r.get("source_specir_id") or r.get("specir_id") or "").strip() == sid
    ]
    derived_rule_ids = {str(r.get("rule_id") or "").strip() for r in derived_rules if str(r.get("rule_id") or "").strip()}
    derived_gates: List[Dict[str, Any]] = []
    for g in gates:
        refs = g.get("rule_refs", g.get("ruleRefs", g.get("rules", g.get("rule_ids", []))))
        if not isinstance(refs, list):
            continue
        if any(str(x).strip() in derived_rule_ids for x in refs):
            derived_gates.append(g)
    form_codes: List[str] = []
    published_rulepacks: List[str] = []
    release_doc = _read_json_if_exists(RULEPACK_RELEASE_REGISTRY_PATH)
    rows = release_doc.get("items", []) if isinstance(release_doc.get("items"), list) else []
    for row in rows:
        if not isinstance(row, dict):
            continue
        if str(row.get("job_id") or "").strip() != str(job_id).strip():
            continue
        form_code = str(row.get("form_code") or "").strip()
        if form_code and form_code not in form_codes:
            form_codes.append(form_code)
    for p in _find_rulepacks_by_job(job_id):
        nm = str(p.name or "").strip()
        if nm and nm not in published_rulepacks:
            published_rulepacks.append(nm)
    return {
        "status": "ok",
        "job_id": job_id,
        "specir_id": sid,
        "source_clause": {
            "normRef": str(hit.get("normRef") or "").strip(),
            "source_clause_id": str(((hit.get("evidence") or {}).get("source_clause_id") if isinstance(hit.get("evidence"), dict) else "") or "").strip(),
            "catalog_path": str(((hit.get("evidence") or {}).get("catalog_path") if isinstance(hit.get("evidence"), dict) else "") or "").strip(),
            "original_text": str(((hit.get("evidence") or {}).get("original_text") if isinstance(hit.get("evidence"), dict) else "") or "").strip(),
        },
        "derived_rules": derived_rules,
        "derived_gates": derived_gates,
        "form_codes": form_codes,
        "used_forms": form_codes,
        "published_rulepacks": published_rulepacks,
    }


