@app.get("/normref/ingest/jobs/{job_id}/traceability/query")
def query_traceability(
    job_id: str,
    rule_id: str = "",
    gate_id: str = "",
    specir_id: str = "",
    normRef: str = "",
    slotKey: str = "",
) -> Dict[str, Any]:
    payload = _read_artifact_payload(job_id, "traceability.json")
    if not payload:
        raise HTTPException(status_code=404, detail="traceability.json 不存在，请先构建 rulepack")
    rid = str(rule_id or "").strip()
    gid = str(gate_id or "").strip()
    sid = str(specir_id or "").strip()
    nref = str(normRef or "").strip()
    skey = str(slotKey or "").strip()
    rules = [x for x in (payload.get("rules", []) if isinstance(payload.get("rules"), list) else []) if isinstance(x, dict)]
    gates = [x for x in (payload.get("gates", []) if isinstance(payload.get("gates"), list) else []) if isinstance(x, dict)]
    specir = [x for x in (payload.get("specir", []) if isinstance(payload.get("specir"), list) else []) if isinstance(x, dict)]
    if rid:
        rules = [x for x in rules if str(x.get("rule_id") or "").strip() == rid]
    if gid:
        gates = [x for x in gates if str(x.get("gate_id") or "").strip() == gid]
    if sid:
        rules = [x for x in rules if str(x.get("specir_id") or "").strip() == sid]
        gates = [x for x in gates if sid in [str(v).strip() for v in (x.get("specir_refs", []) if isinstance(x.get("specir_refs"), list) else [])]]
        specir = [x for x in specir if str(x.get("specir_id") or "").strip() == sid]
    if nref:
        rules = [x for x in rules if str(x.get("normRef") or "").strip() == nref]
    if skey:
        rules = [x for x in rules if str(x.get("slotKey") or "").strip() == skey]
        gates = [x for x in gates if skey in [str(v).strip() for v in (x.get("slotKeys", []) if isinstance(x.get("slotKeys"), list) else [])]]
    return {
        "status": "ok",
        "job_id": job_id,
        "query": {"rule_id": rid, "gate_id": gid, "specir_id": sid, "normRef": nref, "slotKey": skey},
        "rules": rules,
        "gates": gates,
        "specir": specir,
    }


