@app.post("/api/formapi/v1/forms/bridge_shi_1/save-and-validate")
def save_and_validate_bridge_shi_1(request: FormSaveAndValidateRequest) -> Dict[str, Any]:
    values = request.values or {}
    site_condition = str(values.get("site_condition") or "").strip()
    bundle = _load_specbundle(request.bundleId, "v1", "bridge_shi_1")
    rules = [r for r in bundle.get("rules", []) if isinstance(r, dict)]
    failed: List[Dict[str, Any]] = []
    passed: List[Dict[str, Any]] = []
    warnings = 0

    design_d = _to_num(values, "design_pile_diameter_m")
    casing_d = _to_num(values, "casing_inner_diameter_m")
    margin = (casing_d - design_d) if design_d is not None and casing_d is not None else None
    eps = 1e-9
    if margin is None or margin + eps < 0.2:
        failed.append({"ruleId": rules[0]["ruleId"], "fieldKeys": rules[0]["fieldKeys"], "fieldName": "护筒直径", "gateStatus": "failed", "severity": "blocking", "actual": {"casing_inner_diameter_m": casing_d, "design_pile_diameter_m": design_d, "margin_m": margin}, "allowed": {"expression": "护筒内径 >= 设计桩径 + 0.2m", "unit": "m"}, "basis": rules[0]["basis"], "message": "不合格：护筒内径未满足至少大200mm。", "blocking": True})
    else:
        passed.append({"ruleId": rules[0]["ruleId"], "fieldKeys": rules[0]["fieldKeys"], "fieldName": "护筒直径", "gateStatus": "passed", "severity": "blocking"})

    length = _to_num(values, "casing_length_m")
    if length is None or length < 2.3 or length > 4.3:
        warnings += 1

    embed = _to_num(values, "casing_embed_depth_m")
    if site_condition in {"dry_land", "artificial_island"} and (embed is None or embed < 2.0 or embed > 4.0):
        failed.append({"ruleId": rules[2]["ruleId"], "fieldKeys": rules[2]["fieldKeys"], "fieldName": "护筒埋深", "gateStatus": "failed", "severity": "blocking", "actual": {"casing_embed_depth_m": embed}, "allowed": {"minValue": 2.0, "maxValue": 4.0, "unit": "m"}, "basis": rules[2]["basis"], "message": "不合格：旱地/筑岛条件下护筒埋深不在2m～4m。", "blocking": True})
    else:
        passed.append({"ruleId": rules[2]["ruleId"], "fieldKeys": rules[2]["fieldKeys"], "fieldName": "护筒埋深", "gateStatus": "passed", "severity": "blocking"})

    dx = ((_to_num(values, "measured_center_x") or 0.0) - (_to_num(values, "design_center_x") or 0.0))
    dy = ((_to_num(values, "measured_center_y") or 0.0) - (_to_num(values, "design_center_y") or 0.0))
    computed_axis_offset_mm = ((dx * dx + dy * dy) ** 0.5) * 1000.0
    if computed_axis_offset_mm > 50:
        failed.append({"ruleId": rules[3]["ruleId"], "fieldKeys": rules[3]["fieldKeys"], "fieldName": "偏位", "gateStatus": "failed", "severity": "blocking", "actual": {"computed_axis_offset_mm": round(computed_axis_offset_mm, 3)}, "allowed": {"maxValue": 50, "unit": "mm"}, "basis": rules[3]["basis"], "message": "不合格：护筒轴心偏位超过50mm。", "blocking": True})
    else:
        passed.append({"ruleId": rules[3]["ruleId"], "fieldKeys": rules[3]["fieldKeys"], "fieldName": "偏位", "gateStatus": "passed", "severity": "blocking"})

    top = _to_num(values, "casing_top_elevation_m")
    ground = _to_num(values, "ground_elevation_m")
    water = _to_num(values, "water_level_m")
    design_top = _to_num(values, "design_pile_top_elevation_m")
    if site_condition == "dry_land" and (top is None or ground is None or top < ground + 0.3):
        failed.append({"ruleId": rules[4]["ruleId"], "fieldName": "护筒顶高程", "gateStatus": "failed", "severity": "blocking", "basis": rules[4]["basis"], "message": "不合格：旱地施工时护筒顶未高于地面0.3m。", "blocking": True})
    if site_condition == "water" and (top is None or water is None or top < water + 1.0 or top > water + 2.0):
        failed.append({"ruleId": rules[5]["ruleId"], "fieldName": "护筒顶高程", "gateStatus": "failed", "severity": "blocking", "basis": rules[5]["basis"], "message": "不合格：水中施工时护筒顶不在水面+1m~+2m区间。", "blocking": True})
    if top is None or design_top is None or top < design_top + 1.0:
        failed.append({"ruleId": rules[6]["ruleId"], "fieldName": "护筒顶高程", "gateStatus": "failed", "severity": "blocking", "basis": rules[6]["basis"], "message": "不合格：护筒顶未高于桩顶设计高程1m。", "blocking": True})

    blocking_failed = len([x for x in failed if str(x.get("severity")) == "blocking"])
    can_submit = blocking_failed == 0
    return {
        "success": True,
        "saveStatus": "draft_saved",
        "validationStatus": "passed" if can_submit else "failed",
        "formInstanceId": request.formInstanceId,
        "formCode": "bridge_shi_1",
        "dtoId": request.dtoId,
        "specbundle": {"bundleId": request.bundleId, "bundleVersion": "v1", "resolvedRulesCount": len(rules)},
        "summary": {
            "gateStatus": "passed" if can_submit else "failed",
            "canSave": True,
            "canSubmit": can_submit,
            "canGenerateProof": False,
            "totalRules": len(rules),
            "passedRules": len(passed),
            "failedRules": len(failed),
            "warningRules": warnings,
            "blockingFailedRules": blocking_failed,
        },
        "computedValues": {
            "casing_diameter_margin_m": None if margin is None else round(margin, 3),
            "casing_top_above_ground_m": None if top is None or ground is None else round(top - ground, 3),
            "casing_top_above_design_pile_top_m": None if top is None or design_top is None else round(top - design_top, 3),
            "center_dx_m": round(dx, 6),
            "center_dy_m": round(dy, 6),
            "computed_axis_offset_mm": round(computed_axis_offset_mm, 3),
        },
        "fieldResults": passed[:1],
        "failedResults": failed,
        "formActions": {
            "saveDraftAllowed": True,
            "submitAllowed": can_submit,
            "proofReady": False,
            "nextRequiredActions": ["contractor_signature", "supervision_signature"] if can_submit else [],
            "blockedNextActions": [] if can_submit else ["bridge_shi_3_drilling_record", "bridge_shi_5_borehole_acceptance"],
        },
        "proofPreparation": {
            "proofType": "form_gate_result",
            "proofReady": False,
            "reason": "桥施1表Gate校验已通过，但尚缺施工单位与监理签名。" if can_submit else "存在阻断项，暂不可进入签名取证。",
            "requiredSignatures": ["contractor", "supervision"],
            "hashPreview": None,
        },
        "next": {
            "submitEndpoint": "/api/formapi/v1/forms/bridge_shi_1/submit",
            "proofPrepareEndpoint": f"/api/proof/v1/form-gate-results/gate-result-{request.formInstanceId}/prepare",
            "nextAllowedForms": ["bridge_shi_3", "bridge_shi_5"] if can_submit else [],
        },
    }


@app.post("/api/specbundle/v1/bundles/upsert")
def specbundle_upsert(request: SpecbundleUpsertRequest) -> Dict[str, Any]:
    metadata_obj = request.metadata or {}
    normref = str(metadata_obj.get("normRef", "")).strip() if isinstance(metadata_obj, dict) else ""
    if not normref:
        raise HTTPException(status_code=400, detail="禁止模板跳过 normRef：metadata.normRef 不能为空。")
    _parse_normref_uri(normref)
    spec_code = str(metadata_obj.get("spec_code", "")).strip() if isinstance(metadata_obj, dict) else ""
    spec_version = str(metadata_obj.get("spec_version", "")).strip() if isinstance(metadata_obj, dict) else ""
    job_id = str(metadata_obj.get("job_id", "")).strip() if isinstance(metadata_obj, dict) else ""
    source_doc_hash = str(metadata_obj.get("source_doc_hash", "")).strip() if isinstance(metadata_obj, dict) else ""
    if not spec_code:
        raise HTTPException(status_code=400, detail="metadata.spec_code 不能为空。")
    if not spec_version:
        raise HTTPException(status_code=400, detail="metadata.spec_version 不能为空。")
    if not job_id:
        raise HTTPException(status_code=400, detail="metadata.job_id 不能为空。")
    if not source_doc_hash:
        raise HTTPException(status_code=400, detail="metadata.source_doc_hash 不能为空。")
    semantic_tree = request.semanticTree or {}
    if not semantic_tree:
        semantic_tree = {
            "form_code": request.formCode,
            "field_nodes": [],
            "measurement_pairs": [],
            "gate_refs": [],
        }
    st_ok, st_errs = _validate_semantic_tree_for_form(request.formCode, semantic_tree if isinstance(semantic_tree, dict) else {})
    if not st_ok:
        raise HTTPException(status_code=400, detail=f"semantic_tree 非法：{'; '.join(st_errs[:10])}")
    payload = {
        "bundleId": request.bundleId,
        "bundleVersion": request.bundleVersion,
        "formCode": request.formCode,
        "formName": request.formName or "钻（挖）孔桩护筒（壁）桩位检查表",
        "dtoType": request.dtoType,
        "stage": request.stage,
        "rules": request.rules,
        "fieldRuleMap": request.fieldRuleMap,
        "semanticTree": semantic_tree,
        "metadata": {
            **metadata_obj,
            "source_model": "normref_only",
            "updatedAt": _utc_now(),
        },
    }
    path = _bundle_file_path(request.bundleId, request.bundleVersion, request.formCode)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return {
        "status": "ok",
        "bundleId": request.bundleId,
        "bundleVersion": request.bundleVersion,
        "path": str(path),
        "rulesCount": len(request.rules),
    }


