@app.post("/execute")
def execute_by_normref(request: NormRefExecuteRequest) -> Dict[str, Any]:
    parsed = _parse_normref_uri(request.normRef)
    art_dir, rules_doc, gates_doc, aux = _find_artifact_bundle_by_normref(parsed["normRef"])
    rules_rows = rules_doc.get("rules", []) if isinstance(rules_doc, dict) else []
    gates_rows = gates_doc.get("gates", []) if isinstance(gates_doc, dict) else []
    idx_doc = aux.get("index", {}) if isinstance(aux, dict) else {}
    dto_doc = aux.get("dto", {}) if isinstance(aux, dict) else {}
    if not isinstance(rules_rows, list) or not isinstance(gates_rows, list):
        raise HTTPException(status_code=400, detail="Rule/Gate 资产结构非法。")

    target_ref = str(parsed["normRef"]).strip()
    related_rules = [
        r for r in rules_rows
        if isinstance(r, dict) and str(r.get("norm_ref", "")).strip() == target_ref and not bool(r.get("unresolved", False))
    ]
    if not related_rules:
        raise HTTPException(status_code=404, detail=f"未找到 normRef 对应的可执行 Rule：{target_ref}")

    related_rule_ids = {str(r.get("rule_id", "")).strip() for r in related_rules}
    related_gates = []
    for g in gates_rows:
        if not isinstance(g, dict):
            continue
        gids = g.get("rules", g.get("rule_ids", []))
        if not isinstance(gids, list):
            continue
        if any(str(x).strip() in related_rule_ids for x in gids):
            related_gates.append(g)
    if not related_gates:
        raise HTTPException(status_code=404, detail=f"未找到 normRef 对应 Gate：{target_ref}")

    evaluated = [_evaluate_rule_with_input(r, request.input) for r in related_rules]
    gate_results = []
    for g in related_gates:
        rule_ids = g.get("rules", g.get("rule_ids", []))
        rid_set = {str(x).strip() for x in (rule_ids if isinstance(rule_ids, list) else []) if str(x).strip()}
        rows = [x for x in evaluated if str(x.get("rule_id", "")).strip() in rid_set]
        gate_pass = len(rows) > 0 and all(bool(x.get("passed", False)) for x in rows)
        gate_results.append(
            {
                "gate_id": str(g.get("gate_id", "")).strip(),
                "logic": str(g.get("logic", "ALL_PASS")).strip() or "ALL_PASS",
                "rules": sorted(rid_set),
                "passed": gate_pass,
            }
        )

    overall_pass = len(gate_results) > 0 and all(bool(x.get("passed", False)) for x in gate_results)
    idx_entries = idx_doc.get("entries", []) if isinstance(idx_doc, dict) else []
    idx_map = {
        str((e or {}).get("normRef", "")).strip(): e
        for e in idx_entries
        if isinstance(e, dict) and str((e or {}).get("normRef", "")).strip()
    }
    source_refs = []
    for rr in evaluated:
        ref = str(rr.get("norm_ref", "")).strip()
        entry = idx_map.get(ref, {})
        source_refs.append(
            {
                "norm_ref": ref,
                "source_clause_id": str(rr.get("source_clause_id", "")).strip(),
                "locator": (entry.get("locator", {}) if isinstance(entry, dict) else {}),
            }
        )

    dto_rows = dto_doc.get("dto_schemas", []) if isinstance(dto_doc, dict) else []
    loaded_dtos = []
    if isinstance(dto_rows, list):
        related_components = {str(r.get("component_id", "")).strip() for r in related_rules if str(r.get("component_id", "")).strip()}
        for dto in dto_rows:
            if not isinstance(dto, dict):
                continue
            if str(dto.get("component_id", "")).strip() in related_components:
                loaded_dtos.append(dto)

    return {
        "result": "PASS" if overall_pass else "FAIL",
        "normRef": target_ref,
        "rules": evaluated,
        "gates": gate_results,
        "dto": loaded_dtos,
        "source_refs": source_refs,
        "asset_dir": str(art_dir),
    }


@app.post("/layer2/rule-updates")
def create_layer2_rule_update(request: Layer2RuleUpdateRequest) -> Dict[str, Any]:
    project = load_project_config(request.project_id)
    update = _build_rule_update_record(request, project)
    notifications = _build_rule_update_notifications(project, update)

    updates = _load_layer2_store("rule_updates")
    updates.append(update)
    _save_layer2_store("rule_updates", updates)

    notify_store = _load_layer2_store("notifications")
    notify_store.extend(notifications)
    _save_layer2_store("notifications", notify_store)

    return {
        "status": "published",
        "rule_update": update,
        "notification_count": len(notifications),
        "notifications": notifications[:5],
    }


