@app.get("/layer2/notifications")
def list_layer2_notifications(project_id: str, user_did: str = "", status: str = "") -> Dict[str, Any]:
    rows = _load_layer2_store("notifications")
    normalized_status = str(status or "").strip().upper()
    items: List[Dict[str, Any]] = []
    for row in rows:
        if not _project_id_matches(row.get("project_id", ""), project_id):
            continue
        if user_did and str(row.get("recipient_did", "")) != user_did:
            continue
        row_status = str(row.get("status", "")).upper()
        if normalized_status and row_status != normalized_status:
            continue
        items.append(row)

    pending = sum(1 for item in items if str(item.get("status", "")).upper() == "PENDING_ACK")
    return {
        "status": "ok",
        "project_id": project_id,
        "count": len(items),
        "pending_ack_count": pending,
        "items": items,
    }


@app.post("/layer2/notifications/{notification_id}/ack")
def acknowledge_layer2_notification(notification_id: str, request: Layer2AcknowledgeRequest) -> Dict[str, Any]:
    rows = _load_layer2_store("notifications")
    updated: Optional[Dict[str, Any]] = None
    for row in rows:
        if str(row.get("notification_id", "")) != notification_id:
            continue
        if not _project_id_matches(row.get("project_id", ""), request.project_id):
            continue
        row["status"] = "ACKED"
        row["acked_at"] = _utc_now()
        row["acked_by"] = request.user_did
        row["acked_by_name"] = request.user_name
        row["ack_comment"] = request.comment
        updated = row
        break

    if updated is None:
        raise HTTPException(status_code=404, detail=f"未找到通知：{notification_id}")

    _save_layer2_store("notifications", rows)
    return {"status": "ok", "notification": updated}


@app.post("/layer2/retrospect")
def run_layer2_retrospect(request: Layer2RetrospectRequest) -> Dict[str, Any]:
    _ = load_project_config(request.project_id)
    update = _find_rule_update(request.update_id, request.project_id)
    records = [item.model_dump() if hasattr(item, "model_dump") else item.dict() for item in request.records]
    report = _run_retrospect_analysis(request.project_id, update, records)
    return {"status": "ok", "report": report}


@app.post("/layer2/demo/compaction-95-96")
def run_layer2_compaction_demo(project_id: str = "GXX_2024_XXX") -> Dict[str, Any]:
    demo_update_req = Layer2RuleUpdateRequest(
        project_id=project_id,
        form_type="T0921-2019",
        clause_id="clause_4_2_1",
        target="subgrade.Z96.standard_value",
        old_value=95.0,
        new_value=96.0,
        effective_date=date.today().isoformat(),
        scope="全段",
        reason="压实度标准由95%提升至96%",
        changed_by="did:peg:ce_001",
        authority="ProjectOverride",
    )
    creation = create_layer2_rule_update(demo_update_req)
    update = creation.get("rule_update", {})
    if not isinstance(update, dict):
        raise HTTPException(status_code=500, detail="演示链路创建规则更新失败。")

    demo_records = [
        {
            "record_id": "r_001",
            "form_type": "T0921-2019",
            "section": "K15+200",
            "checked_at": "2026-04-10T10:10:00Z",
            "status": "PASS",
            "inputs": {"compaction_degree": 95.2, "layer_zone": "Z96"},
        },
        {
            "record_id": "r_002",
            "form_type": "T0921-2019",
            "section": "K15+400",
            "checked_at": "2026-04-10T11:00:00Z",
            "status": "PASS",
            "inputs": {"compaction_degree": 95.8, "layer_zone": "Z96"},
        },
        {
            "record_id": "r_003",
            "form_type": "T0921-2019",
            "section": "K15+600",
            "checked_at": "2026-04-10T14:20:00Z",
            "status": "PASS",
            "inputs": {"compaction_degree": 96.3, "layer_zone": "Z96"},
        },
    ]
    resolved_project_id = str(update.get("project_id", project_id))
    retrospect = _run_retrospect_analysis(resolved_project_id, update, demo_records)
    notifications = list_layer2_notifications(project_id=resolved_project_id, status="PENDING_ACK")
    return {
        "status": "ok",
        "demo": "compaction_95_to_96",
        "rule_update": update,
        "impact": update.get("impact", {}),
        "notifications": {
            "pending_ack_count": notifications.get("pending_ack_count", 0),
            "sample": notifications.get("items", [])[:5],
        },
        "retrospect_report": retrospect,
    }


@app.post("/chat", response_model=ChatResponse)
def chat(request: ChatRequest) -> ChatResponse:
    project = load_project_config(request.project_id)
    ready, reason = validate_subset_baseline(project)
    if not ready:
        return ChatResponse(
            intent="validate",
            form_type="unknown",
            api_params={},
            gate_result=None,
            natural_reply=f"subset baseline 未完成：{reason}",
            extracted={},
        )
    parser = NL2Gate(project_context=project, session_store=_session_context)
    parsed = parser.parse(request.message, request.user_id)
    normdoc: Optional[Dict[str, Any]] = None
    cross_spec_links: Optional[Dict[str, Any]] = None

    try:
        if parsed.form_type:
            normdoc = load_normdoc_for_form(project, parsed.form_type)
        api_params = parser.to_api_params(
            parsed,
            str(project.get("project_id") or request.project_id),
            normdoc=normdoc,
        )
        if normdoc:
            cross_spec_links = resolve_cross_spec_links(normdoc, api_params, project)
            api_params["cross_spec_links"] = cross_spec_links
    except ValueError as exc:
        return ChatResponse(
            intent=parsed.intent,
            form_type=parsed.form_type or "unknown",
            api_params={},
            gate_result=None,
            natural_reply=str(exc),
            extracted=parsed.entities,
        )
    except HTTPException as exc:
        return ChatResponse(
            intent=parsed.intent,
            form_type=parsed.form_type or "unknown",
            api_params={},
            gate_result=None,
            natural_reply=str(exc.detail),
            extracted=parsed.entities,
        )

    gate_result = call_gate_validate(
        api_params,
        normdoc=normdoc,
        project=project,
        cross_spec_links=cross_spec_links,
    )
    gate_result = merge_cross_spec_into_gate_result(
        gate_result,
        cross_spec_links=cross_spec_links,
        api_params=api_params,
        project=project,
    )
    reply = generate_natural_reply(parsed, gate_result)

    return ChatResponse(
        intent=parsed.intent,
        form_type=parsed.form_type or "unknown",
        api_params=api_params,
        gate_result=gate_result,
        natural_reply=reply,
        extracted=parsed.entities,
    )
UNRESOLVED_TYPES = {
    "missing_threshold",
    "missing_unit",
    "semantic_ambiguity",
    "missing_gate",
    "missing_slot_mapping",
    "unsupported_formula",
}
